const api = {
  list: () => fetch('/api/tasks').then(r => r.json()),
  create: (data) => {
    window._lastLocalEdit = Date.now();
    return fetch('/api/tasks', { method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(data) }).then(r => r.json());
  },
  // Phase 5 (conflict detection) wrapper: inject the current version from
  // state.tasks so the server can detect "somebody else saved first" and
  // return 409. On 409, surface a toast + trigger a refresh so the user
  // sees the latest data instead of overwriting it.
  update: async (id, data) => {
    window._lastLocalEdit = Date.now();
    if (data && data.version == null) {
      try {
        const current = (typeof state !== 'undefined' && state.tasks)
          ? state.tasks.find(t => t.id === id) : null;
        if (current && current.version != null) data = { ...data, version: current.version };
      } catch (_) {}
    }
    const r = await fetch(`/api/tasks/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    const body = await r.json();
    if (r.status === 409) {
      if (typeof showToast === 'function') {
        showToast('Someone else just edited this row. Reloading…', { kind: 'warn' });
      }
      try { if (typeof loadTasks === 'function') loadTasks(); } catch (_) {}
      // Hand the server's authoritative row back to the caller so chained
      // .then() consumers don't choke on undefined.
      return body.server_row || body;
    }
    return body;
  },
  remove: (id) => {
    window._lastLocalEdit = Date.now();
    return fetch(`/api/tasks/${id}`, { method: 'DELETE' }).then(r => r.json());
  },
  getSettings: () => fetch('/api/settings').then(r => r.json()),
  putSetting: (key, value) => fetch(`/api/settings/${key}`, { method: 'PUT', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(value) }).then(r => r.json()),
  team: {
    list:   () => fetch('/api/team').then(r => r.json()),
    // Stamp _lastLocalEdit on every write so the realtime-ui Socket listener
    // skips the immediate echo. Without this stamp, the socket's debounced
    // loadTeam() fires 250 ms after the local save and tears down whatever
    // input the user was typing in — which manifests as "I typed a name and
    // it didn't save" because the input element gets destroyed mid-edit.
    create: (data) => {
      window._lastLocalEdit = Date.now();
      return fetch('/api/team', { method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(data) }).then(r => r.json());
    },
    update: (id, data) => {
      window._lastLocalEdit = Date.now();
      return fetch(`/api/team/${id}`, { method: 'PUT', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(data) }).then(r => r.json());
    },
    remove: (id) => {
      window._lastLocalEdit = Date.now();
      return fetch(`/api/team/${id}`, { method: 'DELETE' }).then(r => r.json());
    },
  },
  // Shop Parts (Parts in Shop) — independent from tasks; its own table + routes.
  shopParts: {
    list:   () => fetch('/api/shop-parts').then(r => r.json()),
    create: (data) => { window._lastLocalEdit = Date.now(); return fetch('/api/shop-parts', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(data) }).then(r => r.json()); },
    update: (id, data) => { window._lastLocalEdit = Date.now(); return fetch(`/api/shop-parts/${id}`, { method: 'PUT', headers: {'Content-Type':'application/json'}, body: JSON.stringify(data) }).then(r => r.json()); },
    remove: (id) => { window._lastLocalEdit = Date.now(); return fetch(`/api/shop-parts/${id}`, { method: 'DELETE' }).then(r => r.json()); },
    reorder: (order) => fetch('/api/shop-parts/reorder', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ order }) }).then(r => r.json()),
  },
  // Vendor POs (Vendor PO Track) — independent table + routes.
  vendorPOs: {
    list:   () => fetch('/api/vendor-pos').then(r => r.json()),
    create: (data) => { window._lastLocalEdit = Date.now(); return fetch('/api/vendor-pos', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(data) }).then(r => r.json()); },
    update: (id, data) => { window._lastLocalEdit = Date.now(); return fetch(`/api/vendor-pos/${id}`, { method: 'PUT', headers: {'Content-Type':'application/json'}, body: JSON.stringify(data) }).then(r => r.json()); },
    remove: (id) => { window._lastLocalEdit = Date.now(); return fetch(`/api/vendor-pos/${id}`, { method: 'DELETE' }).then(r => r.json()); },
  },
  // Total ETO bridge — read-only pulls from the ERP (optional, server-gated).
  eto: {
    status: () => fetch('/api/eto/status').then(r => r.json()),
    syncVendorPOs: (scope) => { window._lastLocalEdit = Date.now(); return fetch('/api/eto/sync-vendor-pos', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ scope: scope || 'linked' }) }).then(r => r.json()); },
    poLines: (job, po) => fetch(`/api/eto/po/${encodeURIComponent(job)}/${encodeURIComponent(po)}/lines`).then(r => { if (!r.ok) throw new Error(`lines fetch failed (${r.status})`); return r.json(); }),
    vendors: (job) => fetch(`/api/eto/vendors/${encodeURIComponent(job)}`).then(r => { if (!r.ok) throw new Error(`vendors fetch failed (${r.status})`); return r.json(); }),
    partcost: (job) => fetch(`/api/eto/partcost/${encodeURIComponent(job)}`).then(r => { if (!r.ok) throw new Error(`part cost fetch failed (${r.status})`); return r.json(); }),
  },
  agent: {
    status: () => fetch('/api/agent/status').then(r => r.json()),
    ask: (question, context, history) => fetch('/api/agent/ask', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ question, context, history: history || [] }) }).then(async r => { const b = await r.json().catch(() => ({})); if (!r.ok) throw new Error(b.error || `request failed (${r.status})`); return b; }),
  },
  // Baseline snapshot — captures the current start/end dates on every task in a
  // project so subsequent edits can be compared against the original plan.
  baseline: {
    set:   (project) => fetch('/api/baseline/set',   { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ project }) }).then(r => r.json()),
    clear: (project) => fetch('/api/baseline/clear', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ project }) }).then(r => r.json()),
  },
  // Per-project financial milestones. Independent from tasks: they're not in the grid,
  // don't have predecessors, and render as a Gantt overlay when the $ Financial toggle
  // is on. Auto-seeded from the default_financial_milestones setting via api.financials.seed.
  // Every method tolerates a missing server-side endpoint (404) — if the server hasn't
  // been restarted with the new routes, list() returns [] and seed() returns ok:false
  // so callers can show a "restart the server" hint instead of crashing.
  financials: {
    list: async (project) => {
      try {
        const r = await fetch(`/api/financials${project ? `?project=${encodeURIComponent(project)}` : ''}`);
        if (!r.ok) { state._financialsApiBroken = true; return []; }
        return await r.json();
      } catch (err) { state._financialsApiBroken = true; return []; }
    },
    create: async (data) => {
      const r = await fetch('/api/financials', { method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(data) });
      if (!r.ok) { state._financialsApiBroken = true; throw new Error('financials.create failed'); }
      return await r.json();
    },
    update: async (id, data) => {
      const r = await fetch(`/api/financials/${id}`, { method: 'PUT', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(data) });
      if (!r.ok) { state._financialsApiBroken = true; throw new Error('financials.update failed'); }
      return await r.json();
    },
    remove: async (id) => {
      const r = await fetch(`/api/financials/${id}`, { method: 'DELETE' });
      if (!r.ok) { state._financialsApiBroken = true; throw new Error('financials.remove failed'); }
      return await r.json();
    },
    seed: async (project) => {
      try {
        const r = await fetch('/api/financials/seed', { method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({ project }) });
        if (!r.ok) { state._financialsApiBroken = true; return { ok: false }; }
        return await r.json();
      } catch (err) { state._financialsApiBroken = true; return { ok: false }; }
    },
  },
  notes: {
    get: async (project) => {
      try { const r = await fetch(`/api/project/${encodeURIComponent(project)}/notes`); if (!r.ok) return null; return await r.json(); }
      catch (_) { return null; }
    },
    save: async (project, data) => fetch(`/api/project/${encodeURIComponent(project)}/notes`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data || { sessions: [] }),
    }),
  },
};

