// v4.54: ROW_H_MIN = 16 (was 12 in v4.52-v4.53; was 18 before that). User
// feedback: even friendly 10 = 12px was too small to be readable. New
// friendly scale goes 0–100 (not 10–100), mapping 0=16px → 100=30px in
// increments of 10 = 1.4px each. The previous "you'd never go smaller
// than 30 (= 16px in v4.53 friendly)" gets renamed to 0 in the new scale.
const ROW_H_MIN = 4;
const ROW_H_MAX = 120;
const ROW_H_FRIENDLY_MIN_PX = 4;
const ROW_H_FRIENDLY_MAX_PX = 30;
const ROW_H_DEFAULT = 26;
const BAR_H_MIN = 10;

// Departments-tab resource bars use a tighter, denser scale than the
// Schedule grid because the user just wants bar-thickness control on the
// timeline — not row spacing inside an editable table. Per Dan's request
// the friendly scale is 0-10 (steps of 1), with row 0 SMALLER than the
// Schedule's row 0 and row 10 equivalent to Schedule's row 50/100.
//   Schedule's row 50/100 = 16 + 0.5 * (30-16) = 23 px
//   So MAX = 23, MIN = 12 (smaller than Schedule's 16).
const RES_BAR_H_MIN_PX  = 12;
const RES_BAR_H_MAX_PX  = 23;
const RES_BAR_H_LEVELS  = 10;
function pxToFriendlyResRow(px) {
  const clamped = Math.max(RES_BAR_H_MIN_PX, Math.min(RES_BAR_H_MAX_PX, px));
  const t = (clamped - RES_BAR_H_MIN_PX) / (RES_BAR_H_MAX_PX - RES_BAR_H_MIN_PX);
  return Math.round(t * RES_BAR_H_LEVELS);
}
function friendlyResRowToPx(friendly) {
  const t = Math.max(0, Math.min(RES_BAR_H_LEVELS, friendly)) / RES_BAR_H_LEVELS;
  return Math.round(RES_BAR_H_MIN_PX + t * (RES_BAR_H_MAX_PX - RES_BAR_H_MIN_PX));
}
// Row-height +/- step. Fixed 2px/click is fine-grained enough for the typical 14–60
// range; small enough to make tight 1-row-difference adjustments without
// overshooting, big enough that holding the button doesn't feel sluggish.
const ROW_H_STEP = 2;

const PHASES = window.PHASES;
const PHASE_BY_KEY = window.PHASE_BY_KEY;
const HIERARCHY = window.HIERARCHY;
const GROUP_BY_KEY = window.GROUP_BY_KEY;
const SVG_NS = 'http://www.w3.org/2000/svg';

// Set of "phase_group/department/sub_department" paths the user has collapsed in the grid.
const collapsedGroups = new Set();
function groupPath(g, d, s) { return [g || '', d || '', s || ''].join('/'); }

// Maps maintained by updateLineNumbersAndPreds. Predecessors are stored by task id but shown
// as line numbers (1, 2, 3 …) so the user has a stable visual reference that keeps re-numbering
// as rows move.
let lineByTaskId = {};
let taskIdByLine = {};

function predDisplay(predString) {
  if (!predString) return '';
  return String(predString).split(',').map(s => {
    const m = s.trim().match(/^(\d+)(.*)$/);
    if (!m) return s.trim().toUpperCase();
    const id = Number(m[1]);
    const line = lineByTaskId[id];
    // If we don't know the line, render nothing for this entry instead of
    // "?id" — a question mark in the predecessor column is just noise.
    if (line == null) return '';
    return (line + m[2]).toUpperCase();
  }).filter(Boolean).join(', ');
}
function predParse(displayString) {
  if (!displayString) return '';
  return String(displayString).split(',').map(s => {
    const m = s.trim().match(/^(\d+)(.*)$/);
    if (!m) return s.trim().toUpperCase();
    const line = Number(m[1]);
    const id = taskIdByLine[line];
    return ((id != null ? id : line) + m[2]).toUpperCase();
  }).join(', ');
}

// ── Financial-milestone trigger storage ──────────────────────────────────────
// Financial triggers track the TASK, not the line, exactly like grid
// predecessors. A task ref is stored as "#<taskId>" (e.g. "#7FF +2w") so it
// follows the task when rows are added / removed / reordered. Anchors (PO / FAT /
// Ship) pass through unchanged. A BARE number is a legacy line ref that still
// resolves positionally and self-heals to "#id" when its project is active.
// finPredDisplay: stored → what the user sees (line numbers). finPredParse: what
// the user typed (line numbers) → stored ("#id"). Both rely on the active
// project's lineByTaskId / taskIdByLine maps.
function finPredDisplay(stored) {
  if (!stored) return '';
  return String(stored).split(',').map(s => {
    const t = s.trim(); if (!t) return '';
    const m = t.match(/^#(\d+)(.*)$/);
    if (m) { const line = lineByTaskId[Number(m[1])]; return line == null ? '' : (line + m[2]).toUpperCase(); }
    return t.toUpperCase(); // legacy bare line number, or an anchor alias
  }).filter(Boolean).join(', ');
}
function finPredParse(displayed) {
  if (!displayed) return '';
  return String(displayed).split(',').map(s => {
    const t = s.trim(); if (!t) return '';
    if (t.startsWith('#')) return t.toUpperCase(); // already a task ref — leave it
    const m = t.match(/^(\d+)(.*)$/);
    if (m) { const id = taskIdByLine[Number(m[1])]; return id != null ? ('#' + id + m[2]).toUpperCase() : t.toUpperCase(); }
    return t.toUpperCase(); // anchor alias (PO / FAT / Ship)
  }).filter(Boolean).join(', ');
}

// Walk HIERARCHY + anchors as if nothing is collapsed. Returns the canonical task ID
// order — used to assign line numbers that stay STABLE across collapse / expand
// operations, so predecessor displays never flip to "?id" just because a section is
// folded up.
function buildCanonicalTaskOrder() {
  // Line numbers should stay STABLE when the user flips between machine
  // pills (All / M1 / M2). Otherwise M2.Builder-1 would be "line 1" in
  // M2 view and "line 24" in All view — and the user references those
  // numbers in predecessors, so they have to point to the same row
  // either way.
  const filtered = applyFilters(state.tasks, { ignoreMachineSubset: true });
  const buckets = {};
  // Mech 1 Release + Machine Power-Up flow through their hierarchy bucket; all
  // other anchors render at fixed spine positions outside the walk.
  const INLINE_ANCHORS = new Set(['mech_release_1', 'machine_power_up']);
  for (const t of filtered) {
    const k = inferredAnchorKey(t);
    if (k && !INLINE_ANCHORS.has(k)) continue;
    const path = groupPath(t.phase_group, t.department, t.sub_department);
    (buckets[path] ||= []).push(t);
  }
  const sortBucket = (arr) => {
    if (state.scheduleView?.sortByStart) {
      arr.sort((a, b) =>
        (a.start_date || '￿').localeCompare(b.start_date || '￿')
        || (a.sort_order || 0) - (b.sort_order || 0));
    } else {
      arr.sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));
    }
  };
  for (const k in buckets) sortBucket(buckets[k]);

  const candidates = filtered.map(t => [t, inferredAnchorKey(t)]).filter(([, k]) => !!k);
  const pickOldest = (key) => {
    const list = candidates.filter(([, k]) => k === key).map(([t]) => t);
    return list.length ? list.reduce((a, b) => (a.id < b.id ? a : b)) : null;
  };
  // Spine anchors: in a multi-machine project, each machine has its OWN
  // FAT / Ship Machine / Power-Up. We need ALL of them in the canonical
  // order, not just the oldest one (otherwise M2's FAT etc. never make
  // it onto the Gantt). Receipt of PO stays shared so a single instance
  // is fine. Sort each set by machine name (with shared/null first) so
  // they render in a predictable order at their spine slot.
  const pickAll = (key) => {
    const list = candidates.filter(([, k]) => k === key).map(([t]) => t);
    return list.sort((a, b) => {
      // Shared (machine=null) comes first, then numeric-aware machine name.
      const ma = a.machine || '';
      const mb = b.machine || '';
      if (ma === mb) return a.id - b.id;
      if (!ma) return -1;
      if (!mb) return  1;
      return ma.localeCompare(mb, undefined, { numeric: true });
    });
  };
  const receiptAnchor = pickOldest('receipt_of_po'); // single shared anchor
  const fatAnchors    = pickAll('fat');
  const shipAnchors   = pickAll('ship_machine');
  const satAnchors    = pickAll('sat');

  const order = [];
  if (receiptAnchor) order.push(receiptAnchor.id);
  // Every non-anchor task with no phase_group sits BETWEEN Receipt of PO and
  // section 10 in the rendered grid — these are the "above section 10" rows
  // (Backlog, or anything the user added below an anchor via right-click).
  // Include them in canonical order so they each get a stable line number
  // that can be used as a predecessor reference.
  const aboveSectionTasks = filtered
    .filter(t => !inferredAnchorKey(t) && !t.phase_group)
    .slice()
    .sort((a, b) => (Number(a.sort_order) || 0) - (Number(b.sort_order) || 0));
  for (const t of aboveSectionTasks) order.push(t.id);
  for (const group of HIERARCHY) {
    if (state.scheduleView?.flatten || isPersonalMode()) {
      // Same INLINE_ANCHORS rule as the table walk.
      let sectionTasks = filtered.filter(t => {
        if (t.phase_group !== group.key) return false;
        const k = inferredAnchorKey(t);
        return !k || INLINE_ANCHORS.has(k);
      });
      sortBucket(sectionTasks);
      // Splice Ship Machine into section 50 by sort_order so line numbers
      // land Teardown / Ship Machine / Install even when tasks carry a
      // null department (sales template suppresses subheaders that way).
      if (group.key === 'teardown_install' && shipAnchors.length) {
        sectionTasks = [...sectionTasks, ...shipAnchors]
          .sort((a, b) => (Number(a.sort_order) || 0) - (Number(b.sort_order) || 0));
      }
      for (const t of sectionTasks) order.push(t.id);
    } else {
      let groupLevelTasks = buckets[groupPath(group.key)] || [];
      // Sales-mode section 50: merge Ship Machine anchors into the
      // group-level list by sort_order. Skips the dept-loop ship-insert
      // below so we don't double-count.
      let shipDroppedAtGroupLevelOrd = false;
      if (group.key === 'teardown_install' && shipAnchors.length && groupLevelTasks.length) {
        groupLevelTasks = [...groupLevelTasks, ...shipAnchors]
          .sort((a, b) => (Number(a.sort_order) || 0) - (Number(b.sort_order) || 0));
        shipDroppedAtGroupLevelOrd = true;
      }
      for (const t of groupLevelTasks) order.push(t.id);
      for (const dept of group.departments) {
        if (group.key === 'teardown_install' && dept.key === 'install' && shipAnchors.length && !shipDroppedAtGroupLevelOrd) {
          for (const s of shipAnchors) order.push(s.id);
        }
        const dPath = groupPath(group.key, dept.key);
        if (dept.subs.length > 0) {
          const deptLevelTasks = buckets[dPath] || [];
          for (const t of deptLevelTasks) order.push(t.id);
          for (const sub of dept.subs) {
            const sPath = groupPath(group.key, dept.key, sub.key);
            for (const t of (buckets[sPath] || [])) order.push(t.id);
          }
        } else {
          for (const t of (buckets[dPath] || [])) order.push(t.id);
        }
      }
    }
    if (group.key === 'machine_testing' && fatAnchors.length) {
      for (const f of fatAnchors) order.push(f.id);
    }
    // SAT closes section 50, after every install task — mirrors the render walk.
    if (group.key === 'teardown_install' && satAnchors.length) {
      for (const s of satAnchors) order.push(s.id);
    }
  }
  return order;
}

function updateLineNumbersAndPreds() {
  const tbody = document.getElementById('tasks-tbody');
  if (!tbody) return;
  // Stable canonical line numbers — built from the FULL hierarchy walk so collapsing
  // a section never reshuffles them. Predecessor displays therefore stay locked even
  // when the predecessor's row is currently hidden.
  const canonicalOrder = buildCanonicalTaskOrder();
  lineByTaskId = {};
  taskIdByLine = {};
  canonicalOrder.forEach((id, i) => {
    const line = i + 1;
    lineByTaskId[id] = line;
    taskIdByLine[line] = id;
  });
  // Stamp each currently-visible row's line cell with its canonical line number.
  const taskRows = Array.from(tbody.querySelectorAll('tr[data-id]'));
  taskRows.forEach(tr => {
    const id = Number(tr.dataset.id);
    const line = lineByTaskId[id];
    const numEl = tr.querySelector('td[data-col="line"] .line-num');
    if (numEl && line != null) numEl.textContent = String(line);
  });
  // Translate the predecessors cell using the canonical map.
  taskRows.forEach(tr => {
    const id = Number(tr.dataset.id);
    const task = state.tasks.find(t => t.id === id);
    const cell = tr.querySelector('td[data-col="pred"]');
    if (cell && !cell.classList.contains('editing')) {
      cell.textContent = predDisplay(task?.predecessors || '');
    }
  });
  // v4.39: fill in duration-link badges with a 🔗 emoji + source line.
  // The link icon makes the relationship visible at a glance; the row
  // number lets you trace which task it's tied to without hovering.
  tbody.querySelectorAll('.name-cell-dur-link[data-link-target-id]').forEach(el => {
    const srcId = Number(el.getAttribute('data-link-target-id'));
    const line = lineByTaskId[srcId];
    el.textContent = line != null ? `🔗${line}` : '🔗?';
  });
}

// Frappe-gantt v0.6.1 hard-codes column_width inside update_view_scale based on view mode,
// which clobbers any custom column_width we pass in. Patch the prototype so a per-instance
// _cwOverride survives the reset — that's how we get continuous zoom.
if (window.Gantt && !Gantt.prototype._sdcPatched) {
  const _orig = Gantt.prototype.update_view_scale;
  Gantt.prototype.update_view_scale = function (mode) {
    _orig.call(this, mode);
    if (this.options && this.options._cwOverride) {
      this.options.column_width = this.options._cwOverride;
    }
  };
  Gantt.prototype._sdcPatched = true;
}

// One continuous zoom. Mode (Day / Week / Month) is auto-derived so the user can scroll
// from "show me everything" all the way to "show me one day" without picking a mode.
const VIEW_MODE_BASE_CW = { Day: 38, Week: 140, Month: 120 };
const VIEW_MODE_STEP_DAYS = { Day: 1, Week: 7, Month: 30 };
// Wheel + setZoom() clamp to the SAME range as the friendly 1-10
// stepper so the user can't scroll past either end. ZOOM_MIN_PCT and
// ZOOM_MAX_PCT below mirror this so the friendly stepper stays in
// sync — adjust both together if you change the range.
const ZOOM_MIN = 10;
const ZOOM_MAX = 145;
const ZOOM_STEP = 10;

// 100% = 20 px/day (matches frappe-gantt's Week default of 140 / 7).
function getZoomConfig(zoomPercent) {
  const pxPerDay = (zoomPercent / 100) * 20;
  if (pxPerDay < 3) {
    return { mode: 'Month', cw: Math.max(20, Math.min(400, Math.round(pxPerDay * 30))) };
  } else if (pxPerDay < 28) {
    return { mode: 'Week', cw: Math.max(15, Math.min(400, Math.round(pxPerDay * 7))) };
  } else {
    return { mode: 'Day', cw: Math.max(10, Math.min(200, Math.round(pxPerDay))) };
  }
}

// ---------- Utilities ----------
// Inclusive count between two ISO dates, in CALENDAR days. Used only where the
// calendar span itself matters (e.g. Gantt bar pixel width derives from this on the
// frappe side, but our routing math uses dates directly). Most logic uses business
// days via businessDaysBetween / addBusinessDays below.
function daysBetween(start, end) {
  if (!start || !end) return null;
  const s = new Date(start), e = new Date(end);
  const ms = e - s;
  if (isNaN(ms)) return null;
  return Math.round(ms / 86400000) + 1;
}

// Team members named "* Placeholder" (case-insensitive) act as role-stand-ins on
// templates. They carry through duplicate-project, sit at the bottom of their team
// card, render with a ghost/italic style, and are skipped by the over-allocation
// calc — they're not real people, just role markers waiting to be reassigned.
function isPlaceholder(name) {
  return /\bplaceholder\b/i.test(String(name || ''));
}

// Capacity snapshot for one discipline:
//   - realCount:     number of active, non-placeholder team members in that discipline
//   - scheduledHrs:  total scheduled hours = SUM(duration_days × 8 × allocation%)
//                    across every task currently assigned to someone in that discipline
//                    (placeholders included, since templated work is still "sold")
//   - weeksAhead:    scheduledHrs ÷ (realCount × 40 × 0.9). null when realCount is 0
//                    (no real people → infinite weeks, not meaningful).
// Drives the "X hrs scheduled · Y wks at 90%" line under each discipline's card.
function computeDisciplineCapacity(discKey, members) {
  const memberNames = new Set(members.map(m => m.name));
  const realCount = members.filter(m => !isPlaceholder(m.name) && m.active !== 0).length;
  let hrs = 0;
  for (const t of state.tasks) {
    if (t.is_milestone) continue;
    // Skip tasks from template projects AND Sales-workspace projects —
    // templates are canonical scaffolding cloned into real projects (not
    // real work); Sales schedules are pre-quote work that hasn't been
    // staffed for real yet. Either would inflate the "X hrs scheduled"
    // reading on every discipline.
    if (isTemplateProject(t.project)) continue;
    if (projectWorkspace(t.project) === 'Sales') continue;
    if (!t.assignee || !memberNames.has(t.assignee)) continue;
    const dur = Number(t.duration_days);
    if (!dur || dur <= 0) continue;
    const alloc = t.allocation == null ? 90 : Math.max(0, Math.min(100, Number(t.allocation)));
    hrs += dur * 8 * (alloc / 100);
  }
  const scheduledHrs = Math.round(hrs);
  const weeklyCapacity = realCount * 40 * 0.9;
  const weeksAhead = weeklyCapacity > 0 ? Math.round((scheduledHrs / weeklyCapacity) * 10) / 10 : null;
  const tooltip = realCount > 0
    ? `${scheduledHrs.toLocaleString()} hrs total ÷ (${realCount} × 40 × 90%) = ${weeksAhead} weeks of work. (Template-project tasks excluded.)`
    : `${scheduledHrs.toLocaleString()} hrs scheduled. Add real team members (non-placeholders) to see capacity in weeks.`;
  return { realCount, scheduledHrs, weeksAhead, tooltip };
}

// Which team disciplines plausibly own this task? Drives the filtered assignee
// dropdown so e.g. a CONTROLS ENGINEERING task only surfaces controls engineers.
// Ambiguous buckets (General Engineering, Section 40/50 dept-level rows where
// either engineers OR shop could own it) return multiple disciplines. Unknown
// or missing classification returns ALL disciplines so the dropdown still shows
// every option as a safe default.
function relevantDisciplinesForTask(task) {
  if (!task) return ['mech', 'controls', 'build', 'wire'];
  const pg  = task.phase_group;
  const dep = task.department;
  const sub = task.sub_department;

  // Section 10 — Design & Build: sub-department is highly specific where set.
  if (pg === 'design_build') {
    if (sub === 'mech')     return ['mech'];
    if (sub === 'controls') return ['controls'];
    if (sub === 'build')    return ['build'];
    if (sub === 'wire')     return ['wire'];
    if (sub === 'general')  return ['mech', 'controls'];   // any engineer
    // Department-level rows (no sub) — engineering = either engineer,
    // shop = either trade, procurement = anyone.
    if (dep === 'engineering') return ['mech', 'controls'];
    if (dep === 'shop')        return ['build', 'wire'];
    if (dep === 'procurement') return ['mech', 'controls', 'build', 'wire'];
  }

  // Section 40 — Machine Testing: dept-only, both disciplines under each.
  if (pg === 'machine_testing') {
    if (dep === 'engineering') return ['mech', 'controls'];
    if (dep === 'shop')        return ['build', 'wire'];
  }

  // Section 50 — Teardown & Install. Teardown is shop-only; Install has both.
  if (pg === 'teardown_install') {
    if (dep === 'teardown') return ['build', 'wire'];
    if (dep === 'install') {
      if (sub === 'engineering') return ['mech', 'controls'];
      if (sub === 'shop')        return ['build', 'wire'];
      // Install at the dept level — anyone.
      return ['mech', 'controls', 'build', 'wire'];
    }
  }

  // Anything else (no classification, anchors before they're given a section,
  // etc.) — return all four so the dropdown is unconstrained.
  return ['mech', 'controls', 'build', 'wire'];
}

function isWeekendDate(d) {
  const day = d.getUTCDay();
  return day === 0 || day === 6;
}

// Snap an ISO date to a business day if it's currently Sat/Sun. dir=1 advances
// forward (Sat → Mon), dir=-1 walks backward (Sat → Fri). Idempotent on weekdays.
function snapToBusinessDay(dateStr, dir = 1) {
  if (!dateStr) return null;
  const d = new Date(dateStr + 'T00:00:00Z');
  while (isWeekendDate(d)) {
    d.setUTCDate(d.getUTCDate() + (dir > 0 ? 1 : -1));
  }
  return d.toISOString().slice(0, 10);
}

// Inclusive count of business days (Mon–Fri) between two ISO dates.
function businessDaysBetween(start, end) {
  if (!start || !end) return null;
  const s = new Date(start + 'T00:00:00Z');
  const e = new Date(end + 'T00:00:00Z');
  if (isNaN(s) || isNaN(e) || e < s) return null;
  let count = 0;
  const cur = new Date(s);
  while (cur <= e) {
    if (!isWeekendDate(cur)) count++;
    cur.setUTCDate(cur.getUTCDate() + 1);
  }
  return count;
}

// Add n business days to an ISO date. n=0 returns the date unchanged.
function addBusinessDays(startISO, n) {
  if (!startISO) return null;
  if (n === 0) return startISO;
  const d = new Date(startISO + 'T00:00:00Z');
  let remaining = Math.abs(n);
  const dir = n >= 0 ? 1 : -1;
  while (remaining > 0) {
    d.setUTCDate(d.getUTCDate() + dir);
    if (!isWeekendDate(d)) remaining--;
  }
  return d.toISOString().slice(0, 10);
}

// Duration display in BUSINESS days. The stored task.duration_days is the SOURCE OF
// TRUTH — what the user typed stays exactly that, regardless of how the end_date
// shifts when crossing weekends. Falls back to a fresh business-day count from
// start/end only when duration_days isn't populated (legacy rows pre-migration).
function durationLabel(task) {
  if (!task) return '';
  if (task.is_milestone) return '0';
  let d = (task.duration_days != null) ? Number(task.duration_days) : null;
  if (d == null) d = businessDaysBetween(task.start_date, task.end_date);
  if (d == null) return '';
  if (d === 0) return '0';
  // Whole weeks: 5, 10, 15, ... → "Nw"
  if (d % 5 === 0 && d >= 5) return `${d / 5}w`;
  // Half-week buckets — every duration generated by the estimate-create
  // pipeline lands on one of these: ceil(n × 2.5) for integer n ≥ 1
  // → 3 (0.5w), 8 (1.5w), 13 (2.5w), 18 (3.5w), 23 (4.5w), 28 (5.5w), 33, 38, 43, 48, 53, 58 (11.5w), ...
  // Detect that pattern and label as half-week: 3 → "0.5w", 13 → "2.5w", etc.
  const nHalfWeeks = Math.round(d / 2.5);
  if (nHalfWeeks >= 1 && Math.ceil(nHalfWeeks * 2.5) === d) {
    return `${nHalfWeeks / 2}w`;
  }
  // Half-week snap for ANY other day count — Dan's hard rule: week values
  // only ever read as 0.5, 1, 1.5, 2, ... never 0.6 / 0.8 / 1.4 — and
  // NOTHING nonzero reads below 0.5w. A 1-day or 2-day row is "0.5w"
  // (the old "1d"/"2d" labels confused the week-based math everywhere).
  const halfWeeks = Math.max(1, Math.round((d / 5) * 2));
  return `${halfWeeks / 2}w`;
}

function sortByPhaseThenOrder(tasks) {
  const phaseRank = (p) => {
    if (!p) return 99;
    const idx = window.PHASES.findIndex(ph => ph.key === p);
    return idx >= 0 ? idx : 98;
  };
  return [...tasks].sort((a, b) => {
    const pa = phaseRank(a.phase);
    const pb = phaseRank(b.phase);
    if (pa !== pb) return pa - pb;
    return (a.sort_order || 0) - (b.sort_order || 0);
  });
}

function fmtDate(d) {
  if (!d) return '';
  const [y, m, day] = d.split('-');
  return `${m}/${day}/${y.slice(2)}`;
}

function escapeHtml(s) {
  if (s == null) return '';
  return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}

// In-app confirm / alert dialogs that match the SDC app styling instead of the
// browser-native white box. Both return a Promise so callers can `await` them.
// Caller passes plain text (which we escape) — line breaks turn into <br>.
function _formatDialogMessage(msg) {
  if (msg == null) return '';
  return escapeHtml(msg).replace(/\n/g, '<br>');
}
function showConfirmDialog(opts = {}) {
  return new Promise(resolve => {
    document.getElementById('app-confirm-dialog')?.remove();
    const overlay = document.createElement('div');
    overlay.id = 'app-confirm-dialog';
    overlay.className = 'modal-overlay app-dialog-overlay';
    overlay.innerHTML = `
      <div class="modal-card app-dialog ${opts.danger ? 'app-dialog-danger' : ''}">
        ${opts.title ? `<div class="modal-head"><h2>${escapeHtml(opts.title)}</h2></div>` : ''}
        <div class="modal-body">
          <div class="app-dialog-message">${_formatDialogMessage(opts.message)}</div>
        </div>
        <div class="modal-foot">
          <button type="button" class="btn-ghost" data-action="cancel">${escapeHtml(opts.cancelLabel || 'Cancel')}</button>
          <button type="button" class="${opts.danger ? 'btn-danger' : 'btn-primary'}" data-action="ok">${escapeHtml(opts.okLabel || 'OK')}</button>
        </div>
      </div>`;
    document.body.appendChild(overlay);
    const done = (result) => {
      document.removeEventListener('keydown', onKey);
      overlay.remove();
      resolve(result);
    };
    overlay.querySelector('[data-action="cancel"]').onclick = () => done(false);
    overlay.querySelector('[data-action="ok"]').onclick     = () => done(true);
    overlay.addEventListener('click', (e) => { if (e.target === overlay) done(false); });
    const onKey = (e) => {
      if (e.key === 'Escape') { e.preventDefault(); done(false); }
      else if (e.key === 'Enter')  { e.preventDefault(); done(true);  }
    };
    document.addEventListener('keydown', onKey);
    setTimeout(() => overlay.querySelector('[data-action="ok"]')?.focus(), 0);
  });
}
function showAlertDialog(opts = {}) {
  // Accept either an opts object or a plain string. String form mirrors window.alert.
  if (typeof opts === 'string') opts = { message: opts };
  return new Promise(resolve => {
    document.getElementById('app-alert-dialog')?.remove();
    const overlay = document.createElement('div');
    overlay.id = 'app-alert-dialog';
    overlay.className = 'modal-overlay app-dialog-overlay';
    overlay.innerHTML = `
      <div class="modal-card app-dialog">
        ${opts.title ? `<div class="modal-head"><h2>${escapeHtml(opts.title)}</h2></div>` : ''}
        <div class="modal-body">
          <div class="app-dialog-message">${_formatDialogMessage(opts.message)}</div>
        </div>
        <div class="modal-foot">
          <button type="button" class="btn-primary" data-action="ok">${escapeHtml(opts.okLabel || 'OK')}</button>
        </div>
      </div>`;
    document.body.appendChild(overlay);
    const done = () => {
      document.removeEventListener('keydown', onKey);
      overlay.remove();
      resolve();
    };
    overlay.querySelector('[data-action="ok"]').onclick = done;
    overlay.addEventListener('click', (e) => { if (e.target === overlay) done(); });
    const onKey = (e) => {
      if (e.key === 'Escape' || e.key === 'Enter') { e.preventDefault(); done(); }
    };
    document.addEventListener('keydown', onKey);
    setTimeout(() => overlay.querySelector('[data-action="ok"]')?.focus(), 0);
  });
}

// ── SDC Assistant (Claude, read-only) ───────────────────────────────────────
// Floating "Ask" button + chat panel. Streams from /api/agent/ask-stream,
// remembers history across turns, renders markdown, and shows tool chips.
let _agentOpen = false, _agentStatus = null, _agentBusy = false;
const _agentMsgs = [];      // visible chat log: {role:'user'|'assistant'|'error', text, tools?, usage?}
let _agentHistory = [];     // Claude-format prior turns (sent back next request)
function _initAgentUI() {
  document.getElementById('btn-ask-sidebar')?.addEventListener('click', _toggleAgentPanel);
}
function _toggleAgentPanel() {
  _agentOpen = !_agentOpen;
  if (_agentOpen && !_agentStatus) {
    api.agent.status().then(s => { _agentStatus = s; if (_agentOpen) _renderAgentPanel(); }).catch(() => { _agentStatus = { reachable: false }; if (_agentOpen) _renderAgentPanel(); });
  }
  _renderAgentPanel();
}
function _agentContext() {
  const p = state.filters && state.filters.project;
  if (!p) return '';
  const job = state.projectsIndex && state.projectsIndex[p] && state.projectsIndex[p].job_number;
  return `The user is currently viewing the schedule "${p}"${job ? ` (ETO job ${job})` : ''}.`;
}
// Suggested starter prompts. Tailor a couple to the current project when open.
function _agentStarters() {
  const p = state.filters && state.filters.project;
  const idx = p && state.projectsIndex && state.projectsIndex[p];
  const job = idx && idx.job_number;
  const base = ['How many tasks are overdue across all projects?', 'Which suppliers have past-due POs?'];
  if (job) return [`How is job ${job} doing?`, `Which parts on ${job} have no PO?`, `What is the materials cost so far on ${job}?`];
  if (p) return [`Tell me about "${p}"`, ...base];
  return ['How is job 1129 doing?', ...base];
}
// Minimal, safe Markdown → HTML. Supports headings, bold/italic, inline code,
// fenced code, lists, tables, links — all from escaped text, so it's XSS-safe.
function _agentMd(src) {
  const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  let s = esc(src || '');
  // fenced code blocks
  s = s.replace(/```([\s\S]*?)```/g, (_, c) => `<pre><code>${c.replace(/^\n/, '')}</code></pre>`);
  // headings
  s = s.replace(/^(#{1,3})\s+(.+)$/gm, (_, h, t) => `<h${h.length}>${t}</h${h.length}>`);
  // markdown tables: a block of lines starting and ending with |
  s = s.replace(/(^\|.+\|\n\|[-:\s|]+\|\n(?:^\|.+\|\n?)+)/gm, (block) => {
    const lines = block.trim().split('\n');
    const cells = (ln) => ln.replace(/^\||\|$/g, '').split('|').map(c => c.trim());
    const head = cells(lines[0]);
    const rows = lines.slice(2).map(cells);
    return `<table class="agent-md-tbl"><thead><tr>${head.map(c => `<th>${c}</th>`).join('')}</tr></thead><tbody>${rows.map(r => `<tr>${r.map(c => `<td>${c}</td>`).join('')}</tr>`).join('')}</tbody></table>`;
  });
  // lists (group consecutive bullet lines)
  s = s.replace(/(?:^[-*]\s+.+\n?)+/gm, (block) => `<ul>${block.trim().split('\n').map(ln => `<li>${ln.replace(/^[-*]\s+/, '')}</li>`).join('')}</ul>`);
  s = s.replace(/(?:^\d+\.\s+.+\n?)+/gm, (block) => `<ol>${block.trim().split('\n').map(ln => `<li>${ln.replace(/^\d+\.\s+/, '')}</li>`).join('')}</ol>`);
  // inline: bold, italic, code, links
  s = s.replace(/`([^`]+)`/g, (_, c) => `<code>${c}</code>`);
  s = s.replace(/\*\*([^*]+)\*\*/g, (_, c) => `<strong>${c}</strong>`);
  s = s.replace(/(^|\W)\*([^*\n]+)\*(\W|$)/g, (_, a, c, b) => `${a}<em>${c}</em>${b}`);
  s = s.replace(/\[([^\]]+)\]\(([^)\s]+)\)/g, (_, t, u) => `<a href="${u}" target="_blank" rel="noopener">${t}</a>`);
  // paragraphs from blank-line separators (skip blocks already wrapped)
  s = s.split(/\n{2,}/).map(p => /^<(h\d|ul|ol|pre|table)/i.test(p.trim()) ? p : `<p>${p.replace(/\n/g, '<br>')}</p>`).join('\n');
  return s;
}
function _agentToolsHtml(tools) {
  if (!tools || !tools.length) return '';
  return `<div class="agent-tools">${tools.map(t => `<span class="agent-tool" title="${escapeHtml(JSON.stringify(t.args || {}))}">${t.ok === false ? '✗' : '✓'} ${escapeHtml(t.name)}</span>`).join('')}</div>`;
}
function _agentUsageHtml(u) {
  if (!u) return '';
  const cached = u.cache_read_input_tokens || 0;
  const inTok = u.input_tokens || 0;
  const out = u.output_tokens || 0;
  return `<div class="agent-usage" title="Tokens used (cached input + new input → output)">${inTok}+${out} tok${cached ? ` · ${cached} cached` : ''}</div>`;
}
function _renderAgentPanel() {
  let panel = document.getElementById('sdc-agent-panel');
  if (!_agentOpen) { if (panel) panel.remove(); return; }
  if (!panel) { panel = document.createElement('div'); panel.id = 'sdc-agent-panel'; document.body.appendChild(panel); }
  const s = _agentStatus;
  const setupHint = s && s.setup ? escapeHtml(s.setup)
    : s && !s.reachable ? 'The assistant isn’t configured. Set <code>ANTHROPIC_API_KEY</code> in the server <code>.env</code> and restart.'
    : '';
  const msgsHtml = _agentMsgs.map(m => {
    if (m.role === 'user') return `<div class="agent-msg agent-user">${escapeHtml(m.text)}</div>`;
    if (m.role === 'error') return `<div class="agent-msg agent-err">⚠ ${escapeHtml(m.text)}</div>`;
    const body = m.text ? _agentMd(m.text) : '';
    return `<div class="agent-msg agent-bot">${body}${_agentToolsHtml(m.tools)}${_agentUsageHtml(m.usage)}</div>`;
  }).join('');
  const startersHtml = (!_agentMsgs.length) ? `<div class="agent-empty"><span class="agent-empty-icon">✦</span><div>Ask about schedules, parts, POs, or cost.</div></div>` : '';
  const modelChip = s && s.model ? `<span class="agent-model-chip">${escapeHtml(s.model)}</span>` : '';
  panel.innerHTML = `
    <div class="agent-head">
      <span class="agent-title">✦ SDC Assistant</span>
      <div class="agent-head-meta"><span class="agent-ro-badge">read-only</span>${modelChip}</div>
      ${_agentMsgs.length ? `<button class="agent-clear" data-act="clear" type="button" title="Clear the conversation">Clear</button>` : ''}
      <button class="agent-close" data-act="close" type="button" title="Close">✕</button>
    </div>
    ${setupHint ? `<div class="agent-setup">${setupHint}</div>` : ''}
    <div class="agent-body" id="agent-body">${startersHtml}${msgsHtml}${_agentBusy ? '<div class="agent-msg agent-bot agent-thinking">Thinking…</div>' : ''}</div>
    <form class="agent-form" id="agent-form">
      <input type="text" id="agent-input" placeholder="Ask a question…" autocomplete="off" ${_agentBusy ? 'disabled' : ''}/>
      <button type="submit" class="btn-primary" ${_agentBusy ? 'disabled' : ''}>Send</button>
    </form>`;
  panel.querySelector('[data-act="close"]').onclick = () => { _agentOpen = false; _renderAgentPanel(); };
  const clr = panel.querySelector('[data-act="clear"]'); if (clr) clr.onclick = () => { _agentMsgs.length = 0; _agentHistory = []; _renderAgentPanel(); };
  panel.querySelectorAll('[data-starter]').forEach(b => b.onclick = () => { const q = b.dataset.starter; const inp = panel.querySelector('#agent-input'); if (inp) inp.value = q; _agentSend(); });
  panel.querySelector('#agent-form').onsubmit = (e) => { e.preventDefault(); _agentSend(); };
  const body = panel.querySelector('#agent-body'); if (body) body.scrollTop = body.scrollHeight;
  const inp = panel.querySelector('#agent-input'); if (inp && !_agentBusy) inp.focus();
}
async function _agentSend() {
  const inp = document.getElementById('agent-input');
  const q = inp ? inp.value.trim() : '';
  if (!q || _agentBusy) return;
  _agentMsgs.push({ role: 'user', text: q });
  _agentBusy = true; _renderAgentPanel();
  try {
    const r = await api.agent.ask(q, _agentContext(), _agentHistory);
    if (Array.isArray(r.history)) _agentHistory = r.history;
    _agentMsgs.push({ role: 'assistant', text: r.answer || '(no answer)', tools: r.tools, usage: r.usage });
  } catch (e) {
    _agentMsgs.push({ role: 'error', text: e.message });
  } finally {
    _agentBusy = false; _renderAgentPanel();
  }
}
if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', _initAgentUI); else _initAgentUI();

// In-app text prompt (replaces the browser-native prompt()). Returns a Promise
// resolving to the trimmed string, or null on cancel. opts.validate(value) may
// return an error string to show inline (keeps the dialog open) or null to pass.
function showPromptDialog(opts = {}) {
  return new Promise(resolve => {
    document.getElementById('app-prompt-dialog')?.remove();
    const overlay = document.createElement('div');
    overlay.id = 'app-prompt-dialog';
    overlay.className = 'modal-overlay app-dialog-overlay';
    overlay.innerHTML = `
      <div class="modal-card app-dialog">
        ${opts.title ? `<div class="modal-head"><h2>${escapeHtml(opts.title)}</h2></div>` : ''}
        <div class="modal-body">
          ${opts.message ? `<div class="app-dialog-message">${_formatDialogMessage(opts.message)}</div>` : ''}
          <input type="text" class="app-dialog-input" autocomplete="off" placeholder="${escapeHtml(opts.placeholder || '')}" />
          <div class="app-dialog-error hidden"></div>
        </div>
        <div class="modal-foot">
          <button type="button" class="btn-ghost" data-action="cancel">${escapeHtml(opts.cancelLabel || 'Cancel')}</button>
          <button type="button" class="btn-primary" data-action="ok">${escapeHtml(opts.okLabel || 'OK')}</button>
        </div>
      </div>`;
    document.body.appendChild(overlay);
    const input = overlay.querySelector('.app-dialog-input');
    if (opts.value) input.value = opts.value;
    const errEl = overlay.querySelector('.app-dialog-error');
    const done = (result) => { document.removeEventListener('keydown', onKey); overlay.remove(); resolve(result); };
    const submit = () => {
      const val = input.value.trim();
      if (opts.validate) {
        const err = opts.validate(val);
        if (err) { errEl.textContent = err; errEl.classList.remove('hidden'); input.focus(); return; }
      }
      done(val || null);
    };
    overlay.querySelector('[data-action="cancel"]').onclick = () => done(null);
    overlay.querySelector('[data-action="ok"]').onclick = submit;
    overlay.addEventListener('click', (e) => { if (e.target === overlay) done(null); });
    const onKey = (e) => {
      if (e.key === 'Escape') { e.preventDefault(); done(null); }
      else if (e.key === 'Enter') { e.preventDefault(); submit(); }
    };
    document.addEventListener('keydown', onKey);
    setTimeout(() => input.focus(), 0);
  });
}

// v4.64: SDC-themed password prompt (replaces the browser-native prompt()).
// Renders an in-app modal with the SDC blue + lime branding, returns a
// Promise that resolves to the entered string or null on cancel.
function showPasswordDialog(opts = {}) {
  const title = opts.title || 'Manager password';
  const message = opts.message || 'Enter the team password to continue.';
  return new Promise(resolve => {
    document.getElementById('app-password-dialog')?.remove();
    const overlay = document.createElement('div');
    overlay.id = 'app-password-dialog';
    overlay.className = 'modal-overlay app-dialog-overlay';
    overlay.innerHTML = `
      <div class="modal-card app-password-card">
        <div class="app-password-head">
          <h2>${escapeHtml(title)}</h2>
        </div>
        <div class="app-password-body">
          <p class="app-password-msg">${escapeHtml(message)}</p>
          <input type="password" class="app-password-input" autocomplete="off" placeholder="Password" />
          <p class="app-password-error hidden">Wrong password.</p>
        </div>
        <div class="app-password-foot">
          <button type="button" class="btn-ghost" data-action="cancel">Cancel</button>
          <button type="button" class="btn-primary" data-action="ok">Unlock</button>
        </div>
      </div>`;
    document.body.appendChild(overlay);
    const input  = overlay.querySelector('.app-password-input');
    const errEl  = overlay.querySelector('.app-password-error');
    const done = (value) => {
      document.removeEventListener('keydown', onKey);
      overlay.remove();
      resolve(value);
    };
    overlay.querySelector('[data-action="cancel"]').onclick = () => done(null);
    overlay.querySelector('[data-action="ok"]').onclick = () => done(input.value);
    overlay.addEventListener('click', (e) => { if (e.target === overlay) done(null); });
    const onKey = (e) => {
      if (e.key === 'Escape') { e.preventDefault(); done(null); }
      else if (e.key === 'Enter') { e.preventDefault(); done(input.value); }
    };
    document.addEventListener('keydown', onKey);
    setTimeout(() => input.focus(), 0);
    // expose for the caller in case they want to surface a "wrong password"
    // shake without reopening — currently unused, kept for future polish.
    overlay._showError = (msg) => {
      errEl.textContent = msg || 'Wrong password.';
      errEl.classList.remove('hidden');
      input.select();
    };
  });
}

function uniqueValues(field) {
  return [...new Set(state.tasks.map(t => t[field]).filter(Boolean))].sort();
}

// Roll up per-project stats for the schedule header pills:
//   - percentComplete: labor-weighted % done = SUM(duration × progress) /
//     SUM(duration) across non-milestone tasks. Returns null when no tasks have
//     durations yet (fresh project).
//   - fatVariance: business-day signed offset between current FAT anchor's
//     start_date and its baseline_start_date. null when no baseline is set.
function computeProjectStats(project, machine) {
  // When `machine` is set (e.g. 'M2'), restrict % complete + FAT to that
  // machine's tasks. Shared (machine=null) tasks always count for the
  // overall project stats. With no machine arg, behaves as before.
  if (!project) return { percentComplete: null, fatVariance: null };
  const allTasks = state.tasks.filter(t => t.project === project);
  // For per-machine view: count only that machine's tasks. For all-machine
  // view, count every project task.
  const tasks = machine
    ? allTasks.filter(t => t.machine === machine)
    : allTasks;
  // % complete (labor-weighted)
  let weighted = 0, total = 0;
  for (const t of tasks) {
    if (t.is_milestone) continue;
    if (inferredAnchorKey(t)) continue;
    const d = Number(t.duration_days);
    if (!d || d <= 0) continue;
    const p = Math.max(0, Math.min(100, Number(t.progress) || 0));
    total += d;
    weighted += d * p;
  }
  const percentComplete = total > 0 ? Math.round(weighted / total) : null;
  // FAT for this machine (or any FAT if no machine specified — fall back
  // to the oldest one project-wide).
  const fatCandidates = allTasks.filter(t => inferredAnchorKey(t) === 'fat');
  let fat = null;
  if (machine) fat = fatCandidates.find(t => t.machine === machine) || null;
  if (!fat && !machine) fat = fatCandidates.length ? fatCandidates.reduce((a, b) => (a.id < b.id ? a : b)) : null;
  // FAT variance — current FAT vs baseline FAT, in business days.
  let fatVariance = null;
  if (fat && fat.baseline_start_date && fat.start_date) {
    if (fat.baseline_start_date === fat.start_date) {
      fatVariance = 0;
    } else {
      const sign = fat.start_date > fat.baseline_start_date ? 1 : -1;
      const days = businessDaysBetween(
        sign > 0 ? fat.baseline_start_date : fat.start_date,
        sign > 0 ? fat.start_date           : fat.baseline_start_date,
      );
      fatVariance = sign * Math.max(0, days - 1);
    }
  }
  return { percentComplete, fatVariance, fat };
}

// Compute how far ahead/behind a task is. Returns business-day integer:
// positive = ahead of plan, negative = behind, 0 = on track / N/A.
//
// Formula: project the task's finish date assuming you keep working at full
// allocation, then compare to the SCHEDULED finish date.
//   remainingDays = (1 − progress/100) × totalDays
//   projectedFinish = today + remainingDays business days
//   drift = scheduledEnd − projectedFinish  (business days)
//
// Examples:
//   • 2-week task, 50% done, today is 3 weeks before scheduled start:
//     remaining = 5 BD, projectedFinish = today + 5 BD, drift ≈ +20d ahead.
//   • Task halfway through window but only 25% done:
//     remaining = 0.75 × 10 = 7.5 ≈ 8 BD, drift goes negative → behind chip.
//
// Skipped (returns 0):
//   • Milestones, anchors, backlog — they have their own status logic.
//   • Completed tasks (progress ≥ 100) — done is done; baseline handles
//     finish variance.
// 0% (not started) tasks: NEVER read "ahead" — a not-started task in the
// future is just not started, not ahead. But once its start has passed with
// no progress, it IS behind, so we show how far behind (full remaining work
// projected from today lands past the scheduled end).
function taskScheduleDelta(task) {
  if (!task || task.is_milestone || !task.start_date || !task.end_date) return 0;
  if (inferredAnchorKey(task)) return 0;
  if (isBacklogTask(task)) return 0;
  // Sales schedules: nothing is sold yet, so there's no commitment to be
  // ahead of or behind — no drift chips anywhere.
  if (isSalesProjectTask(task)) return 0;
  // Effective progress, not stored progress — Backlog rows auto-derive their
  // % from the calendar (stored progress stays 0), which made a long-finished
  // Backlog scream "-40w" while its pill showed a green ✓.
  const actualPct = getEffectiveProgress(task);
  if (actualPct >= 100) return 0;  // Done — no drift chip.
  const totalDays = businessDaysBetween(task.start_date, task.end_date);
  if (!totalDays || totalDays <= 0) return 0;
  const remainingBD = Math.max(0, Math.round((1 - actualPct / 100) * totalDays));
  const todayISO = new Date().toISOString().slice(0, 10);
  // Snap today to a business day (forward) so a Saturday/Sunday "today"
  // doesn't produce odd math.
  const snappedToday = snapToBusinessDay(todayISO, 1);
  // addBusinessDays(date, n) means "n business days FORWARD". When the
  // remaining work is N days, that work SPANS N consecutive business days
  // starting today, so the LAST day of work is today + (N - 1).
  const projectedFinish = remainingBD === 0
    ? snappedToday
    : addBusinessDays(snappedToday, remainingBD - 1);
  if (!projectedFinish) return 0;
  // Sign: projectedFinish BEFORE scheduledEnd → ahead; AFTER → behind.
  let drift = 0;
  if (projectedFinish < task.end_date) {
    const span = businessDaysBetween(projectedFinish, task.end_date) || 0;
    drift = Math.max(0, span - 1); // span is inclusive on both ends
  } else if (projectedFinish > task.end_date) {
    const span = businessDaysBetween(task.end_date, projectedFinish) || 0;
    drift = -Math.max(0, span - 1);
  }
  // Not started: only ever flag BEHIND, never ahead.
  if (actualPct <= 0 && drift >= 0) return 0;
  return drift;
}

function applyFilters(tasks, opts = {}) {
  const { search, project, phase, assignee, quick, projectsSubset, machinesSubset } = state.filters;
  // ignoreMachineSubset: when computing canonical line numbers, we want
  // the order to stay stable across "All / M1 / M2" pill clicks — so
  // M2's Builder-1 keeps its overall line number even when filtered
  // down to just M2's rows. Caller passes { ignoreMachineSubset: true }
  // for that path.
  const skipMachineSubset = !!opts.ignoreMachineSubset;
  const q = (search || '').trim().toLowerCase();
  const qf = quick || {};
  const personal = isPersonalMode();
  const subset = Array.isArray(projectsSubset) ? projectsSubset : [];
  // Subset only applies on the All-projects view (no single-project filter
  // active). Empty subset = no filter; non-empty = whitelist.
  const useSubset = !project && subset.length > 0;
  const subsetSet = useSubset ? new Set(subset) : null;
  // Machine subset: only meaningful inside a SINGLE project tab. Non-empty
  // means "show ONLY tasks belonging to these machines" — shared
  // (machine=null) tasks are hidden too. The user wants per-machine views
  // to show JUST that machine's work; shared design / procurement /
  // anchors are only visible in the "All" view. Empty subset = no
  // filter (All machines + shared).
  // Strip any subset entries that don't actually exist as machines in the
  // current project — otherwise the strict filter would hide every row
  // when a previously-saved machine has since been deleted.
  let machSubset = Array.isArray(machinesSubset) ? machinesSubset : [];
  if (project && machSubset.length > 0) {
    const existing = new Set(tasks.filter(t => t.project === project && t.machine).map(t => t.machine));
    const cleaned = machSubset.filter(m => existing.has(m));
    if (cleaned.length !== machSubset.length) {
      machSubset = cleaned;
      // Persist the cleanup so reloads don't keep re-loading the stale data.
      state.filters.machinesSubset = machSubset;
      try {
        const key = 'sdcMachinesSubset:' + project;
        if (machSubset.length === 0) localStorage.removeItem(key);
        else localStorage.setItem(key, JSON.stringify(machSubset));
      } catch (_) {}
    }
  }
  const useMachineFilter = !!project && machSubset.length > 0 && !skipMachineSubset;
  // In clone mode the user is BUILDING the new machine off the source —
  // they need to see the shared rows (design, anchors) so they can
  // reference them as predecessors. Soften the strict rule during clone.
  const cloneSoftenFilter = !!state.cloneMode;
  const machineSet = useMachineFilter ? new Set(machSubset) : null;
  return tasks.filter(t => {
    if (project && t.project !== project) return false;
    if (useSubset && !subsetSet.has(t.project)) return false;
    // Machine subset filter:
    //   - In clone mode: pass shared (machine=null) OR in-subset.
    //   - Otherwise: STRICT — only in-subset rows pass.
    if (useMachineFilter) {
      if (t.machine == null) {
        if (!cloneSoftenFilter) return false;
      } else if (!machineSet.has(t.machine)) {
        return false;
      }
    }
    if (phase && t.phase !== phase) return false;
    // Personal mode + All Projects view: hide TEMPLATE tasks and
    // SALES-workspace tasks. Templates are scaffolding for cloning into
    // real projects, not work people are doing. Sales projects are
    // pre-quote, no real allocation yet. Both are noise on aggregate views.
    // (If the user explicitly opens a template or Sales project tab,
    // we DO show its tasks — that branch hits the `project` check above.)
    if (!project && t.project &&
        (isTemplateProject(t.project) || projectWorkspace(t.project) === 'Sales')) {
      return false;
    }
    // Personal mode: hide anchor milestones entirely — this view is "one
    // person across many projects", so per-project anchors like Receipt of
    // PO / FAT / Ship Machine are noise.
    if (personal && inferredAnchorKey(t)) return false;
    // Strict assignee filter. The personal view only shows tasks/actions
    // DIRECTLY assigned to the signed-in person. If a task gets reassigned
    // away from them (e.g. to a placeholder), it drops off their view
    // immediately on next render — no stale leftovers.
    if (assignee && t.assignee !== assignee && !inferredAnchorKey(t)) {
      return false;
    }
    if (q) {
      const hay = `${t.name||''} ${t.notes||''} ${t.assignee||''} ${t.project||''} ${t.phase||''}`.toLowerCase();
      if (!hay.includes(q)) return false;
    }
    // Completed handling — two independent controls:
    //   • Filter "Show completed" (popover): when ON, show ONLY completed
    //     items. When OFF, no completion filtering — everything passes.
    //   • View toggle "Hide completed" (View menu): when ON, hides completed
    //     items entirely. Independent of the filter.
    const isDone = (t.progress || 0) >= 100;
    if (qf.showCompleted && !isDone) return false;
    if (state.scheduleView?.hideCompleted && isDone) return false;
    // "Milestones only" filter — straightforward.
    if (qf.milestones && !t.is_milestone) return false;

    // v5.9: milestones and anchors are now subject to the SAME quick-filter
    // logic as tasks. Previously they were unconditionally returned true,
    // which meant clicking "Ahead of schedule" still showed every milestone
    // regardless of whether it was actually ahead. User wanted milestones
    // to be filtered like tasks ("ahead = checked off but not due yet",
    // "behind = past due and not done").
    if (t.is_milestone) {
      const today = new Date().toISOString().slice(0, 10);
      const mDone = (t.progress || 0) >= 100;
      const mPastDue = t.end_date && t.end_date < today;
      const mFutureDue = t.end_date && t.end_date > today;
      if (qf.assigned && !t.assignee) return false;
      // Behind = past due AND not done.
      if (qf.behind && !(!mDone && mPastDue)) return false;
      // Ahead = done AND not yet due (completed before scheduled date).
      if (qf.ahead && !(mDone && mFutureDue)) return false;
      // Over-allocated doesn't apply to milestones (no duration / no work hours).
      if (qf.overallocated) return false;
      return true;
    }

    // Regular tasks.
    if (qf.assigned && !t.assignee) return false;
    if (qf.behind && taskScheduleDelta(t) >= 0) return false;
    if (qf.ahead  && taskScheduleDelta(t) <= 0) return false;
    if (qf.overallocated) {
      if (!state.overAllocatedTaskIds || !state.overAllocatedTaskIds.has(t.id)) return false;
    }
    return true;
  });
}

function phaseChip(phaseKey) {
  if (!phaseKey) return '<span class="phase-chip" style="background:#f1f5f9;color:#64748b">—</span>';
  const p = PHASE_BY_KEY[phaseKey];
  if (!p) return `<span class="phase-chip" style="background:#f1f5f9;color:#64748b">${escapeHtml(phaseKey)}</span>`;
  return `<span class="phase-chip" style="background:${p.color};color:${p.text}">${escapeHtml(p.label)}</span>`;
}

// ---------- Table rendering ----------
function cellHtml(t, key) {
  const cls = colClass(key);
  switch (key) {
    case 'line':     return `<td class="${cls}" data-col="line"><span class="row-drag" draggable="true" title="Drag to move">⋮⋮</span><span class="line-num"></span></td>`;
    case 'name': {
      // Task column layout:
      //   LEFT:  [✓] name [drift chip]
      //   RIGHT: [% complete pill] for duration tasks, [checkbox] for milestones
      //          (NOTHING for Backlog — it's a duration-only spine task)
      const done = (t.progress || 0) >= 100;
      const isAnchor = !!inferredAnchorKey(t);
      const drift = taskScheduleDelta(t);
      let driftChip = '';
      if (drift !== 0 && !t.is_milestone && !isAnchor && !done) {
        const ahead = drift > 0;
        // Half-week snap, same formula as the Gantt drift chip — never days.
        const driftWks = (Math.round((Math.abs(drift) / 5) * 2) / 2) || 0.5;
        driftChip = ` <span class="name-drift-chip ${ahead ? 'ahead' : 'behind'}">${ahead ? '+' : '−'}${driftWks}w</span>`;
      }
      // Backlog rows derive % from today's position between start/end (it's
      // not real work, just calendar ramp). All other rows read the stored
      // t.progress. Helper handles both cases.
      const pct       = getEffectiveProgress(t);
      const isBacklog = isBacklogRow(t);
      let rightWidget = '';
      if (!t.is_milestone && !isAnchor) {
        // Duration task: pill renders as a small PROGRESS BAR. The fill width
        // tracks the percent (0–100%), color tracks the schedule status:
        //   - is-zero    (0%):      empty pill outline, "0%" text in slate
        //   - is-behind  (1–99% behind): red fill at pct% width, black text
        //   - is-ontrack (1–99% on/ahead): green fill at pct% width, black text
        //   - is-done    (100%):    full green fill, white ✓ text
        // Was a flat solid-colored pill — that felt heavy (especially the
        // dark green 100% state). The bar version visually answers "how far
        // along is this?" without you having to read the number.
        let pctClass = 'is-zero';
        let pctText = `${pct}%`;
        if (pct >= 100) {
          pctClass = 'is-done';
          pctText = '✓';
        } else if (pct > 0) {
          pctClass = drift < 0 ? 'is-behind' : 'is-ontrack';
        }
        // Fill width: clamp to 0–100. At 100% the .is-done rules cover the
        // whole pill via CSS anyway, but we still set width here so 99 → 100
        // transitions render correctly.
        const fillW = Math.max(0, Math.min(100, pct));
        // Backlog has its % auto-derived from the calendar — disable the
        // click-to-edit data-attrs so we don't enter inline-edit mode, and
        // update the tooltip so it's clear why.
        const pillDataAttrs = isBacklog
          ? `title="Backlog auto-tracks today's date between start and end — change duration instead to adjust"`
          : `data-edit-pill data-edit-col="progress" data-task-id="${t.id}" title="% complete — click to edit"`;
        const autoCls = isBacklog ? ' is-auto' : '';
        rightWidget = `<span class="name-edit-pill name-pct-pill ${pctClass}${autoCls}" ${pillDataAttrs}>`
          + `<span class="name-pct-fill" style="width:${fillW}%"></span>`
          + `<span class="name-pct-text">${pctText}</span>`
          + `</span>`;
      } else {
        // Milestones / anchors get a click-to-toggle checkbox. Progress is
        // binary (0 or 100). Anchors already render via anchorRowHtml with a
        // green chip, but non-anchor milestones (Mech 2 Release, BOM Review,
        // Order Long Lead, etc.) need a way to mark them complete.
        rightWidget = `<button type="button" class="name-milestone-check ${done ? 'is-done' : ''}" data-toggle-milestone data-task-id="${t.id}" title="${done ? 'Mark not complete' : 'Mark complete'}">${done ? '✓' : ''}</button>`;
      }
      const classes = [cls];
      if (rightWidget) classes.push('has-pills');
      // v4.39: `has-meta` indicates the row will render the alloc + dash +
      // dur spans (regular tasks only).
      const hasMeta = !t.is_milestone && !isAnchor;
      if (hasMeta) classes.push('has-meta');
      // v4.30: Single-line PLAIN-TEXT layout. No more stacked meta row, no
      // more pill-styled allocation/duration. Just inline text:
      //     85%  Task Name - 1w           [% complete pill]
      //     \_/  \_______/ \__/            \_pinned right_/
      //     pre   bold name  dur-post
      //
      // The pre-allocation text is hidden via .hide-alloc-pre on body
      // (controlled by the α icon in the View pill). Both alloc + dur are
      // still click-to-edit via data-edit-pill — they look like plain text
      // but pick up an underline on hover. Skipped for milestones / anchors /
      // backlog (no meaningful allocation × duration there).
      let allocPre = '';
      let dashSep = '';
      let durEl = '';
      if (!t.is_milestone && !isAnchor) {
        const allocVal = t.allocation == null ? null : Number(t.allocation);
        const durDays  = Number(t.duration_days) || 0;
        // Half-week snap — Dan's rule applies EVERYWHERE: weeks values
        // round to the nearest 0.5, never 0.1 or 0.2 increments.
        // Nothing nonzero reads below half a week — a 1-day task is "0.5W",
        // never a blank "—W" (round-to-zero was hiding real durations).
        const wks = durDays > 0 ? Math.max(0.5, Math.round((durDays / 5) * 2) / 2) : 0;
        const allocText = allocVal != null && allocVal > 0 ? `${allocVal}%` : '—%';
        // v4.43: uppercase W in duration text per user request — "10W" not "10w".
        const wksText   = wks > 0 ? `${wks}W` : '—W';
        // v4.36: Sales-workspace tasks NO LONGER auto-hide allocation in
        // the Task column meta. The α icon in the View pill is now the
        // single authoritative control for alloc visibility — turn it off
        // when presenting to a customer / sales rep (hides alloc across
        // ALL projects regardless of workspace), turn it on otherwise.
        // Earlier (v4.22) Sales tasks hid alloc unconditionally even with
        // α on, which made the toggle look broken when the user was
        // viewing the SDC_Sales_Template.
        allocPre = `<span class="name-cell-alloc-pre" data-edit-pill data-edit-col="allocation" data-task-id="${t.id}" title="Allocation — click to edit">${allocText}</span>`;
        dashSep  = `<span class="name-cell-dash">–</span>`;
        // v4.43: link badge moved BEFORE the duration value so the dur
        // value stays right-aligned at the column's right edge (consistent
        // across all rows whether linked or not). Layout reads as
        // "🔗24 10W" — badge on the left, duration on the right. Badge
        // is still inside .name-cell-dur with pointer-events: none so
        // clicks pass through to the dur for re-editing.
        let linkBadge = '';
        if (t.duration_link_task_id) {
          const earlyLine = lineByTaskId[t.duration_link_task_id];
          const earlyText = earlyLine != null ? `🔗${earlyLine}` : '🔗?';
          linkBadge = `<span class="name-cell-dur-link" data-link-target-id="${t.duration_link_task_id}">${earlyText}</span> `;
        }
        durEl = `<span class="name-cell-dur" data-edit-pill data-edit-col="duration" data-task-id="${t.id}" title="Duration — click to edit (e.g. 5d, 2w, or = then click another row to link)">${linkBadge}${wksText}</span>`;
      } else if (t.is_milestone && !isAnchor) {
        // Milestones show no duration, but the slot stays CLICKABLE so an
        // accidental 0-duration can be undone — click it, type "2w", and the
        // row is a task again. Invisible until the row is hovered (same
        // trick as the milestone ✓ checkbox).
        durEl = `<span class="name-cell-dur name-cell-dur-ghost" data-edit-pill data-edit-col="duration" data-task-id="${t.id}" title="Duration — click to set (e.g. 2w) and turn this milestone back into a task">—W</span>`;
      }
      // v4.39: dropped the .name-cell-row flex wrapper. alloc, dash, and
      // dur are now ABSOLUTE-POSITIONED inside the TD (deterministic offsets
      // from the column's left/right edges), and the task name flows in
      // the TD's content area between them. CSS controls the TD's
      // padding-left / padding-right so the name doesn't overlap the
      // absolutely-placed siblings. This guarantees that body alloc lines
      // up pixel-for-pixel with the header ALOC label, since both use the
      // same absolute coordinates from the cell edge.
      //
      // Multi-machine: any row tagged with a machine gets a small pill
      // before its name (e.g. "M2" before "Builder 1") so the user can
      // tell duplicates apart at a glance. Suppressed when the project
      // has only one machine (no point) OR when the M view-pill is off.
      // Color comes from getMachineColor (user-pickable, SDC palette).
      let machineChip = '';
      if (t.machine && shouldShowMachineVisuals()) {
        const c = getMachineColor(t.project, t.machine);
        const style = `background:${c.hex};color:${c.text};border-color:${c.hex};`;
        machineChip = `<span class="name-machine-chip" data-machine="${escapeHtml(t.machine)}" style="${style}">${escapeHtml(t.machine)}</span> `;
      }
      return `<td class="${classes.join(' ')}" data-col="name">${allocPre}${dashSep}<span class="name-cell-main">${machineChip}${escapeHtml(t.name)}${driftChip}</span>${durEl}${rightWidget ? `<span class="name-cell-pills">${rightWidget}</span>` : ''}</td>`;
    }
    case 'assignee': {
      // When this task is over-allocated for its assignee — i.e. its priority pushes the
      // running daily total over 100% somewhere in its span — flag the cell so the user
      // sees in the Schedule view that this person can't actually accomplish all their
      // higher-priority work plus this one.
      const over = state.overAllocatedTaskIds && state.overAllocatedTaskIds.has(t.id);
      const ph = isPlaceholder(t.assignee);
      const classes = [cls];
      if (over) classes.push('over-allocated');
      if (ph)   classes.push('placeholder-assignee');
      const title = over
        ? 'title="Over-allocated — earlier-priority tasks already fill this person\'s capacity"'
        : (ph ? 'title="Placeholder — replace with a real team member when staffing this task"' : '');
      return `<td class="${classes.join(' ')}" data-col="assignee" ${title}>${escapeHtml(t.assignee || '')}</td>`;
    }
    case 'start':    return `<td class="${cls}" data-col="start">${fmtDate(t.start_date)}</td>`;
    case 'finish':   return `<td class="${cls}" data-col="finish">${fmtDate(t.end_date)}</td>`;
    case 'project':  return `<td class="${cls}" data-col="project" title="${escapeHtml(t.project || '')}">${escapeHtml(t.project || '')}</td>`;
    case 'completed':
      // Auto-stamped by the server when progress hits 100, cleared when it
      // drops below. User-editable in case the actual completion date
      // differs from when the checkbox was clicked.
      return `<td class="${cls}" data-col="completed">${fmtDate(t.completed_on)}</td>`;
    case 'duration': {
      // v5.11: no backlog special-case. Every row uses the same path —
      // click cell, type "3w" / "5d" / etc., Enter. The hover pencil
      // signals "editable" on every row.
      let label = durationLabel(t);
      if (!label) label = '—';
      else if (label === '0') label = t.is_milestone ? '0d' : '0';
      return `<td class="${cls} is-editable-duration" data-col="duration" title="Click to edit — e.g. 3w, 5d, 2w">${escapeHtml(label)}<span class="duration-edit-hint">✎</span></td>`;
    }
    case 'pred':     return `<td class="${cls}" data-col="pred"></td>`; /* filled in by updateLineNumbers */
    case 'progress': {
      const p = t.progress || 0;
      return `<td class="${cls}" data-col="progress"><span class="progress-bar"><span style="width:${p}%"></span></span> ${p}%</td>`;
    }
    case 'allocation': {
      // Default to 100 for tasks predating this column. Milestones shouldn't show an
      // allocation since they don't consume time — render a dash so they read as N/A.
      const a = t.is_milestone ? '—' : (t.allocation == null ? 90 : t.allocation);
      return `<td class="${cls}" data-col="allocation">${a === '—' ? '—' : `${a}%`}</td>`;
    }
    case 'priority': {
      // Per-assignee priority. Value displayed verbatim — the resources view is the
      // primary editor (drag/click pills there); this column is mostly for visibility.
      const p = t.priority == null ? '—' : t.priority;
      return `<td class="${cls}" data-col="priority">${p}</td>`;
    }
    case 'notes': {
      // Free-text comments. Truncated visually via CSS so long notes don't
      // blow up the row; full content shown on hover via title attribute.
      const text = t.notes || '';
      const safe = escapeHtml(text);
      return `<td class="${cls}" data-col="notes" title="${safe}">${safe}</td>`;
    }
  }
  return `<td data-col="${key}"></td>`;
}

// Pick the color "key" for a task row based on its position in the hierarchy. Sub-dept
// wins (mech/controls/general/build/wire); else the department's combined key
// (eng-combined / shop-combined / procurement) drives the color.
function rowColorKey(task) {
  // Sub-department wins. The sub-depts named 'engineering' / 'shop' (section 50
  // INSTALL has them) share the combined eng/shop palette so they read like
  // section 40's dept-only engineering/shop.
  if (task.sub_department) {
    if (task.sub_department === 'engineering') return 'eng-combined';
    if (task.sub_department === 'shop')        return 'shop-combined';
    return task.sub_department; // mech, controls, general, build, wire
  }
  // Department-level — Engineering and Shop are the combined blend palette.
  // Teardown (section 50, shop-only) reuses the shop palette.
  if (task.department === 'engineering') return 'eng-combined';
  if (task.department === 'shop')        return 'shop-combined';
  if (task.department === 'teardown')    return 'shop-combined';
  if (task.department === 'procurement') return 'procurement';
  // Fallback for rows with no department / sub_department (e.g. above-section-10
  // rows the user added manually). Keeps the bar fill + label color consistent
  // with every other bar instead of falling through to frappe-gantt's default.
  return 'neutral';
}

function rowHtml(t, depth = 0) {
  const order = state.layout.columnOrder;
  const cells = order.map(k => cellHtml(t, k)).join('');
  const colorKey = rowColorKey(t);
  // The left-edge stripe on the name column uses the HIERARCHY color (mech blue,
  // controls green, build orange, wire yellow, etc.) so every task in a section
  // gets the right stripe — regardless of whether its phase field is set. Falls
  // back to phase color, then to transparent.
  const hier = HIERARCHY_BAR_COLORS && HIERARCHY_BAR_COLORS[colorKey];
  const stripe = (hier && hier.fill) || PHASE_BY_KEY[t.phase]?.color || 'transparent';
  // Row itself is NOT draggable — only the .row-drag handle in the line column is, so the
  // rest of the row is free for click-drag horizontal panning of the grid panel.
  // Non-anchor milestones (e.g. Mech 2 Release, BOM Review) also get the "done"
  // treatment so all 0-duration rows read consistently — green check on the row
  // chip + a diamond fill that matches anchors. Anchors take their own path via
  // anchorRowHtml above; this is for the regular bucket-resident milestones.
  const milestoneDone = t.is_milestone && (t.progress || 0) >= 100 ? ' milestone-done' : '';
  // Completed DURATION tasks (non-milestone, progress >= 100) get
  // a task-done class so CSS can paint the row with the lime outline +
  // diagonal hash pattern.
  const taskDone = !t.is_milestone && (t.progress || 0) >= 100 ? ' task-done' : '';
  // v4.46: action items get is-action so CSS can italicize the task name
  // and (in Combined view) tint the row subtly to differentiate from
  // scheduled work.
  const actionCls = t.is_action ? ' is-action' : '';
  // v4.49: actions past their due date but not marked complete paint
  // RED in both the grid row and (for milestone-style actions) the Gantt
  // diamond. Limited to actions for now — regular scheduled work has its
  // own drift chip system. Today is computed once at render time so we
  // don't re-evaluate per row.
  const todayISO = new Date().toISOString().slice(0, 10);
  const overdueCls = (t.is_action && (t.progress || 0) < 100 && t.end_date && t.end_date < todayISO) ? ' is-overdue' : '';
  return `<tr data-id="${t.id}" class="depth-${depth} ${t.is_milestone ? 'is-milestone' : ''}${milestoneDone}${taskDone}${actionCls}${overdueCls}" data-color-key="${colorKey}" style="--row-phase-color:${stripe}">${cells}</tr>`;
}

function headerRowHtml(level, label, path, collapsed, dataAttrs = {}, hours = null) {
  const cols = state.layout.columnOrder.length;
  const caret = collapsed ? '▸' : '▾';
  const attrs = Object.entries(dataAttrs)
    .map(([k, v]) => ` data-${k}="${escapeHtml(String(v))}"`).join('');
  // Quoted-vs-scheduled hours overlay (H view-pill). The overlay is positioned
  // over the Task column by positionDeptHours() so SCHED lands under DUR and
  // QUOTED under %COM — matching the header sub-labels. Quoted shows "—" when
  // the project has no saved estimate.
  let hoursHtml = '';
  if (hours) {
    const q = hours.quoted == null ? '—' : `${hours.quoted}h`;
    // Variance vs the quote (only when there's a quoted figure to compare to).
    // Over scheduled = scheduled hours exceed quoted (you've planned more labor
    // than was sold); under = scheduled is below quoted. Sits over the
    // Assigned To column, positioned by positionDeptHours().
    let varHtml = '';
    if (hours.quoted != null) {
      const diff = hours.sched - hours.quoted;
      if (diff === 0) {
        varHtml = `<span class="dept-hours-var is-on">On quote</span>`;
      } else {
        const over = diff > 0;
        varHtml = `<span class="dept-hours-var ${over ? 'is-over' : 'is-under'}">`
          + `${over ? 'Over scheduled' : 'Under scheduled'} ${Math.abs(diff)}h</span>`;
      }
    }
    hoursHtml =
      `<span class="dept-hours" aria-hidden="true">` +
        `<span class="dept-hours-sched" title="Scheduled hours (durations × allocation)">${hours.sched}h</span>` +
        `<span class="dept-hours-quoted" title="Quoted hours (from the estimate)">${q}</span>` +
      `</span>` + varHtml;
  }
  // v4.29: wrap the leading "NN " section number (e.g. "10 DESIGN & BUILD")
  // in its own <span> so customer-view CSS can hide just the number portion.
  // SDC team uses the section numbers internally; customers don't care about
  // "10 / 40 / 50" — they just see the section name.
  const labelStr = String(label || '');
  const m = labelStr.match(/^(\d+\s+)(.*)$/);
  const labelHtml = m
    ? `<span class="group-label-num">${escapeHtml(m[1])}</span>${escapeHtml(m[2])}`
    : escapeHtml(labelStr);
  return `
    <tr class="group-header level-${level} ${collapsed ? 'collapsed' : ''}${hours ? ' has-dept-hours' : ''}" data-path="${escapeHtml(path)}"${attrs}>
      <td colspan="${cols}">
        <span class="group-caret">${caret}</span>
        <span class="group-label">${labelHtml}</span>
        ${hoursHtml}
      </td>
    </tr>`;
}

function renderTable() {
  const tbody = document.getElementById('tasks-tbody');
  if (!tbody) return;
  let filtered = applyFilters(state.tasks);
  // v4.46: Actions mode filter. Default 'schedule' hides action items
  // entirely; 'actions' shows ONLY actions; 'combined' shows both.
  // Anchor rows (Receipt of PO, FAT, Ship Machine, etc.) are always kept
  // because they're project-spine markers, not work items.
  const am = state.scheduleView?.actionsMode || 'schedule';
  if (am === 'schedule') {
    filtered = filtered.filter(t => !t.is_action || inferredAnchorKey(t));
  } else if (am === 'actions') {
    filtered = filtered.filter(t => t.is_action || inferredAnchorKey(t));
  }
  // Only-critical mode: restrict the visible set to tasks on the critical-path
  // chain. Anchor milestones are always kept (Receipt of PO / FAT / Ship Machine)
  // since they're the spine markers — Ship Machine sits outside the path but is
  // still useful context. If the user wants ship-machine hidden too, they can
  // collapse the section.
  if (state.scheduleView?.criticalOnly && state.scheduleView?.criticalPath) {
    const crit = computeCriticalPath();
    filtered = filtered.filter(t => crit.has(String(t.id)) || inferredAnchorKey(t));
  }
  if (state._exportOnlyIds) {
    filtered = filtered.filter(t => inferredAnchorKey(t) || state._exportOnlyIds.has(t.id));
  }
  const empty = document.getElementById('empty-state');

  if (filtered.length === 0) {
    tbody.innerHTML = '';
    if (empty) {
      empty.classList.remove('hidden');
      empty.textContent = state.tasks.length === 0
        ? 'No tasks yet. Click + New Task to add one.'
        : 'No tasks match the current filters.';
    }
    return;
  }
  if (empty) empty.classList.add('hidden');

  // Bucket tasks by hierarchy path. Most anchor milestones render as fixed rows
  // outside the section walk (Receipt of PO above 10, FAT between 40/50, Ship
  // Machine between teardown and install). Mech 1 Release and Machine Power-Up
  // are the exceptions — they live INSIDE the hierarchy buckets (10 → Mech Eng
  // and 10 → Shop → Wire respectively) so they flow with their team's work.
  // Anchor styling is layered on at render time via renderTaskRow's branching.
  const INLINE_ANCHORS = new Set(['mech_release_1', 'machine_power_up']);
  const buckets = {};
  for (const t of filtered) {
    const k = inferredAnchorKey(t);
    if (k && !INLINE_ANCHORS.has(k)) continue;
    const path = groupPath(t.phase_group, t.department, t.sub_department);
    (buckets[path] ||= []).push(t);
  }
  // Sort each bucket — by start_date when the user has flipped the "By date" toggle,
  // otherwise by their manual sort_order so drag-reordering sticks. In BOTH cases,
  // action items (is_action = 1) sort to the BOTTOM of their bucket so scheduled
  // work appears first and actions read as "extras tucked under their section."
  // v4.46 added the is_action secondary sort.
  const sortBucket = (arr) => {
    if (state.scheduleView.sortByStart) {
      arr.sort((a, b) =>
        ((a.is_action ? 1 : 0) - (b.is_action ? 1 : 0))
        || (a.start_date || '￿').localeCompare(b.start_date || '￿')
        || (a.sort_order || 0) - (b.sort_order || 0));
    } else {
      arr.sort((a, b) =>
        ((a.is_action ? 1 : 0) - (b.is_action ? 1 : 0))
        || (a.sort_order || 0) - (b.sort_order || 0));
    }
  };
  for (const k in buckets) sortBucket(buckets[k]);

  // Flatten mode collects every task under each section into one ordered list and
  // skips dept / sub-dept walks. Built once so it's cheap to look up per section.
  // Same INLINE_ANCHORS rule as the bucketed walk: Mech 1 Release and Machine
  // Power-Up flow into their section's flat list; the other anchors render
  // outside the walk regardless of what their stored phase_group says.
  // Personal mode (signed in as a specific person on Actions tab) forces
  // flatten — there's no point in showing dept / sub-dept headers when the
  // whole view is one person who typically lives in one department.
  const flattenEffective = state.scheduleView.flatten || isPersonalMode();
  const flatBySection = {};
  if (flattenEffective) {
    for (const t of filtered) {
      const k = inferredAnchorKey(t);
      if (k && !INLINE_ANCHORS.has(k)) continue;
      if (!t.phase_group) continue;
      (flatBySection[t.phase_group] ||= []).push(t);
    }
    for (const k in flatBySection) sortBucket(flatBySection[k]);
  }

  // Per-department QUOTED vs SCHEDULED hours overlay (H view-pill). Shows on
  // each dept / sub-dept subheader so you can sanity-check "do I have the right
  // amount of work scheduled vs what we quoted" without opening Quote vs
  // Schedule. Only meaningful for a single active project whose estimate is
  // loaded — skipped on the All-projects tab. Scheduled = Σ duration×8×alloc
  // over the dept's tasks (matches the durations shown in the rows — NO people
  // multiplier); quoted = Σ of the dept's quote buckets.
  const _svHours = state.scheduleView || {};
  const hoursProject = _svHours.showDeptHours ? (state.filters.project || '') : '';
  let quotedMap = null;
  if (hoursProject) {
    const q = state.quoteCache ? state.quoteCache[hoursProject] : undefined;
    if (q === undefined) ensureProjectQuote(hoursProject);   // async — re-renders when it lands
    else if (q && q.hours_breakdown) quotedMap = deriveQuotedBuckets(q);
  }
  const deptHoursFor = (taskList) => {
    if (!hoursProject || !taskList || !taskList.length) return null;
    let sched = 0; const bset = new Set();
    for (const t of taskList) {
      if (t.is_milestone || t.anchor_key || isBacklogTask(t)) continue;
      sched += (Number(t.duration_days) || 0) * 8 * ((Number(t.allocation) || 90) / 100);
      const k = taskHoursBucket(t); if (k) bset.add(k);
    }
    let quoted = null;
    if (quotedMap) { quoted = 0; for (const k of bset) quoted += quotedMap[k] || 0; }
    if (sched <= 0 && !(quoted > 0)) return null;
    // Round to the nearest 5 — this is a sanity-check readout, not an invoice;
    // 259 → 260, 401 → 400. (Variance is then derived from these rounded
    // values so "Over/Under scheduled" also lands on a multiple of 5.)
    const r5 = (n) => Math.round(n / 5) * 5;
    return { sched: r5(sched), quoted: quoted == null ? null : r5(quoted) };
  };

  let html = '';
  // Anchor milestones (Receipt of PO, FAT, Ship Machine) live OUTSIDE the regular
  // hierarchy as project-spine markers. Receipt of PO sits above section 10; FAT
  // sits between sections 40 and 50; Ship Machine sits between TEARDOWN and INSTALL
  // inside section 50. EXACTLY ONE of each is rendered (oldest wins on duplicates).
  // The row stays plain white — only the task NAME gets the configured anchor color
  // as a small chip, so the marker stands out without flooding the row.
  const anchorRowHtml = (t, opts = {}) => {
    const order = state.layout.columnOrder;
    const isDone = (t.progress || 0) >= 100;
    const isBacklog = !!opts.backlog;
    // v4.84: backlog is "expired" once its end_date is in the past — the
    // calendar time it represented has elapsed. We don't check it off; we
    // just signal with a lime-green border that the backlog window is over.
    const todayMs = (() => { const d = new Date(); d.setHours(0,0,0,0); return d.getTime(); })();
    const backlogExpired = isBacklog && t.end_date && new Date(t.end_date).getTime() < todayMs;
    const cells = order.map(k => {
      if (k === 'name') {
        // Click-to-toggle check pinned to the RIGHT of the name cell,
        // same slot regular milestones use (via name-cell-pills) so
        // every checkable row reads consistently. Backlog rows skip the
        // check — they're a duration spine, not a checkable event.
        const checkBtn = !isBacklog
          ? `<span class="name-cell-pills"><button type="button" class="name-milestone-check ${isDone ? 'is-done' : ''}" data-toggle-milestone data-task-id="${t.id}" title="${isDone ? 'Mark not complete' : 'Mark complete'}">${isDone ? '✓' : ''}</button></span>`
          : '';
        const chipCls = `anchor-name-chip${isBacklog ? ' backlog-chip' : ''}${backlogExpired ? ' is-expired' : ''}`;
        // Multi-machine: prepend the M1/M2/M3 pill on anchor rows too, so
        // M2.FAT visually reads as "M2" before the green FAT chip. Hidden
        // on single-machine projects + when the M view-pill is off.
        let machineChip = '';
        if (t.machine && shouldShowMachineVisuals()) {
          const c = getMachineColor(t.project, t.machine);
          machineChip = `<span class="name-machine-chip" data-machine="${escapeHtml(t.machine)}" style="background:${c.hex};color:${c.text};border-color:${c.hex};">${escapeHtml(t.machine)}</span> `;
        }
        const tdCls = checkBtn ? 'has-pills' : '';
        return `<td data-col="name" class="${tdCls}">${machineChip}<span class="${chipCls}">${escapeHtml(t.name || '')}</span>${checkBtn}</td>`;
      }
      return cellHtml(t, k);
    }).join('');
    // groupTop: black border ABOVE the row (default true for unrelated anchors)
    // groupBottom: black border BELOW the row (default true for unrelated anchors)
    // When PO + Backlog are stacked, PO gets groupTop only and Backlog gets
    // groupBottom only — they read as one continuous spine block.
    const groupTop    = opts.groupTop    !== false;
    const groupBottom = opts.groupBottom !== false;
    const cls = `depth-1 anchor-row${isDone && !isBacklog ? ' is-done' : ''}${isBacklog ? ' backlog-row' : ''}${!groupTop ? ' no-top-border' : ''}${!groupBottom ? ' no-bottom-border' : ''}`;
    return `<tr data-id="${t.id}" class="${cls}" data-anchor-key="${escapeHtml(inferredAnchorKey(t) || '')}">${cells}</tr>`;
  };
  const candidates = filtered
    .map(t => [t, inferredAnchorKey(t)])
    .filter(([, k]) => !!k);
  const pickOldest = (key) => {
    const list = candidates.filter(([, k]) => k === key).map(([t]) => t);
    if (list.length === 0) return null;
    return list.reduce((a, b) => (a.id < b.id ? a : b));
  };
  // pickAll: in multi-machine projects each machine has its own FAT /
  // Ship Machine anchor (Power-Up flows through Section 10's inline
  // walk). Return all of them sorted shared-first then by machine name,
  // so the grid renders M1.FAT, M2.FAT, … side by side at the spine
  // slot. Receipt of PO stays shared so the single-pick is right.
  const pickAll = (key) => {
    const list = candidates.filter(([, k]) => k === key).map(([t]) => t);
    return list.sort((a, b) => {
      const ma = a.machine || '';
      const mb = b.machine || '';
      if (ma === mb) return a.id - b.id;
      if (!ma) return -1;
      if (!mb) return  1;
      return ma.localeCompare(mb, undefined, { numeric: true });
    });
  };
  const receiptAnchor = pickOldest('receipt_of_po');
  const fatAnchors    = pickAll('fat');
  const shipAnchors   = pickAll('ship_machine');
  const satAnchors    = pickAll('sat');
  // Every non-anchor task with no phase_group — the legacy "above section 10"
  // zone (Backlog, right-click additions). These now render INSIDE the
  // 00 KICKOFF section along with the Receipt of PO anchor (v12.3), so the
  // whole opening block collapses like any other section.
  const aboveSectionTasks = filtered
    .filter(t => !inferredAnchorKey(t) && !t.phase_group)
    .slice()
    .sort((a, b) => (Number(a.sort_order) || 0) - (Number(b.sort_order) || 0));

  // Walk the full canonical hierarchy. Every level renders its header even when empty —
  // the skeleton tells the user where to put tasks. Tasks attach at any level: directly
  // under a phase_group (cross-cutting like Perform FAT), under a department, or under a
  // sub-department. Machine Power-Up flows through the bucket walk like any other Wire
  // task — its anchor styling is applied by the row renderer below.
  for (const group of HIERARCHY) {
    const gPath = groupPath(group.key);
    const gCollapsed = collapsedGroups.has(gPath);
    html += headerRowHtml(1, group.label, gPath, gCollapsed, { 'section-key': group.key });
    if (gCollapsed) continue;

    // 00 KICKOFF opens with the Receipt of PO anchor + every no-section row
    // (the legacy above-section-10 zone) so the whole opening block collapses
    // with the section. Tasks explicitly MOVED to kickoff render below these
    // through the normal bucket walk.
    if (group.key === 'kickoff') {
      if (receiptAnchor) html += anchorRowHtml(receiptAnchor, { groupBottom: true });
      for (const t of aboveSectionTasks) html += rowHtml(t, 2);
    }

    // Flatten mode: drop every dept/sub-dept header, render this section's tasks as
    // one flat list. Ship Machine still sits in section 50 between teardown and
    // install tasks; FAT still closes section 40.
    // Helper — pick the right row renderer for a task. Anchor tasks (currently just
    // Machine Power-Up flows through the bucket walk) get the anchor chip styling
    // so they read as spine markers even while sitting inline with their siblings.
    const renderTaskRow = (t, depth) => inferredAnchorKey(t) ? anchorRowHtml(t) : rowHtml(t, depth);

    if (flattenEffective) {
      let sectionTasks = flatBySection[group.key] || [];
      // For section 50, merge Ship Machine anchors into the section list and
      // sort by start_date so it lands between Teardown and Install regardless
      // of whether the tasks carry department='install' (sales schedules
      // clear department to suppress the subheaders, breaking the old
      // dept-based splice trigger).
      if (group.key === 'teardown_install' && shipAnchors.length) {
        const cmp = (a, b) => {
          const ad = String(a.start_date || '');
          const bd = String(b.start_date || '');
          if (ad && bd && ad !== bd) return ad < bd ? -1 : 1;
          return (Number(a.sort_order) || 0) - (Number(b.sort_order) || 0);
        };
        sectionTasks = [...sectionTasks, ...shipAnchors].sort(cmp);
      }
      for (const t of sectionTasks) html += renderTaskRow(t, 2);
      // FAT anchors at the end of section 40 even in flatten mode (collapses with the section).
      if (group.key === 'machine_testing' && fatAnchors.length) {
        for (const f of fatAnchors) html += anchorRowHtml(f);
      }
      // SAT closes section 50 — acceptance at the customer, the project's last marker.
      if (group.key === 'teardown_install' && satAnchors.length) {
        for (const s of satAnchors) html += anchorRowHtml(s);
      }
      continue;
    }

    // Tasks pinned at the phase_group level (no department).
    // Sales-mode section 50 puts every row at the group level (Teardown /
    // Ship Machine / Install with no dept subheaders), so splice Ship
    // Machine anchors in by sort_order here. Set a flag so the dept loop
    // below doesn't render Ship Machine a second time.
    let groupLevelTasks = buckets[gPath] || [];
    let shipDroppedAtGroupLevel = false;
    if (group.key === 'teardown_install' && shipAnchors.length && groupLevelTasks.length) {
      groupLevelTasks = [...groupLevelTasks, ...shipAnchors]
        .sort((a, b) => (Number(a.sort_order) || 0) - (Number(b.sort_order) || 0));
      shipDroppedAtGroupLevel = true;
    }
    for (const t of groupLevelTasks) html += renderTaskRow(t, 2);
    for (const dept of group.departments) {
      // Ship Machine sits between TEARDOWN and INSTALL inside section 50 — it's the
      // gate where the disassembled machine leaves SDC for the customer's site.
      // Multi-machine: render one Ship row per machine. Skip if we already
      // dropped them at the group level (sales schedules).
      if (group.key === 'teardown_install' && dept.key === 'install' && shipAnchors.length && !shipDroppedAtGroupLevel) {
        for (const s of shipAnchors) html += anchorRowHtml(s);
      }
      const dPath = groupPath(group.key, dept.key);
      const dCollapsed = collapsedGroups.has(dPath);
      // Count tasks at the dept level + every sub-dept underneath. If the
      // total is zero, skip rendering the dept header entirely — sales
      // schedules + section 50 / install / teardown live at the section
      // level with no dept, and the empty SHOP / ENGINEERING / TEARDOWN
      // skeleton headers were just noise.
      const deptTaskCount =
        (buckets[dPath]?.length || 0)
        + dept.subs.reduce((sum, sub) =>
            sum + (buckets[groupPath(group.key, dept.key, sub.key)]?.length || 0), 0);
      if (deptTaskCount === 0) continue;
      // For section 10, the Engineering and Shop departments are pure containers —
      // every task lives in a sub-department under them. The container header reads as
      // visual noise, so we skip it and let the sub-deps render directly under the
      // section. Procurement (no subs) and the section 40/50 dept-only groups still
      // get headers — those rows hold tasks themselves.
      const skipDeptHeader = group.key === 'design_build' && dept.subs.length > 0;
      // A parent dept that renders its own sub-department rows (e.g. INSTALL →
      // Shop / Engineering) shows NO hours readout itself — the breakdown lives
      // on the sub rows below. Leaf depts (no subs) carry their own hours.
      const deptHours = dept.subs.length > 0 ? null : deptHoursFor(buckets[dPath] || []);
      if (!skipDeptHeader) {
        html += headerRowHtml(2, dept.label, dPath, dCollapsed,
          { 'section-key': group.key, 'dept-key': dept.key }, deptHours);
        if (dCollapsed) continue;
      }
      if (dept.subs.length > 0) {
        // Tasks pinned at the department level (no sub_department)
        const deptLevelTasks = buckets[dPath] || [];
        for (const t of deptLevelTasks) html += renderTaskRow(t, 3);
        for (const sub of dept.subs) {
          const sPath = groupPath(group.key, dept.key, sub.key);
          const tasks = buckets[sPath] || [];
          // Skip empty sub-dept headers — same rule as dept-level above:
          // no tasks → no header. Keeps sales projects clean.
          if (tasks.length === 0) continue;
          const sCollapsed = collapsedGroups.has(sPath);
          html += headerRowHtml(3, sub.label, sPath, sCollapsed,
            { 'section-key': group.key, 'dept-key': dept.key, 'sub-key': sub.key }, deptHoursFor(tasks));
          if (sCollapsed) continue;
          for (const t of tasks) html += renderTaskRow(t, 4);
        }
      } else {
        const tasks = buckets[dPath] || [];
        for (const t of tasks) html += renderTaskRow(t, 3);
      }
    }
    // FAT anchors close section 40 — they're the gate that ends machine testing.
    // Rendered INSIDE section 40's iteration so that collapsing the section also
    // tucks them away. Multi-machine: one row per machine.
    if (group.key === 'machine_testing' && fatAnchors.length) {
      for (const f of fatAnchors) html += anchorRowHtml(f);
    }
    // SAT anchors close section 50 — acceptance at the customer's plant, after
    // the Install work. The very last spine marker of the project.
    if (group.key === 'teardown_install' && satAnchors.length) {
      for (const s of satAnchors) html += anchorRowHtml(s);
    }
  }

  // No UNASSIGNED bucket and no orphan auto-promote. Orphans (tasks with no phase_group
  // and not an anchor) simply don't render — server-side dedupe handles cleanup.

  tbody.innerHTML = html;
  if (state.layout) applyColumnVisibility();

  updateLineNumbersAndPreds();

  tbody.querySelectorAll('tr.group-header').forEach(tr => {
    tr.addEventListener('click', () => {
      const path = tr.dataset.path;
      if (collapsedGroups.has(path)) collapsedGroups.delete(path);
      else collapsedGroups.add(path);
      // Re-render BOTH grid and Gantt — the Gantt filters by collapsed groups too,
      // so its bars hide / re-appear in lockstep with the grid rows.
      renderTable();
      renderGantt();
    });
  });

  // v5.2: backlog duration is now a regular click-to-edit cell — no special
  // select dropdown wiring needed. handleCellClick → enterCellEdit handles
  // it via the standard "duration" column flow.

  attachRowDragHandlers(tbody);
  // Align the dept hours overlay (if any) over the Task column.
  positionDeptHours();
}

// Drag a task row onto a section header / another task to move it into that section.
// Within-section drops (onto a sibling task) reorder; cross-section drops reclassify.
function attachRowDragHandlers(tbody) {
  let draggedId = null;

  const clearDropMarkers = () => {
    tbody.querySelectorAll('.drop-target, .drop-after, .drop-before').forEach(el => {
      el.classList.remove('drop-target', 'drop-after', 'drop-before');
    });
  };

  // Drag is initiated from the .row-drag handle in the line column, not the whole row.
  tbody.querySelectorAll('.row-drag[draggable]').forEach(handle => {
    const tr = handle.closest('tr[data-id]');
    if (!tr) return;
    handle.addEventListener('dragstart', (e) => {
      draggedId = Number(tr.dataset.id);
      e.dataTransfer.effectAllowed = 'move';
      e.dataTransfer.setData('text/plain', String(draggedId));
      tr.classList.add('dragging');
    });
    handle.addEventListener('dragend', () => {
      tr.classList.remove('dragging');
      clearDropMarkers();
      draggedId = null;
    });
  });

  // Headers, add-rows, and task rows are valid drop targets.
  tbody.querySelectorAll('tr').forEach(tr => {
    tr.addEventListener('dragover', (e) => {
      if (!draggedId) return;
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      clearDropMarkers();
      tr.classList.add('drop-target');
      if (tr.dataset.id) {
        // Task row — pick before/after based on cursor position.
        const rect = tr.getBoundingClientRect();
        const after = (e.clientY - rect.top) > rect.height / 2;
        tr.classList.add(after ? 'drop-after' : 'drop-before');
      }
    });
    tr.addEventListener('drop', async (e) => {
      if (!draggedId) return;
      e.preventDefault();
      const movedId = draggedId;
      draggedId = null;
      clearDropMarkers();
      try {

      // Resolve target section + reorder anchor.
      let phase_group = null, department = null, sub_department = null, anchorId = null, anchorBefore = false;
      if (tr.classList.contains('group-header')) {
        const [pg, d, s] = (tr.dataset.path || '').split('/');
        phase_group = pg || null; department = d || null; sub_department = s || null;
      } else if (tr.dataset.id) {
        const target = state.tasks.find(t => t.id === Number(tr.dataset.id));
        if (!target || target.id === movedId) return;
        phase_group = target.phase_group; department = target.department; sub_department = target.sub_department;
        anchorId = target.id;
        anchorBefore = tr.classList.contains('drop-before') || (e.clientY - tr.getBoundingClientRect().top) <= tr.getBoundingClientRect().height / 2;
      } else {
        return;
      }

      // 1) Reclassify the moved task.
      await api.update(movedId, { phase_group, department, sub_department });

      // 2) If dropped near a sibling task, splice the order.
      if (anchorId) {
        const fresh = await api.list();
        const inSection = fresh
          .filter(t => t.phase_group === phase_group && t.department === department && t.sub_department === sub_department)
          .sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));
        const filtered = inSection.filter(t => t.id !== movedId);
        const idx = filtered.findIndex(t => t.id === anchorId);
        const insertAt = idx + (anchorBefore ? 0 : 1);
        filtered.splice(insertAt, 0, fresh.find(t => t.id === movedId));
        // Build full id list preserving everyone else's existing order.
        const movedSet = new Set(filtered.map(t => t.id));
        const others = fresh.filter(t => !movedSet.has(t.id)).sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));
        const fullOrder = [...others.map(t => t.id)];
        // Splice the section's reordered ids back into the position of the first section task.
        const firstIdx = fresh.findIndex(t => movedSet.has(t.id));
        fullOrder.splice(firstIdx >= 0 ? firstIdx : fullOrder.length, 0, ...filtered.map(t => t.id));
        await fetch('/api/tasks/reorder', {
          method: 'POST',
          headers: {'Content-Type':'application/json'},
          body: JSON.stringify({ order: fullOrder }),
        });
      }

      await loadTasks();
      } catch (_) { await loadTasks().catch(() => {}); }
    });
  });
}

// Clone-mode click handler. In clone mode the schedule grid becomes a
// row-selection tool — NO cell editors open, no pills, no drag handles.
// Every click on a tbody row is eaten. Source-machine rows toggle their
// membership in includeIds; other rows (shared anchors etc.) are inert.
// The ONLY interactive element we let through is the inline
// .clone-pred-editor (the input + OK / ✕ buttons), so the user can
// type into it without it being eaten by row-selection.
//
// Returns true when the event was handled (caller skips its other
// branches). Returns false ONLY when the click was inside an active
// .clone-pred-editor, so the editor's own handlers can run.
function handleCloneModeRowClick(e) {
  const cm = state.cloneMode;
  if (!cm) return false;
  // Let the inline pred editor keep its own click semantics.
  if (e.target.closest('.clone-pred-editor')) return false;
  // Anything else inside the table body is eaten in clone mode. Even
  // clicks on shared-anchor rows (machine=null) are blocked — the
  // user is focused on the M1 → M2 flow and shouldn't be opening
  // random cell editors mid-clone.
  e.preventDefault();
  e.stopPropagation();
  if (typeof e.stopImmediatePropagation === 'function') e.stopImmediatePropagation();
  const tr = e.target.closest('tr[data-id]');
  if (!tr) return true;   // empty area inside tbody — still eat the click
  const id = Number(tr.dataset.id);
  const t = state.tasks.find(x => x.id === id);
  // Any task in the project is togglable — including shared anchors above
  // the Build line (PO, Mech Release, Design tasks). Source-machine rows
  // are pre-selected when clone mode opens; shared rows start unselected
  // and the user opts in by clicking.
  if (!t || t.project !== state.filters.project) return true;
  if (cm.includeIds.has(id)) {
    cm.includeIds.delete(id);
    tr.classList.remove('clone-selected');
    // Hide the chip but keep the stored value — if the user clicks the
    // row back ON we restore their previous custom pred. Orphan customs
    // are filtered out by includeIds in confirmMachineClone, so leaving
    // them in the Map is harmless.
    const chip = tr.querySelector('.clone-pred-chip');
    if (chip) chip.remove();
  } else {
    cm.includeIds.add(id);
    tr.classList.add('clone-selected');
    // Re-paint the chip if there's a stored value from before.
    paintClonePredChip(tr, id);
  }
  renderMachineCloneBanner();
  return true;
}

// Clone-mode row double-click: opens a small inline editor for a custom
// predecessor string on this row. The typed value goes into
// state.cloneMode.customPredecessors (NOT to the server — it's applied
// when the user hits Complete).
function handleCloneModeRowDblClick(e) {
  const cm = state.cloneMode;
  if (!cm) return;
  const tr = e.target.closest('tr[data-id]');
  if (!tr) return;
  const id = Number(tr.dataset.id);
  const t = state.tasks.find(x => x.id === id);
  if (!t || t.project !== state.filters.project) return;
  // Only selected rows can take a custom predecessor (you have to bring
  // the row into the new machine first).
  if (!cm.includeIds.has(id)) {
    cm.includeIds.add(id);
    tr.classList.add('clone-selected');
  }
  e.preventDefault();
  e.stopPropagation();
  openCustomPredecessorEditor(tr, id);
}

// Floating popup that hangs off the clicked row. Appended to document.body
// (NOT inside the row) so the row's opacity / background can't bleed
// through. Anchored to the row's bounding rect — sits just below the
// row, left-aligned with the task name cell. White opaque background,
// drop shadow, clearly a popup. Click outside closes (commits).
function openCustomPredecessorEditor(tr, id) {
  const cm = state.cloneMode;
  if (!cm) return;
  const existing = cm.customPredecessors.get(id) || '';
  // Tear down any prior popup so back-to-back dblclicks don't stack.
  document.getElementById('clone-pred-popup')?.remove();
  const task = state.tasks.find(x => x.id === id);
  const taskName = task?.name || '(unnamed)';
  const popup = document.createElement('div');
  popup.id = 'clone-pred-popup';
  popup.className = 'clone-pred-popup';
  popup.innerHTML = `
    <div class="clone-pred-popup-header">
      <span class="clone-pred-popup-label">New predecessor for</span>
      <strong class="clone-pred-popup-task">${escapeHtml(taskName)}</strong>
    </div>
    <div class="clone-pred-popup-body">
      <input type="text" class="clone-pred-popup-input"
             placeholder="e.g. 12FS or 8FS+2"
             value="${escapeHtml(existing)}" />
      <button type="button" class="clone-pred-popup-ok"    title="Save (Enter)">Save</button>
      <button type="button" class="clone-pred-popup-clear" title="Clear (no predecessor)">Clear</button>
      <button type="button" class="clone-pred-popup-cancel" title="Cancel (Esc)">Cancel</button>
    </div>
    <div class="clone-pred-popup-hint">Use line numbers visible in this view. Blank or "Clear" removes the pred.</div>
  `;
  document.body.appendChild(popup);
  // Position the popup just below the row, left-aligned with its left
  // edge (clamped to viewport so it doesn't overflow).
  const rect = tr.getBoundingClientRect();
  const popW = popup.offsetWidth;
  const popH = popup.offsetHeight;
  const margin = 6;
  let left = Math.max(margin, rect.left);
  if (left + popW > window.innerWidth - margin) {
    left = Math.max(margin, window.innerWidth - popW - margin);
  }
  let top = rect.bottom + margin;
  if (top + popH > window.innerHeight - margin) {
    // Not enough room below; flip above the row.
    top = Math.max(margin, rect.top - popH - margin);
  }
  popup.style.left = left + 'px';
  popup.style.top  = top + 'px';

  const input = popup.querySelector('.clone-pred-popup-input');
  input.focus();
  input.select();
  let done = false;
  const finish = (commit, clear = false) => {
    if (done) return;
    done = true;
    document.removeEventListener('mousedown', onOutside, true);
    if (commit) {
      if (clear) {
        cm.customPredecessors.delete(id);
      } else {
        const val = input.value.trim();
        if (val) cm.customPredecessors.set(id, val);
        else cm.customPredecessors.delete(id);
      }
    }
    popup.remove();
    // Re-paint the chip on this row so the user can see what they entered.
    paintClonePredChip(tr, id);
    renderMachineCloneBanner();
  };
  const onOutside = (ev) => {
    if (popup.contains(ev.target)) return;
    finish(true);
  };
  input.addEventListener('keydown', (ev) => {
    if (ev.key === 'Enter')  { ev.preventDefault(); finish(true); }
    if (ev.key === 'Escape') { ev.preventDefault(); finish(false); }
  });
  popup.querySelector('.clone-pred-popup-ok').addEventListener('click',     () => finish(true));
  popup.querySelector('.clone-pred-popup-clear').addEventListener('click',  () => finish(true, true));
  popup.querySelector('.clone-pred-popup-cancel').addEventListener('click', () => finish(false));
  document.addEventListener('mousedown', onOutside, true);
}

// Render / refresh the small "pred: 12FS" chip on a selected row in
// clone mode. The chip lives INSIDE the .name-cell-main span (right
// after the task name + drift chip) so it's in the natural inline flow
// and doesn't fight with the absolutely-positioned % / duration pills
// at the right edge of the cell. Tears down the previous chip first
// so toggling is clean.
function paintClonePredChip(tr, id) {
  const cm = state.cloneMode;
  const old = tr.querySelector('.clone-pred-chip');
  if (old) old.remove();
  if (!cm) return;
  const val = cm.customPredecessors.get(id);
  if (!val) return;
  // Prefer the .name-cell-main span (inline with the name + drift chip);
  // fall back to the name td directly if the cell has no main span
  // (anchor / milestone rows render a simpler structure).
  const host = tr.querySelector('td[data-col="name"] .name-cell-main')
    || tr.querySelector('td[data-col="name"]')
    || tr.querySelector('td');
  if (!host) return;
  const chip = document.createElement('span');
  chip.className = 'clone-pred-chip';
  chip.title = 'Custom predecessor for the new machine — double-click row to edit';
  chip.textContent = ` pred: ${val}`;
  host.appendChild(chip);
}

// Re-decorate the visible rows after a re-render so selected rows show
// their lime tint + any custom-pred chips. Called from render().
function decorateCloneModeRows() {
  const cm = state.cloneMode;
  const tbody = document.getElementById('tasks-tbody');
  if (!tbody) return;
  // Clear any leftover decoration first (handles exit-cloning too).
  tbody.querySelectorAll('tr.clone-selected').forEach(tr => tr.classList.remove('clone-selected'));
  tbody.querySelectorAll('.clone-pred-chip').forEach(el => el.remove());
  if (!cm) return;
  tbody.querySelectorAll('tr[data-id]').forEach(tr => {
    const id = Number(tr.dataset.id);
    const t = state.tasks.find(x => x.id === id);
    if (!t || t.project !== state.filters.project) return;
    if (cm.includeIds.has(id)) tr.classList.add('clone-selected');
    paintClonePredChip(tr, id);
  });
}

function handleCellClick(e) {
  // Machine clone-mode: a capture-phase listener wired on the tbody
  // already ate the click and toggled the row's inclusion. By the time
  // we get here, the event is fully suppressed (stopImmediatePropagation),
  // so this branch only fires when cloneMode is null. Belt-and-suspenders
  // bail in case the capture-phase pass somehow missed.
  if (state.cloneMode) return;
  const delBtn = e.target.closest('.row-delete');
  if (delBtn) {
    e.stopPropagation();
    deleteTaskById(Number(delBtn.dataset.taskId));
    return;
  }
  // Editable pill inside the Task column (allocation / % complete). Intercept first
  // so the broader name-cell edit handler doesn't try to edit the task name.
  const pill = e.target.closest('[data-edit-pill]');
  if (pill) {
    e.stopPropagation();
    const taskId = Number(pill.dataset.taskId);
    const col = pill.dataset.editCol;
    enterPillEdit(pill, taskId, col);
    return;
  }
  // Milestone / anchor checkbox — toggle progress between 0 and 100.
  const mcheck = e.target.closest('[data-toggle-milestone]');
  if (mcheck) {
    e.stopPropagation();
    const taskId = Number(mcheck.dataset.taskId);
    const task = state.tasks.find(t => t.id === taskId);
    if (!task) return;
    const newProgress = (task.progress || 0) >= 100 ? 0 : 100;
    api.update(taskId, { progress: newProgress }).then(() => loadTasks()).catch(err => showToast(err.message || 'Save failed', { kind: 'error' }));
    return;
  }
  const td = e.target.closest('td[data-col]');
  if (!td) return;
  const tr = td.closest('tr[data-id]');
  if (!tr) return;
  const id = Number(tr.dataset.id);
  const col = td.dataset.col;
  if (col === 'line') return; // auto-computed, not editable
  // Sales-workspace tasks have allocation + assignee suppressed (v4.22).
  // Clicking those blank cells should be a no-op — the tooltip on the cell
  // explains why it's empty.
  if (td.classList.contains('sales-suppressed')) return;
  enterCellEdit(td, id, col);
}

// Mini-editor for the right-side pills inside the Task column. Same machinery as
// enterCellEdit (uses createEditInput + saveCellEdit) but contained inside the
// pill so the surrounding name cell layout doesn't reflow.
function enterPillEdit(pill, taskId, col) {
  if (pill.querySelector('input, select')) return;
  const task = state.tasks.find(t => t.id === taskId);
  if (!task) return;
  const original = currentCellValue(task, col);
  const input = createEditInput(col, original, task);
  input.classList.add('name-pill-input');
  // v4.32: pin the input's width to the column's expected content size.
  // Without this, the browser-default <input> width (~150px) blows up the
  // flex layout (alloc/dur) or the absolute-positioned % pill — the editor
  // appears in a totally different spot than the text the user clicked.
  // The three editable columns all have short values; 44px fits any of them.
  if (col === 'allocation') input.style.width = '36px';
  else if (col === 'duration') input.style.width = '44px';
  else if (col === 'progress') input.style.width = '40px';
  pill.classList.add('editing');
  pill.innerHTML = '';
  pill.appendChild(input);
  input.focus();
  if (typeof input.select === 'function') input.select();

  let done = false;
  // v4.25: click-outside dismissal. blur() alone doesn't fire when the user
  // clicks on the SVG Gantt (SVG elements aren't focusable by default), so
  // the pill editor would just sit there even though the user clearly
  // wanted to dismiss it. A document-level mousedown listener catches the
  // click ANYWHERE outside the input and finalizes (commits) — same as if
  // they'd hit Enter.
  const onOutsideMousedown = (e) => {
    if (input.contains(e.target)) return;
    finalize(true);
  };
  const finalize = async (commit) => {
    if (done) return;
    done = true;
    document.removeEventListener('mousedown', onOutsideMousedown, true);
    if (commit && input.value !== original) {
      try { await saveCellEdit(taskId, col, input.value, task); }
      catch (err) { showToast(err.message || 'Save failed', { kind: 'error' }); }
    }
    await loadTasks();
  };
  input.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') { e.preventDefault(); finalize(true); }
    else if (e.key === 'Escape') { e.preventDefault(); finalize(false); }
    // v4.42: when editing a DURATION cell, pressing "=" enters CLICK-PICK
    // mode — the editor closes WITHOUT saving and the user can click any
    // OTHER row's duration cell to link to it. This is the UX the user
    // asked for ("click the duration, hit equals, click another duration").
    // Cancelable with Escape or by clicking somewhere that isn't a dur cell.
    else if (col === 'duration' && e.key === '=') {
      e.preventDefault();
      // Discard the source-side edit — we're not saving a typed duration,
      // we're starting a link pick.
      finalize(false);
      enterDurationLinkPickMode(taskId);
    }
  });
  input.addEventListener('blur', () => finalize(true));
  // Capture phase so we beat any stopPropagation that Gantt / other handlers
  // might do on their own mousedowns.
  document.addEventListener('mousedown', onOutsideMousedown, true);
}

// v4.42: Duration LINK click-pick mode.
// Flow: user clicks dur on row A → editor opens → user hits "=" → editor
// closes, app shows visual pick-mode hint → user clicks dur on row B →
// row A links to row B (duration_link_task_id = B.id, duration_days copied
// from B). Pressing Escape or clicking somewhere that isn't a dur cell
// cancels without linking.
function enterDurationLinkPickMode(sourceTaskId) {
  const source = state.tasks.find(t => t.id === sourceTaskId);
  if (!source) return;
  document.body.classList.add('duration-link-pick-mode');

  const cleanup = () => {
    document.removeEventListener('mousedown', onPickMousedown, true);
    document.removeEventListener('keydown', onPickKey);
    document.body.classList.remove('duration-link-pick-mode');
  };

  const onPickMousedown = (e) => {
    // Find the dur cell that was clicked (if any).
    const dur = e.target.closest('.name-cell-dur[data-task-id]');
    if (!dur) {
      // Clicked outside any duration cell — cancel.
      cleanup();
      return;
    }
    const targetTaskId = Number(dur.getAttribute('data-task-id'));
    if (!targetTaskId || targetTaskId === sourceTaskId) {
      cleanup();
      return;
    }
    const target = state.tasks.find(t => t.id === targetTaskId);
    if (!target) {
      cleanup();
      return;
    }
    // Beat the regular click handler (which would open an editor on the
    // target dur). Capture-phase + preventDefault + stopPropagation.
    e.preventDefault();
    e.stopPropagation();

    const days = Number(target.duration_days) || 0;
    const data = {
      duration_link_task_id: targetTaskId,
      duration_days: days,
    };
    const today = new Date().toISOString().slice(0, 10);
    const startStr = snapToBusinessDay(source.start_date || today, 1);
    if (startStr !== source.start_date) data.start_date = startStr;
    if (days === 0) {
      data.is_milestone = true;
      data.end_date = startStr;
    } else if (days > 0) {
      if (source.is_milestone) data.is_milestone = false;
      data.end_date = addBusinessDays(startStr, days - 1);
    }
    console.log('[duration link] click-pick: linking task', sourceTaskId, '→ task', targetTaskId, '(', days, 'days )');
    api.update(sourceTaskId, data).then(() => loadTasks()).finally(cleanup);
  };
  const onPickKey = (e) => {
    if (e.key === 'Escape') cleanup();
  };
  document.addEventListener('mousedown', onPickMousedown, true);
  document.addEventListener('keydown', onPickKey);
}


function enterCellEdit(td, taskId, col) {
  if (td.querySelector('input, select')) return;
  const task = state.tasks.find(t => t.id === taskId);
  if (!task) return;
  // A predecessor-linked task's dates are governed by the link. Clicking a
  // Start/Finish date pops a small in-app confirm; on yes, the calendar opens
  // and the predecessor KEEPS its type (FS/SS/FF/SF) — only its lag/lead shifts
  // (in weeks/half-weeks) so the task lands on the chosen date.
  if ((col === 'start' || col === 'finish') && task.predecessors && String(task.predecessors).trim()) {
    const preds = String(task.predecessors).split(',').map(s => s.trim()).filter(Boolean);
    const single = preds.length === 1 ? parsePredecessor(preds[0]) : null;
    if (single) { single.lagBd = _predLagBd(preds[0]); _confirmPredChange(td, task, single, col); return; }
    // Multiple predecessors — ambiguous which lag to shift; fall through to a normal edit.
  }
  const original = currentCellValue(task, col);
  const input = createEditInput(col, original, task);
  // v5.1: when editing the NAME column, swap ONLY the .name-cell-main span
  // for the input — don't wipe the whole td. That keeps the alloc, dur, and
  // %-complete pills visible and constrains the input (and its text-selection
  // highlight) to the name's actual area between them, instead of stretching
  // across the entire Task column.
  let nameMainSpan = null;
  if (col === 'name') {
    nameMainSpan = td.querySelector('.name-cell-main');
  }
  if (nameMainSpan) {
    input.classList.add('name-cell-input');
    nameMainSpan.replaceWith(input);
  } else if (col === 'duration') {
    // v5.3: duration uses a compact right-aligned input that just replaces
    // the text. Skip the full-cell 'editing' state so the input doesn't
    // stretch across the entire 80-px column — it sits where the duration
    // text used to be, so the selection highlight matches the actual edit area.
    input.classList.add('duration-cell-input');
    td.innerHTML = '';
    td.appendChild(input);
  } else {
    td.classList.add('editing');
    td.innerHTML = '';
    td.appendChild(input);
  }
  if (input.type === 'date') {
    // Clicking a date cell opens the calendar in place (no month/day segment
    // highlight, no second click). Defer a frame so the input is laid out in
    // the cell before showPicker anchors to it.
    requestAnimationFrame(() => { try { input.showPicker(); } catch (_) { input.focus(); } });
  } else {
    input.focus();
    if (typeof input.select === 'function') input.select();
  }

  let done = false;
  // v4.25: same click-outside dismissal as enterPillEdit — blur misses
  // clicks on non-focusable SVG Gantt elements, so we attach an explicit
  // document-level mousedown listener that commits on any outside click.
  const onOutsideMousedown = (e) => {
    if (input.contains(e.target)) return;
    finalize(true);
  };
  const finalize = async (commit) => {
    if (done) return;
    done = true;
    document.removeEventListener('mousedown', onOutsideMousedown, true);
    if (commit && input.value !== original) {
      try { await saveCellEdit(taskId, col, input.value, task); }
      catch (err) { showToast(err.message || 'Save failed', { kind: 'error' }); }
    }
    await loadTasks();
  };
  document.addEventListener('mousedown', onOutsideMousedown, true);

  // The input opens with all text selected (input.select() above), so typing
  // immediately overwrites — but if the user clicks/arrows to reposition the
  // cursor (deselecting), typing inserts at the cursor like a normal field.
  // (We deliberately do NOT force-wipe on first keystroke — that nuked the value
  // even after the user had repositioned to append, e.g. adding "+2W" to "3FF".)
  input.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') { e.preventDefault(); finalize(true); return; }
    if (e.key === 'Escape') { e.preventDefault(); finalize(false); return; }
    if (e.key === 'Tab') {
      e.preventDefault();
      finalize(true).then(() => {
        // Move focus to next/prev cell of the SAME row in current column order.
        const order = state.layout.columnOrder.filter(k => state.layout.visibleCols.includes(k));
        const i = order.indexOf(col);
        const nextKey = order[i + (e.shiftKey ? -1 : 1)];
        if (!nextKey || nextKey === 'id') return;
        const nextRow = document.querySelector(`tr[data-id="${taskId}"]`);
        const nextTd = nextRow?.querySelector(`td[data-col="${nextKey}"]`);
        if (nextTd) enterCellEdit(nextTd, taskId, nextKey);
      });
      return;
    }
  });
  input.addEventListener('blur', () => finalize(true));
  // Commit the moment a value is chosen (date picked, dropdown selected) —
  // don't wait for a click-off. For text inputs 'change' fires on blur anyway.
  input.addEventListener('change', () => finalize(true));
}

// Lag of a predecessor ref in BUSINESS days (server convention: 'w' = 5 bd, so
// it matches cascadeSchedule). e.g. "4FF-2w" → -10, "4FF-5.5w" → -28 (rounded).
function _predLagBd(s) {
  const m = String(s).match(/([+-]\s*\d+(?:\.\d+)?)\s*([wd])?/i);
  if (!m) return 0;
  const n = Number(m[1].replace(/\s+/g, ''));
  return Math.round((m[2] || 'd').toLowerCase() === 'w' ? n * 5 : n);
}
// Business-day count to add to fromISO to reach toISO (toISO snapped to a
// business day). Positive = later, negative = earlier.
function _bdDelta(fromISO, toISO) {
  const target = snapToBusinessDay(toISO, 1);
  if (!fromISO || !target || target === fromISO) return 0;
  const forward = target > fromISO;
  const step = forward ? 1 : -1;
  let cur = fromISO, n = 0;
  for (let i = 0; i < 8000; i++) {
    cur = addBusinessDays(cur, step); n += step;
    if (cur === target) return n;
    if (forward ? cur > target : cur < target) return n;
  }
  return n;
}
// Small in-app confirm pill next to the cell: this line has a predecessor.
function _confirmPredChange(td, task, parsed, col) {
  document.getElementById('pred-confirm-pop')?.remove();
  const r = td.getBoundingClientRect();
  const pop = document.createElement('div');
  pop.id = 'pred-confirm-pop';
  pop.className = 'pred-confirm-pop';
  pop.innerHTML = `
    <div class="pcp-msg">This line has a <strong>predecessor</strong>. Change the date anyway? The predecessor stays — its lag just shifts to match.</div>
    <div class="pcp-btns">
      <button type="button" class="pcp-no">Cancel</button>
      <button type="button" class="pcp-yes">Yes, change it</button>
    </div>`;
  pop.style.left = Math.round(Math.min(r.left, window.innerWidth - 280)) + 'px';
  pop.style.top  = Math.round(r.bottom + 6) + 'px';
  document.body.appendChild(pop);
  const close = () => { pop.remove(); document.removeEventListener('mousedown', onDoc, true); };
  const onDoc = (e) => { if (!pop.contains(e.target)) close(); };
  setTimeout(() => document.addEventListener('mousedown', onDoc, true), 0);
  pop.querySelector('.pcp-no').addEventListener('click', close);
  pop.querySelector('.pcp-yes').addEventListener('click', () => { close(); _pickDateAdjustPred(td, task, parsed, col); });
}
// Open a calendar at the cell; on pick, keep the predecessor type and shift its
// lag (weeks/half-weeks) so the task lands there. Undoable. Closing without a
// pick reverts cleanly (no stuck highlight).
function _pickDateAdjustPred(td, task, parsed, col) {
  const baseDate = col === 'finish' ? (task.end_date || '') : (task.start_date || '');
  const inp = document.createElement('input');
  inp.type = 'date';
  inp.value = baseDate;
  inp.className = 'cell-edit-input';
  inp.style.width = '100%';
  td.classList.add('editing');
  td.innerHTML = '';
  td.appendChild(inp);
  let done = false;
  const finish = async (apply) => {
    if (done) return; done = true;
    document.removeEventListener('mousedown', onDoc, true);
    if (apply && inp.value && inp.value !== baseDate) {
      const newLagBd = parsed.lagBd + _bdDelta(baseDate, inp.value);
      const weeks = Math.round((newLagBd / 5) * 2) / 2;   // nearest half-week
      const lagStr = weeks === 0 ? '' : `${weeks > 0 ? '+' : '-'}${Math.abs(weeks)}w`;
      pushUndoSnapshot(task, ['predecessors'], `Change predecessor on "${task.name || 'task'}"`);
      try { await api.update(task.id, { predecessors: `${parsed.id}${parsed.type}${lagStr}` }); } catch (e) { console.error(e); showToast('Could not save the predecessor change.', { kind: 'error' }); }
    }
    await loadTasks();
  };
  const onDoc = (e) => { if (!inp.contains(e.target)) finish(false); };
  inp.addEventListener('change', () => finish(true));
  inp.addEventListener('keydown', (e) => { if (e.key === 'Escape') { e.preventDefault(); finish(false); } });
  inp.addEventListener('blur', () => finish(false));
  setTimeout(() => document.addEventListener('mousedown', onDoc, true), 0);
  requestAnimationFrame(() => { try { inp.showPicker(); } catch (_) { inp.focus(); } });
}

function currentCellValue(task, col) {
  switch (col) {
    case 'name':     return task.name || '';
    case 'project':  return task.project || '';
    case 'assignee': return task.assignee || '';
    case 'start':    return task.start_date || '';
    case 'finish':   return task.end_date || '';
    case 'completed': return task.completed_on || '';
    case 'duration': {
      // v4.37: pre-fill the editor with "=N" when the task is linked,
      // so the user can see + edit the link target directly. Re-saving
      // "=N" with the same N is a no-op; replacing with a duration like
      // "2w" unlinks.
      if (task.duration_link_task_id) {
        const line = lineByTaskId[task.duration_link_task_id];
        if (line) return `=${line}`;
      }
      return durationLabel(task);
    }
    case 'pred':     return predDisplay(task.predecessors || '');
    case 'progress': return String(task.progress || 0);
    case 'allocation': return String(task.allocation == null ? 90 : task.allocation);
    case 'priority': return String(task.priority == null ? 1 : task.priority);
    case 'notes':    return task.notes || '';
  }
  return '';
}

function createEditInput(col, value, task) {
  if (col === 'assignee') {
    // Constrained to active team members in the disciplines that plausibly own
    // this task. CONTROLS ENGINEERING task → only controls engineers. BUILD task
    // → only builders. Ambiguous buckets (General Engineering, Section 40/50
    // dept-level) widen to every relevant discipline. Cross-discipline
    // assignment isn't offered here — use the Resources view if you really need
    // to assign across boundaries.
    //
    // One nuance: if the task is ALREADY assigned to someone from a discipline
    // outside the filter, we expand the filter just enough to include them so
    // they don't disappear from the dropdown when the user opens it.
    const sel = document.createElement('select');
    sel.className = 'cell-edit-input';
    const blank = document.createElement('option');
    blank.value = '';
    blank.textContent = '— unassigned —';
    sel.appendChild(blank);
    const relevant = new Set(relevantDisciplinesForTask(task));
    const currentMember = value ? state.team.find(m => m.name === value && m.active !== 0) : null;
    if (currentMember) relevant.add(currentMember.discipline);
    const seen = new Set();
    for (const disc of DISCIPLINES) {
      if (!relevant.has(disc.key)) continue;
      const members = state.team.filter(m => m.discipline === disc.key && m.active !== 0);
      if (members.length === 0) continue;
      const og = document.createElement('optgroup');
      og.label = disc.label;
      for (const m of members) {
        const o = document.createElement('option');
        o.value = m.name;
        o.textContent = m.name;
        og.appendChild(o);
        seen.add(m.name);
      }
      sel.appendChild(og);
    }
    // Legacy assignees that aren't on the team list at all — show them so old
    // data is still editable, but flag the row clearly.
    if (value && !seen.has(value)) {
      const og = document.createElement('optgroup');
      og.label = 'Not on team';
      const o = document.createElement('option');
      o.value = value;
      o.textContent = `${value} (not on team)`;
      og.appendChild(o);
      sel.appendChild(og);
    }
    sel.value = value || '';
    return sel;
  }
  const input = document.createElement('input');
  input.className = 'cell-edit-input';
  if (col === 'start' || col === 'finish' || col === 'completed') {
    input.type = 'date';
  } else if (col === 'progress' || col === 'allocation' || col === 'priority') {
    // type="text" with inputmode=numeric — looks like a plain text field (no spinner
    // arrows ever, in any browser) but mobile keyboards still pop the number pad.
    // Validation happens in saveCellEdit.
    input.type = 'text';
    input.inputMode = 'numeric';
  } else {
    input.type = 'text';
  }
  input.value = value;
  return input;
}

async function saveCellEdit(id, col, value, task) {
  const data = {};
  switch (col) {
    case 'name':     data.name = (value || '').trim(); break;
    case 'assignee': data.assignee = (value || '').trim() || null; break;
    case 'completed': data.completed_on = (value || '').trim() || null; break;
    case 'start': {
      // Snap to a business day — we don't work weekends, so a Saturday start always
      // means the user wants Monday. Duration NEVER changes on a start edit; only the
      // finish shifts to honor whatever working-days the task already had.
      const snapped = value ? snapToBusinessDay(value, 1) : null;
      data.start_date = snapped;
      if (snapped && !task.is_milestone) {
        const dur = task.duration_days != null
          ? Number(task.duration_days)
          : businessDaysBetween(task.start_date, task.end_date);
        if (dur && dur > 0) {
          data.end_date = addBusinessDays(snapped, dur - 1);
        }
      } else if (task.is_milestone) {
        data.end_date = snapped; // milestones: start === end
      }
      break;
    }
    case 'finish': {
      // Editing the finish manually overrides duration — recompute it from the new
      // span so the duration column matches what the user just set.
      data.end_date = value || null;
      if (task.is_milestone) data.start_date = value || null;
      else if (value && task.start_date) {
        const newDur = businessDaysBetween(task.start_date, value);
        if (newDur != null && newDur > 0) data.duration_days = newDur;
      }
      break;
    }
    case 'duration': {
      // v4.41: "=N" LINKS this task's duration to the row on line N.
      // Regex is permissive — accepts "=24", "=24w", "= 24", "=24 some text",
      // anything starting with "=" followed by digits. We extract the
      // digits and look up the line. If the line isn't found, log a
      // warning and bail (saves nothing — leaves the task untouched).
      // Typing a duration WITHOUT a leading "=" clears the link.
      const trimmed = String(value || '').trim();
      if (trimmed.startsWith('=')) {
        const digitsMatch = trimmed.slice(1).match(/(\d+)/);
        if (!digitsMatch) {
          console.warn('[duration link] expected digits after "=", got:', trimmed);
          break;
        }
        const targetLine = Number(digitsMatch[1]);
        const targetTaskId = taskIdByLine[targetLine];
        if (!targetTaskId) {
          console.warn('[duration link] no task at line', targetLine, '(lineByTaskId keys:', Object.keys(taskIdByLine).slice(0, 10), '...)');
          break;
        }
        if (targetTaskId === id) {
          console.warn('[duration link] self-link ignored — task can\'t link to itself');
          break;
        }
        const sourceTask = state.tasks.find(t => t.id === targetTaskId);
        if (!sourceTask) {
          console.warn('[duration link] source task id', targetTaskId, 'not found in state.tasks');
          break;
        }
        const days = Number(sourceTask.duration_days) || 0;
        data.duration_link_task_id = targetTaskId;
        data.duration_days = days;
        const today = new Date().toISOString().slice(0, 10);
        let startStr = snapToBusinessDay(task.start_date || today, 1);
        if (startStr !== task.start_date) data.start_date = startStr;
        if (days === 0) {
          data.is_milestone = true;
          data.end_date = startStr;
        } else if (days > 0) {
          if (task.is_milestone) data.is_milestone = false;
          data.end_date = addBusinessDays(startStr, days - 1);
        }
        console.log('[duration link] linking task', id, '→ task', targetTaskId, '(line', targetLine, ') duration', days, 'days');
        break;
      }
      // No "=" prefix: standard duration parsing + UNLINK any prior link.
      const days = parseDurationInput(trimmed); // business days
      // Non-empty input that doesn't parse used to break silently — leaving the
      // user thinking they'd set a duration when nothing saved.
      if (days == null) { if (trimmed) showToast('Could not read that duration. Use e.g. "2w" or "10d".', { kind: 'error' }); break; }
      data.duration_days = days;
      // Clear the link (idempotent — server treats null = "no link").
      data.duration_link_task_id = null;
      const today = new Date().toISOString().slice(0, 10);
      let startStr = snapToBusinessDay(task.start_date || today, 1);
      if (startStr !== task.start_date) data.start_date = startStr;
      // Standard duration save. Real anchors keep their milestone flag.
      // Everything else: days=0 flips to milestone, days>0 flips back.
      const isAnchor = !!inferredAnchorKey(task);
      if (days === 0) {
        if (!isAnchor) data.is_milestone = true;
        data.end_date = startStr;
      } else if (days > 0) {
        if (task.is_milestone && !isAnchor) data.is_milestone = false;
        data.end_date = addBusinessDays(startStr, days - 1);
      }
      break;
    }
    case 'pred': {
      const rawPred = (value || '').trim();
      const parsedPred = predParse(rawPred);
      // Non-empty input that doesn't parse used to be dropped silently — tell
      // the user so a typo doesn't look like a successful save.
      if (rawPred && !parsedPred) showToast('Could not read that predecessor. Use e.g. "5FS" or "8FF -2w".', { kind: 'error' });
      data.predecessors = parsedPred || null;
      break;
    }
    case 'progress': {
      const rawN = Number(value);
      const clamped = Math.max(0, Math.min(100, rawN || 0));
      if (value !== '' && value != null && (Number.isNaN(rawN) || rawN !== clamped)) showToast(`Progress must be 0–100% — set to ${clamped}%.`, { kind: 'info' });
      data.progress = clamped;
      break;
    }
    case 'allocation': {
      const rawN = Number(value);
      const clamped = Math.max(0, Math.min(100, rawN || 0));
      if (value !== '' && value != null && (Number.isNaN(rawN) || rawN !== clamped)) showToast(`Allocation must be 0–100% — set to ${clamped}%.`, { kind: 'info' });
      data.allocation = clamped;
      break;
    }
    case 'priority':   data.priority   = Math.max(1, Math.min(99, Number(value) || 1)); break;
    case 'notes':      data.notes      = (value || '').trim() || null; break;
  }
  if (Object.keys(data).length > 0) {
    pushUndoSnapshot(task, Object.keys(data), `Edit ${col} on "${task.name || 'task'}"`);
    try {
      await api.update(id, data);
    } catch (e) {
      showAlertDialog({ title: 'Save failed', message: 'Could not save the edit: ' + e.message });
    }
  }
}

// ---------- Undo ----------
// Simple undo stack — records the BEFORE-state of any task field the user
// edits via the grid (cell edits, pill edits) or the lag editor on the Gantt
// arrows. Click the Undo button in the toolbar to pop the top entry and
// restore that task's snapshot.
// Stack is capped at 20 entries; older edits drop off the bottom.
const UNDO_STACK_MAX = 20;
function pushUndoSnapshot(task, fields, description) {
  if (!task || !Array.isArray(fields) || fields.length === 0) return;
  // Capture only the fields we're about to overwrite — keeps undo precise.
  const before = {};
  for (const f of fields) {
    // Map saveCellEdit's `col` keys to actual task fields.
    const mapped = ({
      'name': 'name',
      'start_date': 'start_date',
      'end_date': 'end_date',
      'duration_days': 'duration_days',
      'progress': 'progress',
      'allocation': 'allocation',
      'priority': 'priority',
      'predecessors': 'predecessors',
      'assignee': 'assignee',
      'notes': 'notes',
    })[f] || f;
    if (mapped in task) before[mapped] = task[mapped];
  }
  if (Object.keys(before).length === 0) return;
  state.undoStack.push({ taskId: task.id, before, description });
  while (state.undoStack.length > UNDO_STACK_MAX) state.undoStack.shift();
  // A new edit invalidates the redo history — otherwise redo would re-apply
  // a "future" state that conflicts with what the user just did.
  state.redoStack = [];
  syncUndoButton();
  syncRedoButton();
}

async function performUndo() {
  const entry = state.undoStack.pop();
  if (!entry) { syncUndoButton(); return; }
  // Undo an "add row" → delete the created row; redo will re-create it.
  if (entry.kind === 'create') {
    try { await api.remove(entry.taskId); }
    catch (err) { console.error('undo(create) failed', err); showToast('Undo failed — the row could not be removed.', { kind: 'error' }); }
    state.redoStack.push({ kind: 'create', payload: entry.payload, description: entry.description });
    while (state.redoStack.length > UNDO_STACK_MAX) state.redoStack.shift();
    await loadTasks();
    syncUndoButton(); syncRedoButton();
    return;
  }
  // Capture current state of the changed fields BEFORE we revert so redo can
  // re-apply them. Look up the task fresh from state.tasks (entry only holds
  // taskId + the original `before` snapshot, not the post-edit values).
  const task = state.tasks.find(t => t.id === entry.taskId);
  if (task) {
    const after = {};
    for (const f of Object.keys(entry.before)) {
      if (f in task) after[f] = task[f];
    }
    if (Object.keys(after).length > 0) {
      state.redoStack.push({ taskId: entry.taskId, before: after, description: entry.description });
      while (state.redoStack.length > UNDO_STACK_MAX) state.redoStack.shift();
    }
  }
  try {
    await api.update(entry.taskId, entry.before);
    await loadTasks();
  } catch (err) {
    console.error('undo failed', err);
    showToast('Undo failed — your change may not have been reverted.', { kind: 'error' });
  }
  syncUndoButton();
  syncRedoButton();
}

async function performRedo() {
  const entry = state.redoStack.pop();
  if (!entry) { syncRedoButton(); return; }
  // Redo an "add row" → re-create the row from its payload (new id is fine).
  if (entry.kind === 'create') {
    try {
      const c = await api.create(entry.payload);
      if (c && c.id) {
        state.undoStack.push({ kind: 'create', taskId: c.id, payload: entry.payload, description: entry.description });
        while (state.undoStack.length > UNDO_STACK_MAX) state.undoStack.shift();
      }
    } catch (err) { console.error('redo(create) failed', err); showToast('Redo failed — the row could not be re-created.', { kind: 'error' }); }
    await loadTasks();
    syncUndoButton(); syncRedoButton();
    return;
  }
  // Capture current state as a new undo entry, then apply the redo snapshot.
  const task = state.tasks.find(t => t.id === entry.taskId);
  if (task) {
    const before = {};
    for (const f of Object.keys(entry.before)) {
      if (f in task) before[f] = task[f];
    }
    if (Object.keys(before).length > 0) {
      state.undoStack.push({ taskId: entry.taskId, before, description: entry.description });
      while (state.undoStack.length > UNDO_STACK_MAX) state.undoStack.shift();
    }
  }
  try {
    await api.update(entry.taskId, entry.before);
    await loadTasks();
  } catch (err) {
    console.error('redo failed', err);
    showToast('Redo failed — your change may not have been re-applied.', { kind: 'error' });
  }
  syncUndoButton();
  syncRedoButton();
}

function syncUndoButton() {
  const btn = document.getElementById('btn-undo');
  if (!btn) return;
  const stack = state.undoStack || [];
  const last = stack[stack.length - 1];
  btn.disabled = !last;
  if (last) {
    btn.title = `Undo: ${last.description}\n(${stack.length} change${stack.length === 1 ? '' : 's'} in history)`;
  } else {
    btn.title = 'Nothing to undo — no edits in this session yet.';
  }
}

function syncRedoButton() {
  const btn = document.getElementById('btn-redo');
  if (!btn) return;
  const stack = state.redoStack || [];
  const last = stack[stack.length - 1];
  btn.disabled = !last;
  if (last) {
    btn.title = `Redo: ${last.description}\n(${stack.length} change${stack.length === 1 ? '' : 's'} ready to re-apply)`;
  } else {
    btn.title = 'Nothing to redo — undo something first.';
  }
}

function parseDurationInput(s) {
  s = String(s || '').trim().toLowerCase();
  const m = s.match(/^(\d+(?:\.\d+)?)\s*([wd])?$/);
  if (!m) return null;
  const n = parseFloat(m[1]);
  const unit = m[2] || 'd';
  // Duration is in BUSINESS days. "1w" = 5 business days (Mon–Fri), "3d" = 3.
  // Weeks support half-week granularity (0.5w = 2.5 days, 1.5w = 7.5 days).
  // Days input always rounds to whole days — fractional days don't make
  // sense in our work-day grid (you can't end mid-day).
  if (unit === 'w') {
    // Snap to 0.5-week increments — SDC doesn't think in finer than half weeks.
    const halfWeeks = Math.round(n * 2);
    return halfWeeks * 2.5;
  }
  return Math.round(n);
}

// ---------- Column reorder (drag-and-drop) ----------
function setupColumnReorder() {
  const ths = document.querySelectorAll('#tasks-table thead th[data-col]');
  ths.forEach(th => {
    th.addEventListener('dragstart', (e) => {
      e.dataTransfer.setData('text/plain', th.dataset.col);
      e.dataTransfer.effectAllowed = 'move';
      th.classList.add('dragging');
    });
    th.addEventListener('dragend', () => th.classList.remove('dragging'));
    th.addEventListener('dragover', (e) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      th.classList.add('drag-over');
    });
    th.addEventListener('dragleave', () => th.classList.remove('drag-over'));
    th.addEventListener('drop', (e) => {
      e.preventDefault();
      th.classList.remove('drag-over');
      const fromKey = e.dataTransfer.getData('text/plain');
      const toKey = th.dataset.col;
      if (!fromKey || fromKey === toKey) return;
      const order = [...state.layout.columnOrder];
      const fromIdx = order.indexOf(fromKey);
      if (fromIdx === -1) return;
      order.splice(fromIdx, 1);
      const toIdx = order.indexOf(toKey);
      order.splice(toIdx === -1 ? order.length : toIdx, 0, fromKey);
      state.layout.columnOrder = order;
      saveLayout();
      renderHeaders();
      renderTable();
    });
  });
}

// ---------- Gantt rendering ----------
// Muted hierarchy palette — drives BOTH the Gantt bar colors and the grid header pill
// colors. Keyed by rowColorKey() / data-color-key. Each entry has a fill (background)
// and a text/stroke shade. Defaults are configurable on Setup → Hierarchy Colors.
const HIERARCHY_COLOR_DEFAULTS = {
  // Sub-department-level (only section 10 has sub-departments).
  mech:           { label: 'Mechanical Engineering', fill: '#cfdcef', text: '#1e3a8a' },
  controls:       { label: 'Controls Engineering',   fill: '#cfe6d2', text: '#14532d' },
  general:        { label: 'General Engineering',    fill: '#ddd0eb', text: '#581c87' },
  build:          { label: 'Build',                  fill: '#f1d4ad', text: '#7c2d12' },
  wire:           { label: 'Wire',                   fill: '#fef08a', text: '#713f12' }, // clear yellow
  // Department-level (used directly in sections 40 / 50, and as the section-10 dept-row color).
  'eng-combined': { label: 'Engineering (combined)', fill: '#b6e5dc', text: '#134e4a' },
  'shop-combined':{ label: 'Shop (combined)',        fill: '#fbc97a', text: '#78350f' }, // distinct amber, not orange-pink
  procurement:    { label: 'Procurement',            fill: '#d6dde6', text: '#334155' },
  // Fallback for rows with no hierarchy (above-section-10 rows). Soft slate
  // background + the same dark-slate text shade procurement uses, so the bar
  // reads consistently with the rest of the chart.
  neutral:        { label: 'Other',                  fill: '#e2e8f0', text: '#334155' },
};
const HIERARCHY_KEYS = Object.keys(HIERARCHY_COLOR_DEFAULTS);

// Live store — populated from settings on load. Read by injectPhaseStyles + the grid CSS
// (via custom properties). The keys never change; only fill/text per key are editable.
let HIERARCHY_BAR_COLORS = { ...HIERARCHY_COLOR_DEFAULTS };

function injectPhaseStyles() {
  const id = 'phase-bar-styles';
  let el = document.getElementById(id);
  if (!el) {
    el = document.createElement('style');
    el.id = id;
    document.head.appendChild(el);
  }
  // Phase-based bar colors (legacy / fallback for tasks without a hierarchy match).
  // Progress fill is the bar's text/stroke color at 0.4 opacity — solid but not
  // bold. The hierarchy/phase color always reflects WHAT the task is; the
  // darker progress portion reflects HOW MUCH is done.
  const phaseRules = PHASES.map(p =>
    `.gantt .bar-wrapper.phase-${p.key} .bar { fill: ${p.color}; stroke: ${p.text}; stroke-width: 1; }
     .gantt .bar-wrapper.phase-${p.key} .bar-progress { fill: ${p.text}; opacity: 0.4; }
     .gantt .bar-wrapper.phase-${p.key} .bar-label { fill: ${p.text}; font-weight: var(--fw-semibold); }`
  ).join('\n');

  // Hierarchy-based bar colors — listed AFTER phase rules so they win on equal specificity.
  // Tasks pick the deepest match (sub-dept > combined dept > procurement).
  const hierarchyRules = Object.entries(HIERARCHY_BAR_COLORS).map(([key, c]) =>
    `.gantt .bar-wrapper.bar-color-${key} .bar { fill: ${c.fill}; stroke: ${c.text}; stroke-width: 1; }
     .gantt .bar-wrapper.bar-color-${key} .bar-progress { fill: ${c.text}; opacity: 0.4; }
     .gantt .bar-wrapper.bar-color-${key} .bar-label { fill: ${c.text}; font-weight: var(--fw-semibold); }`
  ).join('\n');

  // Over-allocated overrides — listed before critical so the critical-path outline
  // wins when both apply (so a critical+over-allocated task still reads as on the
  // critical path).
  const overAlloc = `
    .gantt .bar-wrapper.over-allocated .bar { fill: #fee2e2; stroke: #dc2626; stroke-width: 2; }
    .gantt .bar-wrapper.over-allocated .bar-progress { fill: #dc2626; opacity: 0.45; }
    .gantt .bar-wrapper.over-allocated .bar-label { fill: #b91c1c; font-weight: var(--fw-extrabold); }
  `;

  // Critical path — bars and milestone diamonds on the binding chain from Receipt
  // of PO to FAT get a BOLD red outline (3.5px). The fill stays whatever the
  // hierarchy / phase rules computed, so existing color coding is preserved
  // underneath. Anchor diamonds bump even thicker so they really stand out.
  const critical = `
    .gantt .bar-wrapper.on-critical .bar { stroke: #b91c1c; stroke-width: 3.5; }
    .gantt .bar-wrapper.on-critical .milestone-diamond.anchor-inner { stroke: #b91c1c; stroke-width: 3; }
    .gantt .bar-wrapper.on-critical .milestone-diamond { stroke: #b91c1c; stroke-width: 2.5; }
  `;

  // 100% complete DURATION bars get a lime green border — preserves the
  // hierarchy color underneath (so a finished Build task still reads as
  // "Build") but adds an unmistakable visual cue that it's done. Lime matches
  // the anchor-color palette so the "done" visual language is consistent
  // across tasks and anchors. Critical-path red border still wins (it's
  // declared after and uses the same selector specificity).
  // Done duration tasks: lime outline on the bar signals "complete". We also
  // hide the dark bar-progress overlay because at 100% it covers the entire
  // bar with the text-color fill at 0.4 opacity, which makes the bar-label
  // (also drawn in text color) low-contrast and hard to read. With the
  // overlay gone, the label sits on the bar's normal lighter fill and is
  // readable just like an active task.
  const doneRule = `
    .gantt .bar-wrapper.is-done .bar { stroke: #befa4f !important; stroke-width: 2.5 !important; }
    .gantt .bar-wrapper.is-done .bar-progress { opacity: 0 !important; }
  `;

  el.textContent = phaseRules + '\n' + hierarchyRules + '\n' + doneRule + '\n' + overAlloc + '\n' + critical;
}

function renderGanttLegend() {
  // v4.38: legend element removed from the DOM. Function kept as a no-op
  // so existing call sites (renderGantt + a few others) don't need to be
  // touched. If the legend ever needs to come back, restoring the markup
  // in index.html is enough.
  const legend = document.getElementById('gantt-legend');
  if (!legend) return;
  const present = new Set(state.tasks.map(t => t.phase).filter(Boolean));
  const items = PHASES.filter(p => present.has(p.key));
  legend.innerHTML = items.map(p => `
    <span class="legend-item">
      <span class="legend-swatch" style="background:${p.color};border:1px solid ${p.text}"></span>
      ${escapeHtml(p.label)}
    </span>`).join('');
}

// True when a task lives inside a collapsed section / department / sub-department —
// any ancestor on its hierarchy path being collapsed counts. Used by renderGantt to
// hide bars whose grid row is currently hidden behind a collapsed group, so
// collapsing a section in the grid also tucks its bars away on the Gantt.
function isTaskInCollapsedGroup(task) {
  if (!task) return false;
  // Spine-floater anchors (no phase_group) collapse with the section they render
  // adjacent to:
  //   - FAT closes section 40 → hides when MACHINE TESTING is collapsed.
  //   - Ship Machine sits inside section 50 → hides when TEARDOWN & INSTALL collapses.
  //   - Receipt of PO is at the very top, above any section — always visible.
  // Machine Power-Up has a phase_group (10 → Shop → Wire) so it follows the normal
  // collapse rules at the bottom of this function.
  const anchor = inferredAnchorKey(task);
  if (anchor === 'fat') {
    return collapsedGroups.has(groupPath('machine_testing'));
  }
  if (anchor === 'ship_machine' || anchor === 'sat') {
    return collapsedGroups.has(groupPath('teardown_install'));
  }
  // Receipt of PO + every no-section row live inside 00 KICKOFF (v12.3) —
  // they hide when that section collapses, like FAT does with section 40.
  if (anchor && !task.phase_group) return collapsedGroups.has(groupPath('kickoff'));
  if (!task.phase_group) return collapsedGroups.has(groupPath('kickoff'));
  const paths = [
    groupPath(task.phase_group),
    task.department    ? groupPath(task.phase_group, task.department) : null,
    task.sub_department ? groupPath(task.phase_group, task.department, task.sub_department) : null,
  ].filter(Boolean);
  return paths.some(p => collapsedGroups.has(p));
}

function renderGantt() {
  const container = document.getElementById('gantt-container');
  if (!container) return;
  const empty = document.getElementById('gantt-empty');
  // Same task ordering as the grid so rows align side-by-side. Tasks inside a
  // collapsed group are dropped here so the Gantt mirrors the grid's visibility.
  // Tasks that don't belong to any current section (and aren't anchors) are also
  // dropped — those are leftovers from old data structures that the grid hides;
  // the Gantt should hide them too so no ghost bars appear.
  const validSectionKeys = new Set(HIERARCHY.map(g => g.key));
  // v4.50: when NOT in sortByStart mode, use the GRID's canonical order
  // (buildCanonicalTaskOrder) so the Gantt bars sort the same way the
  // grid rows do — Receipt of PO at top, Backlog under it, section 10
  // bucket walk, FAT closing section 40, Ship Machine inside section 50.
  //
  // IMPORTANT: buildCanonicalTaskOrder ignores the machine-subset filter
  // (so line numbers stay stable across "All / M1 / M2"). After we have
  // the canonical order, we MUST intersect it with the actually-visible
  // task set from applyFilters() — otherwise the Gantt renders bars for
  // every machine even when the grid is narrowed to one (the visual mess
  // the user saw with M2 selected: M1 bars still painting on the right
  // side of the chart).
  // Single applyFilters() call — result reused for both ordering paths below.
  const _ganttFiltered = applyFilters(state.tasks);
  let ordered;
  if (state.scheduleView?.sortByStart) {
    ordered = [..._ganttFiltered].sort((a, b) =>
      (a.start_date || '￿').localeCompare(b.start_date || '￿')
      || (a.sort_order || 0) - (b.sort_order || 0));
  } else {
    const canonicalIds = buildCanonicalTaskOrder();
    const visibleIds = new Set(_ganttFiltered.map(t => t.id));
    const byId = Object.fromEntries(state.tasks.map(t => [t.id, t]));
    ordered = canonicalIds
      .filter(id => visibleIds.has(id))
      .map(id => byId[id])
      .filter(Boolean);
  }
  // Same Only-critical filter renderTable applies, mirrored here so the Gantt only
  // shows the critical bars + anchor markers when the toggle is on.
  const onlyCrit = state.scheduleView?.criticalOnly && state.scheduleView?.criticalPath;
  const critForFilter = onlyCrit ? computeCriticalPath() : null;
  // v4.47: mirror the Schedule/Combined/Actions filter from renderTable —
  // the Gantt must always show the SAME row set as the grid. Without this
  // filter, the Gantt drew every task regardless of actionsMode, so "Actions
  // only" in the grid still showed scheduled bars on the chart.
  const am = state.scheduleView?.actionsMode || 'schedule';
  const filtered = ordered
    .filter(t => t.start_date && t.end_date)
    .filter(t => !isTaskInCollapsedGroup(t))
    // Anchors always render. Above-section-10 rows (phase_group=null, non-anchor)
    // render too. Anything else needs a valid HIERARCHY phase_group; tasks with
    // a phase_group that doesn't match any current section are legacy leftovers
    // and stay hidden (the grid hides them too).
    .filter(t => inferredAnchorKey(t) || !t.phase_group || validSectionKeys.has(t.phase_group))
    .filter(t => !critForFilter || critForFilter.has(String(t.id)) || inferredAnchorKey(t))
    .filter(t => {
      // Anchors always render. Otherwise honor the actionsMode toggle:
      //   schedule → drop is_action tasks
      //   actions  → drop non-action tasks
      //   combined → keep both
      if (inferredAnchorKey(t)) return true;
      if (am === 'schedule') return !t.is_action;
      if (am === 'actions')  return !!t.is_action;
      return true; // combined
    })
    .filter(t => !state._exportOnlyIds || inferredAnchorKey(t) || state._exportOnlyIds.has(t.id));

  renderGanttLegend();

  if (filtered.length === 0) {
    container.innerHTML = '';
    empty && empty.classList.remove('hidden');
    state.gantt = null;
    return;
  }
  empty && empty.classList.add('hidden');
  injectPhaseStyles();

  // Critical-path mode: compute the binding-predecessor chain so we can tag those
  // bars + their drawn arrows with the on-critical class. Empty set when off.
  const criticalIds = state.scheduleView?.criticalPath ? computeCriticalPath() : new Set();
  state._criticalIds = criticalIds;

  const ganttTasks = filtered.map(t => {
    const classes = [];
    if (t.phase) classes.push(`phase-${t.phase}`);
    // Hierarchy color (sub-department / combined-department) — overrides the phase color.
    const colorKey = rowColorKey(t);
    if (colorKey) classes.push(`bar-color-${colorKey}`);
    if (t.is_milestone) classes.push('is-milestone');
    if (isBacklogTask(t)) {
      classes.push('is-backlog');
      // v4.84: backlog with end_date in the past gets is-backlog-expired so
      // the bar picks up the lime-green border styling. No checkbox; just a
      // visual signal that the calendar time has elapsed.
      const todayMs = (() => { const d = new Date(); d.setHours(0,0,0,0); return d.getTime(); })();
      if (t.end_date && new Date(t.end_date).getTime() < todayMs) {
        classes.push('is-backlog-expired');
      }
    }
    // Milestones at 100%: still tagged milestone-done — drawMilestoneDiamonds
    // uses it to paint the ✓ overlay glyph. As of v4.4 milestones keep their
    // normal fill color (lime for anchors, slate for non-anchors) when done;
    // only the ✓ overlay differs. Done is the EXTRA — color is consistent.
    if (t.is_milestone && (t.progress || 0) >= 100) classes.push('milestone-done');
    // 100% complete DURATION task: tag .is-done. CSS adds a LIME BORDER around
    // the bar — preserves the hierarchy color underneath (Build task stays
    // Build-tan when done, etc.) and the lime stroke makes "complete" pop
    // visually without recoloring the bar. Uses getEffectiveProgress so the
    // Backlog row picks up the same lime border + hash overlay once today
    // crosses its end_date.
    if (!t.is_milestone && getEffectiveProgress(t) >= 100) classes.push('is-done');
    if (state.overAllocatedTaskIds.has(t.id)) classes.push('over-allocated');
    if (criticalIds.has(String(t.id))) classes.push('on-critical');
    return {
      id: String(t.id),
      name: t.name,
      start: t.start_date,
      end: t.end_date,
      // Backlog rows: progress derived from today's position; everything
      // else reads stored t.progress. getEffectiveProgress handles both.
      progress: getEffectiveProgress(t),
      dependencies: '', // custom arrows below
      custom_class: classes.join(' '),
    };
  });

  // Invisible phantom tasks 6 months before the earliest task and 6 months after
  // the latest. Symmetric padding lets the user scroll equally past either edge —
  // previously the pre-task pad was 30 days, which meant on a project starting in
  // May you couldn't scroll back to April. 6 months is enough to comfortably
  // bring any edge bar into the center of the viewport.
  const minStart = Math.min(...filtered.map(t => new Date(t.start_date).getTime()));
  const maxEnd   = Math.max(...filtered.map(t => new Date(t.end_date).getTime()));
  const PAD_MS = 183 * 86400000; // ~6 months
  const padBefore = new Date(minStart - PAD_MS).toISOString().slice(0, 10);
  const padAfter  = new Date(maxEnd   + PAD_MS).toISOString().slice(0, 10);
  ganttTasks.unshift({ id: '_pad_before', name: '', start: padBefore, end: padBefore, progress: 0, dependencies: '', custom_class: 'phantom-pad' });
  ganttTasks.push   ({ id: '_pad_after',  name: '', start: padAfter,  end: padAfter,  progress: 0, dependencies: '', custom_class: 'phantom-pad' });

  // Auto fit-to-viewport whenever this is the first render OR the active project just
  // changed. Manual wheel/zoom adjustments stick — we only re-fit on a real navigation.
  const projectKey = state.filters.project || '_all_';
  const fitNow = state._fitOnNextRender === true || state._lastFitProject !== projectKey;
  if (fitNow) {
    const visiblePanel = document.getElementById('schedule-gantt');
    const target = Math.max(300, (visiblePanel ? visiblePanel.clientWidth : 0) - 24);
    const projectDays = Math.max(1, (maxEnd - minStart) / 86400000 + 1);
    const PAD_DAYS = 14;
    if (target > 0) {
      const requiredPxPerDay = target / (projectDays + PAD_DAYS);
      state.zoomPercent = Math.max(ZOOM_MIN, Math.min(ZOOM_MAX, (requiredPxPerDay / 20) * 100));
    }
    state._lastFitProject = projectKey;
    state._fitOnNextRender = false;
  }

  const { mode, cw } = getZoomConfig(state.zoomPercent);
  state.viewMode = mode;
  const oldScroller = document.querySelector('#gantt-container .gantt-container');
  const scrollLeft = oldScroller ? oldScroller.scrollLeft : 0;
  container.innerHTML = '';
  const { bar_height, padding } = getGanttBarMetrics();
  state.gantt = new Gantt(container, ganttTasks, {
    view_mode: mode,
    column_width: cw,
    _cwOverride: cw,
    bar_height,
    padding,
    header_height: 38,
    on_click: (task) => {
      const tr = document.querySelector(`tr[data-id="${task.id}"]`);
      if (tr) tr.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    },
    // Gantt is READ-ONLY for edits (v11.5): dragging a bar changed dates
    // without touching predecessors, which silently corrupted the dependency
    // chain — and made accidental moves too easy. Any drag snaps back on
    // release with a pointer to the grid. Resize/progress handles are hidden
    // via CSS (.gantt .handle) so the affordances don't invite it.
    on_date_change: () => {
      showToast('Dates are edited in the grid — dragging bars on the chart is off.', { kind: 'info' });
      renderGantt();
    },
    on_progress_change: () => {
      showToast('Progress is edited in the grid — dragging on the chart is off.', { kind: 'info' });
      renderGantt();
    },
  });
  const newScroller = document.querySelector('#gantt-container .gantt-container');
  if (newScroller) {
    if (oldScroller && !fitNow) {
      newScroller.scrollLeft = scrollLeft;
    } else {
      // First render OR a fit render (pane-mode change / project switch):
      // land on the earliest real task past the leading phantom-pad. Restoring
      // the previous scrollLeft here was the bug that left the chart "shifted
      // off to the side" after Gantt-only → Both — that scroll came from a
      // different zoom level and panel width, so it pointed at nothing.
      const earliest = filtered.reduce((min, t) =>
        new Date(t.start_date).getTime() < new Date(min.start_date).getTime() ? t : min);
      const wrap = document.querySelector(`#gantt-container .bar-wrapper[data-id="${earliest.id}"]`);
      const bar = wrap && wrap.querySelector('.bar');
      if (bar) newScroller.scrollLeft = Math.max(0, +bar.getAttribute('x') - 24);
    }
  }

  // Keep the topbar zoom-mode picker in sync with whatever mode the current zoom maps to.
  const zoomModeEl = document.getElementById('zoom-mode');
  if (zoomModeEl && zoomModeEl.value !== mode) zoomModeEl.value = mode;

  cleanGanttHeaders();
  // ── Work-day compression ─────────────────────────────────────────────
  // frappe-gantt positions bars by calendar day (7-day weeks). The SDC
  // schedule only operates Mon-Fri, so we squeeze Sat/Sun out: every bar,
  // arrow, today-line, milestone, header label re-anchors to its
  // work-day index instead of its calendar-day index. The downstream
  // drawers (drawCustomArrows / drawTodayLine / drawMilestoneDiamonds /
  // etc.) read positions FROM the .bar elements, so once bars are
  // repositioned here, everything else follows automatically.
  compressGanttToWorkDays();
  // alignGanttToGrid relies on the grid's row offsetTops to position bars row-by-row.
  // In Gantt-only mode the grid is hidden (display:none) so its offsets are zero —
  // skip alignment and let frappe-gantt's natural layout drive bar positions.
  if (!state.scheduleView?.ganttOnly) alignGanttToGrid();

  // Decorations run SYNCHRONOUSLY (this is what worked in 8e7432d before the
  // Abhi merge). Deferring them a frame made clipBarLabels/drawBarMeta measure
  // bar geometry one frame late, which broke the meta cascade — meta ended up
  // inside the bar while the name was pushed outside, and names straddled the
  // bar edge. The cascade requires clipBarLabels (places the name) to run
  // immediately before drawBarMeta (reads that placed name), both measuring the
  // same fresh, synchronous layout. Do NOT wrap these in requestAnimationFrame.
  // All drawers wrapped in try/catch per CLAUDE.md so a throw can't break zoom.
  //
  // Arrows render FIRST (behind everything) — bars and labels cover them visually.
  try { drawCustomArrows(); } catch (_) {}
  try { drawBaselineGhosts(); } catch (_) {}
  try { drawTodayLine(); } catch (_) {}
  try { drawMilestoneDiamonds(); } catch (_) {}
  try { drawMilestoneLabels(); } catch (_) {}
  try { clipBarLabels(); } catch (_) {}
  try { drawScheduleStatus(); } catch (_) {}
  try { drawDoneHashOverlay(); } catch (_) {}
  try { drawWeekdayLetters(); } catch (_) {}
  try { drawFinancialOverlay(); } catch (_) {}
  try { drawPenaltyClauseLine(); } catch (_) {}
  try { drawBarMeta(); } catch (_) {}
  try { drawMachineBorders(); } catch (_) {}
  try { renderProjectStatsPopup(); } catch (_) {}
  // Montserrat loads async and is wider than the fallback — if labels were
  // measured before it finished loading they get mis-placed. Once fonts are
  // ready, re-run the SAME order as above (clipBarLabels first so drawBarMeta
  // can read the name's final position — the meta cascade depends on that
  // order; running meta after a late clip is what breaks "alloc leaves first").
  if (document.fonts && document.fonts.status !== 'loaded') {
    document.fonts.ready.then(() => {
      try { clipBarLabels(); } catch (_) {}
      try { drawBarMeta(); } catch (_) {}
    });
  }
}

// ── Work-day Gantt helpers ───────────────────────────────────────────
// workDayOffset: count of business days (Mon-Fri) from ganttStart to
// the given date. Used to re-anchor every X position so the weekend
// columns collapse to zero.
function workDayOffset(dateStr, ganttStart) {
  if (!dateStr || !ganttStart) return 0;
  const startMs = new Date(ganttStart).getTime();
  const endStr = typeof dateStr === 'string' ? (dateStr.length > 10 ? dateStr.slice(0, 10) : dateStr) : dateStr;
  const endMs  = new Date(endStr + 'T00:00:00Z').getTime();
  if (endMs <= startMs) return 0;
  // Walk day by day, counting Mon-Fri only.
  let count = 0;
  for (let ms = startMs; ms < endMs; ms += 86400000) {
    const dow = new Date(ms).getUTCDay();
    if (dow !== 0 && dow !== 6) count++;
  }
  return count;
}

// Same idea but returns the work-day x for an arbitrary calendar-day x
// (in original frappe-gantt coords). Used to translate paths that were
// drawn in calendar space (e.g. existing arrow logic) to work-day space.
function calXToWorkDayX(calX, pxPerDay, ganttStart) {
  if (!ganttStart || pxPerDay <= 0) return calX;
  const days = calX / pxPerDay;
  const startMs = new Date(ganttStart).getTime();
  const dateMs = startMs + Math.round(days) * 86400000;
  const dateStr = new Date(dateMs).toISOString().slice(0, 10);
  return workDayOffset(dateStr, ganttStart) * pxPerDay;
}

// Reposition every bar (and its inner label / progress / handles) to
// the work-day grid. The convention per Dan's rule:
//   • Bar's left edge sits at the START day's column line.
//   • Bar's right edge sits at the END day's column line.
//   • A 1-day task (start == end) gets a minimum visible width.
//   • Fractional durations round UP to the next full day.
function compressGanttToWorkDays() {
  try {
    const svg = document.querySelector('#gantt-container .gantt');
    if (!svg) return;
    const g = state.gantt;
    if (!g || !g.gantt_start) return;
    const cw = g.options.column_width;
    const mode = g.options.view_mode || 'Week';
    const step = mode === 'Day' ? 1 : mode === 'Week' ? 7 : 30;
    const pxPerDay = cw / step;          // px per CALENDAR day
    const pxPerWorkDay = pxPerDay;       // we keep the column width — chart shrinks horizontally
    const ganttStart = g.gantt_start;
    // 1-day tasks (start == end) get a slim "marker" bar centered on
    // their day's line — wide enough to see, but doesn't claim to span
    // any range. All other bars snap EXACTLY to start-day-line and
    // end-day-line (no clamp), so they always end on a day's line.
    const oneDayMarkerW = Math.max(3, pxPerWorkDay * 0.18);

    const wdoCache = {};
    const wdo = (s) => {
      if (s in wdoCache) return wdoCache[s];
      wdoCache[s] = workDayOffset(s, ganttStart);
      return wdoCache[s];
    };

    // Track each bar's old + new x so the downstream drawers can be told.
    state._workDayMap = { pxPerDay, ganttStart };

    for (const wrap of svg.querySelectorAll('.bar-wrapper')) {
      const id = Number(wrap.dataset.id);
      const t = state.tasks.find(x => x.id === id);
      if (!t || !t.start_date) continue;
      const startOff = wdo(t.start_date);
      const endOff   = t.end_date ? wdo(t.end_date) : startOff;
      const isMilestone = !!t.is_milestone || !!inferredAnchorKey(t);
      let newX = startOff * pxPerWorkDay;
      let newW = (endOff - startOff) * pxPerWorkDay;
      if (newW === 0) {
        if (isMilestone) {
          // Milestones render as diamonds via drawMilestoneDiamonds, but
          // frappe-gantt's underlying .bar still needs SOMETHING — use
          // a centered marker so the diamond drawer has a reliable
          // anchor point.
          newW = Math.max(8, pxPerWorkDay);
          newX -= newW / 2;
        } else {
          // Regular 1-day task: thin marker centered on the day's line.
          newW = oneDayMarkerW;
          newX -= oneDayMarkerW / 2;
        }
      }

      const bar      = wrap.querySelector('.bar');
      const progress = wrap.querySelector('.bar-progress');
      const label    = wrap.querySelector('.bar-label');
      const handleL  = wrap.querySelector('.handle.left');
      const handleR  = wrap.querySelector('.handle.right');
      const handleP  = wrap.querySelector('.handle.progress');
      if (!bar) continue;

      const oldX = +bar.getAttribute('x');
      const oldW = +bar.getAttribute('width');
      const oldProgressW = progress ? +progress.getAttribute('width') : 0;
      const oldLabelX = label ? +label.getAttribute('x') : 0;

      // Update bar
      bar.setAttribute('x', newX);
      bar.setAttribute('width', newW);

      // Progress: keep proportion if both originals had width, else 0
      if (progress) {
        const ratio = oldW > 0 ? (oldProgressW / oldW) : 0;
        progress.setAttribute('x', newX);
        progress.setAttribute('width', Math.max(0, newW * ratio));
      }

      // Label: shift by the SAME delta the bar moved, then clipBarLabels
      // (called later in the chain) will repaint based on the new bar
      // geometry anyway. Just keeps it visible during the transition.
      if (label) {
        const dx = newX - oldX;
        label.setAttribute('x', oldLabelX + dx);
      }

      // Handles
      if (handleL) handleL.setAttribute('x', newX + 1);
      if (handleR) handleR.setAttribute('x', newX + newW - 9);
      if (handleP) {
        // progress handle sits at the progress right edge
        const cx = newX + (progress ? +progress.getAttribute('width') : 0);
        handleP.setAttribute('points', `${cx-5},${+handleP.getAttribute('points').split(',')[1] || 0} ${cx+5},${+(handleP.getAttribute('points').split(' ')[1]||'').split(',')[1] || 0} ${cx},${+(handleP.getAttribute('points').split(' ')[2]||'').split(',')[1] || 0}`);
      }

      // Cache the new geometry on the wrapper for downstream consumers
      // (drawCustomArrows reads bar x/width directly from the DOM).
      wrap.dataset.workDayX = String(newX);
      wrap.dataset.workDayW = String(newW);
    }

    // Replace frappe-gantt's date labels — it labels every 7 calendar
    // days starting from gantt_start, which gives Thursday dates when
    // gantt_start is a Thursday. We want EVERY label to be a Monday.
    // Strategy: remove its lower-text labels + ticks, then redraw our
    // own at each Monday's work-day x. Same for upper-text (month
    // strip) — redraw with proper month boundaries.
    for (const el of svg.querySelectorAll('.lower-text, .upper-text, .tick')) el.remove();
    // Find rows for label Y positions. frappe-gantt typically uses
    // header_height: 38 with the upper-text near top and lower-text just
    // above the bars. Steal Y from any leftover header element, fall
    // back to sensible defaults.
    const lowerY = 28;
    const upperY = 12;
    const tickTop = 36;
    const svgH = +svg.getAttribute('height') || 800;

    // Walk Mondays from the first full-week Monday through the chart's
    // right edge. For each Monday: draw a label + a vertical tick line.
    //
    // Adaptive density rules (all-or-nothing — never every-other):
    //   weekW = 5 * pxPerDay (one full work-week wide on screen).
    //   - weekW >= 14px: date numbers shown (kicks in ~zoom 2)
    //   - weekW <  14px: date numbers SKIPPED (would crowd & overlap)
    //   For month names, computed AFTER walking based on each month's
    //   visible width — if < 70px, switch to short "Nov" form; if even
    //   that doesn't fit, fall back to truncated text.
    const startMs = new Date(ganttStart).getTime();
    const startDow = new Date(startMs).getUTCDay();
    const daysToFirstMonday = startDow === 1 ? 0 : (startDow === 0 ? 1 : 8 - startDow);
    const weekW = 5 * pxPerDay;
    const showDateNumbers = weekW >= 14;
    let walkMs = startMs + daysToFirstMonday * 86400000;
    let lastMonthLabel = '';
    const monthLabels = []; // [{ startX, label, monthIndex, endX }]
    while (true) {
      const walkDate = new Date(walkMs);
      const dateStr = walkDate.toISOString().slice(0, 10);
      const mondayX = workDayOffset(dateStr, ganttStart) * pxPerDay;
      if (mondayX > (+svg.getAttribute('width') || 8000)) break;
      // Date number — only when there's enough room. All-or-nothing
      // (every Monday, or none).
      if (showDateNumbers) {
        const dayNum = walkDate.getUTCDate();
        const text = document.createElementNS(SVG_NS, 'text');
        text.setAttribute('class', 'lower-text');
        text.setAttribute('x', String(mondayX));
        text.setAttribute('y', String(lowerY));
        text.style.fontFamily = "'Montserrat', sans-serif";
        text.style.fontSize = '12px';
        text.style.fontWeight = '500';
        text.setAttribute('text-anchor', 'middle');
        text.setAttribute('fill', '#475569');
        text.textContent = String(dayNum);
        svg.appendChild(text);
      }
      // Solid tick line at Monday. Use a tall fixed height (10000) instead
      // of svgH — alignGanttToGrid (called LATER in the render chain) can
      // grow the SVG to match the grid, and we'd otherwise leave the
      // ticks too short. SVG clips anything past the viewBox naturally.
      const tick = document.createElementNS(SVG_NS, 'path');
      tick.setAttribute('class', 'tick thick');
      tick.setAttribute('d', `M ${mondayX} ${tickTop} v 10000`);
      tick.setAttribute('stroke', '#cbd5e1');
      tick.setAttribute('stroke-width', '1');
      svg.insertBefore(tick, svg.firstChild);
      // Track month transition for the upper strip
      const monthName = walkDate.toLocaleString(undefined, { month: 'long', timeZone: 'UTC' });
      const monthShort = walkDate.toLocaleString(undefined, { month: 'short', timeZone: 'UTC' });
      if (monthName !== lastMonthLabel) {
        if (monthLabels.length) monthLabels[monthLabels.length - 1].endX = mondayX;
        monthLabels.push({ startX: mondayX, label: monthName, short: monthShort, endX: 0 });
        lastMonthLabel = monthName;
      }
      walkMs += 7 * 86400000;
    }
    // Close the last month label
    if (monthLabels.length) {
      monthLabels[monthLabels.length - 1].endX = +svg.getAttribute('width') || (monthLabels[monthLabels.length - 1].startX + weekW * 4);
    }
    // Draw month strip with adaptive label form. Measure each month's
    // available width and pick: full name / short name / single letter /
    // hidden. Truncate with a left-anchored ellipsis if even single
    // letters can't fit (rare).
    for (const m of monthLabels) {
      const w = m.endX - m.startX;
      // Estimated character width at 13px sans-serif: ~7px per character.
      const fullW  = m.label.length * 7 + 8;
      const shortW = m.short.length * 7 + 8;
      let labelText = '';
      let fontSize = '13px';
      if (w >= fullW)       labelText = m.label;
      else if (w >= shortW) labelText = m.short;
      else if (w >= 12)     { labelText = m.short.charAt(0); fontSize = '12px'; }
      else                  labelText = ''; // skip — too tight
      if (!labelText) continue;
      const text = document.createElementNS(SVG_NS, 'text');
      text.setAttribute('class', 'upper-text');
      const cx = (m.startX + m.endX) / 2;
      text.setAttribute('x', String(cx));
      text.setAttribute('y', String(upperY));
      text.style.fontFamily = "'Montserrat', sans-serif";
      text.style.fontSize = fontSize;
      text.style.fontWeight = '600';
      text.setAttribute('text-anchor', 'middle');
      text.setAttribute('fill', '#0f172a');
      text.textContent = labelText;
      svg.appendChild(text);
    }

    // Trim the SVG's right edge so we don't leave a giant empty gantt area
    // past the last bar. Compute the rightmost work-day x across all bars
    // and pad a couple of columns of breathing room.
    let maxRight = 0;
    for (const bar of svg.querySelectorAll('.bar')) {
      const r = (+bar.getAttribute('x') || 0) + (+bar.getAttribute('width') || 0);
      if (r > maxRight) maxRight = r;
    }
    if (maxRight > 0) {
      const newWidth = maxRight + pxPerWorkDay * 4;
      svg.setAttribute('width', String(newWidth));
      // Update viewBox too if set
      if (svg.viewBox && svg.viewBox.baseVal) {
        svg.viewBox.baseVal.width = newWidth;
      }
    }
  } catch (err) {
    // Don't break the render chain if anything goes sideways.
    console.warn('[compressGanttToWorkDays]', err);
  }
}

// When zoomed in enough that each day occupies enough pixels to fit a
// letter, paint faint M / T / W / Th / F labels in the date header along
// with thin vertical tick lines through the chart for each weekday. Skipped
// at lower zoom levels (and skipped on weekends — we don't work Sa/Su).
function drawWeekdayLetters() {
  try {
    const svg = document.querySelector('#gantt-container .gantt');
    if (!svg) return;
    svg.querySelectorAll('.sdc-weekday-letter-group, .sdc-weekday-tick').forEach(el => el.remove());

    const g = state.gantt;
    if (!g || !g.gantt_start) return;
    const cw = g.options.column_width;
    const mode = g.options.view_mode || 'Week';
    const step = mode === 'Day' ? 1 : mode === 'Week' ? 7 : 30;
    const pxPerDay = cw / step;
    // Day letters appear only when one full work-week occupies enough
    // pixels to read M T W Th F without overlap. weekW = 5 * pxPerDay.
    // Threshold of 60 = pxPerDay 12 — that's around zoom level 7 in
    // the friendly stepper, which matches what the user expects.
    // Configurable on Setup → Gantt Weekday Markers (default 12 px/day).
    const threshold = (state.settings?.weekday_marker_threshold != null)
      ? Number(state.settings.weekday_marker_threshold)
      : 12;
    if (pxPerDay < threshold) return;

    const totalWidth = +svg.getAttribute('width') ||
                       (svg.viewBox?.baseVal?.width) || 8000;
    const totalDays = Math.ceil(totalWidth / pxPerDay) + 1;

    // Pin to the existing week-label y so the letters sit just below it.
    // Read from the actual lower-text element in the SVG.
    const lowerTexts = svg.querySelectorAll('.lower-text');
    let baselineY = 26;
    if (lowerTexts.length > 0) {
      baselineY = +lowerTexts[0].getAttribute('y') || baselineY;
    }
    // Push letters further below the header's bottom border so the line
    // doesn't visually clip the top of the glyphs.
    const letterY = baselineY + 22;
    const tickTop = letterY + 6;
    const svgHeight = +svg.getAttribute('height') ||
                      (svg.viewBox?.baseVal?.height) || 800;

    // Letter group — same pattern as drawBarMeta (which DOES render text
    // successfully): create a <g>, append to SVG root, drop text elements
    // inside. Critically, set font-family inline because frappe-gantt's
    // own stylesheet sets `.gantt text { font-family: ... }`, which would
    // otherwise override any presentation attribute and made my letters
    // not render with a usable font in earlier attempts.
    const lettersGroup = document.createElementNS(SVG_NS, 'g');
    lettersGroup.setAttribute('class', 'sdc-weekday-letter-group');
    lettersGroup.style.pointerEvents = 'none';
    svg.appendChild(lettersGroup);

    // Work-day Gantt: each work day is one column, no weekend space.
    // Iterate Mondays from gantt_start forward; for each, draw 5 dashed
    // ticks (M T W Th F) at consecutive work-day positions. The Mon line
    // is solid (drawn by the header), the next 4 are dashed.
    const startMs = new Date(g.gantt_start).getTime();
    const startDow = new Date(startMs).getUTCDay();
    // Days from gantt_start to its first full-week Monday.
    const daysToFirstMonday = startDow === 1 ? 0 : (startDow === 0 ? 1 : 8 - startDow);
    // 5 letters per week (M T W Th F) at column-line positions —
    // evenly spaced one pxPerDay apart. M sits ON the Monday solid
    // line (next to the date number). T, W, Th, F sit on the four
    // dashed lines between Mondays.
    const letters5 = ['M', 'T', 'W', 'Th', 'F'];

    // walkMs steps Monday-by-Monday through the chart range.
    let walkMs = startMs + daysToFirstMonday * 86400000;
    while (true) {
      const walkDate = new Date(walkMs);
      const dateStr = walkDate.toISOString().slice(0, 10);
      const mondayX = workDayOffset(dateStr, g.gantt_start) * pxPerDay;
      if (mondayX > totalWidth) break;
      // Place each letter AT the column boundary (j * pxPerDay from
      // Monday). Bars also end at these boundary positions, so a bar
      // ending Tuesday lands precisely on the T letter's line.
      for (let j = 0; j < 5; j++) {
        const x = mondayX + j * pxPerDay;
        if (x < 0) continue;
        if (x > totalWidth) break;

        // Dashed faint tick.
        const tick = document.createElementNS(SVG_NS, 'line');
        tick.setAttribute('class', 'sdc-weekday-tick');
        tick.setAttribute('x1', x);
        tick.setAttribute('x2', x);
        tick.setAttribute('y1', tickTop);
        // Use a tall fixed value so the dashed tick reaches past the bottom
        // of the chart even if alignGanttToGrid grew the SVG after the
        // header drawer captured svgHeight. Clipped naturally by viewBox.
        tick.setAttribute('y2', 10000);
        tick.setAttribute('stroke', '#e2e8f0');
        tick.setAttribute('stroke-width', '0.5');
        tick.setAttribute('stroke-dasharray', '2 4');
        tick.setAttribute('pointer-events', 'none');
        svg.insertBefore(tick, svg.firstChild);

        // Letter directly above the tick.
        const text = document.createElementNS(SVG_NS, 'text');
        text.setAttribute('class', 'sdc-weekday-letter');
        text.setAttribute('x', String(x));
        text.setAttribute('y', String(letterY));
        text.setAttribute('text-anchor', 'middle');
        text.setAttribute('dominant-baseline', 'central');
        text.setAttribute('fill', '#475569');
        text.setAttribute('paint-order', 'stroke');
        text.setAttribute('stroke', 'rgba(255,255,255,0.9)');
        text.setAttribute('stroke-width', '2');
        text.setAttribute('stroke-linejoin', 'round');
        text.style.fontFamily = "'Montserrat', sans-serif";
        text.style.fontSize = '9px';
        text.style.fontWeight = '700';
        text.style.pointerEvents = 'none';
        text.textContent = letters5[j];
        lettersGroup.appendChild(text);
      }
      walkMs += 7 * 86400000;  // advance to next Monday
    }
  } catch (_) { /* swallow — cosmetic, never break render chain */ }
}

// Paint a diagonal lime hash pattern on every completed (.is-done) bar so
// it reads as "done" at a glance — same visual idea as a checked-off line.
// The pattern is defined once per render in <defs> and reused by every
// overlay rect. The overlay sits ABOVE the bar + bar-progress but BELOW
// the bar-label, so the task name stays readable on top.
function drawDoneHashOverlay() {
  // Diagonal stripes via SVG diagonal-line elements. Each completed bar
  // gets a group of 45° lines that span its bounds. No clipPath — we use
  // a foreignObject with CSS repeating-linear-gradient instead, which is
  // the most reliable cross-browser way to render a hash pattern inside
  // an SVG. Try/catch so any failure can't kill the rest of the render
  // chain (zoom scroll-restore, drawBarMeta, etc.).
  try {
    const svg = document.querySelector('#gantt-container .gantt');
    if (!svg) return;
    svg.querySelectorAll('.sdc-done-hash-overlay').forEach(el => el.remove());

    svg.querySelectorAll('.bar-wrapper.is-done').forEach(wrap => {
      const bar = wrap.querySelector('.bar');
      if (!bar) return;
      const x = +bar.getAttribute('x');
      const y = +bar.getAttribute('y');
      const w = +bar.getAttribute('width');
      const h = +bar.getAttribute('height');
      if (!(w > 0 && h > 0)) return;

      // Diagonal stripes drawn as <line> elements at 45° (slope 1). Endpoints
      // mathematically clamped to stay inside the bar's rectangle — no
      // clipPath / mask / URL refs (all failed in this SVG).
      //
      // DOM placement: insert the line INTO bar-label's parentNode, just
      // before bar-label itself. This makes the line a SIBLING of bar-label
      // (so they share a parent group containing the bar / bar-progress /
      // bar-label). Paint order ends up as: bar → bar-progress → my line →
      // bar-label. So the line paints OVER the bar fill (visible) but
      // UNDER the description text (text stays readable).
      //
      // Earlier attempt inserted before a direct-child ancestor of wrap,
      // which placed the line BEFORE the whole bar group in DOM order,
      // making the bar fill paint over the line. That's why the user saw
      // the stripes only briefly during zoom/render transitions.
      const labelEl = wrap.querySelector('.bar-label');
      const labelParent = labelEl ? labelEl.parentNode : null;
      const spacing = 6;
      for (let i = -h; i <= w; i += spacing) {
        let x1 = x + i,     y1 = y;
        let x2 = x + i + h, y2 = y + h;
        // Clip START point at the bar's LEFT edge.
        if (x1 < x) {
          const dx = x - x1;
          x1 = x;
          y1 = y + dx;
        }
        // Clip END point at the bar's RIGHT edge.
        if (x2 > x + w) {
          const dx = x2 - (x + w);
          x2 = x + w;
          y2 = y + h - dx;
        }
        if (Math.abs(x2 - x1) < 0.5 && Math.abs(y2 - y1) < 0.5) continue;

        const line = document.createElementNS(SVG_NS, 'line');
        line.setAttribute('class', 'sdc-done-hash-overlay');
        line.setAttribute('x1', x1);
        line.setAttribute('y1', y1);
        line.setAttribute('x2', x2);
        line.setAttribute('y2', y2);
        // SDC lime — same color as the bar's lime border (doneRule in
        // injectPhaseStyles uses #befa4f).
        line.setAttribute('stroke', '#befa4f');
        line.setAttribute('stroke-width', '1.5');
        line.setAttribute('stroke-opacity', '0.85');
        line.setAttribute('pointer-events', 'none');
        // Insert into bar-label's PARENT, just before bar-label itself,
        // so the line is a sibling of the label in the same group. Paints
        // over the bar/bar-progress, under the description text.
        if (labelParent && labelEl) {
          labelParent.insertBefore(line, labelEl);
        } else {
          wrap.appendChild(line);
        }
      }
    });
  } catch (_) { /* swallow — hash overlay is cosmetic, render chain must continue */ }
}

// Per-bar allocation + duration labels on the Gantt. Renders ONE compact label
// per task bar — combining allocation % and duration (in weeks) — placed
// BELOW the bar by default, but flipped ABOVE when an arrow passes through
// the below-bar gap (otherwise the label sits right on top of the arrow line
// and you can't read it).
//
// Format: "50% · 3w"  (middle-dot separator; either side is omitted when
// that value is 0 or missing).
//
// Placement priority:
//   1. Below the bar — preferred, sits in its own row's below-gap so
//      adjacent rows never collide.
//   2. Above the bar — fallback when an arrow would cross the below position.
//   3. Skip — last resort, when both above and below would collide with
//      arrows (rare; only happens when the bar has an arrow entering its top
//      AND an arrow exiting its bottom).
//
// Paint a colored border around every Gantt bar / milestone whose task
// has a `machine` tag. Border color matches the per-machine palette used
// by .name-machine-chip in the grid (M1=blue, M2=amber, M3=green, …) so
// the user can tell duplicates apart on the chart at a glance — without
// overlaying any text on top of the bar (the old chip approach covered
// labels + duration markers and was unreadable). Bar fill (phase color)
// stays untouched.
//
// Defensive (try/catch) per CLAUDE.md — must NEVER break the render
// chain; bar-meta + zoom restore live downstream.
function drawMachineBorders() {
  try {
    const svg = document.querySelector('#gantt-container .gantt');
    if (!svg) return;
    // Clear any prior border treatments so re-render is clean.
    svg.querySelectorAll('.bar[data-machine-bordered]').forEach(el => {
      el.removeAttribute('data-machine-bordered');
      el.style.stroke = '';
      el.style.strokeWidth = '';
    });
    // Gated by the M view-pill + project must actually have 2+ machines.
    if (!shouldShowMachineVisuals()) return;
    for (const task of state.tasks) {
      if (!task.machine) continue;
      const wrap = svg.querySelector(`.bar-wrapper[data-id="${task.id}"]`);
      if (!wrap) continue;
      const bar = wrap.querySelector('.bar');
      if (!bar) continue;
      const color = getMachineColor(task.project, task.machine).hex;
      bar.style.stroke = color;
      bar.style.strokeWidth = '2';
      bar.setAttribute('data-machine-bordered', task.machine);
    }
  } catch (_) { /* swallow — cosmetic, must not break render chain */ }
}

// Skipped for milestones, anchors, and backlog. Runs AFTER drawCustomArrows
// so the arrow <path> elements exist in the DOM and we can query their bboxes
// for collision detection.
function drawBarMeta() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;
  // Tear down any prior labels so toggling off cleanly removes them.
  svg.querySelectorAll('.sdc-bar-meta').forEach(el => el.remove());
  // v4.75 BUGFIX: only reset visibility/opacity on NON-MILESTONE bar-labels.
  // drawMilestoneDiamonds sets opacity=0 on milestone bar-labels because
  // drawMilestoneLabels renders its own text — so undoing that here was
  // causing milestone names to render TWICE (one from frappe-gantt, one
  // from drawMilestoneLabels) when the % toggle was on.
  //
  // v4.79: also reset style.textAnchor so the "shifted right" state from a
  // previous render doesn't accumulate. clipBarLabels positions the label
  // via setAttribute, which won't override an inline style.textAnchor.
  svg.querySelectorAll('.bar-wrapper:not(.is-milestone) .bar-label').forEach(el => {
    el.style.opacity = '';
    el.style.visibility = '';
    el.style.textAnchor = '';
    el.style.transform = '';
    el.style.fill = '';
  });
  if (state.scheduleView?.showBarMeta !== true) return;

  const group = document.createElementNS(SVG_NS, 'g');
  group.setAttribute('class', 'sdc-bar-meta');
  group.style.pointerEvents = 'none';
  svg.appendChild(group);

  // Parse each arrow line into axis-aligned segments and collision-check
  // labels against the SEGMENTS, not the path's bounding box. Why: an L-shape
  // arrow's getBBox() encloses both legs PLUS the L's empty corner area, which
  // wrongly marks most bars sitting INSIDE that corner zone as colliding even
  // though the arrow line is on the edges only (v3.56 had this issue — 2/3 of
  // labels ended up suppressed because every bar near a long L-shape looked
  // "occupied"). Per-segment intersection is exact for axis-aligned arrows
  // (all our arrow segments are pure horizontal or vertical by construction
  // in computeArrowPath).
  const arrowSegments = [];
  svg.querySelectorAll('.sdc-arrows path.arrow').forEach(p => {
    const d = p.getAttribute('d');
    if (!d || /Z/i.test(d)) return;  // skip arrowhead triangles (closed with Z)
    const nums = d.match(/-?\d+(\.\d+)?/g);
    if (!nums || nums.length < 4) return;
    // Path is "M x y L x y [L x y]" — pair consecutive points to form segments.
    for (let i = 0; i + 3 < nums.length; i += 2) {
      arrowSegments.push({
        x1: +nums[i],   y1: +nums[i+1],
        x2: +nums[i+2], y2: +nums[i+3],
      });
    }
  });
  // Rect-vs-segment intersection. Each segment is axis-aligned, so its bbox
  // is the segment itself; bbox-overlap therefore exactly equals "the
  // segment passes through the rect". A small pad (2px) is added around the
  // rect so labels don't sit flush against an arrow line.
  const overlapsArrow = (rect, pad = 2) => {
    const rx1 = rect.x - pad, rx2 = rect.x + rect.w + pad;
    const ry1 = rect.y - pad, ry2 = rect.y + rect.h + pad;
    return arrowSegments.some(s => {
      const sx1 = Math.min(s.x1, s.x2), sx2 = Math.max(s.x1, s.x2);
      const sy1 = Math.min(s.y1, s.y2), sy2 = Math.max(s.y1, s.y2);
      return !(sx2 < rx1 || sx1 > rx2 || sy2 < ry1 || sy1 > ry2);
    });
  };

  const LABEL_H = 11;  // 9px font + small descent / breathing room
  const GAP     = 2;   // bar → label vertical offset

  for (const task of state.tasks) {
    if (task.is_milestone) continue;
    if (inferredAnchorKey(task)) continue;
    if (isBacklogTask(task)) continue;
    if (!task.start_date || !task.end_date) continue;

    const wrap = svg.querySelector(`.bar-wrapper[data-id="${task.id}"]`);
    if (!wrap) continue;
    const bar = wrap.querySelector('.bar');
    if (!bar) continue;

    const barX = +bar.getAttribute('x');
    const barY = +bar.getAttribute('y');
    const barW = +bar.getAttribute('width');
    const barH = +bar.getAttribute('height');
    const cx = barX + barW / 2;

    const alloc = Math.max(0, Math.min(100, Number(task.allocation == null ? 90 : task.allocation)));
    const durDays = Number(task.duration_days) || 0;
    const wks = Math.round(durDays / 5);

    // v4.58: SINGLE COMBINED LABEL — "85% · 8w" — feels like one pill.
    // Placement priority changed to match user feedback:
    //   1. INSIDE the bar at the right end (halo so it reads on any color).
    //   2. JUST OUTSIDE on the LEFT of the bar — preferred outside slot
    //      because frappe-gantt drops the bar's NAME outside-right when
    //      the bar is too narrow. Putting our label to the right would
    //      collide with the name; putting it to the left is clear.
    //   3. BELOW the bar at the right end (right-aligned).
    //   4. ABOVE the bar at the right end (right-aligned).
    // For OUTSIDE placements we draw a white "occluder" rect behind the
    // text so any arrow segment passing through the label visually
    // disappears under it. Reads cleanly even when an arrow enters the
    // bar from the left right where our left-label sits.
    const allocText = (alloc > 0) ? `${alloc}%` : '';
    const durText   = (wks > 0)   ? `${wks}w`   : '';
    if (!allocText && !durText) continue;
    const metaText = [allocText, durText].filter(Boolean).join(' · ');

    // BAR-META LAYOUT CASCADE (settled in v5.0).
    //
    //   Terminology:
    //     meta = alloc/duration pill ("85% · 8w")
    //     name = task description (the bar-label rendered by frappe-gantt)
    //     bar  = Gantt bar rectangle
    //
    //   Gaps (all 3 px):
    //     INSIDE_PADDING = bar-left edge ↔ inside-left meta-left edge.
    //     INSIDE_GAP     = meta-right ↔ name-left  AND  name-right ↔ bar-right.
    //     OUTSIDE_GAP    = outside-left meta pill right edge ↔ bar-left edge.
    //
    //   Algorithm — measure where the name actually IS, don't predict:
    //     1. clipBarLabels has already centered the bar-label in its bar by
    //        the time we run, so we can read its real rendered rect via
    //        getBoundingClientRect.
    //     2. metaW is computed via a per-character table calibrated for
    //        bold-9 px sans-serif (digits 5.5, % 6.5, space 2.5, · 3, w 6.5)
    //        plus 3 px stroke halo + safety. The meta text is bounded
    //        ("XX% · YYw"), so the per-char table is reliable without
    //        depending on any browser measurement API (every one tried —
    //        getBBox, getComputedTextLength, getBoundingClientRect, canvas
    //        measureText — was returning widths smaller than actual on at
    //        least some bars).
    //     3. availLeftPx = nameRect.left - barRect.left = the actual gap
    //        between the bar's left edge and the rendered name's left edge.
    //        This is the space the meta can use.
    //
    //   Cascade:
    //     Step 1 — meta inside-left, name stays centered in bar.
    //              Trigger: availLeftPx ≥ metaW + INSIDE_PADDING + INSIDE_GAP.
    //     Step 2 — meta inside-left, name shifts to be centered between
    //              meta-right and bar-right (symmetric gaps on both sides).
    //              Trigger: (barW - INSIDE_PADDING - metaW) ≥ nameW + 2·INSIDE_GAP.
    //              IMPLEMENTATION: the bar-label's x attribute stays at the
    //              centered position; the shift is applied via CSS
    //              `transform: translateX(...)`. Why: setAttribute('x', …)
    //              was updating the SVG DOM (getBoundingClientRect picked
    //              up the new x) but the rendered glyphs visually stayed
    //              at the centered position. CSS transforms hook into the
    //              paint pipeline directly, so the visible text actually
    //              moves.
    //     Step 3 — meta OUTSIDE-left, name centered in bar.
    //              Trigger: barW ≥ nameW + 2·INSIDE_GAP.
    //     Step 4 — both outside. Meta outside-left, name ALWAYS outside-right.
    const INSIDE_PADDING = 3;
    const INSIDE_GAP     = 3;
    const OUTSIDE_GAP    = 3;
    const PILL_PAD       = 2;
    // text right edge = barX - SAME_ROW_GAP, pill right edge = barX - OUTSIDE_GAP.
    const SAME_ROW_GAP   = OUTSIDE_GAP + PILL_PAD;

    const barLabel = wrap.querySelector('.bar-label');
    if (!barLabel) continue;

    // Force a known font on the meta SO IT MATCHES what canvas measures.
    // Via inline style so it beats any CSS rule (frappe-gantt's stylesheet
    // sets font-family on .gantt text — would override a presentation
    // attribute).
    const metaEl = document.createElementNS(SVG_NS, 'text');
    metaEl.setAttribute('class', 'sdc-bar-meta');
    metaEl.setAttribute('x', String(barX + INSIDE_PADDING));
    metaEl.setAttribute('y', String(barY + barH / 2));
    metaEl.setAttribute('text-anchor', 'start');
    metaEl.setAttribute('dominant-baseline', 'central');
    metaEl.setAttribute('fill', '#1e293b');
    metaEl.setAttribute('paint-order', 'stroke');
    metaEl.setAttribute('stroke', 'rgba(255,255,255,0.9)');
    metaEl.setAttribute('stroke-width', '2.5');
    metaEl.setAttribute('stroke-linejoin', 'round');
    metaEl.style.fontFamily = 'sans-serif';
    metaEl.style.fontSize   = '9px';
    metaEl.style.fontWeight = '700';
    metaEl.style.pointerEvents = 'none';
    metaEl.textContent = metaText;
    group.appendChild(metaEl);

    // Center name inside the bar — sets the bar-label to its natural
    // centered-in-bar position. Used for Step 1 (default) and Step 3.
    const centerNameInBar = () => {
      barLabel.setAttribute('x', String(barX + barW / 2));
      barLabel.setAttribute('text-anchor', 'middle');
      barLabel.style.textAnchor = '';
      barLabel.style.transform = '';  // Clear any prior Step-2 shift transform.
      barLabel.classList.remove('bar-label-outside');
    };

    // Move metaEl from inside-left to outside-left + swap halo for pill occluder.
    const moveMetaOutside = () => {
      metaEl.setAttribute('x', String(barX - SAME_ROW_GAP));
      metaEl.setAttribute('text-anchor', 'end');
      metaEl.removeAttribute('paint-order');
      metaEl.removeAttribute('stroke');
      metaEl.removeAttribute('stroke-width');
      metaEl.removeAttribute('stroke-linejoin');
      addPillOccluder(group, metaEl, PILL_PAD);
    };

    // Meta width — PER-CHARACTER estimate. v4.95's first-pass values were
    // about 20 % too generous (visible by the magenta debug tick sitting
    // well past the rendered meta's right edge), so v4.96 trims them
    // proportionally. The meta text is bounded — digits, "%", spaces, "·",
    // "w" — so a per-char table works better than any browser measurement
    // API. Deterministic, slightly conservative, safe from overlap.
    const metaCharW = (ch) => {
      if (/[0-9]/.test(ch)) return 5.5;   // digits 0–9 (was 7)
      if (ch === '%')        return 6.5;   // percent sign (was 8)
      if (ch === ' ')        return 2.5;   // space (was 3)
      if (ch === '·')        return 3;     // middle dot (was 4)
      if (ch === 'w')        return 6.5;   // weeks marker (was 8)
      return 5.5;                          // any other char (was 7)
    };
    let metaTextW = 0;
    for (const ch of metaText) metaTextW += metaCharW(ch);
    // + 3 px = stroke halo (~2.5 px) + tiny safety margin.
    const metaW = metaTextW + 3;

    // Center the bar-label as Step 1 would. clipBarLabels may have placed it
    // outside if the bar is narrower than nameW + PAD — force back to center
    // so we can read its real centered-in-bar position. The browser does a
    // layout pass when we read getBoundingClientRect below.
    centerNameInBar();

    // === READ THE NAME'S ACTUAL RENDERED POSITION ===
    // This is the key change from prior versions: we don't COMPUTE where the
    // name will be from a (potentially wrong) measured width — we READ where
    // the browser actually placed it. getBoundingClientRect on the already-
    // laid-out bar-label is reliable.
    const barRect   = bar.getBoundingClientRect();
    const nameRect  = barLabel.getBoundingClientRect();
    // Gap from bar's left edge to the rendered name's left edge — this is
    // the space available for the meta on the inside-left.
    const availLeftPx = nameRect.left - barRect.left;
    // Gap from the rendered name's right edge to bar's right edge — used
    // for Step 2 "does the name still fit if we re-center it?" check below.
    const availRightPx = barRect.right - nameRect.right;
    const nameWidthPx = nameRect.width;

    // === CASCADE — decide which step ===
    const step1Works = availLeftPx >= metaW + INSIDE_PADDING + INSIDE_GAP;
    const step2AvailableForName = barW - INSIDE_PADDING - metaW;
    const step2Works = step2AvailableForName >= nameWidthPx + 2 * INSIDE_GAP;
    const step3Works = barW >= nameWidthPx + 2 * INSIDE_GAP;

    if (step1Works) {
      // Step 1 — name already centered (centerNameInBar above), meta at
      // default inside-left position. Nothing more to do.
    } else if (step2Works) {
      // Step 2 — meta stays inside-left, name shifts right so it's centered
      // between meta-right and bar-right.
      //
      // Why a CSS transform and not setAttribute('x', ...): on at least some
      // browsers/renderers, setAttribute('x', ...) on a bar-label updates
      // the SVG DOM (getBoundingClientRect picks up the new x) but the
      // rendered glyphs visually stay at the old x — paint and layout
      // disagree. CSS `transform: translateX(...)` hooks into the paint
      // pipeline directly and the visible text actually moves. The x
      // attribute stays at the centered position; the transform supplies
      // the shift.
      const metaInsideRight = barX + INSIDE_PADDING + metaW;
      const barRightEdge    = barX + barW;
      const nameCenterX     = (metaInsideRight + barRightEdge) / 2;
      const shiftX          = nameCenterX - (barX + barW / 2);
      barLabel.setAttribute('x', String(barX + barW / 2));
      barLabel.setAttribute('text-anchor', 'middle');
      barLabel.style.textAnchor = '';
      barLabel.style.transform = `translateX(${shiftX}px)`;
      barLabel.classList.remove('bar-label-outside');
    } else if (step3Works) {
      // Step 3 — meta OUTSIDE-left. Name centered in bar (it now has full
      // width to use).
      moveMetaOutside();
      centerNameInBar();
    } else {
      // Step 4 — both outside.
      moveMetaOutside();
      barLabel.setAttribute('x', String(barX + barW + 6));
      barLabel.setAttribute('text-anchor', 'start');
      barLabel.style.textAnchor = '';
      barLabel.style.transform = '';
      barLabel.classList.add('bar-label-outside');
    }
  }
}

// Floating stat card in the top-right of the Gantt area. Shows project stats:
// Duration (PO→FAT in calendar weeks), labor-weighted % Complete, and FAT
// date with an optional baseline-variance chip. Hidden on All-projects since
// these are per-project.
//
// (View options used to live here too — moved to the View pill in the toolbar
// in v3.50 so this popup stays focused on read-only project stats.)
function renderProjectStatsPopup() {
  const split = document.getElementById('schedule-split');
  if (!split) return;
  let popup = split.querySelector('#project-stats-popup');
  const project = state.filters.project;
  if (!project) {
    if (popup) popup.remove();
    return;
  }
  if (!popup) {
    popup = document.createElement('div');
    popup.id = 'project-stats-popup';
    popup.className = 'project-stats-popup';
    split.appendChild(popup);
  }
  // Single-machine view? Then Duration / Complete / FAT all scope to
  // that machine. Empty subset or multi-machine = whole-project view.
  const subset = state.filters.machinesSubset || [];
  const activeMachine = subset.length === 1 ? subset[0] : null;
  const stats = computeProjectStats(project, activeMachine);
  const tasks = state.tasks.filter(t => t.project === project);
  const po = tasks.find(t => inferredAnchorKey(t) === 'receipt_of_po');
  // FAT for the active scope. stats.fat returns the machine-specific
  // anchor when activeMachine is set; falls back to oldest project FAT.
  const fat = stats.fat || tasks.find(t => inferredAnchorKey(t) === 'fat');
  // Duration — current AND quoted. Quoted comes from (in priority):
  //   1. quote.sold_delivery_weeks — the explicit number Dan enters in
  //      the Quote vs Schedule modal ("this is what we sold").
  //   2. baseline_PO → baseline_FAT span (calculated from the saved
  //      baseline snapshot).
  //   3. nothing — falls back to scheduled-only.
  // Format: "Q / S" with quoted muted, scheduled bold. Falls back to
  // a single number when there's no quoted reference. Half-week
  // rounding per the no-arbitrary-week-fractions rule.
  const _toHalfWeek = (days) => Math.round((days / 7) * 2) / 2;
  // Kick off async quote load — re-renders this popup when it
  // resolves so the next paint includes sold_delivery_weeks.
  if (!(project in state.projectQuotes)) {
    loadProjectQuote(project).then(() => {
      try { renderProjectStatsPopup(); } catch (_) {}
    });
  }
  const _quote = state.projectQuotes[project] || null;
  const _soldW = _quote && Number.isFinite(Number(_quote.sold_delivery_weeks))
    ? Number(_quote.sold_delivery_weeks)
    : null;
  let durationLabel = '—';
  if (po && fat && po.start_date && fat.start_date) {
    const days = Math.round((new Date(fat.start_date + 'T00:00:00') - new Date(po.start_date + 'T00:00:00')) / 86400000);
    const schedW = Math.max(0, _toHalfWeek(days));
    let quotedW = null;
    if (_soldW != null && _soldW > 0) {
      quotedW = Math.round(_soldW * 2) / 2;
    } else if (po.baseline_start_date && fat.baseline_start_date) {
      const qDays = Math.round((new Date(fat.baseline_start_date + 'T00:00:00') - new Date(po.baseline_start_date + 'T00:00:00')) / 86400000);
      quotedW = Math.max(0, _toHalfWeek(qDays));
    }
    // Always show Q / S when a quoted reference exists — even when
    // they match — so the PM can confirm the sold value was saved.
    // Was showing only the scheduled number when they were equal,
    // which made Dan think the sold input didn't stick.
    if (quotedW != null) {
      durationLabel = `<span class="popup-vs"><span class="popup-vs-q">${quotedW}W</span> <span class="popup-vs-sep">/</span> <span class="popup-vs-s">${schedW}W</span></span>`;
    } else {
      durationLabel = `${schedW}W`;
    }
  }
  // Quoted FAT — computed as PO start + (sold weeks × 7 calendar days)
  // when a sold duration is set, OR baseline_FAT date when a baseline
  // exists. Used in the FAT row alongside the live scheduled date so
  // the PM sees "FAT we sold vs FAT we'll hit".
  let quotedFatDate = null;
  if (po && po.start_date) {
    if (_soldW != null && _soldW > 0) {
      // PO start + N*7 calendar days (calendar weeks, matches how the
      // sold duration was negotiated with the customer).
      const t = new Date(po.start_date + 'T00:00:00');
      t.setDate(t.getDate() + Math.round(_soldW * 7));
      quotedFatDate = t.toISOString().slice(0, 10);
    } else if (fat && fat.baseline_start_date) {
      quotedFatDate = fat.baseline_start_date;
    }
  }
  // Expected % at today's date — labor-weighted across all tasks. For
  // each task, expected % = (elapsed business days from start / total
  // business days) × 100, clamped to 0-100. Roll up the same way the
  // actual % does (weighted by duration). Done tasks count as 100%
  // expected since their window is past.
  let expectedPct = null;
  {
    let wSum = 0, dSum = 0;
    for (const t of tasks) {
      if (t.is_milestone) continue;
      if (inferredAnchorKey(t)) continue;
      const d = Number(t.duration_days);
      if (!d || d <= 0) continue;
      if (!t.start_date || !t.end_date) continue;
      const sMs = new Date(t.start_date + 'T00:00:00').getTime();
      const eMs = new Date(t.end_date + 'T00:00:00').getTime();
      const todayLocal = new Date(); todayLocal.setHours(0, 0, 0, 0);
      const tMs = todayLocal.getTime();
      let pct = 0;
      if (tMs >= eMs) pct = 100;
      else if (tMs <= sMs) pct = 0;
      else {
        const span = Math.max(1, eMs - sMs);
        pct = Math.round(((tMs - sMs) / span) * 100);
      }
      dSum += d;
      wSum += d * pct;
    }
    expectedPct = dSum > 0 ? Math.round(wSum / dSum) : null;
  }
  // If we're viewing a per-machine FAT and there's a PREVIOUS machine
  // (e.g. viewing M2 → compare to M1.FAT), show a small delta chip
  // "+N wks vs M1" — that's the typical "one machine every 3 weeks"
  // staggered-delivery view.
  let machineDeltaChip = '';
  if (activeMachine) {
    const allMachines = Array.from(new Set(tasks.filter(t => t.machine).map(t => t.machine)))
      .sort((a, b) => a.localeCompare(b, undefined, { numeric: true }));
    const idx = allMachines.indexOf(activeMachine);
    if (idx > 0) {
      const prevMachine = allMachines[idx - 1];
      const prevFat = tasks.find(t => t.machine === prevMachine && inferredAnchorKey(t) === 'fat');
      if (prevFat && prevFat.start_date && fat && fat.start_date) {
        const days = Math.round((new Date(fat.start_date + 'T00:00:00') - new Date(prevFat.start_date + 'T00:00:00')) / 86400000);
        // Half-week snap — Dan's rule: week values must end in 0 or
        // .5 only. Never show 0.6W / 1.2W / 6.8W etc.
        const wks = Math.round((days / 7) * 2) / 2;
        if (wks !== 0) {
          machineDeltaChip = ` <span class="popup-machine-delta" title="${escapeHtml(activeMachine)}.FAT vs ${escapeHtml(prevMachine)}.FAT">${wks >= 0 ? '+' : ''}${wks}W vs ${escapeHtml(prevMachine)}</span>`;
        }
      }
    }
  }
  const pctLabel = stats.percentComplete != null ? `${stats.percentComplete}%` : '—';
  // Header label — show which machine (if any) the stats scope to.
  const scopeLabel = activeMachine ? `${activeMachine} only` : 'All machines';
  // FAT row: show the actual date plus an optional variance chip when a
  // baseline is set. Variance rounds DAYS → WEEKS (5 business days per week)
  // so the chip reads as "+1 wk / -2 wks / 0 wks" instead of "+3d late /
  // -7d early" — matches how everything else in this app talks about time
  // (estimate sheets, durations, etc. are all weekly). Rounding is to-nearest:
  //   0 days → 0 wks
  //   1-2 days → 0 wks (rounds down)
  //   3-7 days → 1 wk
  //   8-12 days → 2 wks
  //   ...
  // FAT row — show Quoted / Scheduled when there's a quoted FAT to
  // compare against, otherwise just the scheduled date. Same Q/S
  // visual pattern as Duration.
  const schedFatStr = fat?.start_date ? fmtDate(fat.start_date) : '—';
  let fatDateLabel;
  if (quotedFatDate && quotedFatDate !== fat?.start_date) {
    fatDateLabel = `<span class="popup-vs"><span class="popup-vs-q">${escapeHtml(fmtDate(quotedFatDate))}</span> <span class="popup-vs-sep">/</span> <span class="popup-vs-s">${escapeHtml(schedFatStr)}</span></span>`;
  } else if (quotedFatDate) {
    // Same date — still show the pair so the PM can confirm.
    fatDateLabel = `<span class="popup-vs"><span class="popup-vs-q">${escapeHtml(fmtDate(quotedFatDate))}</span> <span class="popup-vs-sep">/</span> <span class="popup-vs-s">${escapeHtml(schedFatStr)}</span></span>`;
  } else {
    fatDateLabel = schedFatStr;
  }
  let fatVarChip = '';
  if (stats.fatVariance != null) {
    // Half-week snap per Dan's no-arbitrary-week-fractions rule.
    const wks = Math.round((stats.fatVariance / 5) * 2) / 2;
    if (wks === 0)       fatVarChip = '<span class="popup-fat-var stat-ok">0W</span>';
    else if (wks > 0)    fatVarChip = `<span class="popup-fat-var stat-late">+${wks}W</span>`;
    else                  fatVarChip = `<span class="popup-fat-var stat-early">${wks}W</span>`;
  }

  // Multi-machine projects: tell the user what these numbers cover.
  // Single-machine project: no scope header (looks the same as before).
  const hasMultiMachine = isMultiMachineProject();
  const scopeHeader = hasMultiMachine
    ? `<div class="popup-scope">${escapeHtml(scopeLabel)}</div>`
    : '';
  // Sales projects are estimates, not live work — there's no real
  // % complete to roll up, so drop the Complete row entirely on the
  // Sales workspace. Duration + FAT still show because those are
  // schedule-level facts the user always wants.
  const isSalesProject = projectWorkspace(project) === 'Sales';
  // Complete row — Q on LEFT (expected, muted), S on RIGHT (actual,
  // bold). Same column order as Duration and FAT so the header row
  // at the top of the popup applies consistently.
  let completeLabel = pctLabel;
  if (stats.percentComplete != null && expectedPct != null) {
    const actualW = `${stats.percentComplete}%`;
    const expectedW = `${expectedPct}%`;
    completeLabel = `<span class="popup-vs"><span class="popup-vs-q">${expectedW}</span> <span class="popup-vs-sep">/</span> <span class="popup-vs-s">${actualW}</span></span>`;
  }
  const completeRow = isSalesProject ? '' : `
    <div class="popup-row">
      <span class="popup-label">Complete</span>
      <span class="popup-value" title="Expected % at today's date (left, muted) / Actual % complete (right, bold). Labor-weighted across non-anchor tasks.">${completeLabel}</span>
    </div>`;
  // Penalty clause row — appears when the quote has has_penalty_clause
  // checked. Date = PO receipt date + penalty_clause_weeks calendar
  // weeks. Single value (no Q/S split since this is just a calendar
  // event derived from the contract).
  let penaltyRow = '';
  if (_quote && _quote.has_penalty_clause && _quote.penalty_clause_weeks != null && po && po.start_date) {
    const wks = Number(_quote.penalty_clause_weeks);
    if (Number.isFinite(wks) && wks > 0) {
      const d = new Date(po.start_date + 'T00:00:00');
      d.setDate(d.getDate() + Math.round(wks * 7));
      const dateStr = fmtDate(d.toISOString().slice(0, 10));
      const isPast = fat?.start_date && fat.start_date > d.toISOString().slice(0, 10);
      penaltyRow = `
        <div class="popup-row">
          <span class="popup-label">Penalty</span>
          <span class="popup-value" title="Penalty clause start date — PO + ${wks} weeks. Set on Quote vs Schedule → 'Has penalty clause'.">${escapeHtml(dateStr)}${isPast ? ' <span class="popup-fat-var stat-late">past</span>' : ''}</span>
        </div>`;
    }
  }
  // Column header — appears at the top of the popup so the user knows
  // which side is Quoted vs Scheduled. Skipped when no row has a
  // Q/S split (i.e. no baseline + no sold value).
  const hasAnyVs = (durationLabel.includes('popup-vs') || completeLabel.includes('popup-vs') || fatDateLabel.includes('popup-vs'));
  const colHeader = hasAnyVs ? `
    <div class="popup-row popup-row-header">
      <span class="popup-label"></span>
      <span class="popup-value popup-header-cols">
        <span class="popup-vs-q">Quoted</span>
        <span class="popup-vs-sep">/</span>
        <span class="popup-vs-s">Scheduled</span>
      </span>
    </div>` : '';
  // Simple vs Advanced mode — persisted in localStorage. Simple
  // shows only the live scheduled values (Duration / Complete / FAT)
  // — no Q/S split, no header, no penalty row. Advanced shows the
  // full comparison + penalty. Per Dan's request: default simple,
  // expand to advanced via the toggle in the top-right.
  let popupMode = 'simple';
  try { popupMode = localStorage.getItem('sdcStatsPopupMode') || 'simple'; } catch (_) {}
  if (popupMode !== 'advanced') popupMode = 'simple';
  const toggleLabel = popupMode === 'advanced' ? '▾ Simple' : '▸ Advanced';
  const toggleTitle = popupMode === 'advanced'
    ? 'Collapse — show only the live schedule numbers.'
    : 'Expand — show Quoted vs Scheduled comparison + penalty clause.';

  if (popupMode === 'simple') {
    // Simple = just the scheduled values, single column per row.
    const schedDur = (() => {
      if (!po || !fat || !po.start_date || !fat.start_date) return '—';
      const days = Math.round((new Date(fat.start_date + 'T00:00:00') - new Date(po.start_date + 'T00:00:00')) / 86400000);
      return `${Math.max(0, _toHalfWeek(days))}W`;
    })();
    const simpleCompleteRow = isSalesProject ? '' : `
      <div class="popup-row">
        <span class="popup-label">Complete</span>
        <span class="popup-value">${pctLabel}</span>
      </div>`;
    popup.innerHTML = `
      <button type="button" class="popup-mode-toggle" data-action="popup-toggle" title="${escapeHtml(toggleTitle)}">${escapeHtml(toggleLabel)}</button>
      ${scopeHeader}
      <div class="popup-row">
        <span class="popup-label">Duration</span>
        <span class="popup-value">${schedDur}${machineDeltaChip}</span>
      </div>
      ${simpleCompleteRow}
      <div class="popup-row">
        <span class="popup-label">FAT</span>
        <span class="popup-value">${schedFatStr}${fatVarChip}</span>
      </div>
    `;
  } else {
    popup.innerHTML = `
      <button type="button" class="popup-mode-toggle" data-action="popup-toggle" title="${escapeHtml(toggleTitle)}">${escapeHtml(toggleLabel)}</button>
      ${scopeHeader}
      ${colHeader}
      <div class="popup-row">
        <span class="popup-label">Duration</span>
        <span class="popup-value" title="Sold delivery (left, muted) / Current scheduled PO→FAT span (right, bold). Half-week steps.">${durationLabel}${machineDeltaChip}</span>
      </div>
      ${completeRow}
      <div class="popup-row">
        <span class="popup-label">FAT</span>
        <span class="popup-value" title="Sold FAT (PO + sold weeks; or baseline FAT) on the left, scheduled ${activeMachine ? activeMachine + '.' : ''}FAT on the right. Chip shows variance.">
          ${fatDateLabel}${fatVarChip}
        </span>
      </div>
      ${penaltyRow}
    `;
  }
  // Wire the toggle button — flips mode + re-renders so the new
  // markup paints in place. localStorage persists across reloads.
  const toggleBtn = popup.querySelector('[data-action="popup-toggle"]');
  if (toggleBtn && !toggleBtn.dataset.bound) {
    toggleBtn.dataset.bound = '1';
    toggleBtn.addEventListener('click', () => {
      const next = popupMode === 'advanced' ? 'simple' : 'advanced';
      try { localStorage.setItem('sdcStatsPopupMode', next); } catch (_) {}
      renderProjectStatsPopup();
    });
  }
}

// ---------- Today line ----------
// Vertical dotted red line at today's date, spanning from the date header to the
// bottom of the chart. Lets the user see at a glance "where are we right now?"
// vs every bar. Hidden when today falls outside the rendered date range (e.g.
// archived projects far in the past).
function drawTodayLine() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;
  svg.querySelectorAll('.today-line, .today-line-label').forEach(el => el.remove());
  if (!state.gantt || !state.gantt.gantt_start) return;

  const g = state.gantt;
  const startMs = new Date(g.gantt_start).getTime();
  const cw = g.options.column_width;
  const mode = g.options.view_mode || 'Week';
  const step = mode === 'Day' ? 1 : mode === 'Week' ? 7 : 30;
  const pxPerDay = cw / step;

  // Snap "today" to start-of-day. If today is a weekend, snap forward to
  // Monday (no work happens on weekends anyway, so the today line lives
  // on Monday's column).
  const todayDt = new Date();
  let todayMs = Date.UTC(todayDt.getUTCFullYear(), todayDt.getUTCMonth(), todayDt.getUTCDate());
  let todayDow = new Date(todayMs).getUTCDay();
  if (todayDow === 6) todayMs += 2 * 86400000;     // Sat → Mon
  else if (todayDow === 0) todayMs += 1 * 86400000;// Sun → Mon
  const days = (todayMs - startMs) / 86400000;
  if (days < 0) return; // today is BEFORE the chart's earliest date
  // Use work-day offset so the today line lands on the right column in
  // the compressed work-day Gantt.
  const todayStr = new Date(todayMs).toISOString().slice(0, 10);
  const x = workDayOffset(todayStr, g.gantt_start) * pxPerDay;
  const svgW = +svg.getAttribute('width') || 8000;
  if (x > svgW) return;  // today is past the right edge of the chart

  // Find the topmost bar to determine where the chart content starts. yTop sits
  // just below the date header — same approach the financial overlay uses.
  let firstBarY = Infinity;
  for (const bar of svg.querySelectorAll('.bar-wrapper:not(.phantom-pad) .bar')) {
    const y = +bar.getAttribute('y');
    if (y < firstBarY) firstBarY = y;
  }
  const yTop = Number.isFinite(firstBarY) ? Math.max(40, firstBarY - 16) : 50;
  const svgH = +svg.getAttribute('height') || 600;

  const line = document.createElementNS(SVG_NS, 'line');
  line.setAttribute('class', 'today-line');
  line.setAttribute('x1', x);
  line.setAttribute('x2', x);
  line.setAttribute('y1', yTop);
  line.setAttribute('y2', svgH);
  // SDC blue — primary brand color. Distinct from the lime anchor diamonds
  // and the green financial overlay lines.
  line.setAttribute('stroke', '#1574c4');
  line.setAttribute('stroke-width', '1.4');
  line.setAttribute('stroke-dasharray', '3 3');
  line.setAttribute('opacity', '0.85');
  line.setAttribute('pointer-events', 'none');
  svg.appendChild(line);

  // Tiny "Today" label at the top of the line. SDC navy text on a white halo
  // so it stays readable wherever it lands.
  const label = document.createElementNS(SVG_NS, 'text');
  label.setAttribute('class', 'today-line-label');
  label.setAttribute('x', x + 4);
  label.setAttribute('y', yTop + 11);
  label.setAttribute('font-size', '10');
  label.setAttribute('font-weight', '700');
  label.setAttribute('fill', '#061d39');     // SDC navy
  label.setAttribute('stroke', '#ffffff');
  label.setAttribute('stroke-width', '3');
  label.setAttribute('paint-order', 'stroke');
  label.setAttribute('pointer-events', 'none');
  label.textContent = 'Today';
  svg.appendChild(label);
}

// ---------- Baseline ghosts ----------
// For every task with baseline_start_date + baseline_end_date set, draw a dashed
// outline at the baseline's date range, behind the current bar. The outline
// uses the SAME color family as the task itself (fill for the dashed stroke,
// stroke shade for the drift label) so it reads as a ghost of THAT specific
// task, not a generic purple overlay. A bare "+Nd" / "−Nd" label sits adjacent
// to the bar — no pill background, no "vs baseline" wording.
function drawBaselineGhosts() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;
  svg.querySelectorAll('.baseline-ghost, .baseline-drift-label').forEach(el => el.remove());
  if (!state.showBaseline) return;
  if (!state.gantt || !state.gantt.gantt_start) return;

  const g = state.gantt;
  const startMs = new Date(g.gantt_start).getTime();
  const cw = g.options.column_width;
  const mode = g.options.view_mode || 'Week';
  const step = mode === 'Day' ? 1 : mode === 'Week' ? 7 : 30;
  const pxPerDay = cw / step;

  // Signed business-day offset between two ISO dates. Returns 0 for same-day
  // (businessDaysBetween itself is inclusive, hence the -1 correction).
  const driftDays = (fromISO, toISO) => {
    if (!fromISO || !toISO || fromISO === toISO) return 0;
    const sign = toISO > fromISO ? 1 : -1;
    const days = businessDaysBetween(
      sign > 0 ? fromISO : toISO,
      sign > 0 ? toISO   : fromISO,
    );
    return sign * Math.max(0, days - 1);
  };

  for (const task of state.tasks) {
    if (!task.baseline_start_date || !task.baseline_end_date) continue;
    if (!task.start_date || !task.end_date) continue;
    const wrap = svg.querySelector(`.bar-wrapper[data-id="${task.id}"]`);
    if (!wrap) continue;
    const bar = wrap.querySelector('.bar');
    if (!bar) continue;

    const barY = +bar.getAttribute('y');
    const barH = +bar.getAttribute('height');
    const barX = +bar.getAttribute('x');
    const barW = +bar.getAttribute('width');

    const bsMs = new Date(task.baseline_start_date + 'T00:00:00').getTime();
    const beMs = new Date(task.baseline_end_date + 'T00:00:00').getTime();
    if (Number.isNaN(bsMs) || Number.isNaN(beMs)) continue;

    // Anchor the ghost to the bar's ACTUAL x + scale instead of recomputing an
    // absolute x from gantt_start. The gantt_start-based math drifted out of sync
    // with frappe's real bar placement and threw the ghost months off (e.g. a
    // task pushed +2wk showed its baseline far to the RIGHT instead of just left).
    // For a real bar, derive px/day from the bar's own width ÷ its duration; for
    // milestones (fixed-width diamonds) fall back to the global px/day.
    const csMs = new Date(task.start_date + 'T00:00:00').getTime();
    const ceMs = new Date(task.end_date + 'T00:00:00').getTime();
    const curDurDays = (ceMs - csMs) / 86400000 + 1;
    const ppd = (!task.is_milestone && curDurDays > 0 && barW > 0) ? (barW / curDurDays) : pxPerDay;
    const ghostX = barX + ((bsMs - csMs) / 86400000) * ppd;
    const ghostW = Math.max(2, ((beMs - bsMs) / 86400000 + 1) * ppd);

    const startDrift = driftDays(task.baseline_start_date, task.start_date);
    const endDrift   = driftDays(task.baseline_end_date,   task.end_date);
    if (startDrift === 0 && endDrift === 0) continue;

    // Pull live colors off the bar so the ghost matches THIS task's hue. Fill
    // = the light shade (used as the dashed stroke); stroke = the dark shade
    // (used as the drift-label text). Falls back to neutral slate if the bar
    // somehow doesn't have computed colors.
    const cs = window.getComputedStyle(bar);
    const ghostStroke = (cs.fill && cs.fill !== 'none' && cs.fill !== 'rgb(0, 0, 0)')
      ? cs.fill : '#64748b';
    const labelFill = (cs.stroke && cs.stroke !== 'none' && cs.stroke !== 'rgb(0, 0, 0)')
      ? cs.stroke : '#334155';

    const ghost = document.createElementNS(SVG_NS, 'rect');
    ghost.setAttribute('class', 'baseline-ghost');
    ghost.setAttribute('x', ghostX);
    ghost.setAttribute('y', barY);
    ghost.setAttribute('width', ghostW);
    ghost.setAttribute('height', barH);
    ghost.setAttribute('rx', 3);
    ghost.setAttribute('ry', 3);
    ghost.setAttribute('fill', 'none');
    ghost.setAttribute('stroke', ghostStroke);
    ghost.setAttribute('stroke-width', '1.5');
    ghost.setAttribute('stroke-dasharray', '5 3');
    ghost.setAttribute('pointer-events', 'none');
    // Top layer (appendChild, per CLAUDE.md) so the dashed baseline outline —
    // especially where it would have ENDED — stays visible on top of the current
    // bar instead of being hidden behind it. It's a fill:none outline, so the
    // bar's label underneath still reads.
    wrap.appendChild(ghost);

    // Drift label — bare "+Nw" / "−Nw", ALWAYS placed to the LEFT of the bar
    // so it never collides with the schedule-status chip on the right.
    // CONSISTENT for every task with a baseline: the FINISH variance is the
    // signal (how late/early it now ENDS vs the plan-of-record); when only
    // the start moved, fall back to start variance. Milestones get the label
    // too, just offset further left so it clears the diamond shape.
    const drift = endDrift !== 0 ? endDrift : startDrift;
    const driftMag = Math.abs(drift);
    if (driftMag > 0) {
      const isLate = drift > 0;
      // Weeks + half-weeks, never days (business-days ÷ 5, half-week snap).
      const driftWks = (Math.round((driftMag / 5) * 2) / 2) || 0.5;
      const labelText = `${isLate ? '+' : '−'}${driftWks}w`;
      const text = document.createElementNS(SVG_NS, 'text');
      text.setAttribute('class', 'baseline-drift-label');
      // Spine anchors (PO / FAT / Ship…) draw their DATE to the left of the
      // diamond — the chip must clear both the diamond AND that ~62px date
      // text. Plain milestones only need to clear the diamond; bars just sit
      // 4px off their left edge.
      const msClear = Math.max(10, barH * 0.8);
      const leftOffset = !task.is_milestone ? 4
        : (inferredAnchorKey(task) ? msClear + 68 : msClear);
      text.setAttribute('x', barX - leftOffset);
      text.setAttribute('y', barY + barH / 2 + 3);
      text.setAttribute('text-anchor', 'end');
      text.setAttribute('font-size', '10');
      text.setAttribute('font-weight', '700');
      // Behind (later than baseline) = red; ahead (earlier) = green.
      text.setAttribute('fill', isLate ? '#dc2626' : '#15803d');
      text.setAttribute('stroke', '#ffffff');
      text.setAttribute('stroke-width', '3');
      text.setAttribute('paint-order', 'stroke');
      text.setAttribute('pointer-events', 'none');
      text.textContent = labelText;
      svg.appendChild(text);
    }
  }
}

// ---------- Financial overlay ----------
// When the $ Financial toggle is on, draw a vertical line through the whole chart
// at each financial milestone's date. Line is DASHED for not-yet-sent invoices
// and SOLID once the Sent checkbox is on (the `paid` DB field is reused for this
// flag — name's legacy). A small label at the top names the milestone + percent.
// Renders ON TOP of bars/arrows so it's always readable.
// Short red vertical line at the penalty-clause start date — appears
// only when the active project's quote has has_penalty_clause checked
// AND penalty_clause_weeks set. Spans ~2 rows above and below the
// FAT bar (full-height would dominate the chart) with a "Penalty
// starts" label so the PM sees both the date and what it means.
// Wrapped in try/catch per CLAUDE.md — render chain must continue
// even if anything in here throws.
function drawPenaltyClauseLine() {
  try {
    const svg = document.querySelector('#gantt-container .gantt');
    if (!svg) return;
    svg.querySelectorAll('.sdc-penalty-line').forEach(el => el.remove());
    if (!state.gantt || !state.gantt.gantt_start) return;
    const project = state.filters.project;
    if (!project) return;
    // Self-load the quote on cache miss so the penalty line shows on
    // the first Gantt render, not just after the user opens the
    // Quote modal. Re-draws when the fetch resolves.
    if (!(project in state.projectQuotes)) {
      loadProjectQuote(project).then(() => {
        try { drawPenaltyClauseLine(); } catch (_) {}
      });
      return;
    }
    const quote = state.projectQuotes[project];
    if (!quote || !quote.has_penalty_clause) return;
    const wks = Number(quote.penalty_clause_weeks);
    if (!Number.isFinite(wks) || wks <= 0) return;
    // PO start anchors the date math (penalty = PO + N weeks). FAT
    // bar anchors the VERTICAL extent (~2 rows above to 2 below).
    const tasks = state.tasks.filter(t => t.project === project);
    const po = tasks.find(t => inferredAnchorKey(t) === 'receipt_of_po');
    const fat = tasks.find(t => inferredAnchorKey(t) === 'fat');
    if (!po || !po.start_date) return;
    const penaltyDateObj = new Date(po.start_date + 'T00:00:00');
    penaltyDateObj.setDate(penaltyDateObj.getDate() + Math.round(wks * 7));
    const penaltyISO = penaltyDateObj.toISOString().slice(0, 10);
    const g = state.gantt;
    const cw = g.options.column_width;
    const mode = g.options.view_mode || 'Week';
    const step = mode === 'Day' ? 1 : mode === 'Week' ? 7 : 30;
    const pxPerDay = cw / step;
    // Work-day positioning so the line lands on the same column as
    // a task ending on that date (matches compressGanttToWorkDays).
    const x = workDayOffset(penaltyISO, g.gantt_start) * pxPerDay;
    if (x < 0) return;
    // Find the FAT bar's y to anchor the line. If FAT isn't rendered
    // (filtered out), fall back to mid-chart.
    const svgH = +svg.getAttribute('height') || svg.viewBox?.baseVal?.height || 600;
    let fatY = svgH / 2;
    let rowH = 28;
    if (fat) {
      const wrap = svg.querySelector(`.bar-wrapper[data-id="${fat.id}"]`);
      const bar = wrap && wrap.querySelector('.bar');
      if (bar) {
        fatY = +bar.getAttribute('y');
        rowH = +bar.getAttribute('height') || rowH;
      }
    }
    // Span: 2 rows ABOVE FAT to 2 rows BELOW — short enough not to
    // dominate the chart, long enough to read as "this matters
    // around delivery". Each row is roughly rowH + a few px padding.
    const ROW_STRIDE = rowH + 8;
    const yTop = Math.max(40, fatY - 2 * ROW_STRIDE);
    const yBottom = fatY + 3 * ROW_STRIDE;

    const layer = document.createElementNS(SVG_NS, 'g');
    layer.setAttribute('class', 'sdc-penalty-line');
    layer.style.pointerEvents = 'none';
    svg.appendChild(layer);
    // Vertical red line.
    const line = document.createElementNS(SVG_NS, 'line');
    line.setAttribute('x1', x);
    line.setAttribute('x2', x);
    line.setAttribute('y1', yTop);
    line.setAttribute('y2', yBottom);
    line.setAttribute('stroke', '#dc2626');
    line.setAttribute('stroke-width', '2.2');
    layer.appendChild(line);
    // Label — "Penalty starts" + date. Positioned to the RIGHT of
    // the line and vertically centered between the line's top and
    // bottom so it doesn't sit ON TOP of any task bar (centering it
    // above the line was overlapping with bars in busy areas like
    // Test/Debug rows).
    const labelText = `Penalty starts ${fmtDate(penaltyISO)}`;
    const padX = 6;
    const approxCharW = 6.2;
    const labelW = labelText.length * approxCharW + padX * 2;
    const labelH = 16;
    const rectX = x + 6;
    const rectY = ((yTop + yBottom) / 2) - (labelH / 2);
    const rect = document.createElementNS(SVG_NS, 'rect');
    rect.setAttribute('x', rectX);
    rect.setAttribute('y', rectY);
    rect.setAttribute('width', labelW);
    rect.setAttribute('height', labelH);
    rect.setAttribute('rx', '3');
    rect.setAttribute('fill', '#fff');
    rect.setAttribute('stroke', '#dc2626');
    rect.setAttribute('stroke-width', '1.4');
    layer.appendChild(rect);
    const text = document.createElementNS(SVG_NS, 'text');
    // Anchor text to the LEFT edge of the pill (since the pill sits
    // to the right of the line now, not centered above it).
    text.setAttribute('x', rectX + labelW / 2);
    text.setAttribute('y', rectY + labelH / 2 + 1);
    text.setAttribute('text-anchor', 'middle');
    text.setAttribute('dominant-baseline', 'central');
    text.setAttribute('fill', '#b91c1c');
    text.style.fontFamily = "'Montserrat', sans-serif";
    text.style.fontSize = '11px';
    text.style.fontWeight = '700';
    text.textContent = labelText;
    layer.appendChild(text);
  } catch (_) { /* swallow — render chain must continue */ }
}

function drawFinancialOverlay() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;
  // Always clear so toggling off clears the overlay even when re-render is skipped.
  svg.querySelectorAll('.financial-marker').forEach(d => d.remove());
  if (!state.showFinancials) return;
  if (!state.gantt || !state.gantt.gantt_start) return;

  // Collect markers for every project currently rendering bars. Skips projects whose
  // bars are all filtered out (so the All-projects view shows everything, a single
  // project tab shows just that one).
  const visibleProjects = new Set();
  for (const t of state.tasks) {
    if (!t.start_date) continue;
    if (svg.querySelector(`.bar-wrapper[data-id="${t.id}"]`)) {
      visibleProjects.add(t.project || '');
    }
  }
  const markers = [];
  for (const project of visibleProjects) {
    const list = state.financials[project] || [];
    for (const f of list) {
      // Predecessor-derived date wins; manual due_date is the fallback. Computed
      // at render time so anchor/task edits update the overlay without needing a
      // round-trip to the server.
      const derived = computeFinancialTriggerDate(f.predecessors, project);
      const due = derived || f.due_date;
      if (!due) continue;
      markers.push({ ...f, due_date: due, project });
    }
  }
  if (markers.length === 0) return;

  // Date → x. gantt_start is the leftmost calendar date the Gantt knows about.
  // step = calendar days per column for the current view mode.
  const g = state.gantt;
  const startMs = new Date(g.gantt_start).getTime();
  const cw = g.options.column_width;
  const mode = g.options.view_mode || 'Week';
  const step = mode === 'Day' ? 1 : mode === 'Week' ? 7 : 30;
  const pxPerDay = cw / step;

  // Lines span the full chart height. yTop has to land BELOW the date header
  // (including the day-number row). The header elements are <g> groups, not
  // <rect>s, so their getAttribute('height') is null — using header_height as a
  // proxy underestimates the actual rendered band. Instead we find the topmost
  // task bar's Y: bars always start AFTER the entire header, so first_bar.y - 16
  // is guaranteed to be in the gap above the first row, comfortably past the
  // dates.
  const svgH = +svg.getAttribute('height') || svg.viewBox?.baseVal?.height || 600;
  let firstBarY = Infinity;
  for (const bar of svg.querySelectorAll('.bar-wrapper:not(.phantom-pad) .bar')) {
    const y = +bar.getAttribute('y');
    if (y < firstBarY) firstBarY = y;
  }
  const yTop = Number.isFinite(firstBarY) ? Math.max(40, firstBarY - 16) : 50;
  const yBottom = svgH;

  const layer = document.createElementNS(SVG_NS, 'g');
  layer.setAttribute('class', 'financial-marker financial-overlay-layer');
  svg.appendChild(layer);

  // Lane assignment — each lane is a horizontal "row" of labels just below the
  // date header. If a label's X overlaps another label's right edge in the same
  // lane, it spills to the next lane down so the labels never sit on top of each
  // other. Markers sorted by date so the lane walk is left-to-right.
  const sortedMarkers = [...markers].sort((a, b) => (a.due_date || '').localeCompare(b.due_date || ''));
  const APPROX_CHAR = 5.8;
  const LANE_H = 17;       // ~3px breathing room between stacked pills
  const LANE_GAP_X = 10;   // min horizontal gap before two labels can share a lane
  const laneEndX = [];
  const laneByMarker = new Map();
  // The schedule Gantt is WORK-DAY compressed (Sat/Sun collapsed) via
  // compressGanttToWorkDays — so bar positions use workDayOffset, not
  // calendar-day math. The overlay must do the same or markers land
  // weeks-to-months off because every weekend along the way adds 2
  // calendar days that don't exist on the chart.
  for (const m of sortedMarkers) {
    if (!m.due_date) continue;
    const x = workDayOffset(m.due_date, g.gantt_start) * pxPerDay;
    const pct = m.percent != null ? ` ${Number(m.percent)}%` : '';
    // Width estimate uses the abbreviation (matches what the label
    // actually renders), not the full name.
    const labelW = (_pdashFinAbbrev(m).length + pct.length) * APPROX_CHAR + 12;
    let lane = 0;
    for (; lane < laneEndX.length; lane++) {
      if (laneEndX[lane] + LANE_GAP_X < x) break;
    }
    laneEndX[lane] = x + labelW;
    laneByMarker.set(m, lane);
  }

  for (const m of markers) {
    if (!m.due_date) continue;
    // Same work-day-based x positioning as the lane loop above —
    // matches the bar positions in the compressed Gantt.
    const x = workDayOffset(m.due_date, g.gantt_start) * pxPerDay;
    const sent = !!m.paid;
    const lane = laneByMarker.get(m) || 0;
    // Labels sit BELOW the dates (yTop already accounts for both header rows),
    // shifted into their assigned lane.
    const labelY = yTop + 12 + lane * LANE_H;

    // Vertical line through the whole chart — bolder than v1.9.x so it reads
    // clearly against busy bars. Dashed when pending, solid when sent.
    const line = document.createElementNS(SVG_NS, 'line');
    line.setAttribute('class', 'financial-marker financial-line' + (sent ? ' is-sent' : ''));
    line.setAttribute('x1', x);
    line.setAttribute('x2', x);
    line.setAttribute('y1', yTop);
    line.setAttribute('y2', yBottom);
    line.setAttribute('stroke', '#16a34a');
    line.setAttribute('stroke-width', sent ? '2.2' : '1.6');
    if (!sent) line.setAttribute('stroke-dasharray', '5 4');
    layer.appendChild(line);

    // Build label text first so we can measure for the pill backdrop.
    // Use the SDC abbreviation (PO / MC / FAT / SAT) — matches the
    // dashboard tile so PMs read the same shorthand in both places.
    const pct = m.percent != null ? ` ${Number(m.percent)}%` : '';
    const abbrev = _pdashFinAbbrev(m);
    const text = document.createElementNS(SVG_NS, 'text');
    text.setAttribute('x', x + 6);
    text.setAttribute('y', labelY);
    text.setAttribute('class', 'financial-marker financial-label');
    text.setAttribute('font-size', '11');
    text.setAttribute('font-weight', '700');
    text.setAttribute('fill', '#14532d');         // green-900 — strong contrast
    text.textContent = abbrev + pct;
    layer.appendChild(text);

    // White pill backdrop behind each label so the label is readable even when
    // it lands over a task label or another visual element. Sized to the text's
    // measured bbox so it hugs the text exactly.
    const tb = text.getBBox();
    const bg = document.createElementNS(SVG_NS, 'rect');
    bg.setAttribute('class', 'financial-marker financial-label-bg');
    bg.setAttribute('x', tb.x - 4);
    bg.setAttribute('y', tb.y - 1);
    bg.setAttribute('width',  tb.width + 8);
    bg.setAttribute('height', tb.height + 2);
    bg.setAttribute('rx', 3);
    bg.setAttribute('fill', '#ffffff');
    bg.setAttribute('stroke', '#16a34a');
    bg.setAttribute('stroke-width', '0.75');
    layer.insertBefore(bg, text);

    // Hover title for full info — attached to the line so the whole vertical hit area works.
    const title = document.createElementNS(SVG_NS, 'title');
    title.textContent = `${m.project ? m.project + ' · ' : ''}${m.name}${pct} (${m.due_date})${sent ? ' — SENT' : ''}`;
    line.appendChild(title);
  }
}

// Compute the critical path — the chain of tasks that drives the schedule from
// Receipt of PO to FAT. We walk BACKWARD from FAT: at each step we pick the
// predecessor whose date drives this task's start/end (the latest-finishing FS
// predecessor, the latest-starting SS one, etc.) Slipping any task in the returned
// set delays FAT. Returns a Set of task ids (including FAT and Receipt of PO).
// Cache keyed by project + task count + max task id — invalidates automatically when
// tasks change (save, delete, load). Avoids the O(n×m) graph walk being repeated 2–3×
// per render pass (renderGantt calls it twice, renderTable once if criticalOnly is on).
let _criticalPathCache = null;
let _criticalPathCacheKey = '';
function computeCriticalPath() {
  const projectFilter = state.filters.project;
  const tasks = projectFilter ? state.tasks.filter(t => t.project === projectFilter) : state.tasks;
  const cacheKey = `${projectFilter}|${tasks.length}|${tasks.reduce((m, t) => Math.max(m, t.id || 0), 0)}`;
  if (_criticalPathCache && _criticalPathCacheKey === cacheKey) return _criticalPathCache;

  const fat = tasks.find(t => inferredAnchorKey(t) === 'fat');
  if (!fat) { _criticalPathCache = new Set(); _criticalPathCacheKey = cacheKey; return _criticalPathCache; }
  // Stringify IDs throughout — bar elements expose IDs via data-id (always string),
  // so storing strings keeps the Set comparable with the lookup site in
  // drawCustomArrows without per-call Number() conversions slipping past.
  const taskById = Object.fromEntries(tasks.map(t => [String(t.id), t]));
  const critical = new Set([String(fat.id)]);
  const visit = [fat];
  while (visit.length > 0) {
    const cur = visit.pop();
    if (!cur.predecessors) continue;
    const refs = String(cur.predecessors)
      .split(',')
      .map(s => parsePredecessor(s.trim()))
      .filter(Boolean);
    if (refs.length === 0) continue;
    // Find the binding predecessor — the one whose driven date is latest. That's
    // the one pinning this task's start; everyone else has slack.
    let bound = null, boundMs = -Infinity;
    for (const ref of refs) {
      const pred = taskById[String(ref.id)];
      if (!pred) continue;
      const drivenDate = (ref.type === 'SS' || ref.type === 'SF')
        ? pred.start_date
        : pred.end_date;
      if (!drivenDate) continue;
      const ms = new Date(drivenDate + 'T00:00:00Z').getTime();
      if (ms > boundMs) { boundMs = ms; bound = pred; }
    }
    if (bound && !critical.has(String(bound.id))) {
      critical.add(String(bound.id));
      visit.push(bound);
    }
  }
  _criticalPathCache = critical;
  _criticalPathCacheKey = cacheKey;
  return critical;
}

// For every in-progress non-milestone task, compare ACTUAL progress (% complete) to
// EXPECTED progress at today's date. A small chip is drawn just to the right of the
// task bar showing how many working days the task is ahead (green) or behind (red).
// On-track tasks (|diff| < 1d) get no chip — keeps the chart clean.
function drawScheduleStatus() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;
  // Clear any prior chips before re-drawing (each render rebuilds them).
  svg.querySelectorAll('.sdc-status-chip').forEach(el => el.remove());
  const todayISO = new Date().toISOString().slice(0, 10);
  for (const task of state.tasks) {
    if (task.is_milestone) continue;
    if (!task.start_date || !task.end_date) continue;
    if (inferredAnchorKey(task)) continue;
    if (isBacklogTask(task)) continue; // backlog is not "behind", it's by design
    const wrap = svg.querySelector(`.bar-wrapper[data-id="${task.id}"]`);
    if (!wrap) continue;
    const bar = wrap.querySelector('.bar');
    if (!bar) continue;
    // For completed tasks, use the locked drift (scheduled_end − completed_on).
    // For incomplete tasks, the live formula based on today.
    // taskScheduleDelta handles both — single source of truth.
    const actualPct = Math.max(0, Math.min(100, Number(task.progress) || 0));
    const diffDays = taskScheduleDelta(task);
    // Hover-tooltip context: % math is only meaningful for INCOMPLETE tasks.
    // For completed tasks, the chip says "finished X days ahead/behind", and
    // the tooltip says the same thing in long form.
    const totalDays = businessDaysBetween(task.start_date, task.end_date) || 0;
    let elapsedDays;
    if (todayISO < task.start_date) elapsedDays = 0;
    else if (todayISO > task.end_date) elapsedDays = totalDays;
    else elapsedDays = businessDaysBetween(task.start_date, todayISO) || 0;
    const expectedPct = totalDays > 0 ? (elapsedDays / totalDays) * 100 : 0;
    if (Math.abs(diffDays) < 1) continue;
    const ahead = diffDays > 0;
    const barX = +bar.getAttribute('x');
    const barY = +bar.getAttribute('y');
    const barW = +bar.getAttribute('width');
    const barH = +bar.getAttribute('height');
    // Default chip position: 6px right of the bar's end. If the bar's name
    // label overflowed past the bar (clipBarLabels added .bar-label-outside
    // with text-anchor='start'), the label sits in that exact spot, so push
    // the chip further right past the label so they don't overlap.
    let cx = barX + barW + 6;
    const labelEl = wrap.querySelector('.bar-label.bar-label-outside');
    if (labelEl && labelEl.getAttribute('text-anchor') === 'start') {
      try {
        const lb = labelEl.getBBox();
        // Label x is its start point; width = lb.width. End = labelX + lb.width.
        const labelEndX = (+labelEl.getAttribute('x')) + lb.width;
        cx = Math.max(cx, labelEndX + 6);
      } catch (_) { /* SVG not measurable yet — fall back to default cx */ }
    }
    const cy = barY + barH / 2;
    // Weeks + half-weeks, never days (business-days ÷ 5, half-week snap).
    const driftWks = (Math.round((Math.abs(diffDays) / 5) * 2) / 2) || 0.5;
    const label = `${ahead ? '+' : '−'}${driftWks}w`;
    const padX = 5, chipH = Math.max(12, barH - 2);
    // Estimate width — text is short, ~7px per char + padding.
    const w = label.length * 6.5 + padX * 2;
    const g = document.createElementNS(SVG_NS, 'g');
    g.setAttribute('class', 'sdc-status-chip');
    g.setAttribute('data-state', ahead ? 'ahead' : 'behind');
    const rect = document.createElementNS(SVG_NS, 'rect');
    rect.setAttribute('x', cx);
    rect.setAttribute('y', cy - chipH / 2);
    rect.setAttribute('width', w);
    rect.setAttribute('height', chipH);
    rect.setAttribute('rx', 3);
    rect.setAttribute('ry', 3);
    rect.setAttribute('fill', ahead ? '#16a34a' : '#dc2626');
    rect.setAttribute('opacity', '0.95');
    g.appendChild(rect);
    const text = document.createElementNS(SVG_NS, 'text');
    text.setAttribute('x', cx + padX);
    text.setAttribute('y', cy);
    text.setAttribute('dominant-baseline', 'middle');
    text.setAttribute('font-size', '10');
    text.setAttribute('font-weight', '700');
    text.setAttribute('fill', '#fff');
    text.setAttribute('pointer-events', 'none');
    text.textContent = label;
    g.appendChild(text);
    // Tooltip for the chip — extra context on hover.
    const title = document.createElementNS(SVG_NS, 'title');
    title.textContent = ahead
      ? `${driftWks} week${driftWks === 1 ? '' : 's'} AHEAD of schedule (${actualPct.toFixed(0)}% complete, expected ${expectedPct.toFixed(0)}%)`
      : `${driftWks} week${driftWks === 1 ? '' : 's'} BEHIND schedule (${actualPct.toFixed(0)}% complete, expected ${expectedPct.toFixed(0)}%)`;
    g.appendChild(title);
    wrap.appendChild(g);
  }
}

// Shift each Gantt bar so its row aligns with the corresponding task row in the grid.
// The grid has group headers and add-task rows that don't exist in the Gantt, so bars
// would otherwise sit at smaller y values than their grid rows.
function alignGanttToGrid() {
  const tasksTable = document.getElementById('tasks-table');
  const ganttSvg = document.querySelector('#gantt-container .gantt');
  if (!tasksTable || !ganttSvg) return;

  // Map task id -> y offset within the table
  const gridYs = {};
  tasksTable.querySelectorAll('tbody tr[data-id]').forEach(tr => {
    gridYs[tr.dataset.id] = tr.offsetTop;
  });

  // Make the SVG at least as tall as the grid so shifted bars stay visible.
  const gridHeight = tasksTable.offsetHeight;
  const svgHeight = +ganttSvg.getAttribute('height') || 0;
  if (gridHeight > svgHeight) {
    ganttSvg.setAttribute('height', gridHeight);
    // Also extend the viewBox so content past the original height isn't clipped.
    const vb = ganttSvg.getAttribute('viewBox');
    if (vb) {
      const [vx, vy, vw, vh] = vb.split(/\s+/).map(Number);
      if (vh < gridHeight) ganttSvg.setAttribute('viewBox', `${vx} ${vy} ${vw} ${gridHeight}`);
    }
  }

  const rowH = state.layout.rowHeight;
  ganttSvg.querySelectorAll('.bar-wrapper[data-id]').forEach(wrap => {
    const id = wrap.getAttribute('data-id');
    const targetTop = gridYs[id];
    if (targetTop === undefined) return;
    const bar = wrap.querySelector('.bar');
    if (!bar) return;
    const currentY = +bar.getAttribute('y');
    const barH = +bar.getAttribute('height');
    const desiredY = targetTop + (rowH - barH) / 2;
    const dy = desiredY - currentY;
    if (Math.abs(dy) < 0.5) return;
    shiftElementY(wrap, dy);
  });

  // Clear any old custom stripes — keep the gantt background plain white.
  const oldStripes = ganttSvg.querySelector('.sdc-row-stripes');
  if (oldStripes) oldStripes.remove();
  const finalSvgHeight = +ganttSvg.getAttribute('height') || gridHeight;

  // Draw fresh full-height vertical tick lines at every date column. We use the lower-text
  // x positions (which we know exist — the date label numbers) as the column anchors. This
  // doesn't depend on frappe-gantt's internal tick rendering, which may be lines/paths/rects.
  let tickGroup = ganttSvg.querySelector('.sdc-tick-fill');
  if (tickGroup) tickGroup.remove();
  const lowerTexts = [...ganttSvg.querySelectorAll('.lower-text')];
  if (lowerTexts.length > 1) {
    tickGroup = document.createElementNS(SVG_NS, 'g');
    tickGroup.setAttribute('class', 'sdc-tick-fill');
    ganttSvg.insertBefore(tickGroup, ganttSvg.firstChild);
    // Header bottom = 60 (matches the th height we set). Vertical lines from there to bottom.
    const tickTop = 60;
    lowerTexts.forEach(t => {
      const x = +t.getAttribute('x') || 0;
      const ln = document.createElementNS(SVG_NS, 'line');
      ln.setAttribute('x1', x);
      ln.setAttribute('x2', x);
      ln.setAttribute('y1', tickTop);
      ln.setAttribute('y2', finalSvgHeight);
      ln.setAttribute('stroke', '#f1f5f9');
      ln.setAttribute('stroke-width', '1');
      tickGroup.appendChild(ln);
    });
  }
}

function shiftElementY(root, dy) {
  root.querySelectorAll('rect, polygon, text, line, circle').forEach(el => {
    const y = el.getAttribute('y');
    if (y !== null) el.setAttribute('y', +y + dy);
    const y1 = el.getAttribute('y1');
    if (y1 !== null) el.setAttribute('y1', +y1 + dy);
    const y2 = el.getAttribute('y2');
    if (y2 !== null) el.setAttribute('y2', +y2 + dy);
    const cy = el.getAttribute('cy');
    if (cy !== null) el.setAttribute('cy', +cy + dy);
    const points = el.getAttribute('points');
    if (points) {
      el.setAttribute('points', points.split(/\s+/).map(p => {
        const [x, y] = p.split(',').map(Number);
        return `${x},${y + dy}`;
      }).join(' '));
    }
  });
}

// Frappe-gantt sometimes puts the month name into the lower (day-level) header
// at month boundaries (e.g. "02 May"), which then duplicates the upper header's
// month label and looks like there are two month rows. Strip the month word
// from the lower-text so day numbers stay alone in the lower row.
function cleanGanttHeaders() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;
  // In Month view, the lower-text IS the month name (Jan / Feb / etc.) and the
  // upper-text is the year — we have to keep both. The de-duplication below was
  // designed for Week view, where the upper-text is "January" and the lower-
  // text used to repeat it ("Jan 12") creating noise; stripping months in
  // Month view leaves the row blank, which is what the user just hit.
  const mode = state.gantt?.options?.view_mode;
  if (mode === 'Month') return;
  const monthRe = /\s*(?:January|February|March|April|May|June|July|August|September|October|November|December|Jan|Feb|Mar|Apr|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\s*/g;
  svg.querySelectorAll('.lower-text').forEach(t => {
    const cleaned = (t.textContent || '').replace(monthRe, ' ').trim();
    if (cleaned !== t.textContent) t.textContent = cleaned;
  });
}

// frappe-gantt creates an inner `.gantt-container` div around the SVG that owns the
// horizontal scroll. The outer #gantt-container and #schedule-gantt panel never grow
// past their own clientWidth, so their scrollLeft is a no-op.
function getGanttScroller() {
  return document.querySelector('#gantt-container .gantt-container');
}

function setZoom(percent) {
  const next = Math.max(ZOOM_MIN, Math.min(ZOOM_MAX, percent));
  if (Math.abs(next - state.zoomPercent) < 0.01) return;

  // Capture the DATE under the viewport center BEFORE we re-render. We can't
  // just scale pixel positions linearly (the old code did `factor * oldCenterPx`)
  // because getZoomConfig may flip the view mode at certain zoom thresholds —
  // and when the mode flips, the gantt's start date, column width formula, and
  // px-per-day all change discontinuously. A pixel that meant "Aug 10" in Week
  // mode might map to "Nov 3" in Month mode after the rebuild, which is what
  // made the chart appear to jump way off to the side at the Week→Month
  // boundary. Converting to a date and back is mode-independent.
  let centerDateMs = null;
  const oldScroller = getGanttScroller();
  const viewW = oldScroller ? oldScroller.clientWidth : 0;
  if (oldScroller && state.gantt?.gantt_start) {
    const oldCenterPx = oldScroller.scrollLeft + viewW / 2;
    const g = state.gantt;
    const oldStartMs = new Date(g.gantt_start).getTime();
    const cw = g.options.column_width;
    const mode = g.options.view_mode || 'Week';
    const step = mode === 'Day' ? 1 : mode === 'Week' ? 7 : 30;
    const pxPerDay = cw / step;
    if (pxPerDay > 0) {
      // Work-day Gantt: pixel x maps to work-day index, not calendar
      // day index. Convert by walking work days forward from gantt_start
      // until we've accumulated the equivalent of oldCenterPx.
      const workDaysFromStart = oldCenterPx / pxPerDay;
      let count = 0;
      let cursorMs = oldStartMs;
      const targetIntegerWorkDays = Math.floor(workDaysFromStart);
      while (count < targetIntegerWorkDays) {
        cursorMs += 86400000;
        const dow = new Date(cursorMs).getUTCDay();
        if (dow !== 0 && dow !== 6) count++;
      }
      // Add the fractional part (within a single work day, no weekend
      // crossing possible).
      const fractionMs = (workDaysFromStart - targetIntegerWorkDays) * 86400000;
      centerDateMs = cursorMs + fractionMs;
    }
  }

  state.zoomPercent = next;
  // v5.7: re-render whichever Gantt is currently active. When the user is
  // on the Actions tab and signed in, zoom changes hit the personal Gantt
  // instead of (or in addition to) the main schedule.
  if (state.view === 'actions' && typeof _actionsPageState !== 'undefined' && _actionsPageState && _actionsPageState.personId != null) {
    renderActionsPersonGantt();
  } else {
    renderGantt();
  }

  // Now find that same date on the new chart and scroll so it sits at the
  // viewport center. Use WORK-DAY x positioning (the same logic the bars
  // and headers use after compressGanttToWorkDays) — otherwise a Month→
  // Week mode flip leaves the chart visually shifted by the weekend
  // compression delta.
  const newScroller = getGanttScroller();
  if (newScroller && centerDateMs != null && state.gantt?.gantt_start) {
    const g = state.gantt;
    const cw = g.options.column_width;
    const mode = g.options.view_mode || 'Week';
    const step = mode === 'Day' ? 1 : mode === 'Week' ? 7 : 30;
    const pxPerDay = cw / step;
    if (pxPerDay > 0) {
      const dateStr = new Date(centerDateMs).toISOString().slice(0, 10);
      const targetPx = workDayOffset(dateStr, g.gantt_start) * pxPerDay;
      const center = Math.max(0, targetPx - viewW / 2);
      newScroller.scrollLeft = center;
      // Re-assert next frame: renderGantt defers its decoration pass to a rAF,
      // and any scroll reset that lands then would otherwise undo the centering
      // (zoom-in appears to drift "back in time"). Pin it after that settles.
      requestAnimationFrame(() => { const s = getGanttScroller(); if (s) s.scrollLeft = center; });
    }
  }
  // v4.55: Keep the Zoom dropdown's displayed value in sync with any zoom
  // change — wheel zoom, Zoom-to-fit, time-scale switch, and the dropdown's
  // own +/− buttons all flow through here. renderZoomMenu bails if the
  // menu element isn't in the DOM yet, so this is safe on init.
  if (typeof renderZoomMenu === 'function') renderZoomMenu();
}


// Personal-Gantt counterpart to zoomToFit. Measures the personal panel,
// reads the signed-in person's tasks (same filter the personal Gantt uses),
// and re-renders the personal Gantt at a zoom that fits the timeline.
function zoomToFitPersonal() {
  const panel = document.getElementById('actions-person-gantt');
  if (!panel) return;
  const personId = _actionsPageState?.personId;
  if (personId == null) return;
  const member = (state.team || []).find(m => m.id === personId);
  if (!member) return;
  const memberNameLower = (member.name || '').trim().toLowerCase();
  const today = new Date().toISOString().slice(0, 10);
  const tasks = (state.tasks || []).filter(t => {
    if (!t.project) return false;
    if (isTemplateProject(t.project)) return false;
    if (projectWorkspace(t.project) === 'Sales') return false;
    if (!t.start_date || !t.end_date) return false;
    const a = (t.assignee || '').trim().toLowerCase();
    const direct = a === memberNameLower;
    const placeholder = t.is_action && isPlaceholder(t.assignee) && actionDisciplineKey(t) === member.discipline;
    if (!direct && !placeholder) return false;
    return personalFilterPass(t, today);
  });
  if (tasks.length === 0) return;
  const target = Math.max(300, panel.clientWidth - 24);
  const minStart = Math.min(...tasks.map(t => new Date(t.start_date).getTime()));
  const maxEnd   = Math.max(...tasks.map(t => new Date(t.end_date).getTime()));
  const projectDays = Math.max(1, (maxEnd - minStart) / 86400000 + 1);
  const PAD_DAYS = 14;
  const requiredPxPerDay = target / (projectDays + PAD_DAYS);
  state.zoomPercent = Math.max(ZOOM_MIN, Math.min(ZOOM_MAX, (requiredPxPerDay / 20) * 100));
  renderActionsPersonGantt();
}

function zoomToFit() {
  const visiblePanel = document.getElementById('schedule-gantt');
  if (!visiblePanel) return;
  const target = Math.max(300, visiblePanel.clientWidth - 24);
  // Fit the VISIBLE span only — tasks inside collapsed sections don't draw
  // on the chart, so they shouldn't stretch the fit. Collapse 05/10 and the
  // fit zooms into the remaining open sections.
  const filtered = applyFilters(state.tasks)
    .filter(t => t.start_date && t.end_date)
    .filter(t => !isTaskInCollapsedGroup(t));
  if (filtered.length === 0 || target <= 0) return;

  const minStartStr = filtered.reduce((s, t) => t.start_date < s ? t.start_date : s, filtered[0].start_date);
  const maxEndStr   = filtered.reduce((e, t) => t.end_date   > e ? t.end_date   : e, filtered[0].end_date);
  // The Gantt now uses WORK-DAY positioning (Sat/Sun compressed out),
  // so the visible span is the work-day count between min start and
  // max end. Using calendar days here gave a too-small px/day and left
  // a big empty area on the right.
  const minStartMs = new Date(minStartStr + 'T00:00:00Z');
  const workDaysSpan = Math.max(1, workDayOffset(maxEndStr, minStartMs));

  // Label-overflow budget — Receipt of PO renders its date (~60px) to
  // the LEFT of its diamond, and long task names overflow ~80-120px
  // past the RIGHT of their bars. Reserve room so neither gets clipped.
  const LABEL_PAD_LEFT  = 70;
  const LABEL_PAD_RIGHT = 120;
  const EDGE_PAD        = 10;
  const usableWidth = Math.max(50, target - LABEL_PAD_LEFT - LABEL_PAD_RIGHT - EDGE_PAD * 2);

  const requiredPxPerDay = usableWidth / workDaysSpan;
  state.zoomPercent = Math.max(ZOOM_MIN, Math.min(ZOOM_MAX, (requiredPxPerDay / 20) * 100));
  renderGantt();

  // Scroll so the earliest task's bar sits LABEL_PAD_LEFT + EDGE_PAD
  // from the viewport's left edge — that's enough room for the date
  // label hanging off the leftmost anchor.
  const earliest = filtered.reduce((min, t) =>
    t.start_date < min.start_date ? t : min);
  const wrap = document.querySelector(`#gantt-container .bar-wrapper[data-id="${earliest.id}"]`);
  const bar = wrap && wrap.querySelector('.bar');
  if (bar) {
    const firstX = +bar.getAttribute('x');
    const scroller = getGanttScroller();
    if (scroller) scroller.scrollLeft = Math.max(0, firstX - LABEL_PAD_LEFT - EDGE_PAD);
  }
}

// ---------- Milestone diamonds ----------
function drawMilestoneDiamonds() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;

  // Clear previous
  svg.querySelectorAll('.milestone-diamond, .milestone-check').forEach(d => d.remove());

  // Checkmark color for done milestones. The diamond itself keeps its normal
  // anchor / non-anchor fill — only the ✓ glyph overlay tells you it's done.
  // (Earlier versions flipped the whole diamond to a deep-green "done" color;
  // that made done anchors look completely different from undone ones, which
  // was confusing when two anchors of the same type — e.g. Receipt of PO not
  // done vs Mech 1 Release done — sat in the same view.)
  const CHECK_COLOR = '#1e293b';   // slate-800; reads against both lime + slate diamonds

  for (const task of state.tasks) {
    if (!task.is_milestone) continue;
    const wrap = svg.querySelector(`.bar-wrapper[data-id="${task.id}"]`);
    if (!wrap) continue;
    const bar = wrap.querySelector('.bar');
    if (!bar) continue;

    const x = +bar.getAttribute('x');
    const y = +bar.getAttribute('y');
    const w = +bar.getAttribute('width');
    const h = +bar.getAttribute('height');
    const cx = x + Math.max(w / 2, 0); // milestones often have w≈step; center of bar
    const cy = y + h / 2;
    // Anchor milestones (Receipt of PO, Mech 1 Release, Machine Power-Up, FAT,
    // Ship Machine) render as a CONCENTRIC double-diamond: a smaller filled
    // inner diamond INSIDE an outline ring that matches the size of a regular
    // non-anchor milestone. So anchors and non-anchors have the same total
    // visual footprint — what distinguishes them is the ring (anchor only) and
    // the color (lime-green fill vs slate).
    //
    // v4.23 hotfix: DECOUPLED milestone size from bar_height. The bar ratio
    // bumped 0.5 → 0.7 in v4.23 (so task bars dominate their rows), which
    // also blew up the diamond ~40% because it was sized off `h` directly
    // and looked oversized for milestones. Now we compute a separate
    // diamondRef at the OLD 0.5 ratio so diamonds stay the same size they
    // always were even though task bars grew.
    //
    // Sizing (against diamondRef, not h):
    //   - Non-anchor diamond:   diamondRef × 1.20 wide.
    //   - Anchor OUTER ring:    diamondRef × 1.20 wide.
    //   - Anchor INNER diamond: diamondRef × 0.75 wide.
    const diamondRef = Math.max(BAR_H_MIN, Math.round(state.layout.rowHeight * 0.5));
    const isAnchor = !!inferredAnchorKey(task);
    const isDone   = (task.progress || 0) >= 100;
    const size = isAnchor ? diamondRef * 0.75 : diamondRef * 1.20;

    bar.style.opacity = '0';
    wrap.querySelectorAll('.bar-progress').forEach(el => el.style.opacity = '0');
    // Hide frappe-gantt's bar-label — we render our own in drawMilestoneLabels (after arrows
    // so the pill background obscures any arrow line that runs underneath).
    const lbl = wrap.querySelector('.bar-label');
    if (lbl) lbl.style.opacity = '0';

    // Anchor color comes from settings (Setup → Anchor Color). Falls back to the
    // green default when settings haven't loaded yet.
    const ac = state.settings?.anchor_color || ANCHOR_COLOR_DEFAULTS;

    if (isAnchor) {
      // Outer ring — pure outline at diamondRef × 1.20 (same size as a non-anchor
      // diamond), in the anchor text/stroke shade. The clear gap between this
      // outer ring and the smaller inner diamond is what makes the anchor
      // visually distinct without making it any larger than other milestones.
      // v4.23 hotfix: uses diamondRef (not h) so anchors stay sized off the
      // OLD bar ratio even though task bars grew when ratio bumped to 0.7.
      const outerSize = diamondRef * 1.20;
      const outerPts = `${cx},${cy - outerSize/2} ${cx + outerSize/2},${cy} ${cx},${cy + outerSize/2} ${cx - outerSize/2},${cy}`;
      const outer = document.createElementNS(SVG_NS, 'polygon');
      outer.setAttribute('points', outerPts);
      outer.setAttribute('class', 'milestone-diamond anchor-outer');
      outer.setAttribute('fill', 'none');
      // Outer ring on a "done" anchor uses the dark-green stroke so the whole
      // double-diamond reads as completed (otherwise the outer ring still looks
      // "pending" while the inner is filled green).
      // Outer ring uses the same anchor text/stroke color whether or not the
      // milestone is done. Done state is signaled by the ✓ overlay added below,
      // not a color flip — so a done Receipt of PO and an undone Receipt of PO
      // are unambiguously the same milestone, just one with a checkmark on top.
      outer.setAttribute('stroke', ac.text);
      outer.setAttribute('stroke-width', '1.75');
      outer.setAttribute('stroke-linejoin', 'miter');
      wrap.appendChild(outer);
    }

    const points = `${cx},${cy - size/2} ${cx + size/2},${cy} ${cx},${cy + size/2} ${cx - size/2},${cy}`;
    const diamond = document.createElementNS(SVG_NS, 'polygon');
    diamond.setAttribute('points', points);
    diamond.setAttribute('class', 'milestone-diamond' + (isAnchor ? ' anchor-inner' : '') + (isDone ? ' done' : '') + (task.is_action ? ' action-milestone' : ''));
    // v4.47/v4.49: action-item milestones get SDC blue (default) or RED
    // (overdue + not done). Grid + Gantt paint the same red so the user
    // immediately sees overdue actions without applying a filter.
    //   - Anchors: lime fill + dark green stroke (from anchor_color settings)
    //   - Action milestones overdue: red-300 fill + red-600 stroke
    //   - Action milestones normal: SDC primary blue
    //   - Regular non-anchor milestones: slate fill + darker slate stroke
    let dFill = '#475569';
    let dStroke = '#334155';
    let dStrokeW = '1';
    const todayISOForDiamond = new Date().toISOString().slice(0, 10);
    const isOverdueAction = task.is_action && !isDone && task.end_date && task.end_date < todayISOForDiamond;
    if (isAnchor) {
      dFill = ac.fill;
      dStroke = ac.text;
      dStrokeW = '1.5';
    } else if (isOverdueAction) {
      dFill = '#fca5a5';  // red-300
      dStroke = '#dc2626'; // red-600
      dStrokeW = '1.5';
    } else if (task.is_action) {
      dFill = '#3a8edc';  // SDC primary lighter
      dStroke = '#1574c4'; // SDC primary
      dStrokeW = '1.5';
    }
    // Done milestone: KEEP the diamond's original fill (slate for non-anchor,
    // lime for anchor) — flipping the whole shape green made a done non-anchor
    // look identical to a fresh anchor, which is exactly the wrong signal.
    // Done state is communicated by a bright SDC-lime stroke at 2.5px + the
    // ✓ overlay. Brighter than the earlier deep-green border so a done
    // milestone reads at a glance against the slate (or lime) fill.
    if (isDone) {
      dStroke  = '#74c415';     // SDC green — same lime used on done bars
      dStrokeW = '2.5';
    }
    diamond.setAttribute('fill',   dFill);
    diamond.setAttribute('stroke', dStroke);
    diamond.setAttribute('stroke-width', dStrokeW);
    wrap.appendChild(diamond);

    // Checkmark glyph rendered on top of the diamond for done milestones.
    // Sized at ~55% of the diamond — the diamond's inscribed square is only
    // ~0.71×size, so a 0.9×size glyph spilled to the points and looked aligned
    // with the diamond outline rather than centered inside it. 0.55 leaves
    // clear breathing room on all four sides so the ✓ reads as "inside the
    // shape" instead of "stretched across the shape." Color is dark slate
    // (anchor lime fill) or white (non-anchor slate fill) for contrast.
    if (isDone) {
      const check = document.createElementNS(SVG_NS, 'text');
      check.setAttribute('x', cx);
      check.setAttribute('y', cy);
      check.setAttribute('class', 'milestone-check');
      check.setAttribute('text-anchor', 'middle');
      check.setAttribute('dominant-baseline', 'central');
      check.setAttribute('fill', isAnchor ? CHECK_COLOR : '#ffffff');
      check.setAttribute('font-size', String(Math.round(size * 0.55)));
      check.setAttribute('font-weight', '900');
      check.setAttribute('pointer-events', 'none');
      check.textContent = '✓';
      wrap.appendChild(check);
    }
  }
}

// Detect arrow lines that cross a milestone's label pill and toggle the pill side override.
// Returns true if any pill was flipped (caller should re-render labels + arrows once).
// Bar labels stay INSIDE the bar — if the task name doesn't fit at the current zoom, we
// truncate with an ellipsis and stash the full text in a <title> for hover tooltip.
// No pills, no spillover, no obstacles for routing to worry about.
function clipBarLabels() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;
  // v4.28: SVG width drives the "would this overflow label clip off the right
  // edge?" check below. Fall back to clientWidth, then Infinity (always-right)
  // if neither is set.
  const svgWidth =
    (svg.viewBox && svg.viewBox.baseVal && svg.viewBox.baseVal.width) ||
    +svg.getAttribute('width') ||
    svg.clientWidth ||
    Infinity;

  for (const task of state.tasks) {
    if (task.is_milestone) continue;
    const wrap = svg.querySelector(`.bar-wrapper[data-id="${task.id}"]`);
    if (!wrap) continue;
    const bar = wrap.querySelector('.bar');
    const label = wrap.querySelector('.bar-label');
    if (!bar || !label) continue;
    const barX = +bar.getAttribute('x');
    const barW = +bar.getAttribute('width');
    const barY = +bar.getAttribute('y');
    const barH = +bar.getAttribute('height');
    // Scale font down for short bars so descenders (g, y, p, S) don't clip below
    // the bar. Visible text-with-descender height ≈ font-size, so cap font-size
    // at barH - 2 to leave 1px breathing room top + bottom.
    //  - barH=10 → 8px  (smallest legible)
    //  - barH=12 → 10px
    //  - barH=14 → 12px
    //  - barH≥14 → 12px (capped to match grid font)
    // IMPORTANT: set via style.fontSize (inline style), NOT setAttribute. The
    // frappe-gantt CDN CSS rule `.gantt .bar-label { font-size: var(--fs-md) }` has
    // higher CSS specificity than a presentation attribute, so attribute-based
    // font-size gets ignored. Inline style wins.
    const fontSize = Math.max(8, Math.min(12, barH - 2));
    label.style.fontSize = fontSize + 'px';

    const fullText = task.name || '';
    // Measure unconstrained.
    label.textContent = fullText;
    label.classList.remove('bar-label-outside');
    let labelW;
    try { labelW = label.getBBox().width; }
    catch (_) { labelW = fullText.length * 6.5; }
    const PAD = 8; // breathing room inside the bar

    if (labelW + PAD <= barW) {
      // Fits INSIDE — center label in bar (dominant-baseline 'central' keeps
      // descenders inside the bar instead of dropping below).
      label.setAttribute('x', barX + barW / 2);
      label.setAttribute('y', barY + barH / 2);
      label.setAttribute('text-anchor', 'middle');
      label.setAttribute('dominant-baseline', 'central');
      // Drop any prior tooltip — full text is visible.
      const t = wrap.querySelector('title');
      if (t) t.remove();
      continue;
    }

    // v4.28: doesn't fit INSIDE — render OUTSIDE the bar (like milestone
    // labels do). Default placement is to the RIGHT of the bar. If the
    // right-side label would clip past the SVG edge AND there's room on
    // the left, place LEFT instead. Otherwise stays right (still readable
    // because the Gantt panel scrolls horizontally).
    //
    // Previously this branch ellipsis-truncated inside the bar ("Configure
    // Mac…"), which for short bars like "Configure Machine" at Week zoom
    // ended up rendering as just "…" or nothing — useless. Out-of-bar
    // labels solve that the same way milestone labels do.
    const labelOffset = 6;
    const rightStartX = barX + barW + labelOffset;
    const leftEndX    = barX - labelOffset;
    const wouldClipRight = (rightStartX + labelW) > svgWidth;
    const fitsLeft       = (leftEndX - labelW) > 0;
    const placeLeft = wouldClipRight && fitsLeft;

    label.textContent = fullText;
    if (placeLeft) {
      label.setAttribute('x', leftEndX);
      label.setAttribute('text-anchor', 'end');
    } else {
      label.setAttribute('x', rightStartX);
      label.setAttribute('text-anchor', 'start');
    }
    label.setAttribute('y', barY + barH / 2);
    label.setAttribute('dominant-baseline', 'central');
    label.classList.add('bar-label-outside');

    // Outside labels render the full task name — no tooltip needed.
    const t = wrap.querySelector('title');
    if (t) t.remove();
  }
}

function drawMilestoneLabels() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;
  let group = svg.querySelector('.milestone-labels');
  if (group) group.remove();
  group = document.createElementNS(SVG_NS, 'g');
  group.setAttribute('class', 'milestone-labels');
  svg.appendChild(group);

  // Milestone labels: name text to the right of the diamond. For ANCHOR
  // milestones (Receipt of PO, Mech 1 Release, Machine Power-Up, FAT, Ship
  // Machine) also paint the date on the OPPOSITE side (left of the diamond)
  // so the spine dates are always visible in Both view without scrolling.
  // Anchor diamonds have a concentric outer ring (~75% larger than inner);
  // labels must clear THAT outer edge, not just the inner diamond.
  for (const task of state.tasks) {
    if (!task.is_milestone) continue;
    const wrap = svg.querySelector(`.bar-wrapper[data-id="${task.id}"]`);
    if (!wrap) continue;
    const bar = wrap.querySelector('.bar');
    if (!bar) continue;
    const x = +bar.getAttribute('x');
    const y = +bar.getAttribute('y');
    const w = +bar.getAttribute('width');
    const h = +bar.getAttribute('height');
    const cx = x + Math.max(w / 2, 0);
    const cy = y + h / 2;
    const isAnchor = !!inferredAnchorKey(task);
    // Anchor outer ring and non-anchor diamond both have the same outer
    // radius. v4.23 hotfix: sized off diamondRef (OLD bar ratio of 0.5×rh)
    // not the current h, since bars grew but milestones stay the same.
    const diamondRef = Math.max(BAR_H_MIN, Math.round(state.layout.rowHeight * 0.5));
    const r = diamondRef * 1.20 / 2;
    const labelOffset = 6;
    const lbl = document.createElementNS(SVG_NS, 'text');
    lbl.setAttribute('x', cx + r + labelOffset);
    lbl.setAttribute('y', cy);
    lbl.setAttribute('dominant-baseline', 'middle');
    lbl.setAttribute('text-anchor', 'start');
    lbl.setAttribute('font-size', '11');
    lbl.setAttribute('font-weight', '600');
    lbl.setAttribute('fill', '#061d39');
    lbl.style.pointerEvents = 'none';
    // In personal mode, append the date to non-anchor milestone labels so
    // the user can see when each thing's due directly on the Gantt
    // (anchors already get a date label on the LEFT — see below).
    const showPersonalDate = isPersonalMode() && !isAnchor && task.start_date;
    lbl.textContent = (task.name || '') + (showPersonalDate ? ` · ${fmtDate(task.start_date)}` : '');
    group.appendChild(lbl);
    // v4.60: milestone labels NO LONGER get the pill occluder — user
    // prefers seeing the arrow pass through the text. Bar-meta keeps the
    // pill (arrows can't otherwise be distinguished from the meta text).
    // Date label on the LEFT side of the diamond for the 5 spine anchors.
    if (inferredAnchorKey(task) && task.start_date) {
      const dateLbl = document.createElementNS(SVG_NS, 'text');
      dateLbl.setAttribute('x', cx - r - labelOffset);
      dateLbl.setAttribute('y', cy);
      dateLbl.setAttribute('dominant-baseline', 'middle');
      dateLbl.setAttribute('text-anchor', 'end');
      dateLbl.setAttribute('font-size', '11');
      dateLbl.setAttribute('font-weight', '700');
      dateLbl.setAttribute('fill', '#061d39');
      dateLbl.style.pointerEvents = 'none';
      dateLbl.textContent = fmtDate(task.start_date);
      group.appendChild(dateLbl);
    }
  }
}

// v4.58: insert an invisible white "occluder" rect behind a freshly-appended
// SVG text element so any arrow line passing through that area visually
// disappears under it. The rect has no stroke and matches the chart
// background (white), so it reads as if the arrow naturally stops at the
// label edge and continues out the other side. Reused by drawBarMeta and
// drawMilestoneLabels. Caller must have already appended the text element
// to the group — we use getBBox to measure the actual rendered glyph box.
// Shared canvas 2D context for text measurement. Created lazily.
// Canvas measureText is the most reliable way to get text widths in CSS
// pixels — it works directly off the browser's font metrics, doesn't
// require the element to be in the DOM or laid out, and returns
// synchronously. Used by drawBarMeta to size the meta/name labels before
// deciding the cascade step.
let _metaCanvasCtx = null;
function ensureMetaCanvasCtx() {
  if (!_metaCanvasCtx) {
    const c = document.createElement('canvas');
    _metaCanvasCtx = c.getContext('2d');
  }
  return _metaCanvasCtx;
}

function addPillOccluder(parent, textEl, pad = 2) {
  try {
    const bbox = textEl.getBBox();
    if (!bbox || bbox.width <= 0) return;
    const rect = document.createElementNS(SVG_NS, 'rect');
    rect.setAttribute('x', bbox.x - pad);
    rect.setAttribute('y', bbox.y - pad);
    rect.setAttribute('width',  bbox.width + pad * 2);
    rect.setAttribute('height', bbox.height + pad * 2);
    rect.setAttribute('fill', 'white');
    rect.setAttribute('stroke', 'none');
    rect.setAttribute('rx', '2');
    rect.style.pointerEvents = 'none';
    parent.insertBefore(rect, textEl);
  } catch (_) { /* getBBox can throw if not laid out; safe to skip */ }
}

function parsePredecessor(s) {
  // Accepts "5", "5FS", "5FF -2w", "5SS +1d", "5SF -3w" etc.
  // Returns { id, type: 'FS'|'SS'|'FF'|'SF', lagDays: number } or null
  const m = String(s).trim().match(/^(\d+)\s*(FS|SS|FF|SF)?\s*([+-]\s*\d+(?:\.\d+)?)\s*([wd])?$|^(\d+)\s*(FS|SS|FF|SF)?$/i);
  if (!m) return null;
  const id = Number(m[1] || m[5]);
  const type = (m[2] || m[6] || 'FS').toUpperCase();
  let lagDays = 0;
  if (m[3]) {
    const n = Number(m[3].replace(/\s+/g, ''));
    lagDays = (m[4] || 'd').toLowerCase() === 'w' ? n * 7 : n;
  }
  return { id, type, lagDays };
}

// Compute the SVG path for one predecessor arrow.
//
// Rules (per ARROW_ROUTING_RULES.md, simplified routing pass):
//   - Arrows render BEHIND bars/labels via z-order, so they may pass through bars; we
//     don't try to avoid them. Bars and labels paint on top.
//   - Path is at most TWO segments: either a single straight drop / horizontal, or an
//     L-shape (one corner). No U-routes, no corridors, no loops.
//   - Exit point on pred is whichever side keeps the path simplest:
//       * If the target entry x falls within pred's x range, exit STRAIGHT DOWN/UP from
//         pred's bottom/top edge at the target x.
//       * Otherwise, exit horizontally from pred's left/right side at center y.
//   - Final segment direction sets the arrowhead orientation (LEFT, RIGHT, UP, DOWN).
// v4.56: arrow head shrunk from 6 → 3 (half size) per user feedback —
// the previous head filled the whole vertical gap between adjacent rows
// at default row heights, which looked clunky. Now it's a small marker
// that points without dominating.
const ARROW_DEFAULTS = { headSize: 3 };
function computeArrowPath(pred, succ, type, opts = {}) {
  const headSize = opts.headSize ?? ARROW_DEFAULTS.headSize;

  const predLeft  = pred.x;
  const predRight = pred.x + pred.w;
  const predTop   = pred.y;
  const predBot   = pred.y + pred.h;
  const succLeft  = succ.x;
  const succRight = succ.x + succ.w;
  const succTop   = succ.y;
  const succBot   = succ.y + succ.h;

  // Vertical relationship by row CENTER. Anything more than 1px difference is treated
  // as a different row — that catches consecutive-row pairs whose bars happen to overlap
  // by a pixel or two.
  const predCy = pred.y + pred.h / 2;
  const succCy = succ.y + succ.h / 2;
  const goingDown = succCy > predCy + 1;
  const goingUp   = succCy < predCy - 1;

  // ----- Pick entry point on succ -----
  // Milestone: entry x is the diamond center; y depends on direction (top/bottom vertex).
  // Bar: entry x defaults by type (FS/SS = left edge; FF/SF = right edge), but when pred
  // sits roughly above/below succ we override to enter from succ's TOP/BOTTOM edge so a
  // straight vertical drop lands cleanly on it.
  let entryX, entryY, headDir;
  if (succ.milestone) {
    entryX = succ.x + succ.w / 2;
    if (goingDown)      { entryY = succTop; headDir = 'DOWN'; }
    else if (goingUp)   { entryY = succBot; headDir = 'UP'; }
    else if (predRight <= succLeft) { entryX = succLeft;  entryY = succ.y + succ.h / 2; headDir = 'RIGHT'; }
    else                            { entryX = succRight; entryY = succ.y + succ.h / 2; headDir = 'LEFT'; }
  } else {
    const enterFromLeft = type === 'FS' || type === 'SS';
    const sideEntryX = enterFromLeft ? succLeft : succRight;
    if (goingDown) {
      entryY = succTop; headDir = 'DOWN';
      // Land just inside the bar on the FS/SS-near side, so the arrowhead nests on succ
      // rather than at the very edge.
      entryX = enterFromLeft
        ? Math.min(sideEntryX + 4, succRight - 2)
        : Math.max(sideEntryX - 4, succLeft + 2);
    } else if (goingUp) {
      entryY = succBot; headDir = 'UP';
      entryX = enterFromLeft
        ? Math.min(sideEntryX + 4, succRight - 2)
        : Math.max(sideEntryX - 4, succLeft + 2);
    } else {
      // Same row — approach from the side, final segment horizontal.
      entryX = sideEntryX;
      entryY = succ.y + succ.h / 2;
      headDir = enterFromLeft ? 'RIGHT' : 'LEFT';
    }
  }

  // ----- Pick exit point on pred -----
  let exitX, exitY;
  if (pred.milestone) {
    if (goingDown)    { exitX = pred.x + pred.w / 2; exitY = predBot; }
    else if (goingUp) { exitX = pred.x + pred.w / 2; exitY = predTop; }
    else if (entryX > pred.x + pred.w / 2) { exitX = predRight; exitY = pred.y + pred.h / 2; }
    else                                    { exitX = predLeft;  exitY = pred.y + pred.h / 2; }
  } else {
    if (goingDown || goingUp) {
      // Straight drop possible if entryX is within pred's x range — exit through the
      // top/bottom edge at entryX. Otherwise exit from the side closest to entryX.
      if (entryX >= predLeft && entryX <= predRight) {
        exitX = entryX;
        exitY = goingDown ? predBot : predTop;
      } else if (opts.predLabelOutside) {
        // The bar's name sits OUTSIDE the bar — a mid-height side exit draws
        // the arrow straight through that text. Leave through the bottom
        // (or top) edge near the bar's end instead; the horizontal run then
        // hugs the row edge, clear of the label.
        exitX = entryX > predRight
          ? Math.max(predLeft + 2, predRight - 4)
          : Math.min(predRight - 2, predLeft + 4);
        exitY = goingDown ? predBot : predTop;
      } else {
        exitX = entryX > predRight ? predRight : predLeft;
        exitY = pred.y + pred.h / 2;
      }
    } else {
      // Same row — exit horizontal from the side.
      const exitingRight = type === 'FS' || type === 'FF';
      exitX = exitingRight ? predRight : predLeft;
      exitY = pred.y + pred.h / 2;
    }
  }

  // Stagger when this pred has multiple successors exiting from the same SIDE edge so
  // their horizontals don't all sit at center y. Straight drops naturally don't overlap
  // (each at its own succ's entryX) so they don't need staggering.
  const total = opts.outgoingTotal || 1;
  const idx   = opts.outgoingIdx   || 0;
  const exitOnSide = !pred.milestone && exitY === pred.y + pred.h / 2 && (exitX === predLeft || exitX === predRight);
  if (exitOnSide && total > 1) {
    const slot = (pred.h * (idx + 1)) / (total + 1);
    exitY = predTop + slot;
  }

  // ----- Build the path: 1 segment if aligned, else L-shape (2 segments) -----
  // Pull the line endpoint back by headSize so the arrowhead's tip lands exactly on
  // the chosen entry point.
  const adj = (() => {
    if (headDir === 'DOWN')  return { x: entryX, y: entryY - headSize };
    if (headDir === 'UP')    return { x: entryX, y: entryY + headSize };
    if (headDir === 'RIGHT') return { x: entryX - headSize, y: entryY };
    return                          { x: entryX + headSize, y: entryY }; // LEFT
  })();

  let linePath;
  // labelAnchor: where a lag label (e.g., "+2 wks") should sit on the arrow.
  // For single-segment arrows it's the midpoint. For L-shape arrows we pick
  // the midpoint of the LONGER segment so the label sits on the visually
  // dominant leg of the route, which is usually the most readable spot.
  let labelAnchor;
  if (Math.abs(exitX - adj.x) < 0.5) {
    linePath = `M ${exitX} ${exitY} L ${exitX} ${adj.y}`;
    labelAnchor = { x: exitX, y: (exitY + adj.y) / 2 };
  } else if (Math.abs(exitY - adj.y) < 0.5) {
    linePath = `M ${exitX} ${exitY} L ${adj.x} ${exitY}`;
    labelAnchor = { x: (exitX + adj.x) / 2, y: exitY };
  } else if (headDir === 'DOWN' || headDir === 'UP') {
    // Final segment is vertical → corner at (entryX, exitY): horizontal then vertical.
    linePath = `M ${exitX} ${exitY} L ${entryX} ${exitY} L ${entryX} ${adj.y}`;
    const horizLen = Math.abs(entryX - exitX);
    const vertLen  = Math.abs(adj.y - exitY);
    labelAnchor = horizLen >= vertLen
      ? { x: (exitX + entryX) / 2, y: exitY }
      : { x: entryX, y: (exitY + adj.y) / 2 };
  } else {
    // Final segment is horizontal → corner at (exitX, entryY): vertical then horizontal.
    linePath = `M ${exitX} ${exitY} L ${exitX} ${entryY} L ${adj.x} ${entryY}`;
    const vertLen  = Math.abs(entryY - exitY);
    const horizLen = Math.abs(adj.x - exitX);
    labelAnchor = vertLen >= horizLen
      ? { x: exitX, y: (exitY + entryY) / 2 }
      : { x: (exitX + adj.x) / 2, y: entryY };
  }

  // ----- Arrowhead -----
  const t = headSize * 0.7;
  let headPath;
  if (headDir === 'DOWN') {
    headPath = `M ${entryX} ${entryY} L ${entryX - t} ${entryY - headSize} L ${entryX + t} ${entryY - headSize} Z`;
  } else if (headDir === 'UP') {
    headPath = `M ${entryX} ${entryY} L ${entryX - t} ${entryY + headSize} L ${entryX + t} ${entryY + headSize} Z`;
  } else if (headDir === 'RIGHT') {
    headPath = `M ${entryX} ${entryY} L ${entryX - headSize} ${entryY - t} L ${entryX - headSize} ${entryY + t} Z`;
  } else {
    headPath = `M ${entryX} ${entryY} L ${entryX + headSize} ${entryY - t} L ${entryX + headSize} ${entryY + t} Z`;
  }

  return { linePath, headPath, labelAnchor };
}

function drawCustomArrows() {
  const svg = document.querySelector('#gantt-container .gantt');
  if (!svg) return;

  // Clean any previous frappe-gantt arrows and our group from prior renders.
  svg.querySelectorAll(':scope > .arrow').forEach(el => el.remove());
  let group = svg.querySelector('.sdc-arrows');
  if (group) group.remove();
  group = document.createElementNS(SVG_NS, 'g');
  group.setAttribute('class', 'sdc-arrows');
  // Insert BEFORE the first bar-wrapper so arrows render BEHIND bars and labels
  // (z-order: later siblings paint on top in SVG). frappe-gantt nests the bar-wrappers
  // inside a parent <g>, so we attach to that parent — not the SVG root.
  const firstBar = svg.querySelector('.bar-wrapper');
  if (firstBar && firstBar.parentNode) firstBar.parentNode.insertBefore(group, firstBar);
  else svg.appendChild(group);

  // Index every bar's geometry. Milestones use the DIAMOND bbox so arrows
  // terminate at the visible outer edge, not the underlying bar-wrapper rect.
  // Anchor diamonds have an OUTER RING ~75% larger than the inner — arrows
  // must terminate at that outer edge, otherwise they pierce the ring.
  const taskById = Object.fromEntries(state.tasks.map(t => [String(t.id), t]));
  const bars = [...svg.querySelectorAll('.bar-wrapper')].map(w => {
    const rect = w.querySelector('.bar');
    if (!rect) return null;
    const id = String(w.getAttribute('data-id'));
    const x = +rect.getAttribute('x');
    const y = +rect.getAttribute('y');
    const ww = +rect.getAttribute('width');
    const hh = +rect.getAttribute('height');
    const task = taskById[id];
    if (task?.is_milestone) {
      const cx = x + ww / 2;
      const cy = y + hh / 2;
      // Anchor outer ring and non-anchor diamond both have outer radius
      // diamondRef × 1.20 / 2 (v4.23 hotfix: decoupled from h). Arrows
      // terminate at this exact boundary so they don't pierce or miss the
      // diamond now that the diamond is smaller than the bar height.
      const diamondRef = Math.max(BAR_H_MIN, Math.round(state.layout.rowHeight * 0.5));
      const r = diamondRef * 1.20 / 2;
      return { id, x: cx - r, y: cy - r, w: 2 * r, h: 2 * r, milestone: true };
    }
    // Will this bar's name label sit OUTSIDE the bar? (Same fits-inside test
    // clipBarLabels applies later.) Arrows leaving such a bar must not
    // side-exit at mid-height — that draws a line straight through the text.
    let labelOutside = false;
    const lbl = w.querySelector('.bar-label');
    if (lbl) {
      try { labelOutside = (lbl.getBBox().width + 10) > ww; } catch (_) {}
    }
    return { id, x, y, w: ww, h: hh, milestone: false, labelOutside };
  });
  const barById = Object.fromEntries(bars.filter(Boolean).map(b => [b.id, b]));

  const arrowColor = '#334155';
  const headSize = 3; // v4.56: half size (was 6)

  // Build the job list, then group by pred + direction so successors leaving the same
  // side of one pred can stagger their exit y values.
  const arrowJobs = [];
  // Lag-label rendering deferred to a second pass after all arrows are drawn —
  // see end of this function. Collecting jobs here avoids a per-arrow forward
  // declaration.
  const lagLabelJobs = [];
  for (const task of state.tasks) {
    if (!task.predecessors) continue;
    const succ = barById[String(task.id)];
    if (!succ) continue;
    const preds = String(task.predecessors).split(',').map(s => s.trim()).filter(Boolean);
    for (const raw of preds) {
      const parsed = parsePredecessor(raw);
      if (!parsed) continue;
      const pred = barById[String(parsed.id)];
      if (!pred) continue;
      arrowJobs.push({ pred, succ, parsed });
    }
  }

  const groups = new Map();
  for (const job of arrowJobs) {
    const dir = job.succ.y > job.pred.y ? 'down' : 'up';
    const key = String(job.pred.id) + '_' + dir;
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(job);
  }
  for (const [, group] of groups) {
    // Closest-succ-first: nearest succ takes the most-direct slot.
    group.sort((a, b) => Math.abs(a.succ.y - a.pred.y) - Math.abs(b.succ.y - b.pred.y));
    group.forEach((job, i) => {
      job.outgoingIdx = i;
      job.outgoingTotal = group.length;
    });
  }

  for (const job of arrowJobs) {
    const { linePath, headPath, labelAnchor } = computeArrowPath(job.pred, job.succ, job.parsed.type, {
      headSize,
      outgoingIdx: job.outgoingIdx,
      outgoingTotal: job.outgoingTotal,
      predLabelOutside: !!job.pred.labelOutside,
    });

    // Arrow color: deep red and bolder ONLY when BOTH endpoints sit on the
    // critical path. That's what makes the segment actually part of the chain —
    // an arrow leaving a critical task to a non-critical successor isn't critical
    // (the successor has slack). Read directly from the bar-wrappers' class so
    // we share the exact source of truth that's already painting the bars red.
    const predEl = svg.querySelector(`.bar-wrapper[data-id="${String(job.pred.id)}"]`);
    const succEl = svg.querySelector(`.bar-wrapper[data-id="${String(job.succ.id)}"]`);
    const onCritical = !!(predEl && predEl.classList.contains('on-critical')
                       && succEl && succEl.classList.contains('on-critical'));

    const line = document.createElementNS(SVG_NS, 'path');
    line.setAttribute('d', linePath);
    line.setAttribute('class', 'arrow' + (onCritical ? ' on-critical' : ''));
    line.setAttribute('fill', 'none');
    line.setAttribute('stroke', onCritical ? '#b91c1c' : arrowColor);
    line.setAttribute('stroke-width', onCritical ? '3' : '1.4');
    line.setAttribute('stroke-linecap', 'square');
    line.setAttribute('stroke-linejoin', 'miter');
    if (onCritical) line.setAttribute('data-on-critical', '1');
    group.appendChild(line);

    const head = document.createElementNS(SVG_NS, 'path');
    head.setAttribute('d', headPath);
    head.setAttribute('class', 'arrow' + (onCritical ? ' on-critical' : ''));
    head.setAttribute('fill', onCritical ? '#b91c1c' : arrowColor);
    if (onCritical) head.setAttribute('data-on-critical', '1');
    group.appendChild(head);

    // Collect lag-label data for this arrow if it carries a non-zero lag and
    // the user has lag labels enabled. We render labels AFTER all arrows are
    // drawn, in a separate group on top of bars, so they don't get covered.
    const lagDays = Number(job.parsed.lagDays) || 0;
    if (state.scheduleView?.showArrowLags !== false && Math.abs(lagDays) >= 7 && labelAnchor) {
      const wks = Math.round(lagDays / 7);
      if (wks !== 0) {
        lagLabelJobs.push({
          job,
          wks,
          onCritical,
          anchor: { x: labelAnchor.x, y: labelAnchor.y },
        });
      }
    }
  }

  // ----- Render lag labels in a separate group ABOVE bars -----
  // Two reasons to render here, after the arrows loop, rather than inline:
  //   1. Z-order: the .sdc-arrows group sits BEHIND bars on purpose (so
  //      arrows duck under bars when routes overlap). Lag labels need to sit
  //      ABOVE bars so the user can read them — bars covered the labels
  //      otherwise (user feedback: "−2 weeks from designer view is underneath
  //      mechanical design").
  //   2. Overlap avoidance: once we have ALL label positions, we can detect
  //      colliding labels and shift them along the segment so they don't sit
  //      directly on top of each other (user feedback: "robot vision and
  //      robot programming labels are on top of each other").
  if (lagLabelJobs.length > 0) renderArrowLagLabels(svg, lagLabelJobs);
}

// Render the lag labels for every arrow that has a non-zero lag, in a group
// that paints ABOVE bars (so labels are always visible). Also runs an
// overlap-resolution pass: any label whose pill bbox would collide with a
// previously-placed label gets shifted vertically by one pill-height (with a
// small gap) until it no longer collides. We keep the original anchor.x so
// the label still reads as belonging to its arrow segment.
function renderArrowLagLabels(svg, jobs) {
  // Tear down any previous labels group so we start clean each render.
  svg.querySelectorAll(':scope > .sdc-arrow-labels').forEach(el => el.remove());
  const group = document.createElementNS(SVG_NS, 'g');
  group.setAttribute('class', 'sdc-arrow-labels');
  // Append AT THE END of the SVG's children so we paint over bars/labels.
  svg.appendChild(group);

  // Precompute the placed bboxes so we can avoid overlap as we lay each one
  // out. Pills are roughly the same size, so a simple AABB collision check
  // is enough.
  const placed = [];
  const PILL_H = 14;
  const GAP    = 2;
  const overlaps = (a, b) =>
    !(a.x + a.w + GAP <= b.x || b.x + b.w + GAP <= a.x ||
      a.y + a.h + GAP <= b.y || b.y + b.h + GAP <= a.y);

  for (const { job, wks, onCritical, anchor } of jobs) {
    const labelText = (wks > 0 ? '+' : '−') + Math.abs(wks) + ' wk' + (Math.abs(wks) === 1 ? '' : 's');
    const pillW = labelText.length * 6 + 10;

    // Shift the label vertically until it no longer collides with any
    // previously-placed pill. Max ~10 shifts (so a worst-case label still
    // lands within a couple of rows of its anchor). Alternate up/down to
    // keep the label as close to its arrow as possible.
    let cy = anchor.y;
    for (let attempt = 0; attempt < 12; attempt++) {
      const candX = anchor.x - pillW / 2;
      const candY = cy - PILL_H / 2;
      const cand = { x: candX, y: candY, w: pillW, h: PILL_H };
      const hit = placed.some(p => overlaps(cand, p));
      if (!hit) {
        // Place here.
        placePill({
          group, job, wks, onCritical, labelText, pillW,
          x: anchor.x, y: cy,
        });
        placed.push(cand);
        break;
      }
      // Try one slot up, then one slot down, expanding outward.
      const slot = Math.ceil((attempt + 1) / 2);
      const dir  = attempt % 2 === 0 ? -1 : 1;
      cy = anchor.y + dir * slot * (PILL_H + GAP);
    }
  }
}

// Actually paint one pill + text into the labels group, with a click handler
// that opens the inline lag editor.
function placePill({ group, job, wks, onCritical, labelText, pillW, x, y }) {
  const pillH = 14;
  const pill = document.createElementNS(SVG_NS, 'rect');
  pill.setAttribute('x', x - pillW / 2);
  pill.setAttribute('y', y - pillH / 2);
  pill.setAttribute('width',  pillW);
  pill.setAttribute('height', pillH);
  pill.setAttribute('rx', 3);
  pill.setAttribute('ry', 3);
  pill.setAttribute('class', 'arrow-lag-pill');
  pill.setAttribute('fill', '#ffffff');
  pill.setAttribute('stroke', onCritical ? '#b91c1c' : '#475569');
  pill.setAttribute('stroke-width', '1');
  pill.style.cursor = 'pointer';
  pill.dataset.taskId = String(job.succ.id);
  pill.dataset.predIdx = String(job.parsed.id);
  group.appendChild(pill);

  const label = document.createElementNS(SVG_NS, 'text');
  label.setAttribute('x', x);
  label.setAttribute('y', y);
  label.setAttribute('text-anchor', 'middle');
  label.setAttribute('dominant-baseline', 'central');
  label.setAttribute('font-size', '10');
  label.setAttribute('font-weight', '700');
  label.setAttribute('fill', onCritical ? '#b91c1c' : '#1e293b');
  label.setAttribute('class', 'arrow-lag-label');
  label.style.pointerEvents = 'none';
  label.textContent = labelText;
  group.appendChild(label);

  pill.addEventListener('click', (ev) => {
    ev.stopPropagation();
    editArrowLag({
      taskId: Number(job.succ.id),
      predId: Number(job.parsed.id),
      currentWks: wks,
      clientX: ev.clientX,
      clientY: ev.clientY,
    });
  });
}

// Inline editor for an arrow lag. Pops a tiny number input near the click point,
// reads a new weeks value, rewrites the predecessor string on the successor task,
// and reloads. Empty input or "0" removes the lag entirely (predecessor becomes
// the base form like "5FS").
function editArrowLag({ taskId, predId, currentWks, clientX, clientY }) {
  const task = state.tasks.find(t => t.id === taskId);
  if (!task) return;
  // Tear down any previous editor.
  document.getElementById('arrow-lag-edit')?.remove();
  const box = document.createElement('div');
  box.id = 'arrow-lag-edit';
  box.className = 'arrow-lag-edit';
  box.innerHTML = `
    <label>Lag (wks)</label>
    <input type="number" step="1" value="${currentWks}" />
    <button type="button" class="confirm-popup-cancel">Cancel</button>
    <button type="button" class="confirm-popup-ok">Save</button>
  `;
  document.body.appendChild(box);
  const w = box.offsetWidth || 220;
  const h = box.offsetHeight || 56;
  box.style.left = Math.min(window.innerWidth - w - 8, Math.max(8, clientX - w / 2)) + 'px';
  box.style.top  = Math.min(window.innerHeight - h - 8, Math.max(8, clientY + 12)) + 'px';
  const input = box.querySelector('input');
  input.focus();
  input.select();

  const close = () => {
    box.remove();
    document.removeEventListener('mousedown', onOutside, true);
    document.removeEventListener('keydown', onKey, true);
  };
  const save = async () => {
    const v = input.value.trim();
    const newWks = v === '' ? 0 : Math.round(Number(v));
    if (!Number.isFinite(newWks)) { close(); return; }
    // Rewrite the predecessor segment that points at predId. Preserve the
    // FS/SS/FF/SF type; replace any existing [+-]Nw/d lag suffix with the
    // new weeks value (or remove the suffix entirely when newWks === 0).
    const parts = String(task.predecessors || '').split(',').map(s => s.trim()).filter(Boolean);
    let changed = false;
    const updated = parts.map(p => {
      const m = p.match(/^(\d+)(FS|SS|FF|SF)?(\s*[+-]\s*\d+\s*[wd]?)?$/i);
      if (!m) return p;
      if (Number(m[1]) !== predId) return p;
      changed = true;
      const id = m[1];
      const type = (m[2] || 'FS').toUpperCase();
      if (newWks === 0) return `${id}${type}`;
      const sign = newWks > 0 ? '+' : '-';
      return `${id}${type} ${sign}${Math.abs(newWks)}w`;
    });
    close();
    if (!changed) return;
    pushUndoSnapshot(task, ['predecessors'], `Edit lag on "${task.name || 'task'}"`);
    await api.update(taskId, { predecessors: updated.join(', ') });
    await loadTasks();
  };
  const onOutside = (ev) => { if (!box.contains(ev.target)) close(); };
  const onKey = (ev) => {
    if (ev.key === 'Escape') { ev.preventDefault(); close(); }
    else if (ev.key === 'Enter') { ev.preventDefault(); save(); }
  };
  box.querySelector('.confirm-popup-cancel').addEventListener('click', close);
  box.querySelector('.confirm-popup-ok').addEventListener('click', save);
  setTimeout(() => {
    document.addEventListener('mousedown', onOutside, true);
    document.addEventListener('keydown', onKey, true);
  }, 0);
}


// ---------- Filter controls ----------
function renderFilters() {
  // Datalists for any free-text inputs elsewhere that autocomplete from current data.
  const projects = uniqueValues('project');
  document.getElementById('dl-projects').innerHTML = projects.map(p => `<option value="${escapeHtml(p)}">`).join('');
  document.getElementById('dl-assignees').innerHTML = uniqueValues('assignee').map(a => `<option value="${escapeHtml(a)}">`).join('');

  const qf = state.filters.quick || {};
  // Active-filter chip count next to the topbar button. Counts every active quick
  // chip so the user sees at a glance how many filters are on.
  const activeCount = Object.values(qf).filter(Boolean).length;
  const chip = document.getElementById('filter-chip-count');
  if (chip) {
    chip.textContent = activeCount ? String(activeCount) : '';
    chip.hidden = activeCount === 0;
  }

  const pop = document.getElementById('filters-popover');
  if (!pop) return;
  // Quick-chip filters — single-click toggles that focus the schedule on a state
  // ("behind", "ahead", "milestones only", etc.). Anchors AND non-anchor
  // milestones are always exempt so the schedule spine stays visible
  // regardless of which chips are on.
  //
  // Critical Path lives here too (alongside other quick filters):
  //   - "Critical path"     = highlight mode (red bars + arrows on the chain)
  //   - "Critical path only" = filter mode (hide everything not on the chain;
  //                             auto-enables highlight too).
  const sv = state.scheduleView || {};
  const chipDefs = [
    { key: 'showCompleted', label: 'Show completed',    source: 'quick' },
    { key: 'behind',        label: 'Behind schedule',   source: 'quick' },
    { key: 'ahead',         label: 'Ahead of schedule', source: 'quick' },
    { key: 'milestones',    label: 'Milestones only',   source: 'quick' },
    { key: 'assigned',      label: 'Assigned (real work)', source: 'quick' },
    { key: 'overallocated', label: 'Over-allocated',    source: 'quick' },
    { key: 'criticalPath',  label: 'Critical path',     source: 'view',  active: !!sv.criticalPath },
    { key: 'criticalOnly',  label: 'Critical path only', source: 'view', active: !!sv.criticalOnly },
  ];
  // v4.54: Filters popover uses CHECKBOXES (not pills). Each filter is a
  // row with checkbox + label. Easier to scan as a list. For Customer mode
  // is just another checkbox in the same list under a VIEW section.
  const inCustomerView = document.body.classList.contains('customer-view');
  pop.innerHTML = `
    <div class="filters-popover-title">Quick filters</div>
    <div class="filters-check-list">
      ${chipDefs.map(c => {
        const active = c.source === 'view' ? !!c.active : !!qf[c.key];
        return `
          <label class="filters-check-row">
            <input type="checkbox" data-quick="${c.key}" data-source="${c.source}" ${active ? 'checked' : ''}>
            <span>${escapeHtml(c.label)}</span>
          </label>
        `;
      }).join('')}
    </div>
    <div class="filters-popover-sep"></div>
    <div class="filters-popover-title">View</div>
    <label class="filters-check-row">
      <input type="checkbox" id="filters-customer-view-toggle" ${inCustomerView ? 'checked' : ''}>
      <span>For Customer mode</span>
    </label>
    <div class="filters-popover-actions">
      <button type="button" id="btn-clear-filters" class="btn-ghost btn-tight">Clear all</button>
    </div>
  `;
  // Stop propagation on every click inside the popover so the document-level
  // close handler doesn't see "click outside" and dismiss the popover. Users
  // want to toggle multiple filters in one session without re-opening.
  pop.querySelectorAll('input[type="checkbox"][data-quick]').forEach(cb => {
    cb.addEventListener('change', (e) => {
      e.stopPropagation();
      const k = cb.dataset.quick;
      const src = cb.dataset.source;
      if (src === 'view' && k === 'criticalPath') {
        const turningOff = state.scheduleView.criticalPath;
        state.scheduleView.criticalPath = !turningOff;
        if (turningOff) state.scheduleView.criticalOnly = false;
        saveScheduleView();
        applyScheduleView();
      } else if (src === 'view' && k === 'criticalOnly') {
        const turningOn = !state.scheduleView.criticalOnly;
        state.scheduleView.criticalOnly = turningOn;
        if (turningOn) state.scheduleView.criticalPath = true;
        saveScheduleView();
        applyScheduleView();
      } else {
        if (!state.filters.quick) state.filters.quick = {};
        state.filters.quick[k] = !state.filters.quick[k];
      }
      render();
    });
  });
  // Stop propagation on label clicks so the popover doesn't auto-close.
  pop.querySelectorAll('.filters-check-row').forEach(row => {
    row.addEventListener('click', (e) => e.stopPropagation());
  });
  pop.querySelector('#btn-clear-filters').addEventListener('click', (e) => {
    e.stopPropagation();
    state.filters.quick = { behind: false, ahead: false, milestones: false, assigned: false, overallocated: false, showCompleted: false };
    // Also clear Critical path since it lives among quick filters now.
    state.scheduleView.criticalPath = false;
    state.scheduleView.criticalOnly = false;
    saveScheduleView();
    applyScheduleView();
    render();
  });
  // v4.51: For Customer mode toggle (moved out of toolbar into Filters).
  // Drives the existing enterCustomerView / exitCustomerView flow so the
  // flatten + zoom-to-fit side effects still fire. Falls back to a no-op
  // alert if no project is selected (the customer view is per-project).
  const cvToggle = pop.querySelector('#filters-customer-view-toggle');
  if (cvToggle) {
    cvToggle.addEventListener('change', (e) => {
      e.stopPropagation();
      if (cvToggle.checked) {
        if (!state.filters.project) {
          cvToggle.checked = false;
          showAlertDialog('Pick a project tab first — customer view is per-project.');
          return;
        }
        enterCustomerView();
      } else {
        exitCustomerView();
      }
    });
  }
}

// ---------- Project tabs (open schedules) ----------
// Open projects persist in localStorage so reloads remember them. The empty string ""
// is the canonical "All projects" pseudo-tab — always present, can't be closed. Switching
// tabs sets state.filters.project which the existing applyFilters honors.
function loadProjectTabs() {
  // Open tabs + active project use sessionStorage — persists across F5 within the
  // same browser tab (so refresh doesn't wipe your work), but clears automatically
  // when the browser tab is closed. This prevents old sessions from auto-loading
  // a pile of stale tabs on a fresh start.
  let saved = null;
  try { saved = JSON.parse(sessionStorage.getItem('sdcOpenProjects') || 'null'); } catch {}
  if (Array.isArray(saved) && saved.length) {
    state.openProjects = saved.includes('') ? saved : ['', ...saved];
  } else {
    state.openProjects = [''];
  }
  const savedActive = sessionStorage.getItem('sdcActiveProject');
  state.filters.project = (savedActive != null && state.openProjects.includes(savedActive))
    ? savedActive : '';
  let savedTemplates = [];
  try { savedTemplates = JSON.parse(localStorage.getItem('sdcTemplateProjects') || '[]'); } catch {}
  state.templateProjects = Array.isArray(savedTemplates) ? savedTemplates : [];
  let savedWorkspaces = {};
  try { savedWorkspaces = JSON.parse(localStorage.getItem('sdcProjectWorkspaces') || '{}'); } catch {}
  state.projectWorkspaces = (savedWorkspaces && typeof savedWorkspaces === 'object') ? savedWorkspaces : {};
  const savedActiveWs = localStorage.getItem('sdcActiveWorkspace');
  state.activeWorkspace = (savedActiveWs && ['Active', 'Sales', 'Closed'].includes(savedActiveWs)) ? savedActiveWs : 'Active';
  // Projects-page expanded sections (per workspace). Defaults to all
  // collapsed; user clicks a header to expand.
  let savedExpanded = {};
  try { savedExpanded = JSON.parse(localStorage.getItem('sdcProjectsExpanded') || '{}'); } catch {}
  // Active defaults to expanded. Merge saved on top — so explicit { Active: false } from
  // the user overrides the default, but a blank {} (first load) still shows Active open.
  state._projectsExpanded = { Active: true, ...((savedExpanded && typeof savedExpanded === 'object') ? savedExpanded : {}) };
  // Favorites + Recents are per-browser localStorage lists of project names.
  let favs = [];
  try { favs = JSON.parse(localStorage.getItem('sdcFavoriteProjects') || '[]'); } catch {}
  state.favoriteProjects = Array.isArray(favs) ? favs : [];
  let recents = [];
  try { recents = JSON.parse(localStorage.getItem('sdcRecentProjects') || '[]'); } catch {}
  state.recentProjects = Array.isArray(recents) ? recents.slice(0, 10) : [];
  // If the active project belongs to a different workspace than the saved
  // active workspace, sync the workspace to the project. Otherwise the user
  // would load into a workspace where their last-viewed project doesn't appear.
  if (state.filters.project) {
    const ws = projectWorkspace(state.filters.project);
    if (ws !== state.activeWorkspace) state.activeWorkspace = ws;
  }
}

function saveProjectTabs() {
  sessionStorage.setItem('sdcOpenProjects', JSON.stringify(state.openProjects));
  sessionStorage.setItem('sdcActiveProject', state.filters.project || '');
  localStorage.setItem('sdcTemplateProjects', JSON.stringify(state.templateProjects || []));
  localStorage.setItem('sdcProjectWorkspaces', JSON.stringify(state.projectWorkspaces || {}));
  localStorage.setItem('sdcActiveWorkspace', state.activeWorkspace || 'Active');
  localStorage.setItem('sdcFavoriteProjects', JSON.stringify(state.favoriteProjects || []));
  localStorage.setItem('sdcRecentProjects',   JSON.stringify(state.recentProjects   || []));
}

// Toggle a project's favorite flag. Updates state + localStorage + refreshes
// any open Projects / Favorites / Recents page so the UI reflects the change.
function toggleFavoriteProject(name) {
  if (!name) return;
  const i = state.favoriteProjects.indexOf(name);
  if (i >= 0) state.favoriteProjects.splice(i, 1);
  else        state.favoriteProjects.unshift(name);
  saveProjectTabs();
  // Re-render whichever view is showing so the star flips immediately.
  if (state.view === 'projects')  renderProjectsPage();
  if (state.view === 'favorites') renderFavoritesPage();
  if (state.view === 'recents')   renderRecentsPage();
}

// Record a project open in the Recents list. Newest-first, deduped, capped at 10.
function recordRecentProject(name) {
  if (!name) return;
  state.recentProjects = [name, ...(state.recentProjects || []).filter(p => p !== name)].slice(0, 10);
  saveProjectTabs();
}

function isTemplateProject(p) {
  if (!p) return false;
  if (Array.isArray(state.templateProjects) && state.templateProjects.includes(p)) return true;
  return /_template$/i.test(p.trim());
}

// Fixed list of workspaces for v4.7. Order here is also the display order in
// the picker. Adding a new workspace just means dropping its name into this
// array — assignments live in state.projectWorkspaces keyed by project name.
const WORKSPACES = ['Active', 'Sales', 'Closed'];
const DEFAULT_WORKSPACE = 'Active';

// Get the workspace a project belongs to. Falls back to the default for any
// project that hasn't been explicitly assigned (i.e. everything from before
// v4.7 is in "Active").
function projectWorkspace(p) {
  if (!p) return DEFAULT_WORKSPACE;
  const ws = state.projectWorkspaces?.[p];
  if (WORKSPACES.includes(ws)) return ws;
  // Auto-detect workspace from project name when nothing's explicitly set.
  // Keeps the SDC_Sales_Template (and any other *sales* / *closed* schedule)
  // in the right workspace on first load without requiring manual right-click
  // assignment per browser. The user can still override via right-click →
  // Workspace: ___; that explicit choice persists in state.projectWorkspaces.
  const lower = String(p).toLowerCase();
  if (/\bsales?\b|_sales/.test(lower))  return 'Sales';
  if (/\bclosed\b|_closed|_archive/.test(lower)) return 'Closed';
  return DEFAULT_WORKSPACE;
}

// True iff the task lives in a Sales-workspace project. Used by the grid to
// SUPPRESS the allocation pill, allocation column, and assignee column for
// Sales schedules (per v4.22): Sales work is pre-quote, so showing "85% × 4
// engineers" or "ME Placeholder" surfaces detail the customer / sales rep
// doesn't need and risks accidentally communicating commitments. Anything
// auto-detected as Sales (name match) OR explicitly assigned via right-click
// → Workspace: Sales gets the suppression.
function isSalesProjectTask(t) {
  if (!t || !t.project) return false;
  return projectWorkspace(t.project) === 'Sales';
}

function setProjectWorkspace(p, workspace) {
  if (!p) return;
  if (!WORKSPACES.includes(workspace)) return;
  state.projectWorkspaces = state.projectWorkspaces || {};
  // ALWAYS write the explicit value — even 'Active'. The auto-detect by
  // name (used as a fallback in projectWorkspace) returns 'Sales' for any
  // name matching /_sales/, which used to override an explicit 'Active'
  // setting because we'd clear the map entry. e.g. "Test_Sales — Project"
  // was being auto-tagged as Sales after promote despite the server
  // setting workspace='Active'. Recording every explicit assignment fixes
  // this; the trade-off is a slightly larger map.
  state.projectWorkspaces[p] = workspace;
  saveProjectTabs();
  // Persist to the DB too. init() re-reads /api/projects on EVERY boot and
  // overwrites this map with the server's workspace values — so a local-only
  // assignment silently reverts on the next reload (how a schedule created
  // from the sales template escaped to Active).
  _persistWorkspaceToServer(p, workspace);
}

async function _persistWorkspaceToServer(p, workspace) {
  try {
    let rec = state.projectsIndex?.[p];
    if (!rec || !rec.id) {
      // No projects row yet (fresh clone) — POST creates one carrying the
      // workspace, or returns the existing row (unchanged) if it was there.
      const r = await fetch('/api/projects', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: p, workspace }),
      });
      if (!r.ok) return;
      const row = await r.json();
      state.projectsIndex = state.projectsIndex || {};
      state.projectsIndex[p] = { id: row.id, job_number: row.job_number || '', hours_job_id: row.hours_job_id || '' };
      if (row.workspace === workspace) return; // fresh INSERT already carries it
      rec = state.projectsIndex[p];
    }
    await fetch(`/api/projects/${rec.id}`, {
      method: 'PUT', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ workspace }),
    });
  } catch (_) { /* offline / viewer role — localStorage still has it for this browser */ }
}

// Has the given project had a baseline set? "Set" = at least one task carries
// baseline_start_date. Used by the Baseline toolbar buttons to label the left
// half "Set baseline" vs "Reset baseline" and to enable/disable the visibility
// toggle on the right half.
function projectHasBaseline(p) {
  if (!p) return false;
  return state.tasks.some(t => t.project === p && t.baseline_start_date);
}

// Refresh the Baseline dropdown button's label + tooltip to reflect the active
// project's baseline state. The button shows the overall state at a glance;
// clicking opens a dropdown with the specific actions (Turn on / Reset / Show
// or Hide / Turn off).
function syncBaselineButtons() {
  const btn = document.getElementById('btn-view-baseline');
  if (!btn) return;
  const project = state.filters.project;
  const has = projectHasBaseline(project);
  btn.classList.toggle('is-active', !!state.showBaseline && has);
  btn.disabled = !project;
  btn.title = !project
    ? 'Open a specific project tab first — baselines are per-project.'
    : (has
        ? (state.showBaseline
            ? `Baseline is ON (overlay visible). Click for actions: Reset / Hide / Turn off.`
            : `Baseline is set but HIDDEN. Click for actions: Show / Reset / Turn off.`)
        : `No baseline set for "${project}". Click to turn one on.`);
}

// Projects landing page — full-page view that the user navigates to by
// clicking the Projects icon in the left sidebar. Single column with each
// workspace as a collapsible section; click the header row to expand /
// collapse. Project rows inside each section open as a tab on click.
// "+ New schedule" button per workspace (disabled for Closed).
// Sales → detailed project promote modal. Prompts for the new project
// name, calls the server's /api/project/:source/promote, then opens
// the freshly-stamped project as the active tab.
function openPromoteModal(sourceProject) {
  const existing = document.getElementById('promote-modal');
  if (existing) existing.remove();
  // Default name: `<sales> — detailed`. Strip a trailing " — detailed" if
  // somehow the user is promoting an already-promoted project so we don't
  // end up with " — detailed — detailed".
  const baseName = sourceProject.replace(/ — detailed$/, '');
  const suggestedName = `${baseName} — detailed`;
  const overlay = document.createElement('div');
  overlay.id = 'promote-modal';
  overlay.className = 'modal-overlay app-dialog-overlay';
  overlay.innerHTML = `
    <div class="modal-card" style="max-width: 520px;">
      <div class="modal-head">
        <h2>Promote to detailed project</h2>
        <button class="modal-close" type="button">×</button>
      </div>
      <div class="modal-body">
        <p style="margin:0 0 12px;font-size:var(--fs-base);color:#334155;">
          Stamps a fresh schedule from <code>SDC_StandardProject_Template</code>
          and copies <strong>${escapeHtml(sourceProject)}</strong>'s saved
          quote across — hours per bucket, People # (incl. fractional
          values like 1.25), and any manual Quoted-hours overrides.
        </p>
        <p style="margin:0 0 16px;font-size:var(--fs-md);color:#64748b;">
          People-math: a sales value of <em>1.25 ce_engineering</em>
          becomes 1 CE row @ 85% + 1 helper row @ 25% on the detailed
          schedule. Durations recompute so total hours per discipline
          match the sales quote, then cascadeSchedule fills in dates.
        </p>
        <label style="display:block;font-size:var(--fs-md);font-weight:var(--fw-semibold);color:#334155;margin-bottom:6px;">
          New project name
        </label>
        <input type="text" id="promote-name-input" value="${escapeHtml(suggestedName)}"
               style="width:100%;padding:8px 10px;border:1px solid #cbd5e1;border-radius:4px;font-size:var(--fs-lg);font-family:inherit;" />
        <p class="promote-error" id="promote-error" style="background:#fee2e2;color:#991b1b;padding:8px 10px;border-radius:4px;font-size:var(--fs-base);margin:10px 0 0;display:none;"></p>
      </div>
      <div class="modal-foot">
        <button type="button" class="btn-secondary" data-action="cancel">Cancel</button>
        <button type="button" class="btn-primary" data-action="confirm" id="promote-confirm-btn">Promote</button>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  const close = () => overlay.remove();
  overlay.querySelector('.modal-close').onclick = close;
  overlay.querySelector('[data-action="cancel"]').onclick = close;
  overlay.addEventListener('click', (e) => { if (e.target === overlay) close(); });
  const input    = overlay.querySelector('#promote-name-input');
  const errorEl  = overlay.querySelector('#promote-error');
  const showErr  = (msg) => { errorEl.textContent = msg; errorEl.style.display = ''; };
  const hideErr  = () => { errorEl.style.display = 'none'; };
  input.addEventListener('input', hideErr);
  input.addEventListener('keydown', (e) => { if (e.key === 'Enter') overlay.querySelector('[data-action="confirm"]').click(); });
  setTimeout(() => input.select(), 50);
  overlay.querySelector('[data-action="confirm"]').addEventListener('click', async () => {
    const newName = input.value.trim();
    if (!newName) { showErr('Name is required.'); return; }
    if (newName === sourceProject) { showErr('New name must differ from the source.'); return; }
    const btn = overlay.querySelector('#promote-confirm-btn');
    btn.disabled = true;
    btn.textContent = 'Promoting…';
    try {
      const r = await fetch(`/api/project/${encodeURIComponent(sourceProject)}/promote`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ newName }),
      });
      const body = await r.json();
      if (!r.ok) throw new Error(body.error || 'Promotion failed');
      close();
      if (typeof showToast === 'function') showToast(`Created "${newName}" from ${sourceProject}.`, { kind: 'success' });
      // Pin the new project to the Active workspace explicitly. Without
      // this, projectWorkspace's name-based auto-detect tags anything
      // matching /_sales/ as Sales — so "Test_Sales — Project" would
      // open with the sales-mode (combined) Quote vs Schedule rows
      // instead of the detailed breakdown we just stamped.
      setProjectWorkspace(newName, 'Active');
      // Open the new project as the active tab.
      if (!state.openProjects.includes(newName)) state.openProjects.push(newName);
      state.filters.project = newName;
      state.activeWorkspace = 'Active';
      recordRecentProject(newName);
      saveProjectTabs();
      await loadTasks();
      setView('schedule');
    } catch (err) {
      btn.disabled = false;
      btn.textContent = 'Promote';
      showErr(err.message || String(err));
    }
  });
}

// ───────────────────────────────────────────────────────────────────────
// Dashboard — at-a-glance status across one or many projects, organized
// by department (the disciplines that actually do the work).
//
// Layout, top to bottom:
//   1. Filters row: Project picker (multi-select dropdown) + "Coming due
//      in N weeks" number input. Both persist in localStorage.
//   2. Key Milestones strip — one row per selected project, showing the
//      5 spine anchors (PO / Mech 1 / Power-Up / FAT / Ship) as a visual
//      timeline with done/upcoming/overdue states.
//   3. Overall Health — single donut chart + counts for all open work
//      tasks across the selected projects (done / on-time / ahead / behind).
//   4. By Department — one card per ownership bucket (Mechanical, Controls,
//      General, Procurement, Build, Wire, Testing, Teardown, Install).
//      Each card has:
//        • Progress bar comparing actual % done vs expected % done. The
//          expected % is the fraction of THIS DEPT'S tasks whose end_date
//          has already passed — i.e. "should be finished by now" by count,
//          not by elapsed calendar time. Per Dan's spec.
//        • Donut showing the dept's ahead/on-time/behind split.
//        • Three short lists: Coming due (within the N-week window),
//          Behind, Ahead.
//
// "Ownership bucket" is computed from (phase_group, department,
// sub_department) so Mechanical Engineering tasks live with their own
// kind, not lumped under generic 'engineering'.
//
// Built straight off state.tasks so it always reflects whatever the
// schedule already loaded. No new server endpoints — pure derived view.

// Map a task to its ownership bucket — group by ASSIGNEE'S team
// discipline, not by the task's section/department. Dan's spec:
// "People are assigned to departments. Right? Not tasks. So in that
// case, you only have four departments… mechanical engineering,
// controls engineering, wiring, building. I guess you could put in
// p m there." The team-discipline values come from DISCIPLINES at the
// top of the file: pm, mech, controls, build, wire.
function _pdashOwnershipKey(t) {
  if (!t.assignee) return 'unassigned';
  const member = (state.team || []).find(m => m.name === t.assignee);
  if (!member || !member.discipline) return 'unassigned';
  return member.discipline;
}

// Five team disciplines + the catch-all unassigned bucket. Labels match
// DISCIPLINE_BY_KEY so the dashboard and Departments tab read the same.
const _PDASH_OWNERSHIP = [
  { key: 'mech',       label: 'Mechanical Engineering' },
  { key: 'controls',   label: 'Controls Engineering' },
  { key: 'pm',         label: 'Project Management' },
  { key: 'build',      label: 'Build' },
  { key: 'wire',       label: 'Wire' },
  { key: 'unassigned', label: 'Unassigned' },
];
// Map a financial milestone (by name OR predecessor) to its short
// abbreviation used in the dashboard tile + the Gantt overlay label.
// Dan's canonical set: PO, MC, FAT, SAT. Anything not in the standard
// four falls back to the first 3-4 chars of the name uppercased.
function _pdashFinAbbrev(f) {
  const name = String(f && f.name || '').trim();
  const pred = String(f && f.predecessors || '').trim().toLowerCase();
  const n = name.toLowerCase();
  if (/\bpo\b|receipt of po|down payment/.test(n) || pred === 'po') return 'PO';
  if (/major commercial|mid payment|\bmc\b/.test(n))                 return 'MC';
  if (/\bfat\b|acceptance at sdc/.test(n) || pred === 'fat')         return 'FAT';
  if (/\bsat\b|acceptance at customer/.test(n) || /^ship/i.test(pred)) return 'SAT';
  // Fallback — first non-space chunk uppercased, max 4 chars.
  const fallback = (name.match(/[A-Za-z0-9]+/g) || []).join('').slice(0, 4);
  return fallback.toUpperCase() || '$';
}

// Canonical order for the dashboard milestone strip — PO, MC, FAT, SAT.
// Anything else falls to the tail end, sorted by date.
function _pdashFinOrder(f) {
  return ({ PO: 0, MC: 1, FAT: 2, SAT: 3 })[_pdashFinAbbrev(f)] ?? 99;
}

// Short month-year string from an ISO date — "2026-05-08" → "May '26".
// Used by the milestone-strip financial badges so the PM sees the
// target month at a glance without the full M/D/Y. Returns '' for an
// unparseable or empty date.
function _pdashFinMonth(isoDate) {
  if (!isoDate) return '';
  const d = new Date(String(isoDate) + 'T00:00:00');
  if (Number.isNaN(d.getTime())) return '';
  const monthShort = d.toLocaleString('en-US', { month: 'short' });
  const yearShort  = String(d.getFullYear()).slice(2);
  return `${monthShort} '${yearShort}`;
}

// Convert a (calendar) day count to a half-week-snapped string like
// "0.5W" / "1W" / "1.5W". Per Dan's spec: the dashboard never shows raw
// days, and any week value is rounded to the nearest 0.5 — no 0.2 / 0.4
// / 0.6 fractions even when the underlying math would produce them.
// Five work days = one work week is the SDC convention used throughout
// the schedule.
function _pdashDaysToWeeks(days) {
  const w = (Math.abs(days) || 0) / 5;
  const snapped = Math.round(w * 2) / 2;
  // Round-trip is intentional: tiny values that would render "0W" still
  // count as "0.5W" minimum, so a 1-day slip reads "0.5W late" not "0W".
  const out = snapped === 0 && Math.abs(days) > 0 ? 0.5 : snapped;
  // Drop trailing ".0" so 2.0 → "2", but keep "0.5".
  return out % 1 === 0 ? String(out) : String(out);
}

// Month-range picker used by the Financial Milestones section.
// Returns HTML for two <input type="month"> fields side by side. The
// data-action="set-fin-month-from|to" attrs are read by the change
// handler wired in renderDashboard.
function _pdashFinMonthControls(from, to) {
  return `<label class="pdash-fin-month">From <input type="month" data-action="set-fin-month-from" value="${escapeHtml(from || '')}"/></label>
          <label class="pdash-fin-month">To <input type="month" data-action="set-fin-month-to" value="${escapeHtml(to || '')}"/></label>
          <button type="button" class="btn-ghost btn-tight" data-action="clear-fin-months">Clear</button>`;
}

// ──────────────────────────────────────────────────────────────────────
// DEPARTMENTS — project rollup + capacity cards.
//
// In v7.6 the standalone Dashboard view was merged into the Departments
// tab. The project rollup (picker + key milestone strips + financial
// milestones) now sits ABOVE the SDC Team grid; the capacity cards
// (Under/Over allocated + Due this month) sit BELOW the existing team
// dashboard cards, scoped to the active discipline + the projects
// picked at the top.
//
// Selected-projects persistence reuses the old sdcDashboardProjects
// localStorage key so users keep their picks across the upgrade.
// ──────────────────────────────────────────────────────────────────────
function _deptSelectedProjects() {
  let selected;
  try { selected = JSON.parse(localStorage.getItem('sdcDashboardProjects') || '[]'); }
  catch (_) { selected = []; }
  if (!Array.isArray(selected)) selected = [];
  const allProjects = uniqueValues('project')
    .filter(p => p && p.trim().length > 0)
    .filter(p => !isTemplateProject(p))
    .filter(p => projectWorkspace(p) !== 'Sales')
    .sort();
  if (selected.length === 0) {
    selected = (state.openProjects || []).filter(p => p && allProjects.includes(p));
    if (selected.length === 0 && allProjects.length > 0) selected = [allProjects[0]];
  } else {
    selected = selected.filter(p => allProjects.includes(p));
  }
  return { selected, allProjects };
}

function renderDeptProjectRollup() {
  const root = document.getElementById('dept-project-rollup');
  if (!root) return;

  const { selected, allProjects } = _deptSelectedProjects();

  const today = new Date(); today.setHours(0, 0, 0, 0);
  const todayMs  = today.getTime();
  const todayISO = today.toISOString().slice(0, 10);

  // Pool tasks across the selected projects — milestone-only subset for
  // the strip.
  const pool = state.tasks.filter(t => selected.includes(t.project) && !isBacklogTask(t));
  const milestoneTasks = pool.filter(t => t.is_milestone || t.anchor_key);

  // Kick off lazy financial loads for any project that hasn't been
  // fetched yet — re-render when each resolves.
  for (const p of selected) {
    if (!state.financials[p]) {
      loadFinancialsForProject(p).then(() => {
        if (state.view === 'team') {
          try { renderDeptProjectRollup(); } catch (_) {}
        }
      }).catch(() => {});
    }
  }
  const financials = selected.flatMap(p =>
    (state.financials[p] || []).map(r => ({ ...r, project: p }))
  );

  // Per-project milestone strip — 5 spine anchors at fixed left% +
  // financial mini-columns slotted between them. (Same logic the old
  // Dashboard view used; kept inline so the helper stays close to its
  // only caller.)
  function milestoneStripForProject(project) {
    const KEY_ANCHORS = [
      { key: 'receipt_of_po',    short: 'PO' },
      { key: 'mech_release_1',   short: 'Mech 1' },
      { key: 'machine_power_up', short: 'Power' },
      { key: 'fat',              short: 'FAT' },
      { key: 'ship_machine',     short: 'Ship' },
      { key: 'sat',              short: 'SAT' },
    ];
    const items = KEY_ANCHORS.map(a => {
      const t = milestoneTasks.find(m => m.project === project && inferredAnchorKey(m) === a.key);
      if (!t) return { ...a, missing: true };
      const done = (Number(t.progress) || 0) >= 100;
      const baselineDate = t.baseline_end_date || t.baseline_start_date || null;
      const currentDate  = t.start_date || t.end_date || null;
      const actualDate   = done ? (t.completed_on || currentDate) : null;
      const displayDate  = actualDate || currentDate;
      const overdue = !done && currentDate && currentDate < todayISO;
      let slipDays = null;
      if (baselineDate && displayDate) {
        const baseMs = new Date(baselineDate + 'T00:00:00').getTime();
        const dateMs = new Date(displayDate + 'T00:00:00').getTime();
        slipDays = Math.round((dateMs - baseMs) / 86400000);
      }
      return { ...a, task: t, done, overdue, baselineDate, currentDate, actualDate, displayDate, slipDays };
    });
    // Anchors live at fixed 10/30/53/72/90% across every row so all
    // PO/Mech-1/Power/FAT/Ship dots line up vertically regardless of
    // which financial milestones each project has. Financials slot in
    // at their own dedicated percentages BETWEEN the anchors — no
    // pushing, no shifting.
    const ANCHOR_POS = { receipt_of_po: 9, mech_release_1: 26, machine_power_up: 44, fat: 61, ship_machine: 77, sat: 92 };
    // Money sits RIGHT BESIDE the milestone it bills against: PO money next
    // to PO, FAT money next to FAT, SAT money next to the SAT anchor. MC has
    // no single parent milestone — it stays midway between Mech 1 and Power-Up.
    const FIN_POS    = { PO: 14, MC: 35, FAT: 66, SAT: 97 };

    function mileItem(kind, cls, iconHtml, label, dateHtml, slipChip, leftPct, dataAttrs, tipText) {
      return `<div class="pdash-mile-item pdash-mile-${kind} ${cls}" style="left:${leftPct}%" ${dataAttrs}${tipText ? ` title="${escapeHtml(tipText)}"` : ''}>
        <div class="pdash-mile-icon"><span class="pdash-mile-glyph">${iconHtml}</span></div>
        <div class="pdash-mile-label">${escapeHtml(label)}</div>
        ${dateHtml}
        ${slipChip || ''}
      </div>`;
    }
    const segments = items.map(a => {
      const cls = a.missing ? 'is-missing' : a.done ? 'is-done' : a.overdue ? 'is-overdue' : 'is-upcoming';
      const icon = a.done ? '✓' : (a.overdue ? '!' : '');
      let dateHtml;
      if (a.missing) {
        dateHtml = '<div class="pdash-mile-date">—</div>';
      } else if (!a.baselineDate || a.baselineDate === a.displayDate) {
        dateHtml = `<div class="pdash-mile-date">${escapeHtml(a.displayDate ? fmtDate(a.displayDate) : '—')}</div>`;
      } else {
        const baseStr = fmtDate(a.baselineDate);
        const dispStr = a.displayDate ? fmtDate(a.displayDate) : '—';
        dateHtml = `<div class="pdash-mile-dates" title="Baseline ${baseStr} → ${a.done ? 'Actual' : 'Revised'} ${dispStr}">
          <span class="pdash-date-baseline">${escapeHtml(baseStr)}</span>
          <span class="pdash-date-current">${escapeHtml(dispStr)}</span>
        </div>`;
      }
      // Slip chip vs baseline — HOLLOW while the milestone is still open
      // ("trending", forecast off the current schedule date) and SOLID with a
      // ✓ once complete ("done", actual vs baseline — the final verdict).
      // Same math either way; the fill tells you forecast vs final. Tooltip
      // carries all three dates: baseline → scheduled → actual.
      let slipChip = '';
      if (a.slipDays != null && a.slipDays !== 0) {
        const isEarly = a.slipDays < 0;
        const tone = isEarly ? 'is-early' : 'is-late';
        const wks = _pdashDaysToWeeks(a.slipDays);
        const word = isEarly ? 'early' : 'late';
        const tipDates = `Baseline ${fmtDate(a.baselineDate)}`
          + (a.done && a.currentDate && a.currentDate !== a.actualDate ? ` → Scheduled ${fmtDate(a.currentDate)}` : '')
          + ` → ${a.done ? 'Actual' : 'Scheduled'} ${a.displayDate ? fmtDate(a.displayDate) : '—'}`;
        slipChip = a.done
          ? `<div class="pdash-mile-slip is-final ${tone}" title="Final — actual vs baseline. ${escapeHtml(tipDates)}">✓ ${wks}W ${word}</div>`
          : `<div class="pdash-mile-slip is-trend ${tone}" title="Forecast — current schedule vs baseline; not complete yet. ${escapeHtml(tipDates)}">trending ${wks}W ${word}</div>`;
      }
      const anchorAttrs = `data-project="${escapeHtml(project)}"${a.task ? ` data-task-id="${a.task.id}"` : ''}`;
      return mileItem('anchor', cls, icon, a.short, dateHtml, slipChip,
        ANCHOR_POS[a.key] != null ? ANCHOR_POS[a.key] : 50, anchorAttrs, '');
    }).join('');

    // Financial milestones — SAME line as the key milestones, at their fixed
    // slots between the anchors (PO-money 18 / MC 44 / FAT-money 80 / SAT 96
    // — identical x on every row). Money reads differently at a glance:
    // key dates are DIAMONDS (matching the schedule Gantt), money is a
    // $-in-circle. Label carries the billing % ("40% MC").
    let finItemsHtml = '';
    for (const f of (state.financials[project] || [])) {
      const fAbbrev = _pdashFinAbbrev(f);
      const leftPct = FIN_POS[fAbbrev];
      if (leftPct == null) continue;
      const fd = computeFinancialTriggerDate(f.predecessors, project) || f.due_date || '';
      const fPaid = !!f.paid;
      const fOverdue = !fPaid && fd && fd < todayISO;
      let fCls = 'is-upcoming';
      if (fPaid)         fCls = 'is-paid';
      else if (!fd)      fCls = 'is-no-date';
      else if (fOverdue) fCls = 'is-overdue';
      const fPct = (f.percent != null && Number(f.percent) > 0) ? `${Number(f.percent)}% ` : '';
      const monthStr = fd ? _pdashFinMonth(fd) : '—';
      const fDateFull = fd ? fmtDate(fd) : 'no date';
      const fStatusTip = fPaid ? ' · paid'
        : (!fd ? ' · no date set'
        : (fOverdue ? ' · past due' : ''));
      const finDateHtml = `<div class="pdash-mile-date">${escapeHtml(monthStr)}</div>`;
      finItemsHtml += mileItem('fin', fCls, '$', fPct + fAbbrev, finDateHtml, '', leftPct, '',
        (f.name || fAbbrev) + (fPct ? ' · ' + fPct.trim() : '') + ' · ' + fDateFull + fStatusTip);
    }
    return `
      <div class="pdash-milestone-row">
        <div class="pdash-milestone-project" title="${escapeHtml(project)}">${escapeHtml(project)}</div>
        <div class="pdash-milestone-track">${segments}${finItemsHtml}</div>
      </div>`;
  }

  // ── Financial milestones table ── Per-project payment events. Sorted
  //    by due date. Default month filter = the CURRENT month so the PM
  //    lands on "what am I invoicing this month?" rather than
  //    "everything ever". Clear button stores the sentinel "any".
  const _currentMonth = (() => {
    const d = new Date();
    return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0');
  })();
  const _storedFrom = localStorage.getItem('sdcDashboardFinMonthFrom');
  const _storedTo   = localStorage.getItem('sdcDashboardFinMonthTo');
  const finMonthFrom = _storedFrom == null ? _currentMonth : (_storedFrom === 'any' ? '' : _storedFrom);
  const finMonthTo   = _storedTo   == null ? _currentMonth : (_storedTo   === 'any' ? '' : _storedTo);
  const financialsTableHtml = (() => {
    if (selected.length === 0) {
      return '<div class="pdash-empty-block">Pick at least one project to see financial milestones.</div>';
    }
    const monthOf = (iso) => iso ? iso.slice(0, 7) : '';
    const rows = [...financials]
      .filter(f => f.due_date)
      .filter(f => {
        if (!finMonthFrom && !finMonthTo) return true;
        const m = monthOf(f.due_date);
        if (finMonthFrom && m < finMonthFrom) return false;
        if (finMonthTo   && m > finMonthTo)   return false;
        return true;
      })
      .sort((a, b) => (a.due_date || '').localeCompare(b.due_date || ''));
    if (rows.length === 0) {
      const filterHint = (finMonthFrom || finMonthTo) ? ' in the selected month range' : '';
      return `<div class="pdash-fin-controls">${_pdashFinMonthControls(finMonthFrom, finMonthTo)}</div>
        <div class="pdash-empty-block">No financial milestones${filterHint} for the selected projects.</div>`;
    }
    // ── Timeline (v11.5, replaces the grid) — reads like the schedule Gantt:
    //    month header, dashed blue Today line, one row per project, and each
    //    payment event as a DIAMOND at its date with "% · abbrev" on it.
    //    Status colors match the old chips: red past-due, amber ≤2wks,
    //    light blue upcoming, green paid.
    const NAME_W = 280; // same name column as the Key Milestones strips
    const dayMs = 86400000;
    let winStartMs = Math.min(...rows.map(r => Date.parse(r.due_date + 'T00:00:00')), todayMs);
    let winEndMs   = Math.max(...rows.map(r => Date.parse(r.due_date + 'T00:00:00')), todayMs);
    winStartMs -= 12 * dayMs;
    winEndMs   += 12 * dayMs;
    const span = Math.max(dayMs, winEndMs - winStartMs);
    const pctOf = (ms) => ((ms - winStartMs) / span) * 100;

    // Month header labels (inside the header track) + faint grid lines that
    // span the FULL container height, Gantt-style. Lines use the same
    // name-column-offset calc as the Today line so they align with the track.
    const NAME_OFF = NAME_W + 12; // name column + grid gap
    const trackCalc = (frac) => `calc(${NAME_OFF}px + (100% - ${NAME_OFF}px) * ${frac.toFixed(4)})`;
    let monthTicksHtml = '';
    let monthLinesHtml = '';
    {
      const d = new Date(winStartMs); d.setDate(1); d.setHours(0, 0, 0, 0);
      if (d.getTime() < winStartMs) d.setMonth(d.getMonth() + 1);
      while (d.getTime() <= winEndMs) {
        const frac = (d.getTime() - winStartMs) / span;
        const lbl = d.toLocaleString('en-US', { month: 'short' }) + " '" + String(d.getFullYear()).slice(2);
        monthTicksHtml += `<div class="pdash-fintl-month" style="left:${(frac * 100).toFixed(2)}%">${lbl}</div>`;
        monthLinesHtml += `<div class="pdash-fintl-gridline" style="left:${trackCalc(frac)}"></div>`;
        d.setMonth(d.getMonth() + 1);
      }
    }

    const byProject = {};
    for (const r of rows) (byProject[r.project] ||= []).push(r);
    const rowsHtml = Object.keys(byProject).map(p => {
      const diamonds = byProject[p].map(r => {
        const dueMs = Date.parse(r.due_date + 'T00:00:00');
        const isPast = dueMs < todayMs;
        let cls = 'is-upcoming', status = 'Upcoming';
        if (r.paid)        { cls = 'is-paid';    status = 'Paid'; }
        else if (isPast)   { cls = 'is-overdue'; status = 'Invoice now'; }
        else if (dueMs - todayMs <= 14 * dayMs) { cls = 'is-soon'; status = 'Due soon'; }
        const pctVal = (r.percent != null && Number(r.percent) > 0) ? `${Number(r.percent)}%` : '';
        const abbrev = _pdashFinAbbrev(r);
        const lbl = pctVal ? `${pctVal} ${abbrev}` : abbrev;
        return `<div class="pdash-fintl-ms ${cls}" style="left:${pctOf(dueMs)}%"
            title="${escapeHtml((r.name || abbrev) + (pctVal ? ' · ' + pctVal : '') + ' · ' + fmtDate(r.due_date) + ' · ' + status)}">
          <span class="pdash-fintl-lbl">${escapeHtml(lbl)}</span>
          <span class="pdash-fintl-di"></span>
          <span class="pdash-fintl-date">${escapeHtml(fmtDate(r.due_date))}</span>
        </div>`;
      }).join('');
      return `<div class="pdash-fintl-row" data-project="${escapeHtml(p)}">
        <div class="pdash-milestone-project" title="${escapeHtml(p)}">${escapeHtml(p)}</div>
        <div class="pdash-fintl-track">${diamonds}</div>
      </div>`;
    }).join('');

    // Dashed blue Today line spanning header + all rows, same look as the Gantt.
    const todayFrac = (todayMs - winStartMs) / span;
    const todayHtml = (todayFrac >= 0 && todayFrac <= 1)
      ? `<div class="pdash-fintl-today" style="left:${trackCalc(todayFrac)};"><span>Today</span></div>`
      : '';

    return `<div class="pdash-fin-controls">${_pdashFinMonthControls(finMonthFrom, finMonthTo)}</div>
      <div class="pdash-fintl">
        ${monthLinesHtml}
        ${todayHtml}
        <div class="pdash-fintl-row pdash-fintl-head">
          <div class="pdash-milestone-project"></div>
          <div class="pdash-fintl-track">${monthTicksHtml}</div>
        </div>
        ${rowsHtml}
      </div>`;
  })();

  const milestoneStripsHtml = selected.length === 0
    ? '<div class="pdash-empty-block">Pick at least one project to see milestone dates.</div>'
    : selected.map(p => milestoneStripForProject(p)).join('');

  // ── Compose ──
  root.innerHTML = `
    <div class="pdash-filters">
      <details class="pdash-picker">
        <summary>📂 Projects: <strong>${
          selected.length === 0 ? 'none'
            : (selected.length === 1 ? escapeHtml(selected[0]) : `${selected.length} selected`)
        }</strong> <span class="pdash-picker-caret">▾</span></summary>
        <div class="pdash-picker-list">
          ${allProjects.map(p => `
            <label class="pdash-picker-item">
              <input type="checkbox" data-project="${escapeHtml(p)}" ${selected.includes(p) ? 'checked' : ''}/>
              <span>${escapeHtml(p)}</span>
            </label>`).join('')}
        </div>
        <div class="pdash-picker-actions">
          <button type="button" data-action="select-all" class="btn-ghost btn-tight">Select all</button>
          <button type="button" data-action="select-none" class="btn-ghost btn-tight">Clear</button>
        </div>
      </details>
    </div>

    <section class="pdash-section">
      <header class="pdash-section-head">
        <h2>🚦 Key Milestones</h2>
        <span class="pdash-section-sub">PO → Mech 1 → Power-Up → FAT → Ship → SAT, per project</span>
      </header>
      <div class="pdash-milestones">${milestoneStripsHtml}</div>
    </section>

    <section class="pdash-section">
      <header class="pdash-section-head">
        <h2>💲 Financial Milestones</h2>
        <span class="pdash-section-sub">Invoiceable payment events across selected projects.</span>
      </header>
      ${financialsTableHtml}
    </section>
  `;

  // ── Wire handlers ──
  root.querySelectorAll('.pdash-picker input[type="checkbox"]').forEach(box => {
    box.addEventListener('change', () => {
      const sel = [...root.querySelectorAll('.pdash-picker input[type="checkbox"]')]
        .filter(b => b.checked).map(b => b.dataset.project);
      try { localStorage.setItem('sdcDashboardProjects', JSON.stringify(sel)); } catch (_) {}
      renderDeptProjectRollup();
      try { renderTeamDashboard(); } catch (_) {}
    });
  });
  root.querySelector('[data-action="select-all"]')?.addEventListener('click', () => {
    try { localStorage.setItem('sdcDashboardProjects', JSON.stringify(allProjects)); } catch (_) {}
    renderDeptProjectRollup();
    try { renderTeamDashboard(); } catch (_) {}
  });
  root.querySelector('[data-action="select-none"]')?.addEventListener('click', () => {
    try { localStorage.setItem('sdcDashboardProjects', JSON.stringify([])); } catch (_) {}
    renderDeptProjectRollup();
    try { renderTeamDashboard(); } catch (_) {}
  });
  root.querySelectorAll('[data-action="set-fin-month-from"]').forEach(inp => {
    inp.addEventListener('change', () => {
      try { localStorage.setItem('sdcDashboardFinMonthFrom', inp.value || ''); } catch (_) {}
      renderDeptProjectRollup();
    });
  });
  root.querySelectorAll('[data-action="set-fin-month-to"]').forEach(inp => {
    inp.addEventListener('change', () => {
      try { localStorage.setItem('sdcDashboardFinMonthTo', inp.value || ''); } catch (_) {}
      renderDeptProjectRollup();
    });
  });
  root.querySelectorAll('[data-action="clear-fin-months"]').forEach(btn => {
    btn.addEventListener('click', () => {
      try {
        localStorage.setItem('sdcDashboardFinMonthFrom', 'any');
        localStorage.setItem('sdcDashboardFinMonthTo', 'any');
      } catch (_) {}
      renderDeptProjectRollup();
    });
  });
  // Click a milestone tile or a financial row → jump to that project on
  // the schedule view.
  root.querySelectorAll('.pdash-mile-item, .pdash-fin-row').forEach(el => {
    el.addEventListener('click', () => {
      const p = el.dataset.project;
      if (!p) return;
      if (!state.openProjects.includes(p)) state.openProjects.push(p);
      state.filters.project = p;
      state.activeWorkspace = projectWorkspace(p);
      saveProjectTabs();
      setView('schedule');
    });
  });
}

function renderDashboard() {
  const root = document.getElementById('dashboard-page');
  if (!root) return;

  // ── Filters: selected projects + coming-due horizon (weeks). Persisted. ──
  let selected;
  try { selected = JSON.parse(localStorage.getItem('sdcDashboardProjects') || '[]'); }
  catch (_) { selected = []; }
  if (!Array.isArray(selected)) selected = [];
  let comingDueWeeks = parseFloat(localStorage.getItem('sdcDashboardComingWeeks') || '2');
  if (!Number.isFinite(comingDueWeeks) || comingDueWeeks <= 0) comingDueWeeks = 2;

  // Dashboard is for ACTIVE work only — drop templates (scaffolding) and
  // Sales-workspace projects (pre-quote, not real schedules yet).
  const allProjects = uniqueValues('project')
    .filter(p => p && p.trim().length > 0)
    .filter(p => !isTemplateProject(p))
    .filter(p => projectWorkspace(p) !== 'Sales')
    .sort();
  // Default to currently-open projects when nothing's persisted yet.
  if (selected.length === 0) {
    selected = (state.openProjects || []).filter(p => p && allProjects.includes(p));
    if (selected.length === 0 && allProjects.length > 0) selected = [allProjects[0]];
  } else {
    selected = selected.filter(p => allProjects.includes(p));
  }

  const today = new Date(); today.setHours(0, 0, 0, 0);
  const todayMs   = today.getTime();
  const todayISO  = today.toISOString().slice(0, 10);
  const comingDueMs = todayMs + comingDueWeeks * 7 * 86400000;

  // Pool tasks across the selected projects, separating real work from
  // spine milestones (anchors).
  const pool = state.tasks.filter(t =>
    selected.includes(t.project) &&
    !isBacklogTask(t)
  );
  const work = pool.filter(t => !t.is_milestone && !t.anchor_key);
  const milestoneTasks = pool.filter(t => t.is_milestone || t.anchor_key);

  // Load financial milestones for each selected project (cached in
  // state.financials[project]). Skipping the await chain — kick off the
  // fetches if they haven't happened, and use whatever's already
  // cached for this render. The next render after the fetches resolve
  // will paint the financial dots and section.
  for (const p of selected) {
    if (!state.financials[p]) {
      loadFinancialsForProject(p).then(() => {
        // Only re-render if the dashboard is still the active view.
        if (state.view === 'dashboard') renderDashboard();
      }).catch(() => {});
    }
  }
  // Flat list of financial rows across the selection. Each row carries
  // { project, name, due_date, paid, amount, percent }.
  const financials = selected.flatMap(p =>
    (state.financials[p] || []).map(r => ({ ...r, project: p }))
  );

  // ── Per-task health: actual vs expected % complete + status bucket. ──
  // Expected = time elapsed between start and end (linear). On-time means
  // |expected − actual| < 15. Beyond that, ahead or behind.
  function taskStatus(t) {
    const actual = Math.max(0, Math.min(100, Number(t.progress) || 0));
    if (actual >= 100) return { actual, expected: 100, status: 'done', lag: 0 };
    if (!t.start_date || !t.end_date)
      return { actual, expected: actual, status: 'on-time', lag: 0 };
    const startMs = new Date(t.start_date + 'T00:00:00').getTime();
    const endMs   = new Date(t.end_date   + 'T00:00:00').getTime();
    if (todayMs <= startMs)
      return { actual, expected: 0, status: 'on-time', lag: 0 };
    const total = Math.max(1, endMs - startMs);
    const elapsed = Math.min(total, todayMs - startMs);
    const expected = Math.round((elapsed / total) * 100);
    const lag = expected - actual;
    if (lag >= 15)  return { actual, expected, status: 'behind', lag };
    if (lag <= -15) return { actual, expected, status: 'ahead',  lag };
    return            { actual, expected, status: 'on-time', lag };
  }

  // ── Bucket counts for a task set: done / on-time / ahead / behind. ──
  function bucketCounts(tasks) {
    let done = 0, behind = 0, ahead = 0, ontime = 0, shouldBeDone = 0;
    for (const t of tasks) {
      const s = taskStatus(t);
      if (s.status === 'done')        done++;
      else if (s.status === 'behind') behind++;
      else if (s.status === 'ahead')  ahead++;
      else                            ontime++;
      // "should be done by now" = count of tasks whose end_date has
      // already passed. Per Dan's spec: expected % is tasks-based, not
      // calendar-based.
      if (t.end_date && t.end_date < todayISO) shouldBeDone++;
    }
    return { total: tasks.length, done, behind, ahead, ontime, shouldBeDone };
  }

  // ── Group work tasks by ownership bucket. ──
  const tasksByOwner = new Map();
  for (const t of work) {
    const k = _pdashOwnershipKey(t);
    if (!tasksByOwner.has(k)) tasksByOwner.set(k, []);
    tasksByOwner.get(k).push(t);
  }

  // Render order: known buckets first (in our canonical order), then any
  // strays (alphabetical). Buckets with zero tasks are skipped.
  const knownKeys = new Set(_PDASH_OWNERSHIP.map(o => o.key));
  const knownInOrder = _PDASH_OWNERSHIP.filter(o => tasksByOwner.has(o.key));
  const strays = [...tasksByOwner.keys()].filter(k => !knownKeys.has(k)).sort()
    .map(k => ({ key: k, label: k.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()) }));
  const renderOrder = [...knownInOrder, ...strays];

  const overall = bucketCounts(work);

  // ── SVG donut chart. Three segments: ahead / on-time / behind, with
  //    done shown as a separate inner ring (slightly darker green). ──
  function donutSvg(stats, size = 130) {
    const cx = size / 2, cy = size / 2;
    const ringR = size * 0.36;
    const stroke = size * 0.16;
    const C = 2 * Math.PI * ringR;
    const total = Math.max(1, stats.done + stats.ontime + stats.behind + stats.ahead);
    // SDC palette per Dan's spec: dark blue, light blue, lime, yellow.
    //   done   → SDC green (#74c415)
    //   ontime → SDC dark blue (#1574c4)
    //   ahead  → SDC lime light (#befa4f)
    //   behind → red (warning state — kept from palette outside the four
    //            so behind reads as alarming, not just "different blue")
    const segs = [
      { val: stats.done,   color: '#74c415' },
      { val: stats.ontime, color: '#1574c4' },
      { val: stats.ahead,  color: '#befa4f' },
      { val: stats.behind, color: '#dc2626' },
    ];
    let acc = 0;
    const arcs = segs.filter(s => s.val > 0).map(seg => {
      const len = (seg.val / total) * C;
      const gap = C - len;
      const out = `<circle cx="${cx}" cy="${cy}" r="${ringR}" fill="none" stroke="${seg.color}" stroke-width="${stroke}" stroke-dasharray="${len} ${gap}" stroke-dashoffset="${-acc}" transform="rotate(-90 ${cx} ${cy})"/>`;
      acc += len;
      return out;
    }).join('');
    const centerPct = total > 0 ? Math.round((stats.done / total) * 100) : 0;
    return `<svg viewBox="0 0 ${size} ${size}" width="${size}" height="${size}" class="pdash-donut-svg">
      <circle cx="${cx}" cy="${cy}" r="${ringR}" fill="none" stroke="#e5e7eb" stroke-width="${stroke}"/>
      ${arcs}
      <text x="${cx}" y="${cy - 4}" text-anchor="middle" dominant-baseline="central" font-size="${size * 0.20}" font-weight="700" fill="#1f2937" style="font-family:'Montserrat',sans-serif">${centerPct}%</text>
      <text x="${cx}" y="${cy + size * 0.12}" text-anchor="middle" dominant-baseline="central" font-size="${size * 0.08}" fill="#64748b" style="font-family:'Montserrat',sans-serif">done</text>
    </svg>`;
  }

  // ── Progress bar: actual filled vs expected tick. ──
  function progressBar(actualPct, expectedPct) {
    actualPct   = Math.max(0, Math.min(100, actualPct));
    expectedPct = Math.max(0, Math.min(100, expectedPct));
    let tone = 'good';
    if      (actualPct < expectedPct - 15) tone = 'bad';
    else if (actualPct < expectedPct - 5)  tone = 'mid';
    return `<div class="pdash-progress" data-tone="${tone}">
      <div class="pdash-progress-track">
        <div class="pdash-progress-bar" style="width:${actualPct}%"></div>
        <div class="pdash-progress-tick" style="left:${expectedPct}%" title="Expected by now: ${expectedPct}%"></div>
      </div>
      <div class="pdash-progress-readout">
        <strong>${actualPct}%</strong> done
        <span class="pdash-progress-expected">vs. ${expectedPct}% expected</span>
      </div>
    </div>`;
  }

  // ── Per-project milestone strip (5 spine anchors). ──
  const KEY_ANCHORS = [
    { key: 'receipt_of_po',    short: 'PO' },
    { key: 'mech_release_1',   short: 'Mech 1' },
    { key: 'machine_power_up', short: 'Power' },
    { key: 'fat',              short: 'FAT' },
    { key: 'ship_machine',     short: 'Ship' },
  ];
  function milestoneStripForProject(project) {
    // Map each financial milestone abbreviation to the spine cell it
    // SHARES. The badge becomes a sibling item inside that cell (same
    // icon/label/date stack as the anchor) — keeps all the main
    // anchor dots horizontally aligned across rows and reads as one
    // continuous left-to-right timeline.
    //   MC was previously dropped into the Power-Up cell as a leading
    //   badge, but that pushed the Power-Up dot out of alignment.
    //   Moved MC into Mech 1's cell instead — sits AFTER Mech 1's
    //   mini-column but BEFORE the Power-Up cell, which matches Dan's
    //   "Proceed to major commercials, just before power up" spec
    //   without disturbing the anchor row.
    const FIN_TO_ANCHOR = {
      PO:  'receipt_of_po',
      MC:  'mech_release_1',
      FAT: 'fat',
      SAT: 'ship_machine',
    };
    const finByAnchor = new Map();
    for (const f of (state.financials[project] || [])) {
      const ak = FIN_TO_ANCHOR[_pdashFinAbbrev(f)] || null;
      if (!ak) continue;
      if (!finByAnchor.has(ak)) finByAnchor.set(ak, []);
      finByAnchor.get(ak).push(f);
    }
    const projFinancials = (state.financials[project] || []).slice().sort((a, b) => {
      // Canonical SDC billing order — PO, MC, FAT, SAT — regardless of
      // dates. Custom milestones outside the standard four fall to the
      // end and sort by date among themselves.
      const oa = _pdashFinOrder(a);
      const ob = _pdashFinOrder(b);
      if (oa !== ob) return oa - ob;
      const da = computeFinancialTriggerDate(a.predecessors, project) || a.due_date || '';
      const db = computeFinancialTriggerDate(b.predecessors, project) || b.due_date || '';
      return da.localeCompare(db);
    });

    const items = KEY_ANCHORS.map(a => {
      const t = milestoneTasks.find(m => m.project === project && inferredAnchorKey(m) === a.key);
      if (!t) return { ...a, missing: true };
      const done = (Number(t.progress) || 0) >= 100;
      // Three possible dates per Dan's spec:
      //   baselineDate = when the project ORIGINALLY committed to this date
      //   currentDate  = what's in the schedule today (PM-adjusted)
      //   actualDate   = when the milestone actually completed (if done)
      // For display: show baseline → (actual|current) when they differ.
      // For slip:    compare baseline → (actual if done, else current).
      const baselineDate = t.baseline_end_date || t.baseline_start_date || null;
      const currentDate  = t.start_date || t.end_date || null;
      const actualDate   = done ? (t.completed_on || currentDate) : null;
      const displayDate  = actualDate || currentDate;
      const overdue = !done && currentDate && currentDate < todayISO;
      let slipDays = null;
      if (baselineDate && displayDate) {
        const baseMs = new Date(baselineDate + 'T00:00:00').getTime();
        const dateMs = new Date(displayDate + 'T00:00:00').getTime();
        slipDays = Math.round((dateMs - baseMs) / 86400000);
      }
      return { ...a, task: t, done, overdue, baselineDate, currentDate, actualDate, displayDate, slipDays };
    });

    // Each item is positioned ABSOLUTELY at a fixed left% inside the
    // track. This is the key to alignment: anchors live at the same
    // 10/30/50/70/90% across every project row, regardless of which
    // financial milestones happen to exist. Financials slot in at
    // their own dedicated percentages BETWEEN the anchors — no
    // pushing, no shifting.
    const ANCHOR_POS = {
      receipt_of_po:    10,
      mech_release_1:   30,
      machine_power_up: 53,
      fat:              72,
      ship_machine:     90,
    };
    const FIN_POS = {
      PO:  18,   // just to the right of the PO anchor (10%)
      MC:  44,   // between Mech 1 (30%) and Power-Up (53%), closer to Power
      FAT: 80,   // just to the right of FAT (72%)
      SAT: 96,   // just past Ship (90%)
    };

    function _mileItem(kind, cls, iconHtml, label, dateHtml, slipChip, leftPct, dataAttrs, tipText) {
      return `<div class="pdash-mile-item pdash-mile-${kind} ${cls}" style="left:${leftPct}%" ${dataAttrs}${tipText ? ` title="${escapeHtml(tipText)}"` : ''}>
        <div class="pdash-mile-icon">${iconHtml}</div>
        <div class="pdash-mile-label">${escapeHtml(label)}</div>
        ${dateHtml}
        ${slipChip || ''}
      </div>`;
    }

    const segments = items.map((a) => {
      const cls = a.missing ? 'is-missing'
                : a.done    ? 'is-done'
                : a.overdue ? 'is-overdue'
                : 'is-upcoming';
      const icon = a.done ? '✓' : (a.overdue ? '!' : '');

      let dateHtml;
      if (a.missing) {
        dateHtml = '<div class="pdash-mile-date">—</div>';
      } else if (!a.baselineDate || a.baselineDate === a.displayDate) {
        dateHtml = `<div class="pdash-mile-date">${escapeHtml(a.displayDate ? fmtDate(a.displayDate) : '—')}</div>`;
      } else {
        const baseStr = fmtDate(a.baselineDate);
        const dispStr = a.displayDate ? fmtDate(a.displayDate) : '—';
        dateHtml = `<div class="pdash-mile-dates" title="Baseline ${baseStr} → ${a.done ? 'Actual' : 'Revised'} ${dispStr}">
          <span class="pdash-date-baseline">${escapeHtml(baseStr)}</span>
          <span class="pdash-date-current">${escapeHtml(dispStr)}</span>
        </div>`;
      }

      // Slip chip vs baseline — HOLLOW while the milestone is still open
      // ("trending", forecast off the current schedule date) and SOLID with a
      // ✓ once complete ("done", actual vs baseline — the final verdict).
      // Same math either way; the fill tells you forecast vs final. Tooltip
      // carries all three dates: baseline → scheduled → actual.
      let slipChip = '';
      if (a.slipDays != null && a.slipDays !== 0) {
        const isEarly = a.slipDays < 0;
        const tone = isEarly ? 'is-early' : 'is-late';
        const wks = _pdashDaysToWeeks(a.slipDays);
        const word = isEarly ? 'early' : 'late';
        const tipDates = `Baseline ${fmtDate(a.baselineDate)}`
          + (a.done && a.currentDate && a.currentDate !== a.actualDate ? ` → Scheduled ${fmtDate(a.currentDate)}` : '')
          + ` → ${a.done ? 'Actual' : 'Scheduled'} ${a.displayDate ? fmtDate(a.displayDate) : '—'}`;
        slipChip = a.done
          ? `<div class="pdash-mile-slip is-final ${tone}" title="Final — actual vs baseline. ${escapeHtml(tipDates)}">✓ ${wks}W ${word}</div>`
          : `<div class="pdash-mile-slip is-trend ${tone}" title="Forecast — current schedule vs baseline; not complete yet. ${escapeHtml(tipDates)}">trending ${wks}W ${word}</div>`;
      }

      const anchorAttrs = `data-project="${escapeHtml(project)}"${a.task ? ` data-task-id="${a.task.id}"` : ''}`;
      return _mileItem('anchor', cls, icon, a.short, dateHtml, slipChip,
        ANCHOR_POS[a.key] != null ? ANCHOR_POS[a.key] : 50, anchorAttrs, '');
    }).join('');

    // Financial mini-columns — rendered as siblings of the anchor
    // items inside the track, each at its own fixed left%. Uses the
    // exact same icon/label/date stack so a $-tile reads visually
    // identical to a ●-tile (just the icon differs).
    let finItemsHtml = '';
    for (const f of (state.financials[project] || [])) {
      const fAbbrev = _pdashFinAbbrev(f);
      const leftPct = FIN_POS[fAbbrev];
      if (leftPct == null) continue;   // custom milestones — skip strip
      const fd = computeFinancialTriggerDate(f.predecessors, project) || f.due_date || '';
      const fPaid = !!f.paid;
      const fOverdue = !fPaid && fd && fd < todayISO;
      let fCls = 'is-upcoming';
      if (fPaid)         fCls = 'is-paid';
      else if (!fd)      fCls = 'is-no-date';
      else if (fOverdue) fCls = 'is-overdue';
      const monthStr = fd ? _pdashFinMonth(fd) : '—';
      const fDateFull = fd ? fmtDate(fd) : 'no date';
      const fPctTip = f.percent ? ` · ${f.percent}%` : '';
      const fStatusTip = fPaid ? ' · paid'
        : (!fd ? ' · no date set'
        : (fOverdue ? ' · past due' : ''));
      const finDateHtml = `<div class="pdash-mile-date">${escapeHtml(monthStr)}</div>`;
      finItemsHtml += _mileItem('fin', fCls, '$', fAbbrev, finDateHtml, '', leftPct, '',
        (f.name || fAbbrev) + fPctTip + ' · ' + fDateFull + fStatusTip);
    }

    return `
      <div class="pdash-milestone-row">
        <div class="pdash-milestone-project" title="${escapeHtml(project)}">${escapeHtml(project)}</div>
        <div class="pdash-milestone-track">${segments}${finItemsHtml}</div>
      </div>
    `;
  }

  // ── Build one department card. ──
  function renderDeptCard(def, tasks) {
    const stats = bucketCounts(tasks);
    const actualPct   = stats.total > 0 ? Math.round((stats.done / stats.total) * 100) : 0;
    const expectedPct = stats.total > 0 ? Math.round((stats.shouldBeDone / stats.total) * 100) : 0;

    // Current-month window — used for "tasks due this month".
    const cmStart = new Date(); cmStart.setHours(0, 0, 0, 0);
    cmStart.setDate(1);
    const cmEndDate = new Date(cmStart.getFullYear(), cmStart.getMonth() + 1, 0);
    cmEndDate.setHours(23, 59, 59, 999);
    const cmStartMs = cmStart.getTime();
    const cmEndMs   = cmEndDate.getTime();
    const currentMonthLabel = cmStart.toLocaleString('en-US', { month: 'long', year: 'numeric' });

    // Tasks due in the current calendar month (not yet complete).
    const dueThisMonth = tasks
      .filter(t => (Number(t.progress) || 0) < 100 && t.end_date)
      .filter(t => {
        const endMs = new Date(t.end_date + 'T00:00:00').getTime();
        return endMs >= cmStartMs && endMs <= cmEndMs;
      })
      .sort((a, b) => (a.end_date || '').localeCompare(b.end_date || ''));

    const annotated = tasks.map(t => ({ task: t, status: taskStatus(t) }));
    const behindList = annotated.filter(x => x.status.status === 'behind').sort((a, b) => b.status.lag - a.status.lag);

    // ── Under / over allocated PEOPLE in this discipline ──
    // Active team members whose discipline matches this dept. Look at
    // their open-task load over the next ~8 weeks:
    //   over  = computeOverloadRegions returns any region above 100%
    //   under = no active tasks at all OR total open < 2
    // Placeholders ("ME Placeholder", etc.) are skipped — they're role
    // stand-ins, not real capacity to flag.
    const deptMembers = (def.key === 'unassigned')
      ? []
      : (state.team || []).filter(m =>
          m.discipline === def.key && m.active !== 0 && !isPlaceholder(m.name)
        );
    const windowStart = new Date(); windowStart.setHours(0, 0, 0, 0);
    const windowMs    = windowStart.getTime();
    const windowEnd   = windowMs + 56 * 86400000; // 8 weeks ahead
    const underPeople = [];
    const overPeople  = [];
    for (const m of deptMembers) {
      // Member's tasks in the next 8 weeks that are still open and
      // belong to one of the selected projects.
      const memTasks = state.tasks.filter(t =>
        t.assignee === m.name &&
        (Number(t.progress) || 0) < 100 &&
        t.start_date && t.end_date &&
        !isTemplateProject(t.project) &&
        projectWorkspace(t.project) !== 'Sales' &&
        selected.includes(t.project)
      ).filter(t => {
        const eMs = new Date(t.end_date + 'T00:00:00').getTime();
        return eMs >= windowMs && eMs <= windowEnd + 30 * 86400000;
      });
      if (memTasks.length === 0) {
        underPeople.push({ name: m.name, reason: 'no open tasks' });
        continue;
      }
      const overlap = computeOverloadRegions(memTasks, windowStart);
      if (overlap.length > 0) {
        const peak = Math.max(...overlap.map(r => r.peak));
        overPeople.push({ name: m.name, peak });
        continue;
      }
      // Heuristic for "under": avg daily allocation across the window
      // < 60%. Sum (task allocation × days in window) / total days × 100.
      let totalAlloc = 0, daysCovered = 0;
      const totalDays = 56;
      for (const t of memTasks) {
        const sMs = Math.max(windowMs, new Date(t.start_date + 'T00:00:00').getTime());
        const eMs = Math.min(windowEnd, new Date(t.end_date + 'T00:00:00').getTime());
        if (eMs < sMs) continue;
        const days = Math.round((eMs - sMs) / 86400000) + 1;
        const alloc = t.allocation == null ? 90 : Number(t.allocation);
        totalAlloc += alloc * days;
        daysCovered += days;
      }
      const avgAlloc = daysCovered > 0 ? totalAlloc / totalDays : 0;
      if (avgAlloc < 60) {
        underPeople.push({ name: m.name, reason: `${Math.round(avgAlloc)}% avg load` });
      }
    }

    const showProjectCol = selected.length > 1;
    const taskLine = (t, chipHtml) => {
      const proj = showProjectCol
        ? `<span class="pdash-tl-project">${escapeHtml(t.project || '')}</span>` : '';
      const ass = t.assignee
        ? `<span class="pdash-tl-assignee">${escapeHtml(t.assignee)}</span>` : '';
      return `<li class="pdash-tl-row" data-project="${escapeHtml(t.project || '')}" data-task-id="${t.id}">
        <span class="pdash-tl-name">${escapeHtml(t.name || '')}</span>
        ${proj}${ass}
        ${chipHtml || ''}
      </li>`;
    };
    // Due-this-month rows show TWO chips: the % complete (with
    // ahead/behind/done coloring) AND the days-until-due chip. So the
    // PM sees "almost done and not until next week" vs "0% and due
    // tomorrow" at a glance.
    const dueLis = dueThisMonth.length === 0
      ? `<li class="pdash-tl-empty">Nothing due in ${escapeHtml(currentMonthLabel)}.</li>`
      : dueThisMonth.slice(0, 12).map(t => {
          const endMs = new Date(t.end_date + 'T00:00:00').getTime();
          const days = Math.max(0, Math.round((endMs - todayMs) / 86400000));
          const dueCls = days <= 3 ? 'chip-danger' : (days <= 7 ? 'chip-warn' : 'chip-info');
          const s = taskStatus(t);
          const pct = s.actual;
          let pctCls = 'chip-info';
          if (pct >= 100)       pctCls = 'chip-success';
          else if (s.status === 'behind') pctCls = 'chip-danger';
          else if (s.status === 'ahead')  pctCls = 'chip-success';
          else if (pct > 0)               pctCls = 'chip-info';
          const pctChip = `<span class="pdash-chip ${pctCls}" title="Actual ${pct}% vs expected ${s.expected}%">${pct}%</span>`;
          const dueChip = `<span class="pdash-chip ${dueCls}">${_pdashDaysToWeeks(days)}W</span>`;
          return taskLine(t, pctChip + dueChip);
        }).join('');
    const behindLis = behindList.length === 0
      ? '<li class="pdash-tl-empty">Nothing behind.</li>'
      : behindList.slice(0, 12).map(({ task, status }) =>
          taskLine(task, `<span class="pdash-chip chip-danger">-${status.lag}%</span>`)).join('');
    // Under-allocated — plain text rows (no chips). Previously every
    // row carried a yellow chip and a roster of free people looked
    // like a wall of yellow. Now: name in normal weight + reason in
    // muted text below, reads like a cleaner address book.
    const underLis = underPeople.length === 0
      ? '<li class="pdash-tl-empty">Everyone is fully booked.</li>'
      : underPeople.map(p =>
          `<li class="pdash-tl-person">
            <span class="pdash-tl-person-name">${escapeHtml(p.name)}</span>
            <span class="pdash-tl-person-reason">${escapeHtml(p.reason)}</span>
          </li>`).join('');
    const overLis = overPeople.length === 0
      ? '<li class="pdash-tl-empty">No one is over-allocated.</li>'
      : overPeople.map(p =>
          `<li class="pdash-tl-person is-over">
            <span class="pdash-tl-person-name">${escapeHtml(p.name)}</span>
            <span class="pdash-tl-person-reason">peak ${p.peak}%</span>
          </li>`).join('');

    return `
      <article class="pdash-dept-card" data-dept="${escapeHtml(def.key)}">
        <header class="pdash-dept-head">
          <h3>${escapeHtml(def.label)}</h3>
          <span class="pdash-dept-count">${stats.total} task${stats.total === 1 ? '' : 's'} · ${actualPct}% complete (expected ${expectedPct}%)</span>
        </header>
        <div class="pdash-dept-lists pdash-dept-lists-4">
          <section class="pdash-dept-list">
            <h4>Under-allocated <span class="pdash-list-count">${underPeople.length}</span></h4>
            <ul>${underLis}</ul>
          </section>
          <section class="pdash-dept-list">
            <h4>Over-allocated <span class="pdash-list-count">${overPeople.length}</span></h4>
            <ul>${overLis}</ul>
          </section>
          <section class="pdash-dept-list">
            <h4>Due in ${escapeHtml(currentMonthLabel)} <span class="pdash-list-count">${dueThisMonth.length}</span></h4>
            <ul>${dueLis}</ul>
          </section>
          <section class="pdash-dept-list">
            <h4>Behind schedule <span class="pdash-list-count">${behindList.length}</span></h4>
            <ul>${behindLis}</ul>
          </section>
        </div>
      </article>
    `;
  }

  // ── Compose ──
  const summaryLabel = selected.length === 0
    ? 'No projects selected.'
    : (selected.length === 1
        ? `1 project — grouped by department`
        : `${selected.length} projects — combined and grouped by department`);

  // ── Financial milestones table ── Per-project payment events. Sorted
  //    by due date. Filtered by the month-range selector below.
  //    Default = the CURRENT month so the PM lands on "what am I
  //    invoicing this month?" rather than "everything ever". User
  //    overrides persist in localStorage. To explicitly mean "no
  //    filter", the Clear button stores the sentinel "any".
  const _currentMonth = (() => {
    const d = new Date();
    return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0');
  })();
  const _storedFrom = localStorage.getItem('sdcDashboardFinMonthFrom');
  const _storedTo   = localStorage.getItem('sdcDashboardFinMonthTo');
  let finMonthFrom = _storedFrom == null ? _currentMonth : (_storedFrom === 'any' ? '' : _storedFrom);
  let finMonthTo   = _storedTo   == null ? _currentMonth : (_storedTo   === 'any' ? '' : _storedTo);
  const financialsTableHtml = (() => {
    if (selected.length === 0) {
      return '<div class="pdash-empty-block">Pick at least one project to see financial milestones.</div>';
    }
    // Month-range filter. "" / "" → no filter. Month strings are
    // YYYY-MM (the value an <input type="month"> produces).
    const monthOf = (iso) => iso ? iso.slice(0, 7) : '';
    const rows = [...financials]
      .filter(f => f.due_date)
      .filter(f => {
        if (!finMonthFrom && !finMonthTo) return true;
        const m = monthOf(f.due_date);
        if (finMonthFrom && m < finMonthFrom) return false;
        if (finMonthTo   && m > finMonthTo)   return false;
        return true;
      })
      .sort((a, b) => (a.due_date || '').localeCompare(b.due_date || ''));
    if (rows.length === 0) {
      const filterHint = (finMonthFrom || finMonthTo)
        ? ' in the selected month range'
        : '';
      return `<div class="pdash-fin-controls">
        ${_pdashFinMonthControls(finMonthFrom, finMonthTo)}
      </div>
      <div class="pdash-empty-block">No financial milestones${filterHint} for the selected projects.</div>`;
    }
    const showProjectCol = selected.length > 1;
    // Column order matches the financials modal (% · description ·
    // date) but PRECEDED by Project when multiple projects are
    // selected, so the eye lands on which schedule the row belongs
    // to first. Status chip sits on the right. Column widths follow
    // the CLAUDE.md grid rule — Description (Milestone) gets the
    // remainder so long names never clip; everything else is sized
    // to its data.
    const colgroup = showProjectCol
      ? `<colgroup>
          <col style="width:240px"/>
          <col style="width:60px"/>
          <col style="width:auto"/>
          <col style="width:130px"/>
          <col style="width:130px"/>
        </colgroup>`
      : `<colgroup>
          <col style="width:60px"/>
          <col style="width:auto"/>
          <col style="width:130px"/>
          <col style="width:130px"/>
        </colgroup>`;
    const head = showProjectCol
      ? '<thead><tr><th>Project</th><th class="num">%</th><th>Milestone</th><th>Date</th><th>Status</th></tr></thead>'
      : '<thead><tr><th class="num">%</th><th>Milestone</th><th>Date</th><th>Status</th></tr></thead>';
    const body = rows.map(r => {
      const dueMs = r.due_date ? new Date(r.due_date + 'T00:00:00').getTime() : null;
      const isPast = dueMs != null && dueMs < todayMs;
      let chip;
      if (r.paid) chip = '<span class="pdash-chip chip-success">Paid</span>';
      else if (isPast) chip = '<span class="pdash-chip chip-danger">Invoice now</span>';
      else if (dueMs != null && dueMs - todayMs <= 14 * 86400000) chip = '<span class="pdash-chip chip-warn">Due soon</span>';
      else chip = '<span class="pdash-chip chip-info">Upcoming</span>';
      const pctVal = (r.percent != null && Number(r.percent) > 0) ? `${Number(r.percent)}%` : '—';
      const projCell = showProjectCol ? `<td title="${escapeHtml(r.project)}">${escapeHtml(r.project)}</td>` : '';
      return `<tr class="pdash-fin-row" data-project="${escapeHtml(r.project)}">
        ${projCell}
        <td class="num">${pctVal}</td>
        <td title="${escapeHtml(r.name || '')}">${escapeHtml(r.name || '')}</td>
        <td>${escapeHtml(r.due_date ? fmtDate(r.due_date) : '—')}</td>
        <td>${chip}</td>
      </tr>`;
    }).join('');
    return `<div class="pdash-fin-controls">${_pdashFinMonthControls(finMonthFrom, finMonthTo)}</div>
            <table class="pdash-fin-table">${colgroup}${head}<tbody>${body}</tbody></table>`;
  })();

  const milestoneStripsHtml = selected.length === 0
    ? '<div class="pdash-empty-block">Pick at least one project to see milestone dates.</div>'
    : selected.map(p => milestoneStripForProject(p)).join('');

  const deptCardsHtml = renderOrder.length === 0
    ? '<div class="pdash-empty-block">No work tasks in this selection.</div>'
    : renderOrder.map(def => renderDeptCard(def, tasksByOwner.get(def.key))).join('');

  const overallTotal = Math.max(1, overall.total);
  const overallLegend = `
    <div class="pdash-overall-legend">
      <div class="pdash-legend-item"><span class="pdash-legend-dot" style="background:#74c415"></span>
        <strong>${overall.done}</strong> done
        <span class="pdash-legend-pct">${Math.round(overall.done/overallTotal*100)}%</span></div>
      <div class="pdash-legend-item"><span class="pdash-legend-dot" style="background:#1574c4"></span>
        <strong>${overall.ontime}</strong> on time
        <span class="pdash-legend-pct">${Math.round(overall.ontime/overallTotal*100)}%</span></div>
      <div class="pdash-legend-item"><span class="pdash-legend-dot" style="background:#befa4f"></span>
        <strong>${overall.ahead}</strong> ahead
        <span class="pdash-legend-pct">${Math.round(overall.ahead/overallTotal*100)}%</span></div>
      <div class="pdash-legend-item"><span class="pdash-legend-dot" style="background:#dc2626"></span>
        <strong>${overall.behind}</strong> behind
        <span class="pdash-legend-pct">${Math.round(overall.behind/overallTotal*100)}%</span></div>
    </div>`;

  root.innerHTML = `
    <h1 class="pdash-title">Dashboard</h1>
    <p class="pdash-sub">${escapeHtml(summaryLabel)}</p>

    <div class="pdash-filters">
      <details class="pdash-picker">
        <summary>📂 Projects: <strong>${
          selected.length === 0 ? 'none'
            : (selected.length === 1 ? escapeHtml(selected[0]) : `${selected.length} selected`)
        }</strong> <span class="pdash-picker-caret">▾</span></summary>
        <div class="pdash-picker-list">
          ${allProjects.map(p => `
            <label class="pdash-picker-item">
              <input type="checkbox" data-project="${escapeHtml(p)}" ${selected.includes(p) ? 'checked' : ''}/>
              <span>${escapeHtml(p)}</span>
            </label>`).join('')}
        </div>
        <div class="pdash-picker-actions">
          <button type="button" data-action="select-all" class="btn-ghost btn-tight">Select all</button>
          <button type="button" data-action="select-none" class="btn-ghost btn-tight">Clear</button>
        </div>
      </details>
      <label class="pdash-weeks-control" title="How far ahead 'Coming due' looks, in weeks.">
        ⏰ Coming due in
        <input type="number" min="0.5" max="52" step="0.5" value="${comingDueWeeks}" data-action="set-weeks"/>
        weeks
      </label>
    </div>

    <section class="pdash-section">
      <header class="pdash-section-head">
        <h2>🚦 Key Milestones</h2>
        <span class="pdash-section-sub">PO → Mech 1 → Power-Up → FAT → Ship → SAT, per project</span>
      </header>
      <div class="pdash-milestones">${milestoneStripsHtml}</div>
    </section>

    <section class="pdash-section">
      <header class="pdash-section-head">
        <h2>💲 Financial Milestones</h2>
        <span class="pdash-section-sub">Invoiceable payment events across selected projects.</span>
      </header>
      ${financialsTableHtml}
    </section>

    <section class="pdash-section">
      <header class="pdash-section-head">
        <h2>📊 Overall Health</h2>
        <span class="pdash-section-sub">${overall.total} open + done tasks across selected projects</span>
      </header>
      <div class="pdash-overall">
        <div class="pdash-overall-donut">${donutSvg(overall, 170)}</div>
        ${overallLegend}
      </div>
    </section>

    <section class="pdash-section">
      <header class="pdash-section-head">
        <h2>🏢 By Department</h2>
        <span class="pdash-section-sub">Each card: progress bar (actual vs. expected), donut, and lists by person.</span>
      </header>
      <div class="pdash-dept-grid">${deptCardsHtml}</div>
    </section>
  `;

  // ── Wire handlers ──
  root.querySelectorAll('.pdash-picker input[type="checkbox"]').forEach(box => {
    box.addEventListener('change', () => {
      const sel = [...root.querySelectorAll('.pdash-picker input[type="checkbox"]')]
        .filter(b => b.checked).map(b => b.dataset.project);
      try { localStorage.setItem('sdcDashboardProjects', JSON.stringify(sel)); } catch (_) {}
      renderDashboard();
    });
  });
  root.querySelector('[data-action="select-all"]')?.addEventListener('click', () => {
    try { localStorage.setItem('sdcDashboardProjects', JSON.stringify(allProjects)); } catch (_) {}
    renderDashboard();
  });
  root.querySelector('[data-action="select-none"]')?.addEventListener('click', () => {
    try { localStorage.setItem('sdcDashboardProjects', JSON.stringify([])); } catch (_) {}
    renderDashboard();
  });
  const weeksInput = root.querySelector('[data-action="set-weeks"]');
  if (weeksInput) {
    weeksInput.addEventListener('change', () => {
      const w = parseFloat(weeksInput.value);
      if (Number.isFinite(w) && w > 0) {
        try { localStorage.setItem('sdcDashboardComingWeeks', String(w)); } catch (_) {}
        renderDashboard();
      }
    });
  }
  // Financial milestones month-range filter — persists to localStorage,
  // re-renders on change.
  root.querySelectorAll('[data-action="set-fin-month-from"]').forEach(inp => {
    inp.addEventListener('change', () => {
      try { localStorage.setItem('sdcDashboardFinMonthFrom', inp.value || ''); } catch (_) {}
      renderDashboard();
    });
  });
  root.querySelectorAll('[data-action="set-fin-month-to"]').forEach(inp => {
    inp.addEventListener('change', () => {
      try { localStorage.setItem('sdcDashboardFinMonthTo', inp.value || ''); } catch (_) {}
      renderDashboard();
    });
  });
  root.querySelectorAll('[data-action="clear-fin-months"]').forEach(btn => {
    btn.addEventListener('click', () => {
      // Sentinel "any" means "user explicitly cleared" — without it
      // the default kicks back in (current month) on every render and
      // the Clear button would feel broken.
      try {
        localStorage.setItem('sdcDashboardFinMonthFrom', 'any');
        localStorage.setItem('sdcDashboardFinMonthTo', 'any');
      } catch (_) {}
      renderDashboard();
    });
  });
  // Click any task row OR milestone tile → open that task's project in
  // the schedule view.
  root.querySelectorAll('.pdash-tl-row, .pdash-milestone, .pdash-fin-row').forEach(el => {
    el.addEventListener('click', () => {
      const p = el.dataset.project;
      if (!p) return;
      if (!state.openProjects.includes(p)) state.openProjects.push(p);
      state.filters.project = p;
      state.activeWorkspace = projectWorkspace(p);
      saveProjectTabs();
      setView('schedule');
    });
  });
}

// ── Parts in Shop ───────────────────────────────────────────────────────────
// PM-facing grid of parts physically at the SDC shop. Its own table/API (not
// tasks). Inline-editable cells, add/delete, filter (Open/Complete/All), search,
// and group-by-job. Completed rows highlight yellow like the source Smartsheet.
const SHOP_COLS = [
  { key: 'rank',              label: 'Rank',               type: 'num',  w: '52px'  },
  { key: 'job',               label: 'Job #',              type: 'text', w: '78px'  },
  { key: 'qty',               label: 'QTY',                type: 'num',  w: '46px'  },
  { key: 'part_no',           label: 'Part No.',           type: 'text', w: '120px' },
  { key: 'description',       label: 'Description',        type: 'text', w: 'auto'  },
  { key: 'shop_release',      label: 'Shop Release',       type: 'text', w: '92px'  },
  { key: 'new_mod',           label: 'New/MOD',            type: 'mod',  w: '140px' },
  { key: 'location',          label: 'Location/Machinist', type: 'text', w: '120px' },
  { key: 'out_for_finishing', label: 'Out for Finishing',  type: 'text', w: '120px' },
  { key: 'comments',          label: 'Comments',           type: 'text', w: '150px' },
  { key: 'engineer',          label: 'Engineer',           type: 'text', w: '100px' },
  { key: 'pm',                label: 'PM',                 type: 'pm',   w: '110px' },
  { key: 'added_to_bom',      label: 'BOM',                type: 'check', w: '42px' },
  { key: 'part_complete',     label: 'Done',               type: 'check', w: '46px' },
];
let _shopPartsState = null;
let _shopAddOpen = false; // the add form is collapsed by default
function _shopState() {
  if (_shopPartsState) return _shopPartsState;
  let s = { filter: 'open', search: '', view: 'list', fPri: 'all', fPm: 'all', fEng: 'all', fDue: '', dashRange: 7 };
  try { s = Object.assign(s, JSON.parse(localStorage.getItem('sdcShopPartsState') || '{}')); } catch (_) {}
  if (s.view !== 'cards') s.view = 'list';
  _shopPartsState = s;
  return s;
}
// Priority level: 1 = hot (now), 2 = hit the due date, 3 = low. Blank → 3.
function _shopPri(r) { const n = parseInt(r && r.priority, 10); return (n === 1 || n === 2 || n === 3) ? n : 3; }
// Small SDC-style donut gauge (e.g. on-time delivery %). Green high, lime mid.
function _shopDonut(pct, size = 76) {
  const cx = size / 2, cy = size / 2, r = size * 0.36, sw = size * 0.15, C = 2 * Math.PI * r;
  const frac = pct == null ? 0 : Math.max(0, Math.min(1, pct / 100));
  const len = frac * C, gap = C - len;
  const color = pct == null ? '#cbd5e1' : (pct >= 90 ? '#74c415' : (pct >= 70 ? '#befa4f' : '#1574c4'));
  return `<svg viewBox="0 0 ${size} ${size}" width="${size}" height="${size}" class="sp-donut">
    <circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="#e5e7eb" stroke-width="${sw}"/>
    ${len > 0 ? `<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${color}" stroke-width="${sw}" stroke-dasharray="${len} ${gap}" transform="rotate(-90 ${cx} ${cy})" stroke-linecap="round"/>` : ''}
    <text x="${cx}" y="${cy}" text-anchor="middle" dominant-baseline="central" font-size="${size * 0.24}" font-weight="800" fill="#1f2937" style="font-family:'Montserrat',sans-serif">${pct == null ? '—' : pct + '%'}</text>
  </svg>`;
}
// Set a part's priority (1/2/3) from the click popup.
async function _shopSetPri(id, val) {
  const r = (state.shopParts || []).find(x => x.id === id);
  if (!r) return;
  r.priority = String(val);
  renderShopPartsPage();
  try {
    const upd = await api.shopParts.update(id, { priority: String(val) });
    if (upd) Object.assign(r, upd);
  } catch (_) {}
}
// Qty +/- stepper — updates in place without a full re-render (keeps scroll/pos).
async function _shopBumpQty(id, d) {
  const r = (state.shopParts || []).find(x => x.id === id);
  if (!r) return;
  const next = Math.max(0, (Number(r.qty) || 0) + d);
  r.qty = next;
  const inp = document.querySelector(`.sp-qty-inp[data-id="${id}"]`);
  if (inp) inp.value = next;
  try {
    const upd = await api.shopParts.update(id, { qty: next });
    if (upd) Object.assign(r, upd);
  } catch (_) {}
}
function _saveShopState() { try { localStorage.setItem('sdcShopPartsState', JSON.stringify(_shopPartsState)); } catch (_) {} }

async function loadShopParts() {
  try { state.shopParts = await api.shopParts.list(); }
  catch (_) { state.shopParts = []; }
  renderShopPartsPage();
}

// Date helpers — the sheet mixes "06/09/26" strings with ISO from the date picker.
function _shopFmtDue(v) { const s = String(v || ''); return /^\d{4}-\d{2}-\d{2}$/.test(s) ? fmtDate(s) : s; }
function _shopDueMs(v) {
  const s = String(v || ''); let iso = null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) iso = s;
  else { const m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/); if (m) { let y = m[3]; if (y.length === 2) y = '20' + y; iso = `${y}-${m[1].padStart(2, '0')}-${m[2].padStart(2, '0')}`; } }
  if (!iso) return null;
  const t = Date.parse(iso + 'T00:00:00'); return isNaN(t) ? null : t;
}
// Filtered rows, sorted by priority (1→3) then soonest due date.
function _shopDisplayedRows(all, st) {
  let rows = all.slice();
  if (st.filter === 'open') rows = rows.filter(r => !r.part_complete);
  else if (st.filter === 'complete') rows = rows.filter(r => r.part_complete);
  if (st.fPri && st.fPri !== 'all') rows = rows.filter(r => _shopPri(r) === Number(st.fPri));
  if (st.fPm && st.fPm !== 'all') rows = rows.filter(r => (r.pm || '') === st.fPm);
  if (st.fEng && st.fEng !== 'all') rows = rows.filter(r => (r.engineer || '') === st.fEng);
  if (st.fDue) { const lim = Date.parse(st.fDue + 'T23:59:59'); if (!isNaN(lim)) rows = rows.filter(r => { const m = _shopDueMs(r.shop_release); return m != null && m <= lim; }); }
  const q = (st.search || '').trim().toLowerCase();
  if (q) rows = rows.filter(r => [r.job, r.part_no, r.description, r.pm, r.engineer, r.comments]
    .some(v => String(v || '').toLowerCase().includes(q)));
  const dms = r => { const m = _shopDueMs(r.shop_release); return m == null ? Infinity : m; };
  rows.sort((a, b) => _shopPri(a) - _shopPri(b) || dms(a) - dms(b) || (a.id - b.id));
  return rows;
}
// Move a part up/down — swaps priority (sort_order) with its neighbour. In
// "by project" view the neighbour is within the same job (per-project priority);
// in "overall" it's the global neighbour.
async function _shopReorder(id, dir, scope) {
  const all = state.shopParts || [];
  let seq;
  if (!scope || scope === 'overall') {
    // Top-10 list = open parts in overall-priority order.
    seq = _shopDisplayedRows(all, { filter: 'open', search: '', view: 'overall' });
  } else {
    // Within a project card — reorder just that project's parts.
    seq = _shopDisplayedRows(all, _shopState()).filter(r => ((r.job && r.job.trim()) ? r.job : 'Not assigned') === scope);
  }
  const idx = seq.findIndex(r => r.id === id);
  const tgt = idx + dir;
  if (idx < 0 || tgt < 0 || tgt >= seq.length) return;
  const a = seq[idx], b = seq[tgt];
  const ao = a.sort_order, bo = b.sort_order;
  a.sort_order = bo; b.sort_order = ao;
  renderShopPartsPage();
  try {
    await api.shopParts.update(a.id, { sort_order: a.sort_order });
    await api.shopParts.update(b.id, { sort_order: b.sort_order });
  } catch (_) {}
}

function renderShopPartsPage() {
  const root = document.getElementById('shop-parts-page');
  if (!root) return;
  const st = _shopState();
  const all = Array.isArray(state.shopParts) ? state.shopParts : [];
  const rows = _shopDisplayedRows(all, st);
  const openCount = all.filter(r => !r.part_complete).length;

  const teamNames = (state.team || []).filter(m => !isPlaceholder(m.name) && m.active !== 0).map(m => m.name).sort();
  const projOpts = Array.isArray(state.tasks) ? uniqueValues('project').filter(p => !isTemplateProject(p) && projectWorkspace(p) !== 'Sales') : [];
  const jobOpts = [...new Set([...all.map(r => r.job).filter(Boolean), ...projOpts])].sort((a, b) => String(a).localeCompare(String(b), undefined, { numeric: true }));
  const pmVals  = [...new Set(all.map(r => r.pm).filter(Boolean))].sort();
  const engVals = [...new Set(all.map(r => r.engineer).filter(Boolean))].sort();
  const pmList  = `<datalist id="shop-pm-list">${[...new Set([...teamNames, ...pmVals, ...engVals])].map(n => `<option value="${escapeHtml(n)}"></option>`).join('')}</datalist>`;
  const modList = `<datalist id="shop-mod-list">${['New Part-Initial Release', 'New Part-Redesign', 'MOD', 'MOD/NEW', 'AT BUILD'].map(o => `<option value="${o}"></option>`).join('')}</datalist>`;
  const jobList = `<datalist id="shop-job-list">${jobOpts.map(j => `<option value="${escapeHtml(j)}"></option>`).join('')}</datalist>`;

  // Detail editor field (shown when a card is expanded).
  const detailInput = (r, c) => {
    const val = r[c.key];
    const a = `data-id="${r.id}" data-field="${c.key}"`;
    let inp;
    if (c.type === 'check') inp = `<input type="checkbox" ${a} ${val ? 'checked' : ''}/>`;
    else if (c.type === 'num') inp = `<input type="number" step="any" class="sp-dinput" ${a} value="${val ?? ''}"/>`;
    else if (c.type === 'pm') inp = `<input type="text" list="shop-pm-list" class="sp-dinput" ${a} value="${escapeHtml(val || '')}"/>`;
    else if (c.type === 'mod') inp = `<input type="text" list="shop-mod-list" class="sp-dinput" ${a} value="${escapeHtml(val || '')}"/>`;
    else inp = `<input type="text" class="sp-dinput" ${a} value="${escapeHtml(val || '')}"/>`;
    return `<label class="sp-field${c.type === 'check' ? ' sp-field-check' : ''}"><span>${escapeHtml(c.label)}</span>${inp}</label>`;
  };
  // Expand editor = the fields not already inline in the row (qty/complete) or
  // the legacy rank. Everything else stays editable here.
  const detailFields = (r) => SHOP_COLS.filter(c => !['qty', 'part_complete', 'rank'].includes(c.key)).map(c => detailInput(r, c)).join('');

  // Priority select (1 hot / 2 due / 3 low), color-coded inline.
  const priSel = (r) => { const p = _shopPri(r); return `<span class="sp-pri pri-${p}" data-pri="${r.id}" title="Priority ${p} — click to change">${p}</span>`; };
  const partHeader = `<div class="sp-list-head"><span>Pri</span><span>Job</span><span>Qty</span><span>Part No.</span><span>Description</span><span>Due</span><span></span></div>`;

  // One row: Priority · [Job] · Qty(stepper) · PartNo — Description · Type · Due ·
  // [PM] · ✓complete. Click the name to expand the full editor.
  const partRow = (r, showProject) => {
    const done = !!r.part_complete;
    const isMod = /mod/i.test(r.new_mod || '');
    const due = r.shop_release;
    const overdue = !done && _shopDueMs(due) != null && _shopDueMs(due) < Date.now();
    const pn = r.part_no || '(no #)';
    // Type encoded by ROW colour (mod = SDC light yellow, new = white) like the
    // Vendor PO page. Part No. is plain text (no pill). Row shows the must-sees:
    // priority · qty · PN · (description faint) · due · ✓.
    return `<div class="sp-prow${done ? ' is-complete' : ''}${isMod ? ' is-mod' : ''}" data-id="${r.id}">
      <div class="sp-prow-line">
        ${priSel(r)}
        ${showProject ? `<span class="sp-jobcell">${escapeHtml(r.job || 'Not assigned')}</span>` : ''}
        <span class="sp-qty-wrap"><input type="number" min="0" class="sp-qty-inp" data-id="${r.id}" data-field="qty" value="${r.qty ?? 1}" title="Qty"/></span>
        <span class="sp-pncell" data-toggle="${r.id}" title="${isMod ? 'MOD' : 'New part'} · ${escapeHtml(pn)} — click to edit">${escapeHtml(pn)}</span>
        <span class="sp-namecell" data-toggle="${r.id}" title="${escapeHtml(r.description || '')}">${escapeHtml(r.description || '')}</span>
        <span class="sp-duecell${overdue ? ' is-late' : ''}">${due ? escapeHtml(_shopFmtDue(due)) : ''}</span>
        <label class="sp-done" title="Mark complete → moves to Complete"><input type="checkbox" data-id="${r.id}" data-field="part_complete" ${done ? 'checked' : ''}/></label>
      </div>
      <div class="sp-card-details" data-details="${r.id}" hidden><div class="sp-fields">${detailFields(r)}</div><button class="sp-del" data-id="${r.id}" type="button">Delete part</button></div>
    </div>`;
  };

  // Priority-1 (hot) open parts — the "work on these now" list.
  const pri1 = _shopDisplayedRows(all, { filter: 'open' }).filter(r => _shopPri(r) === 1);
  const topHtml = pri1.length
    ? `<div class="sp-flat">${partHeader}${pri1.map(r => partRow(r, true)).join('')}</div>`
    : '<p class="sp-empty">No priority-1 parts right now.</p>';

  // Main area — List (flat) or Cards (by project).
  let mainHtml;
  if (rows.length === 0) {
    mainHtml = '<p class="sp-empty">No parts to show.</p>';
  } else if (st.view === 'cards') {
    const groups = {};
    rows.forEach(r => { const k = (r.job && r.job.trim()) ? r.job : 'Not assigned'; (groups[k] = groups[k] || []).push(r); });
    mainHtml = `<div class="sp-proj-grid">${Object.keys(groups).sort((a, b) => a.localeCompare(b, undefined, { numeric: true })).map(job =>
      `<section class="sp-proj-card">
        <header class="sp-proj-head"><span class="sp-proj-name">${escapeHtml(job)}</span><span class="sp-group-count">${groups[job].length}</span></header>
        <div class="sp-proj-body"><div class="sp-prow-line sp-card-colhead"><span>Pri</span><span>Qty</span><span>Part No.</span><span>Description</span><span>Due</span><span></span></div>${groups[job].map(r => partRow(r, false)).join('')}</div>
      </section>`).join('')}</div>`;
  } else {
    mainHtml = `<div class="sp-flat">${partHeader}${rows.map(r => partRow(r, true)).join('')}</div>`;
  }

  // ── Top dashboards (SDC HMI style: clean cards, lime/blue, big numbers) ──
  const now = Date.now();
  const openParts = all.filter(r => !r.part_complete);
  const doneParts = all.filter(r => r.part_complete);
  const totalParts = all.length || 1;
  const donePctW = Math.round((doneParts.length / totalParts) * 100);
  const openPctW = 100 - donePctW;
  const dashRange = [7, 14, 21, 28, 99999].includes(Number(st.dashRange)) ? Number(st.dashRange) : 7;
  const cutoff = dashRange >= 99999 ? -Infinity : now - dashRange * 86400000;
  const toWeeks = (days) => Math.round((Math.max(0, days) / 7) * 2) / 2;
  // All-time = every completed part (even ones with no completed_on on file); a
  // specific range needs a date to place it, so undated completes only show in All time.
  const completedInRange = dashRange >= 99999 ? doneParts.length : doneParts.filter(r => { const t = r.completed_on ? Date.parse(r.completed_on) : NaN; return !isNaN(t) && t >= cutoff; }).length;
  const weeksOpen = (r) => { const t = Date.parse(r.created_at); return isNaN(t) ? 0 : toWeeks((now - t) / 86400000); };
  const oldest = [...openParts].sort((a, b) => (Date.parse(a.created_at) || 0) - (Date.parse(b.created_at) || 0)).slice(0, 5);
  const rangeOpts = [{ v: 7, t: '1 week' }, { v: 14, t: '2 weeks' }, { v: 21, t: '3 weeks' }, { v: 28, t: '4 weeks' }, { v: 99999, t: 'All time' }];
  // Late = open + past its due date. Per-project open counts (with late markers).
  const lateOpen = openParts.map(r => { const m = _shopDueMs(r.shop_release); return { r, late: (m != null && m < now) ? Math.floor((now - m) / 86400000) : -1 }; }).filter(x => x.late >= 0);
  const lateCount = lateOpen.length;
  const behindList = [...lateOpen].sort((a, b) => b.late - a.late).slice(0, 5);
  const byProj = {};
  openParts.forEach(r => { const k = (r.job && r.job.trim()) ? r.job : 'Not assigned'; const m = _shopDueMs(r.shop_release); (byProj[k] = byProj[k] || { n: 0, late: 0 }); byProj[k].n++; if (m != null && m < now) byProj[k].late++; });
  const projRows = Object.keys(byProj).sort((a, b) => byProj[b].n - byProj[a].n);
  // On-time delivery — of parts completed in the range that had a due date, how
  // many finished on/before it. All-time uses every dated completion.
  const compRange = dashRange >= 99999 ? doneParts.filter(r => r.completed_on) : doneParts.filter(r => { const t = r.completed_on ? Date.parse(r.completed_on) : NaN; return !isNaN(t) && t >= cutoff; });
  const compWithDue = compRange.filter(r => _shopDueMs(r.shop_release) != null);
  const onTimeN = compWithDue.filter(r => Date.parse(r.completed_on) <= _shopDueMs(r.shop_release) + 86400000).length;
  const onTimePct = compWithDue.length ? Math.round((onTimeN / compWithDue.length) * 100) : null;
  const dueStrOf = (r) => r.shop_release ? _shopFmtDue(r.shop_release) : '—';
  const rangeSelect = `<select class="sp-dash-range">${rangeOpts.map(o => `<option value="${o.v}"${dashRange === o.v ? ' selected' : ''}>${o.t}</option>`).join('')}</select>`;
  const dashHtml = `
    <div class="sp-dash sp-dash-main">
      <div class="sp-dcard">
        <div class="sp-dcard-head">Open by project <span class="sp-dhint">${lateCount} behind</span></div>
        <div class="sp-dproj-head"><span>Job</span><span>Parts</span><span>Behind</span></div>
        <div class="sp-dproj-list">${projRows.length ? projRows.map(p => `<div class="sp-dprow"><span class="sp-dproj">${escapeHtml(p)}</span><span class="sp-dcount">${byProj[p].n}</span><span class="sp-dbehind">${byProj[p].late ? `<span class="sp-dlate-pill">${byProj[p].late}</span>` : '—'}</span></div>`).join('') : '<div class="sp-dempty">No open parts</div>'}</div>
      </div>
      <div class="sp-dcard sp-dcard-num">
        <div class="sp-dcard-head">Completed ${rangeSelect}</div>
        <div class="sp-dnum">${completedInRange}</div>
        <div class="sp-dsub">parts completed</div>
      </div>
      <div class="sp-dcard">
        <div class="sp-dcard-head">Behind schedule <span class="sp-dhint">${lateCount}</span></div>
        <div class="sp-bhead"><span>Part No.</span><span>Job</span><span>Due</span><span>Behind</span></div>
        <div class="sp-dlist">${behindList.length ? behindList.map(x => `<div class="sp-brow"><span class="sp-dpn">${escapeHtml(x.r.part_no || '—')}</span><span class="sp-dproj">${escapeHtml(x.r.job || '')}</span><span class="sp-deta">${escapeHtml(dueStrOf(x.r))}</span><span class="sp-cvar is-late">${toWeeks(x.late)}w</span></div>`).join('') : '<div class="sp-dempty">Nothing behind 🎉</div>'}</div>
      </div>
      <div class="sp-dcard">
        <div class="sp-dcard-head">Longest open</div>
        <div class="sp-bhead sp-bhead-3"><span>Part No.</span><span>Job</span><span>Open</span></div>
        <div class="sp-dlist">${oldest.length ? oldest.map(r => `<div class="sp-brow sp-brow-3"><span class="sp-dpn">${escapeHtml(r.part_no || '—')}</span><span class="sp-dproj">${escapeHtml(r.job || '')}</span><span class="sp-cvar">${weeksOpen(r)}w</span></div>`).join('') : '<div class="sp-dempty">Nothing open 🎉</div>'}</div>
      </div>
    </div>`;

  // On-time delivery sits up top, left of the + Add part button (like Vendor PO).
  const headStat = `
    <div class="vpo-headstat sp-headstat">
      <div class="vpo-hs-ontime">
        <span class="vpo-hs-label">On-time delivery</span>
        ${_shopDonut(onTimePct)}
        <span class="vpo-hs-sub">${compWithDue.length ? `${onTimeN}/${compWithDue.length}` : '—'}</span>
      </div>
    </div>`;

  const sel = (val, opts, attr) => `<select ${attr}>${opts.map(o => `<option value="${escapeHtml(o.v)}"${val === o.v ? ' selected' : ''}>${escapeHtml(o.t)}</option>`).join('')}</select>`;
  const pmFilterOpts  = [{ v: 'all', t: 'PM: all' },  ...pmVals.map(v => ({ v, t: v }))];
  const engFilterOpts = [{ v: 'all', t: 'Eng: all' }, ...engVals.map(v => ({ v, t: v }))];

  root.innerHTML = `
    <div class="shop-parts-head">
      <div class="sp-head-top">
        <h1 class="projects-page-title">Parts in Shop</h1>
        ${headStat}
        <button class="btn-primary sp-add-toggle" data-action="toggle-add" type="button">${_shopAddOpen ? '✕ Close' : '＋ Add part'}</button>
      </div>
      <form class="sp-add-bar${_shopAddOpen ? '' : ' is-hidden'}" data-action="add-form">
        <label class="sp-add-f"><span>Priority</span><select name="priority" class="sp-add-pri"><option value="1">1 · Hot</option><option value="2">2 · Due</option><option value="3" selected>3 · Low</option></select></label>
        <label class="sp-add-f"><span>Qty</span><input name="qty" type="number" min="1" value="1" class="sp-add-qty"/></label>
        <label class="sp-add-f"><span>Project</span><input name="job" list="shop-job-list" class="sp-add-job" autocomplete="off"/></label>
        <label class="sp-add-f"><span>Part No.</span><input name="part_no" class="sp-add-pn" autocomplete="off"/></label>
        <label class="sp-add-f sp-add-f-grow"><span>Description</span><input name="description" class="sp-add-desc" autocomplete="off"/></label>
        <label class="sp-add-f"><span>Type</span><select name="type" class="sp-add-type"><option value="New Part-Initial Release">New Part</option><option value="MOD">MOD</option></select></label>
        <label class="sp-add-f"><span>Due</span><input name="shop_release" type="date" class="sp-add-due"/></label>
        <label class="sp-add-f"><span>Engineer</span><input name="engineer" list="shop-pm-list" class="sp-add-eng" autocomplete="off"/></label>
        <label class="sp-add-f"><span>PM</span><input name="pm" list="shop-pm-list" class="sp-add-pm" autocomplete="off"/></label>
        <label class="sp-add-f sp-add-f-grow"><span>Notes</span><input name="comments" class="sp-add-notes" autocomplete="off"/></label>
        <button class="btn-primary sp-add-btn" type="submit">Add</button>
      </form>
      <div class="shop-parts-toolbar">
        <div class="seg-control sp-view">
          <button class="seg-btn${st.view === 'list' ? ' is-active' : ''}" data-view="list" type="button">List</button>
          <button class="seg-btn${st.view === 'cards' ? ' is-active' : ''}" data-view="cards" type="button">Cards</button>
        </div>
        <div class="seg-control sp-filter">
          <button class="seg-btn${st.filter === 'open' ? ' is-active' : ''}" data-filter="open" type="button">Open ${openCount}</button>
          <button class="seg-btn${st.filter === 'complete' ? ' is-active' : ''}" data-filter="complete" type="button">Complete</button>
          <button class="seg-btn${st.filter === 'all' ? ' is-active' : ''}" data-filter="all" type="button">All</button>
        </div>
        ${sel(st.fPri, [{ v: 'all', t: 'Priority: all' }, { v: '1', t: '1 · Hot' }, { v: '2', t: '2 · Due' }, { v: '3', t: '3 · Low' }], 'class="sp-fsel" data-fk="fPri"')}
        ${sel(st.fPm, pmFilterOpts, 'class="sp-fsel" data-fk="fPm"')}
        ${sel(st.fEng, engFilterOpts, 'class="sp-fsel" data-fk="fEng"')}
        <label class="sp-fdue">Due ≤ <input type="date" class="sp-fdue-inp" value="${escapeHtml(st.fDue || '')}"/></label>
        <input type="search" class="sp-search" placeholder="Search…" value="${escapeHtml(st.search || '')}"/>
      </div>
      <div class="vpo-legend sp-legend">
        <span class="vpo-leg"><i style="background:#fff;border:1px solid var(--border,#e2e8f0)"></i>New part</span>
        <span class="vpo-leg"><i style="background:var(--sdc-accent,#ffde51)"></i>MOD</span>
        <span class="sp-legend-pri">Priority: <i class="sp-pri pri-1">1</i> hot · <i class="sp-pri pri-2">2</i> · <i class="sp-pri pri-3">3</i> low</span>
      </div>
    </div>
    ${dashHtml}
    <section class="sp-section sp-top">
      <header class="sp-section-head">🔴 Priority 1 parts</header>
      ${topHtml}
    </section>
    <section class="sp-section sp-projects">
      <header class="sp-section-head">${st.view === 'cards' ? 'By project' : 'All parts'}</header>
      ${mainHtml}
    </section>
    ${pmList}${modList}${jobList}`;

  // Add part
  root.querySelector('[data-action="add-form"]').addEventListener('submit', async (e) => {
    e.preventDefault();
    const f = e.target;
    const data = {
      priority: f.priority.value,
      qty: f.qty.value === '' ? 1 : Number(f.qty.value),
      job: f.job.value.trim() || null,
      part_no: f.part_no.value.trim() || null,
      description: f.description.value.trim() || null,
      new_mod: f.type.value,
      shop_release: f.shop_release.value || null,
      engineer: f.engineer.value.trim() || null,
      pm: f.pm.value.trim() || null,
      comments: f.comments.value.trim() || null,
      part_complete: 0,
    };
    let created;
    try { created = await api.shopParts.create(data); } catch (e) { showAlertDialog({ title: 'Add failed', message: e.message }); return; }
    if (created && created.id) {
      if (!Array.isArray(state.shopParts)) state.shopParts = [];
      state.shopParts.push(created); f.reset(); _shopAddOpen = true; renderShopPartsPage(); const pn = document.querySelector('.sp-add-pn'); if (pn) pn.focus();
    }
  });
  // Toggle the collapsible add form
  const addToggle = root.querySelector('[data-action="toggle-add"]');
  if (addToggle) addToggle.addEventListener('click', () => {
    _shopAddOpen = !_shopAddOpen; renderShopPartsPage();
    if (_shopAddOpen) { const pn = document.querySelector('.sp-add-pn'); if (pn) pn.focus(); }
  });
  // View toggle + filter chips + filter selects + due + search
  root.querySelectorAll('.sp-view [data-view]').forEach(b => b.addEventListener('click', () => { st.view = b.dataset.view; _saveShopState(); renderShopPartsPage(); }));
  root.querySelectorAll('.sp-filter [data-filter]').forEach(b => b.addEventListener('click', () => { st.filter = b.dataset.filter; _saveShopState(); renderShopPartsPage(); }));
  root.querySelectorAll('.sp-fsel').forEach(s => s.addEventListener('change', () => { st[s.dataset.fk] = s.value; _saveShopState(); renderShopPartsPage(); }));
  const dueF = root.querySelector('.sp-fdue-inp');
  if (dueF) dueF.addEventListener('change', () => { st.fDue = dueF.value; _saveShopState(); renderShopPartsPage(); });
  const dashRangeEl = root.querySelector('.sp-dash-range');
  if (dashRangeEl) dashRangeEl.addEventListener('change', () => { st.dashRange = Number(dashRangeEl.value); _saveShopState(); renderShopPartsPage(); });
  const searchEl = root.querySelector('.sp-search');
  searchEl.addEventListener('input', () => {
    st.search = searchEl.value; _saveShopState(); renderShopPartsPage();
    const s2 = document.querySelector('.sp-search');
    if (s2) { s2.focus(); s2.setSelectionRange(s2.value.length, s2.value.length); }
  });
  // Priority — click the number, pick from a popup (no inline arrows).
  root.querySelectorAll('.sp-pri[data-pri]').forEach(el => el.addEventListener('click', (e) => {
    e.stopPropagation();
    const id = Number(el.dataset.pri);
    showContextMenu(e.clientX, e.clientY, [
      { label: '1 · Hot — now', onClick: () => _shopSetPri(id, 1) },
      { label: '2 · Hit the due date', onClick: () => _shopSetPri(id, 2) },
      { label: '3 · Low', onClick: () => _shopSetPri(id, 3) },
    ]);
  }));
  // Expand/collapse a row to edit its full details
  root.querySelectorAll('[data-toggle]').forEach(b => b.addEventListener('click', () => {
    const d = root.querySelector(`[data-details="${b.dataset.toggle}"]`);
    if (d) d.hidden = !d.hidden;
  }));
  // Field edits (delegated). Bound ONCE — root persists across re-renders, so
  // re-binding every render would stack duplicate handlers.
  if (!root.dataset.changeBound) { root.dataset.changeBound = '1'; root.addEventListener('change', async (e) => {
    const el = e.target.closest('[data-id][data-field]');
    if (!el) return;
    const id = Number(el.dataset.id), field = el.dataset.field;
    let val;
    if (el.type === 'checkbox') val = el.checked ? 1 : 0;
    else if (el.type === 'number') val = el.value === '' ? null : Number(el.value);
    else val = el.value;
    let updated;
    try { updated = await api.shopParts.update(id, { [field]: val }); } catch (err) { showToast(err.message || 'Save failed', { kind: 'error' }); return; }
    const row = state.shopParts.find(r => r.id === id);
    if (row && updated) Object.assign(row, updated);
    if (field === 'part_complete' || field === 'priority' || field === 'job') renderShopPartsPage();
  }); }
  // Delete
  root.querySelectorAll('.sp-del').forEach(btn => btn.addEventListener('click', async () => {
    const id = Number(btn.dataset.id);
    const r = state.shopParts.find(x => x.id === id);
    const ok = await showConfirmDialog({ title: 'Delete part?', message: `Delete "${escapeHtml(r?.part_no || r?.description || 'this part')}"?`, okLabel: 'Delete', cancelLabel: 'Cancel', danger: true });
    if (!ok) return;
    try { await api.shopParts.remove(id); } catch (err) { showToast(err.message || 'Delete failed', { kind: 'error' }); return; }
    state.shopParts = state.shopParts.filter(x => x.id !== id);
    renderShopPartsPage();
  }));
}

// ── Vendor PO Track ─────────────────────────────────────────────────────────
const VPO_COLS = [
  { key: 'priority', label: 'Priority', type: 'num' },
  { key: 'po', label: 'PO #', type: 'text' },
  { key: 'job', label: 'Job #', type: 'text' },
  { key: 'vendor', label: 'Vendor', type: 'text' },
  { key: 'po_date', label: 'PO Date', type: 'date' },
  { key: 'lead_time', label: 'Lead (wks)', type: 'num' },
  { key: 'eta', label: 'ETA', type: 'date' },
  { key: 'ship_date', label: 'Ship Date', type: 'date' },
  { key: 'delivery_date', label: 'Delivery', type: 'date' },
  { key: 'tracking', label: 'Tracking #', type: 'text' },
  { key: 'po_price', label: 'PO Price', type: 'text' },
  { key: 'pm', label: 'PM', type: 'pm' },
  { key: 'comments', label: 'Comments', type: 'text' },
];
// SDC status palette + legend. green done · blue partial · navy late · yellow due-soon.
const VPO_STATUS = {
  complete: { label: 'Complete', color: '#74c415' },
  shipped:  { label: 'Shipped',  color: '#befa4f' },
  partial:  { label: 'Partial',  color: '#1574c4' },
  late:     { label: 'Late',     color: '#061d39' },
  soon:     { label: 'Due ≤1 wk', color: '#ffde51' },
  open:     { label: 'Open',     color: '#d9d9d9' },
};
let _vpoState = null;
let _vpoAddOpen = false;
let _vpoChangeBound = false;
let _vpoChangeRoot = null;
let _vpoSearchT = 0;
const VPO_PAGE_SIZE = 100;
// Column resize — 8 resizable cols: po, job, vendor, eta, ship, tracking, pm, price
const VPO_COL_DEFAULTS = [80, 72, 180, 78, 72, 160, 76, 100];
function _vpoColWidths() { try { const s = localStorage.getItem('vpo_col_widths'); return s ? JSON.parse(s) : [...VPO_COL_DEFAULTS]; } catch(_) { return [...VPO_COL_DEFAULTS]; } }
function _vpoSaveColWidths(w) { try { localStorage.setItem('vpo_col_widths', JSON.stringify(w)); } catch(_) {} }
function _vpoApplyCols(w) {
  // col 2 (Vendor) stays as minmax so it absorbs remaining space — prevents overflow
  const tpl = `20px 22px ${w[0]}px ${w[1]}px minmax(${Math.max(60, w[2])}px,1fr) ${w[3]}px ${w[4]}px ${w[5]}px ${w[6]}px ${w[7]}px 32px 32px`;
  let el = document.getElementById('vpo-col-style');
  if (!el) { el = document.createElement('style'); el.id = 'vpo-col-style'; document.head.appendChild(el); }
  el.textContent = `.vpo-page .sp-flat .sp-prow-line, .vpo-page .vpo-head { grid-template-columns: ${tpl} !important; }`;
}
function _vpoStateGet() {
  if (_vpoState) return _vpoState;
  let s = { filter: 'open', search: '', view: 'list', fVendor: 'all', fPm: 'all', fStatus: 'all', fJob: 'all', dashRange: 7, page: 0, etaRange: 'all', sortKey: 'eta', sortDir: 'asc' };
  try { s = Object.assign(s, JSON.parse(localStorage.getItem('sdcVendorPoState') || '{}')); } catch (_) {}
  if (s.view !== 'cards') s.view = 'list';
  _vpoState = s; return s;
}
function _vpoSave() { try { localStorage.setItem('sdcVendorPoState', JSON.stringify(_vpoState)); } catch (_) {} }
function _vpoFmtDate(v) { const s = String(v || ''); return /^\d{4}-\d{2}-\d{2}$/.test(s) ? fmtDate(s) : s; }
function _vpoEtaMs(r) {
  if (r.eta) { const t = Date.parse(r.eta + 'T00:00:00'); if (!isNaN(t)) return t; }
  if (r.po_date && r.lead_time) { const t = Date.parse(r.po_date + 'T00:00:00'); if (!isNaN(t)) return t + Number(r.lead_time) * 7 * 86400000; }
  return null;
}
// Actual lead time in weeks (½-snap): PO Date → completion date. null when we
// don't know one of them (so it's left blank / excluded from averages).
function _vpoActualWeeks(r) {
  const o = Date.parse(r.po_date || '');
  const c = Date.parse(r.completed_on || r.delivery_date || '');
  if (isNaN(o) || isNaN(c) || c < o) return null;
  return Math.round(((c - o) / 604800000) * 2) / 2;
}
function _vpoStatusOf(r) {
  if (r.complete) return 'complete';
  if (r.tracking && String(r.tracking).trim()) return 'shipped'; // has tracking = on its way
  if (r.partial) return 'partial';
  const e = _vpoEtaMs(r);
  if (e != null) { if (e < Date.now()) return 'late'; if (e - Date.now() <= 7 * 86400000) return 'soon'; }
  return 'open';
}
// Total ETO availability — checked once; ETO UI (sync button, banner chip,
// quote actuals) only renders when the server actually has ETO_* configured,
// so every page stays clean otherwise.
let _etoAvailable = false;
let _etoChecked = false;
function _etoCheckOnce() {
  if (_etoChecked) return;
  _etoChecked = true;
  api.eto.status().then(s => {
    if (s && s.configured) {
      _etoAvailable = true;
      try { renderVendorPOsPage(); } catch (_) {}
      try { renderProjectTabs(); } catch (_) {}
    }
  }).catch(() => {});
}

// ── Job Hours availability (Power BI) ───────────────────────────────────────
let _hoursAvailable = false;
let _hoursChecked = false;
const _hoursCache = {};
const _hoursFetching = {};
// UI filter state — survives re-renders within a session
const _hoursUI = { mode: 'quoted', billing: 'all', fnSel: null, fnOpen: false, fnExp: new Set(), fnSearch: '' };
function _hoursCheckOnce() {
  if (_hoursChecked) return;
  _hoursChecked = true;
  fetch('/api/hours/status').then(r => r.json()).then(s => {
    if (s && s.enabled) {
      _hoursAvailable = true;
      try { renderScheduleHours(); } catch (_) {}
      try { renderProjectTabs(); } catch (_) {}
      // Start warming the frontend cache for all local jobs immediately
      _prefetchJobHours();
    }
  }).catch(() => {});
}

// ── Total ETO project-link chip (schedule banner) ───────────────────────────
// A project links to the ERP through its job number (=== ETO ProjectID).
// The chip shows the link state and opens an in-app prompt to set it.
const _etoNameCache = {}; // job → official ETO name, or null when not found

// SDC names projects "<job#>_<customer>…" (e.g. "1158_Panduit, …"), so the
// leading digits are almost always the Total ETO ProjectID. Pull them out as a
// suggestion — never auto-linked, only offered + validated on click.
function _etoJobFromName(name) {
  // Leading 3+ digits. No \b after — SDC names are "1158_…" and "_" is a word
  // char, so \b wouldn't match there; just grab the leading digit run.
  const m = String(name || '').match(/^\s*(\d{3,})/);
  return m ? m[1] : '';
}

function _etoBannerChipHtml(project) {
  if (!_etoAvailable) return '';
  const job = (state.projectsIndex && state.projectsIndex[project] && state.projectsIndex[project].job_number) || '';
  if (!job) {
    const guess = _etoJobFromName(project);
    if (guess) {
      return `<button type="button" id="eto-link-chip" class="eto-chip eto-chip-unlinked" data-eto-guess="${escapeHtml(guess)}" title="Looks like Total ETO job ${escapeHtml(guess)} (from the project name). Click to verify against the ERP and link.">🔗 Link ETO #${escapeHtml(guess)}</button>`;
    }
    return `<button type="button" id="eto-link-chip" class="eto-chip eto-chip-unlinked" title="Link this schedule to a Total ETO job — turns on automatic vendor PO sync and live cost actuals for this project.">🔗 Link ETO job…</button>`;
  }
  const known = _etoNameCache[job]; // undefined = not looked up yet
  const bad = known === null;
  const title = bad ? `Job ${job} was not found in Total ETO — click to fix the number.`
    : known ? `Linked to Total ETO job ${job} — ${known}. Vendor POs and cost actuals sync from the ERP. Click to change.`
    : `Linked to Total ETO job ${job}. Click to change.`;
  return `<button type="button" id="eto-link-chip" class="eto-chip${bad ? ' eto-chip-bad' : ''}" title="${escapeHtml(title)}">ETO #${escapeHtml(job)}${bad ? ' ✗' : ''}</button>`;
}

function _wireEtoBannerChip(banner, project) {
  const chip = banner.querySelector('#eto-link-chip');
  if (!chip) return;
  const job = (state.projectsIndex && state.projectsIndex[project] && state.projectsIndex[project].job_number) || '';
  // Lazy one-time validation: fetch the official ETO name for the tooltip.
  if (job && _etoNameCache[job] === undefined) {
    fetch(`/api/eto/project/${encodeURIComponent(job)}`)
      .then(r => r.ok ? r.json() : null)
      .then(info => { _etoNameCache[job] = info ? (info.ProjectName || '') : null; try { renderProjectTabs(); } catch (_) {} })
      .catch(() => {});
  }
  const guess = chip.dataset.etoGuess;
  chip.addEventListener('click', () => guess ? _etoLinkSuggested(project, guess) : _etoLinkJobFlow(project));
}

function _pbiChipHtml(project) {
  const idx = state.projectsIndex && state.projectsIndex[project];
  const job = idx && idx.hours_job_id;
  if (job) {
    return `<button type="button" id="pbi-link-chip" class="eto-chip" title="Power BI hours linked to job ${escapeHtml(String(job))}. Click to change.">PBI #${escapeHtml(String(job))}</button>`;
  }
  return `<button type="button" id="pbi-link-chip" class="eto-chip eto-chip-unlinked" title="Link a Power BI job ID to show hours data for this project.">🔗 Link PBI job…</button>`;
}

function _wirePbiChip(banner, project) {
  const chip = banner.querySelector('#pbi-link-chip');
  if (!chip) return;
  chip.addEventListener('click', () => _hoursLinkJobFlow(project));
}

// Persist the job-number link. Updates the projects row if it exists, or
// CREATES it when the project is only a task-tab with no projects-table row yet
// (POST /api/projects is create-or-return). Returns true on success.
async function _etoApplyJobLink(project, job, info) {
  let idx = state.projectsIndex && state.projectsIndex[project];
  try {
    if (idx && idx.id) {
      const r = await fetch(`/api/projects/${idx.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ job_number: job }) });
      if (!r.ok) throw new Error(`save failed (${r.status})`);
    } else {
      const r = await fetch('/api/projects', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name: project, job_number: job }) });
      if (!r.ok) throw new Error(`create failed (${r.status})`);
      const row = await r.json();
      state.projectsIndex = state.projectsIndex || {};
      state.projectsIndex[project] = { id: row.id, job_number: job };
      idx = state.projectsIndex[project];
    }
  } catch (e) { showToast(`Could not save the job number: ${e.message}`, { kind: 'error' }); return false; }
  idx.job_number = job;
  _etoNameCache[job] = info ? (info.ProjectName || '') : '';
  showToast(`Linked to ETO job ${job}${info && info.ProjectName ? ' — ' + info.ProjectName : ''}`, { kind: 'success' });
  try { renderProjectTabs(); } catch (_) {}
  return true;
}

// One-click link of a name-derived job number — still validated against ETO.
// If the guess isn't a real ETO job, fall back to the manual prompt (prefilled)
// so nothing links silently and a wrong prefix is easy to correct.
async function _etoLinkSuggested(project, guess) {
  let info = null;
  try {
    const r = await fetch(`/api/eto/project/${encodeURIComponent(guess)}`);
    if (r.ok) info = await r.json();
    else if (r.status !== 404) return _etoLinkJobFlow(project, guess); // server error → manual
  } catch (_) { return _etoLinkJobFlow(project, guess); }
  if (!info) {
    showToast(`Job ${guess} (from the name) isn't in Total ETO — enter the correct number.`, { kind: 'error' });
    return _etoLinkJobFlow(project, guess);
  }
  await _etoApplyJobLink(project, guess, info);
}

async function _etoLinkJobFlow(project, prefill) {
  const idx = state.projectsIndex && state.projectsIndex[project];
  const current = (idx && idx.job_number) || '';
  const val = await showPromptDialog({
    title: 'Link to Total ETO',
    message: `Enter the Total ETO job number for "${project}". The vendor PO sync and live cost actuals follow this link.`,
    placeholder: 'e.g. 1129',
    value: prefill || current,
    validate: v => (v === '' || /^\d+$/.test(v)) ? null : 'Job number must be digits only',
    okLabel: 'Save',
  });
  if (val === null || val === current) return; // cancelled or unchanged
  // Verify against the ERP before saving — typos get caught here, visibly.
  let info = null;
  try {
    const r = await fetch(`/api/eto/project/${encodeURIComponent(val)}`);
    if (r.ok) info = await r.json();
    else if (r.status !== 404) { const e = await r.json().catch(() => ({})); showToast(`ETO lookup failed: ${e.error || r.status}`, { kind: 'error' }); return; }
  } catch (e) { showToast(`ETO lookup failed: ${e.message}`, { kind: 'error' }); return; }
  if (!info) { showToast(`Job ${val} was not found in Total ETO — check the number.`, { kind: 'error' }); return; }
  await _etoApplyJobLink(project, val, info);
}

// ETO actuals strip inside the Quote vs Schedule modal — live est-vs-actual
// hours, materials, total cost and margin from the ERP costing view.
async function _loadQuoteEtoActuals(project, overlay) {
  try {
    if (!_etoAvailable) return;
    const job = state.projectsIndex && state.projectsIndex[project] && state.projectsIndex[project].job_number;
    if (!job) return;
    const r = await fetch(`/api/eto/costing/${encodeURIComponent(job)}`);
    if (!r.ok) return;
    const c = await r.json();
    const box = overlay.querySelector('#quote-eto-actuals');
    if (!box) return;
    const hrs = v => v == null ? '—' : Math.round(Number(v)).toLocaleString();
    const usd = v => v == null ? '—' : '$' + Math.round(Number(v)).toLocaleString();
    const pct = v => v == null ? '—' : Number(v).toFixed(1) + '%';
    const over = (est, act) => est != null && act != null && Number(act) > Number(est);
    const cell = (label, estStr, actStr, isOver, tip) => `
      <div class="eto-stat" title="${escapeHtml(tip)}">
        <span class="eto-stat-label">${label}</span>
        <span class="eto-stat-vals"><span class="eto-stat-est">${estStr}</span> est&nbsp;·&nbsp;<span class="eto-stat-act${isOver ? ' is-over' : ''}">${actStr}</span> act</span>
      </div>`;
    box.hidden = false;
    box.innerHTML = `
      <div class="eto-actuals-head">Total ETO actuals — job ${escapeHtml(String(job))} <span class="eto-actuals-hint">live from the ERP</span></div>
      <div class="eto-actuals-grid">
        ${cell('Eng hours', hrs(c.EstEngHrs), hrs(c.ActEngHrs), over(c.EstEngHrs, c.ActEngHrs), 'Engineering hours — estimate vs actual hours booked in Total ETO')}
        ${cell('Mfg hours', hrs(c.EstMfgHrs), hrs(c.ActMfgHrs), over(c.EstMfgHrs, c.ActMfgHrs), 'Manufacturing hours — estimate vs actual hours booked in Total ETO')}
        ${cell('Materials', usd(c.EstMaterials), usd(c.ActMaterials), over(c.EstMaterials, c.ActMaterials), 'Material cost — estimate vs actual (purchased + inventory pulls)')}
        ${cell('Total cost', usd(c.TotalEstimate), usd(c.TotalActualCost), over(c.TotalEstimate, c.TotalActualCost), 'Total project cost — estimate vs actual')}
        ${cell('Margin', pct(c.BudgetMargin), pct(c.ActualMargin), c.BudgetMargin != null && c.ActualMargin != null && Number(c.ActualMargin) < Number(c.BudgetMargin), 'Margin — budget vs actual. Red when actual margin is below budget.')}
      </div>`;
  } catch (_) { /* cosmetic — modal works fine without the strip */ }
}

