let _procState = { job: '', tab: 'assemblies', filter: 'all', vstatus: 'all', pstatus: 'all', pcat: 'all', pmfr: 'all', psup: 'all', pdatemode: 'purchase', pfrom: '', pto: '', search: '', open: {}, partsListMode: 'table', upcomingWeek: 1, hiddenPartCols: [] };
try { _procState = Object.assign(_procState, JSON.parse(localStorage.getItem('sdcProcState') || '{}')); } catch (_) {}
function _procSave() { try { const { drawerTab: _dt, ...s } = _procState; localStorage.setItem('sdcProcState', JSON.stringify({ ...s, open: {} })); } catch (_) {} }
const _procCache = {};   // job → readiness payload
const _procVendorCache = {};   // job → vendor status payload (used by card view + PO panel)
let _procLoading = false;

function _procLinkedJobs() {
  const out = [];
  const idx = state.projectsIndex || {};
  for (const name of Object.keys(idx)) {
    if (idx[name].job_number) out.push({ name, job: idx[name].job_number });
  }
  return out.sort((a, b) => Number(a.job) - Number(b.job));
}

function _procBarColor(pct) { return pct >= 90 ? '#74C415' : pct >= 60 ? '#AACEE8' : '#1574C4'; }

// ── Vendors tab (Build Readiness "Vendor Status" view) ──────────────────────
// POs grouped by supplier, each with received progress + a status badge; click
// a PO to expand its line items inline. Lazily fetches /api/eto/vendors/:job.
function _procRerender() {
  try { renderScheduleProcurement(); } catch (_) {}
  try { renderScheduleHours(); } catch (_) {}
}

// ── Cost tab (ETO "Part Cost" report card) ──────────────────────────────────
// Materials-only financial summary: estimated → purchased → received → paid,
// plus left-to-pay and estimate-to-complete. Lazily fetches /api/eto/partcost.
const _procCostCache = {}; // job → part-cost payload

// One delegated listener (document-level) for the editable materials-estimate
// controls, so they work whether the Cost card is on the full page or the drawer.
function _procWireEstimateEditor() {
  if (window._procEstWired) return;
  window._procEstWired = true;
  document.addEventListener('click', (e) => {
    const edit = e.target.closest('[data-action="proc-edit-estimate"]');
    if (edit) { e.preventDefault(); _procEditEstimate(edit.dataset.job); return; }
    const rev = e.target.closest('[data-action="proc-revert-estimate"]');
    if (rev) { e.preventDefault(); _procRevertEstimate(rev.dataset.job); return; }
  });
}
async function _procEditEstimate(job) {
  const c = _procCostCache[job] || {};
  const v = await showPromptDialog({
    title: 'Materials estimate to purchase',
    message: 'Enter the estimated materials cost (USD) for this job. It drives the “Purchased vs estimate” bar and Estimate-to-Complete. (Total ETO has no reliable per-job materials budget, so PMs set it here.)',
    placeholder: 'e.g. 200000',
    value: (c.estimateSource === 'user' && c.estimated != null) ? String(Math.round(c.estimated)) : '',
    validate: x => /^\d{1,12}(\.\d{1,2})?$/.test(x) ? null : 'Enter a dollar amount — numbers only (e.g. 200000).',
    okLabel: 'Save',
  });
  if (v === null) return;
  await _procSaveEstimate(job, Number(v), 'Materials estimate saved');
}
async function _procRevertEstimate(job) {
  await _procSaveEstimate(job, null, 'Reverted to the Total ETO estimate');
}
async function _procSaveEstimate(job, estimate, okMsg) {
  try {
    const r = await fetch(`/api/eto/partcost/${encodeURIComponent(job)}/estimate`, {
      method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ estimate }),
    });
    if (!r.ok) throw new Error((await r.json().catch(() => ({}))).error || ('HTTP ' + r.status));
    delete _procCostCache[job];
    _procCostCache[job] = await api.eto.partcost(job);
    _procRerender();
    if (typeof showToast === 'function') showToast(okMsg, { kind: 'success' });
  } catch (e) { if (typeof showToast === 'function') showToast('Could not save estimate: ' + e.message, { kind: 'error' }); }
}

function _procCostGauge(c) {
  const usd = v => _procUsd(v);
  const budget = Number(c.estimated) || 0;
  const spent = Number(c.purchased) || 0;
  const projection = Number(c.projection) || 0;
  const budgetUnset = !budget || (c.estimateSource === 'eto' && budget < spent * 0.25);
  const pct = budgetUnset ? null : Math.round((spent / budget) * 100);
  const projPct = budgetUnset ? null : Math.round((projection / budget) * 100);
  const frac = budgetUnset ? 0 : Math.min(1, spent / budget);
  const color = pct == null ? '#94a3b8' : pct <= 80 ? '#1574c4' : pct <= 100 ? '#eab308' : '#dc2626';

  // 270° arc — sweep clockwise from 135° (bottom-left) over the top to 405° (=45°, bottom-right).
  const cx = 130, cy = 130, r = 92, sw = 20;
  const pol = (deg) => { const a = deg * Math.PI / 180; return [cx + r * Math.cos(a), cy + r * Math.sin(a)]; };
  const arc = (s, e) => { const [x1, y1] = pol(s), [x2, y2] = pol(e); const large = (e - s) > 180 ? 1 : 0; return `M ${x1.toFixed(1)} ${y1.toFixed(1)} A ${r} ${r} 0 ${large} 1 ${x2.toFixed(1)} ${y2.toFixed(1)}`; };

  // Compact dollar formatter for the small callout chips: $600,000 → $600K, $1.2M, etc.
  const compactUsd = (v) => {
    const n = Math.round(Number(v) || 0);
    if (n === 0) return '—';
    if (Math.abs(n) >= 1000000) return '$' + (n / 1000000).toFixed(1).replace(/\.0$/, '') + 'M';
    if (Math.abs(n) >= 1000) return '$' + Math.round(n / 1000) + 'K';
    return '$' + n.toLocaleString();
  };

  const paid = Number(c.paid) || 0;
  // Position on the 270° arc for a given fraction (0..1 of budget).
  const arcAt = (f) => pol(135 + 270 * Math.min(1, Math.max(0, f)));
  const spentFrac = budgetUnset ? null : Math.min(1, spent / budget);
  const projFrac  = budgetUnset ? null : Math.min(1, projection / budget);
  const paidFrac  = budgetUnset ? null : Math.min(1, paid / budget);

  // Sizing — area encodes magnitude. sqrt(v/budget) so a value 4× larger
  // shows up as a 2× radius (8× bigger by eye); reads as "this one is way
  // bigger" rather than swamping everything. Budget = max; everything scales
  // relative to it.
  const sqrtFrac = (v) => (!budget || v <= 0) ? 0 : Math.min(1, Math.sqrt(v / budget));
  const dotR = (v) => 5 + 9 * sqrtFrac(v);             // 5..14 px
  const dot = (f, v, fill, stroke, label) => {
    if (f == null || !(v > 0)) return '';
    const [x, y] = arcAt(f);
    return `<g><title>${escapeHtml(label)}: ${usd(v)}</title><circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="${dotR(v).toFixed(1)}" fill="${fill}" stroke="${stroke}" stroke-width="2"/></g>`;
  };
  // Callout box style — also scaled by value so the boxes themselves visually
  // rank Budget > Projected > Purchased > Paid (or however the numbers fall).
  const coStyle = (v) => {
    const f = sqrtFrac(v);
    return `font-size:${(10.5 + 5 * f).toFixed(1)}px;padding:${(1.5 + 3 * f).toFixed(1)}px ${(9 + 9 * f).toFixed(1)}px;`;
  };

  return `<div class="proc-gauge">
    <div class="proc-gauge-chart">
      <svg viewBox="0 0 260 260" class="proc-gauge-svg" role="img" aria-label="Cost gauge">
        <path d="${arc(135, 405)}" fill="none" stroke="#e8edf3" stroke-width="${sw}" stroke-linecap="round"/>
        ${!budgetUnset ? `<path d="${arc(135, 135 + 270 * spentFrac)}" fill="none" stroke="${color}" stroke-width="${sw}" stroke-linecap="round"/>` : ''}
        ${dot(1, budget, '#cfe2f5', '#1574c4', 'Part Cost Budget')}
        ${dot(projFrac, projection, '#fff', '#0f172a', 'Projected total')}
        ${dot(spentFrac, spent, color, color, 'Part Cost Purchased')}
        ${dot(paidFrac, paid, '#bef264', '#5a9e10', 'Part Cost Paid')}
      </svg>
      <div class="proc-gauge-callouts">
        <div class="proc-gauge-co proc-gauge-co-budget" style="${coStyle(budget)}" title="Part Cost Budget — ${usd(budget)}">${compactUsd(budget)}${budgetUnset && budget ? ' <i>unset</i>' : ''}</div>
        <div class="proc-gauge-co" style="${coStyle(projection)}" title="Projected Total (Purchased + ETC) — ${usd(projection)}">${compactUsd(projection)}</div>
        <div class="proc-gauge-co" style="${coStyle(spent)}" title="Part Cost Purchased — ${usd(spent)}">${compactUsd(spent)}</div>
        <div class="proc-gauge-co proc-gauge-co-paid" style="${coStyle(paid)}" title="Part Cost Paid — ${usd(paid)}">${compactUsd(paid)}</div>
      </div>
    </div>
    <div class="proc-gauge-summary">
      <div class="proc-gauge-row"><b>Part Cost Budget:</b> ${usd(budget)}${budgetUnset && budget ? ' <span class="proc-gauge-hint">— set via ✎ Edit</span>' : ''}</div>
      <div class="proc-gauge-row"><b>Part Cost Budget Projection:</b> ${usd(projection)}${projPct != null ? ` <i>(${projPct}%)</i>` : ''}</div>
    </div>
  </div>`;
}

// 3 concentric ring gauges: Estimated (outer) -> Purchased (middle) -> Paid (inner)
function _procCostWaterfall(c) {
  const usd = v => _procUsd(v);
  const estimated = Number(c.estimated) || 0;
  const purchased = Number(c.purchased) || 0;
  const paid      = Number(c.paid)      || 0;

  const purRaw  = estimated ? purchased / estimated : 0;
  const paidRaw = estimated ? paid / estimated : 0;
  const purOver  = purRaw > 1, paidOver = paidRaw > 1;

  // Scale all arcs to the largest value so over-budget shows estimated as a small slice
  const scale = Math.max(estimated, purchased, paid) || 1;

  const rings = [
    { label: 'Estimated', sub: 'Budget',     value: estimated, pct: estimated / scale, over: false,    color: '#1574C4', tipColor: '#60a5fa', track: '#dbeafe', ro: 68, ri: 54 },
    { label: 'Purchased', sub: 'Parts Cost', value: purchased, pct: purchased / scale, over: purOver,  color: '#061D39', tipColor: '#93c4e8', track: '#d0d9e6', ro: 49, ri: 35 },
    { label: 'Paid',      sub: 'Parts Cost', value: paid,      pct: paid / scale,      over: paidOver, color: '#74C415', tipColor: '#a3e635', track: '#e2f5c0', ro: 30, ri: 16 },
  ];

  // large-arc always 0 — semicircle never sweeps > 180°
  function donutPath(pct, ox, oy, ro, ri) {
    const full = `M ${ox-ro} ${oy} A ${ro} ${ro} 0 0 1 ${ox+ro} ${oy} L ${ox+ri} ${oy} A ${ri} ${ri} 0 0 0 ${ox-ri} ${oy} Z`;
    if (pct <= 0) return { track: full, fill: '' };
    if (pct >= 1) return { track: full, fill: full };
    const a = (1 - pct) * Math.PI;
    const cos = Math.cos(a), sin = Math.sin(a);
    const fill = `M ${ox-ro} ${oy} A ${ro} ${ro} 0 0 1 ${(ox+ro*cos).toFixed(1)} ${(oy-ro*sin).toFixed(1)} L ${(ox+ri*cos).toFixed(1)} ${(oy-ri*sin).toFixed(1)} A ${ri} ${ri} 0 0 0 ${ox-ri} ${oy} Z`;
    return { track: full, fill };
  }

  const VW = 180, cy = 72, cx = VW / 2;
  const mainPct = estimated ? Math.round(purRaw * 100) : 0;
  const mainColor = purOver ? '#dc2626' : (mainPct >= 90 ? '#f59e0b' : '#0f172a');

  const usdShort = v => {
    if (!v) return '$0';
    if (v >= 1e6) return '$' + (v / 1e6).toFixed(1).replace(/\.0$/, '') + 'M';
    return '$' + Math.round(v / 1000) + 'K';
  };
  const arcs = rings.map(r => {
    const { track, fill } = donutPath(r.pct, cx, cy, r.ro, r.ri);
    const rawPct   = estimated ? (r.value / estimated) : 0;
    const pctLabel = estimated ? Math.round(rawPct * 100) + '%' : '—';
    const fillColor = r.color;   // never red — arc size already shows the overrun
    const tipColor  = r.tipColor;
    const da = `data-tl="${r.label}" data-ts="${r.sub}" data-tp="${pctLabel}" data-tv="${usd(r.value)}" data-tc="${tipColor}"`;
    return `<path d="${track}" fill="${r.track}" ${da} style="cursor:pointer;"/>` +
           (fill ? `<path d="${fill}" fill="${fillColor}" stroke="white" stroke-width="2.5" ${da} style="cursor:pointer;"/>` : '');
  }).join('');
  // Labels at the left ($0) and right (ring value) tips of each arc
  // Labels end at each ring's right outer tip — natural spread, no overlap
  const tipLabels = rings.map(r => {
    const rx = (cx + r.ro - 2).toFixed(1);
    const ly = cy + 11;
    return `<text x="${rx}" y="${ly}" text-anchor="end" font-family="'Montserrat',sans-serif" font-size="6" font-weight="700" fill="${r.color}">${usdShort(r.value)}</text>`;
  }).join('');

  const legendRows = rings.map((r, i) => {
    const rawPct   = estimated ? (r.value / estimated) : 0;
    const pctLabel = estimated ? Math.round(rawPct * 100) + '%' : '—';
    const pctColor = r.over ? '#dc2626' : '#64748b';
    const barColor = r.over ? '#dc2626' : r.color;
    const overTag  = r.over ? `<span style="font-size:var(--fs-2xs);background:#fee2e2;color:#dc2626;border-radius:3px;padding:1px 4px;font-weight:var(--fw-bold);margin-left:5px;vertical-align:middle;">OVER</span>` : '';
    const border   = i < rings.length - 1 ? 'border-bottom:1px solid #f1f5f9;' : '';
    return `
      <div style="display:flex;align-items:center;gap:6px;padding:2px 0;${border}">
        <div style="width:3px;height:24px;border-radius:2px;background:${barColor};flex-shrink:0;"></div>
        <div style="flex:1;min-width:0;">
          <div style="font-size:var(--fs-sm);font-weight:var(--fw-bold);color:#1e293b;">${r.label}${overTag}</div>
          <div style="font-size:var(--fs-2xs);color:#94a3b8;text-transform:uppercase;letter-spacing:0.4px;margin-top:1px;">${r.sub}</div>
        </div>
        <div style="text-align:right;flex-shrink:0;">
          <div style="font-size:var(--fs-base);font-weight:var(--fw-extrabold);color:#111827;">${usd(r.value)}</div>
          <div style="font-size:var(--fs-xs);font-weight:var(--fw-semibold);color:${pctColor};margin-top:1px;">${pctLabel}</div>
        </div>
      </div>`;
  }).join('');

  return `
    <div style="background:white;border-radius:8px;border:1px solid #e2e8f0;margin-top:5px;overflow:hidden;">
      <div style="padding:5px 8px;border-bottom:1px solid #f1f5f9;display:flex;align-items:center;justify-content:space-between;">
        <div>
          <div style="font-size:var(--fs-md);font-weight:var(--fw-bold);color:#0f172a;letter-spacing:-0.1px;">Cost Overview</div>
          <div style="font-size:var(--fs-xs);color:#94a3b8;margin-top:1px;">${estimated ? usd(estimated) + ' estimated budget' : 'No budget set'}</div>
        </div>
        ${estimated ? `<div style="font-size:var(--fs-base);font-weight:var(--fw-extrabold);color:${mainColor};">${mainPct}%<span style="font-size:var(--fs-2xs);font-weight:var(--fw-medium);color:#94a3b8;margin-left:3px;">purchased</span></div>` : ''}
      </div>
      <div style="padding:5px 8px 2px;position:relative;">
        <div id="cg-tip" style="display:none;position:absolute;pointer-events:none;z-index:100;background:#1e293b;color:#fff;border-radius:7px;padding:9px 13px;font-size:var(--fs-md);white-space:nowrap;box-shadow:0 4px 14px rgba(0,0,0,0.25);">
          <div id="cg-tip-h" style="font-weight:var(--fw-bold);font-size:var(--fs-base);margin-bottom:1px;"></div>
          <div id="cg-tip-s" style="color:#94a3b8;font-size:var(--fs-xs);margin-bottom:5px;"></div>
          <div id="cg-tip-v" style="font-weight:var(--fw-extrabold);font-size:var(--fs-lg);"></div>
          <div id="cg-tip-p" style="font-size:var(--fs-xs);color:#94a3b8;margin-top:1px;"></div>
        </div>
        <svg viewBox="0 0 ${VW} 104" style="width:100%;height:auto;display:block;"
          onmousemove="(function(e){const p=e.target.closest('[data-tl]');const t=document.getElementById('cg-tip');if(!p){t.style.display='none';return;}const b=e.currentTarget.getBoundingClientRect();t.style.left=(e.clientX-b.left+12)+'px';t.style.top=(e.clientY-b.top-75)+'px';t.style.display='block';document.getElementById('cg-tip-h').style.color=p.dataset.tc;document.getElementById('cg-tip-h').textContent=p.dataset.tl;document.getElementById('cg-tip-s').textContent=p.dataset.ts;document.getElementById('cg-tip-v').textContent=p.dataset.tv;document.getElementById('cg-tip-p').textContent=p.dataset.tp+' of estimated budget';})(event)"
          onmouseleave="document.getElementById('cg-tip').style.display='none'">
          ${arcs}${tipLabels}
        </svg>
        <div style="text-align:center;margin-top:0;padding-bottom:3px;border-bottom:1px solid #f1f5f9;">
          <div style="font-size:var(--fs-lg);font-weight:var(--fw-extrabold);color:${mainColor};line-height:1;">${estimated ? mainPct + '%' : '—'}</div>
          <div style="font-size:var(--fs-2xs);color:#94a3b8;text-transform:uppercase;letter-spacing:0.6px;margin-top:1px;">of budget purchased</div>
        </div>
      </div>
      <div style="padding:0 8px 4px;">${legendRows}</div>
    </div>
  `;
}

// Simplified panel for parts without POs
function _procOpenNoPoPanel(vendorName, job) {
  const data = _procCache[job];
  if (!data || !data.partsList) return;

  const noPoParts = data.partsList.filter(p => (p.supplier || 'No Supplier') === vendorName && (!p.poId || p.poId === 'NO_PO'));
  if (!noPoParts.length) return;

  document.getElementById('proc-po-overlay')?.remove();
  const fmt = d => d ? fmtDate(d) : '—';
  const initials = (vendorName || '?').replace(/[^A-Za-z0-9 ]/g, '').split(/\s+/).filter(Boolean).slice(0, 2).map(w => w[0]).join('').toUpperCase() || '?';

  const received = noPoParts.filter(p => _procPartStatus(p).key === 'received').length;
  const total = noPoParts.length;
  const pct = total > 0 ? Math.round((received / total) * 100) : 0;
  const barColor = _procBarColor(pct);

  const rows = noPoParts.map(p => {
    const st = _procPartStatus(p);
    let cls = 'ppo-line-received';
    if (st.key !== 'received') {
      const exp = p.requiredDate ? Date.parse(p.requiredDate + 'T00:00:00') : NaN;
      cls = (!isNaN(exp) && exp < Date.now()) ? 'ppo-line-late' : 'ppo-line-pending';
    }
    return `<div class="ppo-line ${cls}">
      <span class="ppo-line-part"><span class="ppo-line-pn">${escapeHtml(p.pn || '—')}</span><span class="ppo-line-desc" title="${escapeHtml(p.desc || '')}">${escapeHtml(p.desc || '')}</span></span>
      <span class="num">${p.qty ?? ''}</span>
      <span>—</span>
      <span>${fmt(p.requiredDate)}</span>
      <span>${st.label}</span>
      <span class="num">—</span>
    </div>`;
  }).join('');

  const overlay = document.createElement('div');
  overlay.id = 'proc-po-overlay';
  overlay.className = 'proc-po-overlay';
  overlay.innerHTML = `
    <div class="proc-po-backdrop" data-action="ppo-close"></div>
    <aside class="proc-po-panel" role="dialog" aria-label="Parts without PO">
      <div class="ppo-head">
        <span class="proc-vavatar">${escapeHtml(initials)}</span>
        <div class="ppo-head-name"><div class="ppo-vname" title="${escapeHtml(vendorName)}">${escapeHtml(vendorName)}</div><div class="ppo-ponum">Parts without PO</div></div>
        <button class="ppo-close" data-action="ppo-close" type="button" title="Close">✕</button>
      </div>
      <div class="ppo-summary">
        <div class="ppo-stat"><span class="ppo-sk">TOTAL ITEMS</span><span class="ppo-sv">${total}</span></div>
        <div class="ppo-stat ppo-prog"><span class="ppo-sk">${received}/${total} received</span><span class="proc-bar"><span class="proc-bar-fill" style="width:${pct}%;background:${barColor}"></span></span><span class="proc-pct" style="color:${barColor}">${pct}%</span></div>
      </div>
      <div class="ppo-lines">
        <div class="ppo-line ppo-lines-head">
          <span class="ppo-line-part"><span class="ppo-line-pn">Part #</span><span class="ppo-line-desc">Description</span></span>
          <span class="num">Qty</span>
          <span>Ordered</span>
          <span>Due</span>
          <span>Status</span>
          <span class="num">Price</span>
        </div>
        ${rows}
      </div>
    </aside>
  `;

  document.body.appendChild(overlay);

  // Wire close button
  overlay.querySelectorAll('[data-action="ppo-close"]').forEach(btn => {
    btn.addEventListener('click', () => overlay.remove());
  });
  overlay.querySelector('.proc-po-backdrop')?.addEventListener('click', () => overlay.remove());
}

// Open full summary panel for all items in a section (delivery or nopo)
function _procOpenSummaryPanel(job, section, data) {
  if (!data || !data.partsList) return;

  const fmt = d => d ? fmtDate(d) : '—';
  const now = Date.now();
  const weekMs = 7 * 24 * 60 * 60 * 1000;

  let title, parts, icon, headerColor;

  if (section === 'nopo') {
    title = 'Parts Without Purchase Order';
    parts = data.partsList.filter(p => !p.poId || p.poId === 'NO_PO');
    icon = '✕';
    headerColor = '#1574C4';
  } else if (section === 'delivery') {
    title = 'Parts on Delivery';
    parts = data.partsList.filter(p => p.poId && _procPartStatus(p).key !== 'received');
    icon = '⚠';
    headerColor = '#f59e0b';
  } else {
    return;
  }

  if (!parts.length) return;

  const rows = parts.map(p => {
    const st = _procPartStatus(p);
    let cls = 'ppo-line-received';
    if (st.key !== 'received') {
      const exp = p.requiredDate ? Date.parse(p.requiredDate + 'T00:00:00') : NaN;
      cls = (!isNaN(exp) && exp < now) ? 'ppo-line-late' : 'ppo-line-pending';
    }
    return `<div class="ppo-line ${cls}">
      <span class="ppo-line-part"><span class="ppo-line-pn">${escapeHtml(p.pn || '—')}</span><span class="ppo-line-desc" title="${escapeHtml(p.desc || '')}">${escapeHtml(p.desc || '')}</span></span>
      <span class="num">${p.qty ?? ''}</span>
      <span>${escapeHtml(p.supplier || '—')}</span>
      <span>${fmt(p.requiredDate)}</span>
      <span>${st.label}</span>
      <span class="num">—</span>
    </div>`;
  }).join('');

  document.getElementById('proc-po-overlay')?.remove();
  const overlay = document.createElement('div');
  overlay.id = 'proc-po-overlay';
  overlay.className = 'proc-po-overlay';
  overlay.innerHTML = `
    <div class="proc-po-backdrop" data-action="ppo-close"></div>
    <aside class="proc-po-panel" role="dialog" aria-label="${title}">
      <div class="ppo-head">
        <div style="font-size: var(--fs-2xl); margin-right: 8px;">${icon}</div>
        <div class="ppo-head-name"><div class="ppo-vname">${title}</div><div class="ppo-ponum">${parts.length} items</div></div>
        <button class="ppo-close" data-action="ppo-close" type="button" title="Close">✕</button>
      </div>
      <div class="ppo-lines">
        <div class="ppo-line ppo-lines-head">
          <span class="ppo-line-part"><span class="ppo-line-pn">Part #</span><span class="ppo-line-desc">Description</span></span>
          <span class="num">Qty</span>
          <span>Supplier</span>
          <span>Due</span>
          <span>Status</span>
          <span class="num">Price</span>
        </div>
        ${rows}
      </div>
    </aside>
  `;

  document.body.appendChild(overlay);

  // Wire close button
  overlay.querySelectorAll('[data-action="ppo-close"]').forEach(btn => {
    btn.addEventListener('click', () => overlay.remove());
  });
  overlay.querySelector('.proc-po-backdrop')?.addEventListener('click', () => overlay.remove());
}

// Right-side slide-out panel for one PO (Build Readiness style): header +
// ordered/due/value summary + line-items table. Data comes from the cached
// vendor status — no extra fetch. Triggered from the full page or the drawer.
function _procOpenPoPanel(job, vname, poId) {
  const vd = _procVendorCache[job];
  const vendor = vd && vd.vendors && vd.vendors.find(v => v.name === vname);
  const po = vendor && vendor.pos.find(p => String(p.po) === String(poId));
  if (!po) return;
  document.getElementById('proc-po-overlay')?.remove();
  const fmt = d => d ? fmtDate(d) : '—';
  const initials = (vname || '?').replace(/[^A-Za-z0-9 ]/g, '').split(/\s+/).filter(Boolean).slice(0, 2).map(w => w[0]).join('').toUpperCase() || '?';
  const badge = { received: ['RECEIVED', 'vstat-ok'], late: ['PAST DUE', 'vstat-bad'], open: ['LATE / EXP', 'vstat-warn'] }[po.status] || ['', ''];
  const barColor = _procBarColor(po.pct);
  const ordered = po.lines.map(l => l.ordered).filter(Boolean).sort()[0];
  const due = po.lines.map(l => l.expected).filter(Boolean).sort().slice(-1)[0];

  // Calculate parts-based metrics (for assembly readiness) from the parts list
  const data = _procCache[job];
  const poBOM = data && data.partsList ? data.partsList.filter(p => String(p.poId) === String(poId)) : [];
  const bomReceived = poBOM.filter(p => _procPartStatus(p).key === 'received').length;
  const bomTotal = poBOM.length;
  const bomPct = bomTotal > 0 ? Math.round((bomReceived / bomTotal) * 100) : 0;
  const bomBarColor = _procBarColor(bomPct);
  const rows = po.lines.map(l => {
    // Row tint by status, matching the card-dot legend: received → green,
    // overdue → red, on order (not yet due) → yellow.
    let cls = 'ppo-line-received';
    if (l.status !== 'received') {
      const exp = l.expected ? Date.parse(l.expected + 'T00:00:00') : NaN;
      cls = (!isNaN(exp) && exp < Date.now()) ? 'ppo-line-late' : 'ppo-line-pending';
    }
    const rcvd = l.status === 'received'
      ? `<span class="ppo-rcvd-ok">✓ ${fmt(l.receivedDate)}</span>`
      : `<span class="ppo-rcvd-exp">Exp ${fmt(l.expected)}</span>`;
    return `<div class="ppo-line ${cls}">
      <span class="ppo-line-part"><span class="ppo-line-pn">${escapeHtml(l.partNumber || '—')}</span><span class="ppo-line-desc" title="${escapeHtml(l.desc || '')}">${escapeHtml(l.desc || '')}</span></span>
      <span class="num">${l.qty ?? ''}</span>
      <span>${fmt(l.ordered)}</span>
      <span>${fmt(l.expected)}</span>
      <span>${rcvd}</span>
      <span class="num">${l.price != null ? '$' + Number(l.price).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '—'}</span>
    </div>`;
  }).join('');
  const overlay = document.createElement('div');
  overlay.id = 'proc-po-overlay';
  overlay.className = 'proc-po-overlay';
  overlay.innerHTML = `
    <div class="proc-po-backdrop" data-action="ppo-close"></div>
    <aside class="proc-po-panel" role="dialog" aria-label="PO detail">
      <div class="ppo-head">
        <span class="proc-vavatar">${escapeHtml(initials)}</span>
        <div class="ppo-head-name"><div class="ppo-vname" title="${escapeHtml(vname)}">${escapeHtml(vname)}</div><div class="ppo-ponum">PO #${escapeHtml(String(poId))}</div></div>
        <span class="proc-vbadge ${badge[1]}">${badge[0]}</span>
        <button class="ppo-close" data-action="ppo-close" type="button" title="Close">✕</button>
      </div>
      <div class="ppo-summary">
        <div class="ppo-stat"><span class="ppo-sk">ORDERED</span><span class="ppo-sv">${fmt(ordered)}</span></div>
        <div class="ppo-stat"><span class="ppo-sk">DUE</span><span class="ppo-sv">${fmt(due)}</span></div>
        <div class="ppo-stat"><span class="ppo-sk">PO VALUE</span><span class="ppo-sv">$${Math.round(po.price).toLocaleString()}</span></div>
        <div style="font-size: var(--fs-xs); color: #64748b; padding: 8px 0; border-top: 1px solid #e2e8f0; margin-top: 8px;">
          <div style="margin-bottom: 4px;">PO Lines (Supplier Status)</div>
        </div>
        <div class="ppo-stat ppo-prog"><span class="ppo-sk">${po.received}/${po.itemCount} received</span><span class="proc-bar"><span class="proc-bar-fill" style="width:${po.pct}%;background:${barColor}"></span></span><span class="proc-pct" style="color:${barColor}">${po.pct}%</span></div>
        ${bomTotal > 0 ? `<div style="font-size: var(--fs-xs); color: #64748b; padding: 8px 0; border-top: 1px solid #e2e8f0; margin-top: 8px;">
          <div style="margin-bottom: 4px;">Parts (Assembly Readiness)</div>
        </div>
        <div class="ppo-stat ppo-prog"><span class="ppo-sk">${bomReceived}/${bomTotal} parts</span><span class="proc-bar"><span class="proc-bar-fill" style="width:${bomPct}%;background:${bomBarColor}"></span></span><span class="proc-pct" style="color:${bomBarColor}">${bomPct}%</span></div>` : ''}
      </div>
      <div class="ppo-lines">
        <div class="ppo-line ppo-line-head"><span>PART</span><span class="num">QTY</span><span>ORDERED</span><span>EXPECTED</span><span>RECEIVED</span><span class="num">PRICE</span></div>
        ${rows}
      </div>
    </aside>`;
  document.body.appendChild(overlay);
  const close = () => { overlay.remove(); document.removeEventListener('keydown', onKey); };
  overlay.querySelectorAll('[data-action="ppo-close"]').forEach(b => b.addEventListener('click', close));
  const onKey = (e) => { if (e.key === 'Escape') { e.preventDefault(); close(); } };
  document.addEventListener('keydown', onKey);
  // Force a reflow so the transform transition plays, then flip to the open
  // state synchronously (rAF can no-op if the tab isn't actively painting).
  void overlay.offsetWidth;
  overlay.classList.add('is-open');
}


// Compact money — $843K / $12.4K / $730. Assembly rows are tight on space.
// Exact whole-dollar amount with thousands separators — $5,200, $90,000, $228.
// No K/M abbreviation, no decimals.
function _procUsd(v) {
  const n = Number(v) || 0;
  if (n <= 0) return '—';
  return '$' + Math.round(n).toLocaleString();
}

// ── Flat Parts List tab ──────────────────────────────────────────────────────
// Every leaf-part occurrence across all assemblies, one row each, with PO +
// delivery status. Complements the Assemblies (BOM tree) and Vendors (by-supplier)
// views — this is the part-centric cut.
function _procPartStatus(p) {
  if (p.inStock) return { key: 'received', label: 'IN STOCK', cls: 'ok', sub: 'from inventory' };
  if (p.status === 'received') return { key: 'received', label: 'RECEIVED', cls: 'ok', sub: '' };
  if (p.hold) return { key: 'hold', label: 'ON HOLD', cls: 'hold', sub: 'in ETO' };
  if (p.status === 'noPO') return { key: 'noPO', label: 'NO PO', cls: 'bad', sub: '' };
  const due = p.expDate || p.requiredDate;
  if (due) {
    const diff = Math.ceil((Date.parse(due + 'T00:00:00') - Date.now()) / 86400000);
    if (isNaN(diff)) return { key: 'ordered', label: 'ON ORDER', cls: 'info', sub: '' };
    if (diff < 0) return { key: 'overdue', label: 'OVERDUE', cls: 'bad', sub: `${Math.abs(diff)}d late` };
    if (diff <= 14) return { key: 'soon', label: 'DUE SOON', cls: 'warn', sub: `in ${diff}d` };
    return { key: 'ordered', label: 'ON ORDER', cls: 'info', sub: `in ${diff}d` };
  }
  return { key: 'ordered', label: 'ON ORDER', cls: 'info', sub: '' };
}

// Display fallbacks used for both rendering and the filter dropdowns, so the
// option values line up exactly with what shows in the rows.
function _procMfr(p) { return p.manufacturer || 'SDC'; }

// Parts List filter bar — Status, Category, Manufacturer, Supplier, Purchase
// date range. Options come straight from the loaded BOM so they always match
// what's in the rows. Shared by the full page and the schedule drawer so both
// filter identically (state lives on _procState). Mirrors the ETO report.
function _procPartsFilterBar(data) {
  if (!data || !Array.isArray(data.partsList)) return '';
  const pstatusOpts = [['all', 'Status: all'], ['received', 'Received'], ['ordered', 'On order'], ['soon', 'Due soon'], ['overdue', 'Overdue'], ['noPO', 'No PO'], ['hold', 'On hold']];
  const uniqSorted = (arr) => [...new Set(arr.filter(Boolean))].sort((a, b) => String(a).localeCompare(String(b)));
  const cats = uniqSorted(data.partsList.map(p => p.category));
  const mfrs = uniqSorted(data.partsList.map(p => _procMfr(p)));
  const sups = uniqSorted(data.partsList.map(p => p.supplier));
  const opt = (cur, v, label) => `<option value="${escapeHtml(String(v))}" ${cur === v ? 'selected' : ''}>${escapeHtml(String(label))}</option>`;
  const drop = (id, title, cur, values) => `<label class="proc-filt"><span class="proc-filt-lbl">${title}</span>
    <select id="${id}" class="proc-job-pick">${opt(cur, 'all', 'All')}${values.map(v => opt(cur, v, v)).join('')}</select></label>`;
  const mode = _procState.pdatemode === 'invoiced' ? 'invoiced' : 'purchase';
  const dateLabel = mode === 'invoiced' ? 'Invoiced' : 'Purchased';
  const seg = (val, label) => `<button class="seg-btn${mode === val ? ' is-active' : ''}" data-pdatemode="${val}" type="button">${label}</button>`;
  const active = _procState.pstatus !== 'all' || _procState.pcat !== 'all' || _procState.pmfr !== 'all' || _procState.psup !== 'all' || _procState.pfrom || _procState.pto || mode !== 'purchase';
  const hidden = new Set(_procState.hiddenPartCols || []);
  const colPopover = `<div class="proc-col-pop-wrap" style="position:relative;display:inline-block;">
    <button class="proc-view-btn${hidden.size ? ' is-active' : ''}" id="proc-col-btn" type="button" title="Show / hide columns">⊞ Columns${hidden.size ? ` <span style="font-size:10px;background:#1574c4;color:#fff;border-radius:8px;padding:0 5px;margin-left:3px;">${hidden.size}</span>` : ''}</button>
    <div class="proc-col-pop" id="proc-col-pop" style="display:none;">
      ${PROC_PART_COLS.map(c => `<label class="proc-col-check"><input type="checkbox" data-col-key="${c.key}"${!hidden.has(c.key) ? ' checked' : ''}> ${c.label}</label>`).join('')}
      <div style="border-top:1px solid #e2e8f0;margin-top:6px;padding-top:6px;display:flex;gap:6px;">
        <button class="btn-ghost btn-tight" data-col-all="show" type="button">Show all</button>
        <button class="btn-ghost btn-tight" data-col-all="reset" type="button">Reset</button>
      </div>
    </div>
  </div>`;
  return `<div class="proc-parts-filters">
    <div class="proc-view-seg">
      <button class="proc-view-btn${_procState.partsListMode === 'table' ? ' is-active' : ''}" data-list-mode="table" type="button">≡ List</button>
      <button class="proc-view-btn${_procState.partsListMode === 'card' ? ' is-active' : ''}" data-list-mode="card" type="button">⊟ Card</button>
    </div>
    ${_procState.partsListMode === 'table' ? colPopover : ''}
    <div class="proc-filt-divider"></div>
    <label class="proc-filt"><span class="proc-filt-lbl">Status</span>
      <select id="proc-pstatus" class="proc-job-pick">${pstatusOpts.map(([v, t]) => `<option value="${v}" ${_procState.pstatus === v ? 'selected' : ''}>${v === 'all' ? 'All' : t}</option>`).join('')}</select></label>
    ${drop('proc-pcat', 'Category', _procState.pcat, cats)}
    ${drop('proc-pmfr', 'Manufacturer', _procState.pmfr, mfrs)}
    ${drop('proc-psup', 'Supplier', _procState.psup, sups)}
    <label class="proc-filt"><span class="proc-filt-lbl">Date type</span>
      <div class="seg-control proc-datemode">${seg('purchase', 'Purchase')}${seg('invoiced', 'Invoiced')}</div></label>
    <label class="proc-filt"><span class="proc-filt-lbl">${dateLabel} from</span><input type="date" id="proc-pfrom" class="proc-date" value="${escapeHtml(_procState.pfrom || '')}"></label>
    <label class="proc-filt"><span class="proc-filt-lbl">to</span><input type="date" id="proc-pto" class="proc-date" value="${escapeHtml(_procState.pto || '')}"></label>
    ${active ? `<button class="btn-ghost btn-tight" id="proc-pclear" type="button">Clear</button>` : ''}
  </div>`;
}

// Wire the parts filter controls inside `root`, re-rendering via `rerender`.
function _wirePartsFilters(root, rerender) {
  const bind = (id, key) => { const el = root.querySelector(id); if (el) el.addEventListener('change', () => { _procState[key] = el.value; _procSave(); rerender(); }); };
  bind('#proc-pstatus', 'pstatus');
  bind('#proc-pcat', 'pcat');
  bind('#proc-pmfr', 'pmfr');
  bind('#proc-psup', 'psup');
  bind('#proc-pfrom', 'pfrom');
  bind('#proc-pto', 'pto');
  // Date Selector — apply the date range to Purchase date or Invoiced date.
  root.querySelectorAll('[data-pdatemode]').forEach(b => b.addEventListener('click', () => {
    _procState.pdatemode = b.dataset.pdatemode; _procSave(); rerender();
  }));
  // Parts List view mode toggle (List vs Card)
  root.querySelectorAll('[data-list-mode]').forEach(b => b.addEventListener('click', () => {
    _procState.partsListMode = b.dataset.listMode; _procSave(); rerender();
  }));

  // Columns popover — toggle visibility
  const colBtn = root.querySelector('#proc-col-btn');
  const colPop = root.querySelector('#proc-col-pop');
  if (colBtn && colPop) {
    colBtn.addEventListener('click', e => { e.stopPropagation(); colPop.style.display = colPop.style.display === 'none' ? 'block' : 'none'; });
    colPop.addEventListener('click', e => e.stopPropagation());
    document.addEventListener('click', () => { if (colPop) colPop.style.display = 'none'; }, { once: true, capture: false });
    colPop.querySelectorAll('[data-col-key]').forEach(cb => {
      cb.addEventListener('change', () => {
        const hidden = new Set(_procState.hiddenPartCols || []);
        cb.checked ? hidden.delete(cb.dataset.colKey) : hidden.add(cb.dataset.colKey);
        _procState.hiddenPartCols = [...hidden]; _procSave(); rerender();
      });
    });
    colPop.querySelector('[data-col-all="show"]')?.addEventListener('click', () => { _procState.hiddenPartCols = []; _procSave(); rerender(); });
    colPop.querySelector('[data-col-all="reset"]')?.addEventListener('click', () => { _procState.hiddenPartCols = []; _procSave(); rerender(); });
  }

  const pclear = root.querySelector('#proc-pclear');
  if (pclear) pclear.addEventListener('click', () => { Object.assign(_procState, { pstatus: 'all', pcat: 'all', pmfr: 'all', psup: 'all', pdatemode: 'purchase', pfrom: '', pto: '' }); _procSave(); rerender(); });
}

function _procFilteredParts(data) {
  const q = (_procState.search || '').toLowerCase();
  const want = _procState.pstatus;
  const cat = _procState.pcat, mfr = _procState.pmfr, sup = _procState.psup;
  const from = _procState.pfrom || '', to = _procState.pto || '';
  return (data.partsList || []).filter(p => {
    const st = _procPartStatus(p);
    if (want !== 'all' && st.key !== want) return false;
    if (cat !== 'all' && (p.category || '') !== cat) return false;
    if (mfr !== 'all' && _procMfr(p) !== mfr) return false;
    if (sup !== 'all' && (p.supplier || '') !== sup) return false;
    const dcol = _procState.pdatemode === 'invoiced' ? p.invoicedDate : p.orderDate;
    if (from && (!dcol || dcol < from)) return false;
    if (to && (!dcol || dcol > to)) return false;
    if (q && ![p.pn, p.desc, p.category, p.manufacturer, p.supplier, p.parentPN, p.parentDesc, p.poId].some(v => String(v || '').toLowerCase().includes(q))) return false;
    return true;
  });
}

function _procPartsCardView(rows) {
  const fmt = d => d ? fmtDate(d) : '—';
  const vendors = {};
  const backendVendors = _procVendorCache[_procState.job]?.vendors || [];
  const hasBackendData = backendVendors.length > 0;

  // Group parts by vendor, then by PO within each vendor
  rows.forEach(p => {
    const vendor = p.supplier || 'No Supplier';
    if (!vendors[vendor]) vendors[vendor] = { name: vendor, pos: {}, total: 0, received: 0 };

    const poId = p.poId || 'NO_PO';
    if (!vendors[vendor].pos[poId]) {
      vendors[vendor].pos[poId] = { poId: p.poId, parts: [], received: 0, total: 0, orderDate: null, expDate: null };
    }

    vendors[vendor].pos[poId].parts.push(p);
    vendors[vendor].pos[poId].total++;
    vendors[vendor].total++;
    if (!vendors[vendor].pos[poId].orderDate && p.orderDate) vendors[vendor].pos[poId].orderDate = p.orderDate;
    if (!vendors[vendor].pos[poId].expDate && (p.expDate || p.requiredDate)) vendors[vendor].pos[poId].expDate = p.expDate || p.requiredDate;

    if (_procPartStatus(p).key === 'received') {
      vendors[vendor].pos[poId].received++;
      vendors[vendor].received++;
    }
  });

  // Update PO-level data from backend for accuracy (backend is authoritative for line status)
  // Note: vendor-level totals stay parts-based, not line-based, to match what's displayed
  if (hasBackendData) {
    backendVendors.forEach(backendVendor => {
      const vendorName = backendVendor.name;
      if (vendors[vendorName]) {
        for (const poKey in vendors[vendorName].pos) {
          if (poKey === 'NO_PO') continue;
          const cardPo = vendors[vendorName].pos[poKey];
          // Find matching backend PO by comparing numeric values to handle string/number mismatch
          const backendPo = backendVendor.pos.find(bp => {
            const bpNum = parseInt(bp.po) || 0;
            const cpNum = parseInt(poKey) || 0;
            return bpNum > 0 && bpNum === cpNum;
          });
          if (backendPo) {
            cardPo.received = backendPo.received;
            cardPo.total = backendPo.itemCount;
          }
        }
      }
    });
  }

  const vendorCards = Object.entries(vendors).map(([vendor, vendorGroup]) => {
    const vendorPct = vendorGroup.total > 0 ? Math.round((vendorGroup.received / vendorGroup.total) * 100) : 0;
    const vendorBarColor = vendorPct >= 90 ? '#74c415' : vendorPct >= 60 ? '#befa4f' : '#1574c4';
    const initials = (vendor || '?').replace(/[^A-Za-z0-9 ]/g, '').split(/\s+/).filter(Boolean).slice(0, 2).map(w => w[0]).join('').toUpperCase() || '?';

    // Count non-NO_PO entries
    const poCount = Object.keys(vendorGroup.pos).filter(k => k !== 'NO_PO').length;

    // Check if any POs have overdue dates (expected date in past)
    const now = Date.now();
    const hasOverdue = Object.values(vendorGroup.pos).some(po => {
      if (po.received >= po.total) return false; // fully received, not overdue
      return po.expDate && new Date(po.expDate + 'T00:00:00').getTime() < now;
    });

    let statusBadge, statusLabel;
    if (hasOverdue) {
      statusBadge = 'bad';
      statusLabel = 'PAST DUE';
    } else if (vendorPct >= 90) {
      statusBadge = 'ok';
      statusLabel = 'RECEIVED';
    } else if (vendorPct >= 60) {
      statusBadge = 'warn';
      statusLabel = 'PARTIAL';
    } else {
      statusBadge = 'bad';
      statusLabel = 'PENDING';
    }

    // Build PO rows with sort key, then sort by completion status (incomplete first)
    const poRowsWithSort = Object.entries(vendorGroup.pos).map(([poKey, poGroup]) => {
      const poPct = poGroup.total > 0 ? Math.round((poGroup.received / poGroup.total) * 100) : 0;
      const poLabel = poGroup.poId ? String(poGroup.poId) : '—';
      const rcvdText = `${poGroup.received}/${poGroup.total} rcvd`;
      const dateText = poGroup.expDate ? fmt(poGroup.expDate) : '—';
      const dotColor = poPct >= 100 ? 'received' : poPct >= 60 ? 'ordered' : 'noPO';

      const isNoPo = poKey === 'NO_PO';
      return {
        html: `<div class="proc-vpo${isNoPo ? ' clickable' : ''}" data-vpo="${escapeHtml(vendor)}|${escapeHtml(poLabel)}" data-vpo-id="${poGroup.poId || ''}" ${isNoPo ? `data-nopo-vendor="${escapeHtml(vendor)}"` : ''} title="${isNoPo ? 'View parts without PO' : 'Open PO detail'}">
        <button class="proc-pn proc-pn-sm" data-copy="${escapeHtml(poLabel)}" type="button" title="${isNoPo ? 'Parts without PO number' : 'Click to copy PO number'}">${escapeHtml(poLabel)}</button>
        <span class="proc-vpo-rcvd">${rcvdText}</span>
        <span class="proc-vpo-date" title="Expected delivery">${dateText}</span>
        <span class="proc-dot proc-dot-${dotColor}" title="${poPct >= 100 ? 'All received' : poPct >= 60 ? 'On order' : 'No PO'}"></span>
        <span class="proc-vpo-go" aria-hidden="true">›</span>
      </div>`,
        sortKey: dotColor === 'received' ? 1 : 0  // 0 for incomplete (top), 1 for received (bottom)
      };
    });
    // Sort: incomplete POs (sortKey 0) first, then received POs (sortKey 1)
    const poRows = poRowsWithSort.sort((a, b) => a.sortKey - b.sortKey).map(r => r.html).join('');

    return `<div class="proc-pcard">
      <div class="proc-pcard-head">
        <span class="proc-pavatar">${escapeHtml(initials)}</span>
        <span class="proc-pname" title="${escapeHtml(vendor)}">${escapeHtml(vendor)}</span>
        <span class="proc-vbadge ${statusBadge === 'ok' ? 'vstat-ok' : statusBadge === 'warn' ? 'vstat-warn' : 'vstat-bad'}">${statusLabel}</span>
      </div>
      <div class="proc-vmeta">${poCount} PO${poCount === 1 ? '' : 's'} · ${vendorGroup.total} item${vendorGroup.total === 1 ? '' : 's'}</div>
      <div class="proc-pbar-row"><span class="proc-bar"><span class="proc-bar-fill" style="width:${Math.min(100, vendorPct)}%;background:${vendorBarColor}"></span></span><span class="proc-pct" style="color:${vendorBarColor}">${vendorPct}%</span></div>
      <div class="proc-vpos">
        <div class="proc-vpo proc-vpo-head">
          <span class="proc-vpo-hpn" title="Purchase order number">PO #</span>
          <span class="proc-vpo-rcvd" title="Items received / total on this PO">Received</span>
          <span class="proc-vpo-date" title="Expected delivery date">Date</span>
          <span class="proc-dot" style="visibility:hidden"></span>
          <span class="proc-vpo-go" style="visibility:hidden" aria-hidden="true">›</span>
        </div>
        ${poRows}
      </div>
    </div>`;
  }).join('');

  return `<div class="proc-pcards">${vendorCards}</div>`;
}

// Build Readiness-style summary cards for Parts List - EXACT LOGIC MATCH
function _procPartsSummary(data) {
  if (!data || !data.partsList) return '';

  const parts = data.partsList || [];
  const fmt = d => d ? fmtDate(d) : '—';
  const now = new Date();
  now.setHours(0, 0, 0, 0);
  const todayMs = now.getTime();
  const weekMs = 7 * 24 * 60 * 60 * 1000;

  // ── DELIVERY SLIP (Build Readiness logic) ──
  // Parts due within today ±7 days: past-due this week AND arriving this week
  const slipWindowStart = new Date(now);
  slipWindowStart.setDate(slipWindowStart.getDate() - 7);
  const slipWindowEnd = new Date(now);
  slipWindowEnd.setDate(slipWindowEnd.getDate() + 8); // +7 days, inclusive

  const deliveryParts = parts.filter(p => {
    if (!p.poId || _procPartStatus(p).key === 'received') return false;
    const dueDate = p.expDate || p.requiredDate;
    if (!dueDate) return false;
    const dueDateMs = Date.parse(dueDate + 'T00:00:00');
    if (!isFinite(dueDateMs)) return false;
    // Within 7-day window (7 days ago to end of today)
    return dueDateMs >= slipWindowStart.getTime() && dueDateMs < slipWindowEnd.getTime();
  });

  const deliveryCount = deliveryParts.length;
  const deliveryOldest = deliveryParts.length ? Math.min(...deliveryParts.map(p => {
    const reqDate = p.requiredDate ? Date.parse(p.requiredDate + 'T00:00:00') : Infinity;
    return isFinite(reqDate) ? reqDate : Infinity;
  })) : null;
  // Avg late: only count parts that are actually overdue
  const lateParts = deliveryParts.filter(p => {
    const dueDate = p.expDate || p.requiredDate;
    const dueDateMs = Date.parse(dueDate + 'T00:00:00');
    return isFinite(dueDateMs) && dueDateMs < todayMs;
  });
  const deliveryAvgLate = lateParts.length > 0
    ? Math.round(lateParts.reduce((sum, p) => {
        const dueDate = p.expDate || p.requiredDate;
        const dueDateMs = Date.parse(dueDate + 'T00:00:00');
        return sum + Math.ceil((todayMs - dueDateMs) / weekMs);
      }, 0) / lateParts.length)
    : 0;

  // ── NO PURCHASE ORDER (Build Readiness logic) ──
  // Filter out: parts on hold, parts with any PO, fully received parts
  // Deduplicate by part number
  const noPoParts = (() => {
    const seen = new Set();
    return parts.filter(p => {
      // Skip if has PO
      if (p.poId && p.poId !== 'NO_PO') return false;
      // Skip if fully received
      if (_procPartStatus(p).key === 'received') return false;
      // Skip if on hold
      if (p.hold || p.onHold || p.status === 'hold') return false;
      // Deduplicate by part number
      if (seen.has(p.pn)) return false;
      seen.add(p.pn);
      return true;
    });
  })();

  const noPOCount = noPoParts.length;
  const noPOOldest = noPoParts.length ? Math.min(...noPoParts.map(p => {
    const reqDate = p.requiredDate ? Date.parse(p.requiredDate + 'T00:00:00') : Infinity;
    return isFinite(reqDate) ? reqDate : Infinity;
  })) : null;
  // This week: parts due within next 7 days
  const weekEnd = new Date(now);
  weekEnd.setDate(weekEnd.getDate() + 7);
  const noPOThisWeek = noPoParts.filter(p => {
    const reqDate = p.requiredDate ? Date.parse(p.requiredDate + 'T00:00:00') : NaN;
    return isFinite(reqDate) && reqDate <= weekEnd.getTime();
  }).length;

  // ── UPCOMING DELIVERIES (Build Readiness logic) ──
  // Parts due tomorrow through next 8 weeks (or more based on config)
  const upcomingWindowStart = new Date(now);
  upcomingWindowStart.setDate(upcomingWindowStart.getDate() + 1);
  const upcomingWindowEnd = new Date(now);
  upcomingWindowEnd.setDate(upcomingWindowEnd.getDate() + 57);  // ~8 weeks

  const upcoming = parts.filter(p => {
    if (_procPartStatus(p).key === 'received') return false;
    const dueDate = p.expDate || p.requiredDate;
    if (!dueDate) return false;
    const dueDateMs = Date.parse(dueDate + 'T00:00:00');
    if (!isFinite(dueDateMs)) return false;
    return dueDateMs >= upcomingWindowStart.getTime() && dueDateMs < upcomingWindowEnd.getTime();
  }).sort((a, b) => {
    const aDate = a.expDate || a.requiredDate;
    const bDate = b.expDate || b.requiredDate;
    return (aDate || '').localeCompare(bDate || '');
  });

  const deliveryHtml = deliveryParts.length ? `
    <div class="proc-stbl">
      <div class="proc-stbl-hrow proc-stbl-grid-slip">
        ${['Part #','Description','Supplier','Req','Exp','Ordered'].map(t => `<div class="proc-stbl-hcell">${t}</div>`).join('')}
      </div>
      ${deliveryParts.map(p => {
        const expMs = p.expDate ? Date.parse(p.expDate + 'T00:00:00') : NaN;
        const expOverdue = isFinite(expMs) && expMs <= todayMs;
        return `<div class="proc-stbl-drow proc-stbl-grid-slip">
          <div class="proc-stbl-cell"><span class="proc-stbl-pn" data-slip-pn="${escapeHtml(p.pn)}" title="Click to jump to part">${escapeHtml(p.pn)}</span></div>
          <div class="proc-stbl-cell"><span class="proc-stbl-desc" title="${escapeHtml(p.desc||'')}">${escapeHtml(p.desc||'—')}</span></div>
          <div class="proc-stbl-cell"><span class="proc-stbl-sup" title="${escapeHtml(p.supplier||'')}">${escapeHtml(p.supplier||'—')}</span></div>
          <div class="proc-stbl-cell"><span class="proc-stbl-date">${fmt(p.requiredDate)}</span></div>
          <div class="proc-stbl-cell"><span class="proc-stbl-date${expOverdue ? ' proc-stbl-date-late' : ''}">${fmt(p.expDate)}</span></div>
          <div class="proc-stbl-cell"><span class="proc-stbl-date">${fmt(p.orderDate)}</span></div>
        </div>`;
      }).join('')}
    </div>
  ` : '<div class="proc-stbl-empty">No delivery items this week</div>';

  const noPOHtml = noPoParts.length ? `
    <div class="proc-stbl">
      <div class="proc-stbl-hrow proc-stbl-grid-nopo">
        ${['Part #','Description','Req Date'].map(t => `<div class="proc-stbl-hcell">${t}</div>`).join('')}
      </div>
      ${noPoParts.map(p => `<div class="proc-stbl-drow proc-stbl-grid-nopo">
        <div class="proc-stbl-cell"><span class="proc-stbl-pn" data-slip-pn="${escapeHtml(p.pn)}" title="Click to jump to part">${escapeHtml(p.pn)}</span></div>
        <div class="proc-stbl-cell"><span class="proc-stbl-desc" title="${escapeHtml(p.desc||'')}">${escapeHtml(p.desc||'—')}</span></div>
        <div class="proc-stbl-cell"><span class="proc-stbl-date">${fmt(p.requiredDate)}</span></div>
      </div>`).join('')}
    </div>
  ` : '<div class="proc-stbl-empty">No parts without PO</div>';

  const upcomingHtml = upcoming.length ? (() => {
    const allWeekData = Array.from({length: 8}, (_, i) => {
      const weekNum = i + 1;
      const wStart = new Date(now); wStart.setDate(wStart.getDate() + (weekNum - 1) * 7 + 1);
      const wEnd   = new Date(now); wEnd.setDate(wEnd.getDate() + weekNum * 7 + 1);
      const wParts = upcoming.filter(p => {
        const ms = Date.parse((p.expDate || p.requiredDate) + 'T00:00:00');
        return isFinite(ms) && ms >= wStart.getTime() && ms < wEnd.getTime();
      });
      return { weekNum, parts: wParts, count: wParts.length };
    });
    const firstWeekWithData = allWeekData.find(w => w.count > 0);
    const selectedWeek = _procState.upcomingWeek || (firstWeekWithData ? firstWeekWithData.weekNum : 1);
    const selectedParts = (allWeekData.find(w => w.weekNum === selectedWeek) || {}).parts || [];
    const suppliers = new Set(selectedParts.map(p => p.supplier).filter(Boolean));
    const nearest = selectedParts.length > 0 ? Math.min(...selectedParts.map(p => Date.parse((p.expDate || p.requiredDate) + 'T00:00:00'))) : null;
    return `
      <div class="proc-week-tabs">
        ${allWeekData.map(w => `<button class="proc-week-btn${w.weekNum === selectedWeek ? ' is-active' : ''}${w.count > 0 ? ' has-parts' : ''}" data-week="${w.weekNum}">${w.weekNum}W${w.count > 0 ? ` <span class="proc-week-btn-count">(${w.count})</span>` : ''}</button>`).join('')}
      </div>
      <div class="proc-week-stats">
        ${[['Parts', selectedParts.length], ['Suppliers', suppliers.size], ['Nearest Exp', nearest ? fmt(new Date(nearest).toISOString().slice(0,10)) : '—']].map(([label, val]) => `<div><div class="proc-week-stat-num">${val}</div><div class="proc-week-stat-lbl">${label}</div></div>`).join('')}
      </div>
      <div class="proc-stbl-upcoming">
        <div class="proc-stbl-hrow proc-stbl-grid-upcoming">
          ${['PO #','Part #','Description','Supplier','Exp Date','Req Date','Ordered'].map(t => `<div class="proc-stbl-hcell">${t}</div>`).join('')}
        </div>
        ${selectedParts.length === 0
          ? `<div class="proc-stbl-empty" style="text-align:center;padding:20px;">No parts with exp date in week ${selectedWeek}</div>`
          : selectedParts.map(p => `<div class="proc-stbl-drow proc-stbl-grid-upcoming">
              <div class="proc-stbl-cell"><span class="proc-stbl-date">${escapeHtml(p.poId||'—')}</span></div>
              <div class="proc-stbl-cell"><span class="proc-stbl-pn" data-slip-pn="${escapeHtml(p.pn)}" title="Click to jump to part">${escapeHtml(p.pn)}</span></div>
              <div class="proc-stbl-cell"><span class="proc-stbl-desc" title="${escapeHtml(p.desc||'')}">${escapeHtml(p.desc||'—')}</span></div>
              <div class="proc-stbl-cell"><span class="proc-stbl-sup" title="${escapeHtml(p.supplier||'')}">${escapeHtml(p.supplier||'—')}</span></div>
              <div class="proc-stbl-cell"><span class="proc-stbl-date">${fmt(p.expDate)}</span></div>
              <div class="proc-stbl-cell"><span class="proc-stbl-date">${fmt(p.requiredDate)}</span></div>
              <div class="proc-stbl-cell"><span class="proc-stbl-date">${fmt(p.orderDate)}</span></div>
            </div>`).join('')}
      </div>
    `;
  })() : '';

  const statBlock = (num, cls, label) => `
    <div>
      <div class="proc-scard-stat-num${cls ? ' ' + cls : ''}">${num}</div>
      <div class="proc-scard-stat-lbl">${label}</div>
    </div>`;

  return `
    <div class="proc-summary-grid">
      <div class="proc-scard">
        <div class="proc-scard-title-row">
          <div class="proc-scard-dot proc-scard-dot-amber"></div>
          <div class="proc-scard-title">Delivery Slip</div>
        </div>
        <div class="proc-scard-stats">
          ${statBlock(deliveryCount, '', 'Parts')}
          ${statBlock('+' + deliveryAvgLate + 'd', deliveryAvgLate > 0 ? 'proc-scard-stat-num-warn' : 'proc-scard-stat-num-ok', 'Avg Late')}
          ${statBlock(deliveryOldest ? fmt(new Date(deliveryOldest).toISOString().slice(0,10)) : '—', '', 'Oldest Req')}
        </div>
        ${deliveryHtml}
      </div>
      <div class="proc-scard">
        <div class="proc-scard-title-row">
          <div class="proc-scard-dot proc-scard-dot-blue"></div>
          <div class="proc-scard-title">No Purchase Order</div>
        </div>
        <div class="proc-scard-stats">
          ${statBlock(noPOCount, '', 'Parts')}
          ${statBlock(noPOThisWeek, noPOThisWeek > 0 ? 'proc-scard-stat-num-warn' : '', 'This Week')}
          ${statBlock(noPOOldest ? fmt(new Date(noPOOldest).toISOString().slice(0,10)) : '—', '', 'Oldest Req')}
        </div>
        ${noPOHtml}
      </div>
    </div>
    ${upcomingHtml ? `<div class="proc-upcoming">
      <div class="proc-upcoming-title">Upcoming Deliveries</div>
      ${upcomingHtml}
    </div>` : ''}
  `;
}

function _procColResizeStart(e, colIdx) {
  e.preventDefault();
  e.stopPropagation();
  const container = e.target.closest('.proc-plist');
  if (!container) return;
  const cell = container.querySelector('.proc-plist-head').children[colIdx];
  const startW = cell.getBoundingClientRect().width;
  const startX = e.clientX;
  const minW = colIdx === 0 ? 30 : 48;
  e.target.classList.add('resizing');
  document.body.style.cursor = 'col-resize';
  document.body.style.userSelect = 'none';
  function onMove(ev) {
    container.style.setProperty('--pc' + colIdx, Math.max(minW, startW + (ev.clientX - startX)) + 'px');
  }
  function onUp() {
    e.target.classList.remove('resizing');
    document.body.style.cursor = '';
    document.body.style.userSelect = '';
    document.removeEventListener('mousemove', onMove);
    document.removeEventListener('mouseup', onUp);
  }
  document.addEventListener('mousemove', onMove);
  document.addEventListener('mouseup', onUp);
}

function _procPartsTable(data) {
  const rows = _procFilteredParts(data);
  if (!rows.length) return `<div class="proc-empty">No parts match the current filter or search.</div>`;
  if (_procState.partsListMode === 'card') {
    // Preload vendor data so PO clicks work in card view
    const job = _procState.job;
    if (job && !_procVendorCache[job]) {
      api.eto.vendors(job)
        .then(d => { _procVendorCache[job] = d; })
        .catch(e => { _procVendorCache[job] = { error: e.message }; });
    }
    return _procPartsCardView(rows);
  }
  const usd = v => v > 0 ? '$' + Number(v).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '—';
  const fmt = d => d ? fmtDate(d) : '—';
  const rh = i => `<div class="proc-col-resize" onmousedown="_procColResizeStart(event,${i})"></div>`;
  const leadChip = (orderDate, expDate) => {
    if (!orderDate || !expDate) return `<span>—</span>`;
    const days = (new Date(expDate) - new Date(orderDate)) / 86400000;
    if (isNaN(days) || days < 0) return `<span>—</span>`;
    const wks = Math.round(days / 7 * 2) / 2; // nearest 0.5
    const cls = wks <= 4 ? 'ok' : wks <= 8 ? 'warn' : 'long';
    const label = `${wks}w`;
    return `<span class="proc-lead proc-lead-${cls}" title="${Math.round(days)} day lead time (ordered → expected delivery)">${label}</span>`;
  };
  const dueChip = (expDate, isReceived) => {
    if (isReceived) return `<span class="proc-due proc-due-rcvd" title="Already received">RCVD</span>`;
    if (!expDate) return `<span>—</span>`;
    const rawDays = (new Date(expDate) - Date.now()) / 86400000;
    if (isNaN(rawDays)) return `<span>—</span>`;
    const wks = Math.round(rawDays / 7 * 2) / 2;
    const daysRounded = Math.round(rawDays);
    if (rawDays > 7)  return `<span class="proc-due proc-due-ahead" title="Due in ${daysRounded} days">+${wks}w</span>`;
    if (rawDays >= 0) return `<span class="proc-due proc-due-soon"  title="Due in ${daysRounded} days">+${wks}w</span>`;
    const overWks = Math.round(Math.abs(rawDays) / 7 * 2) / 2;
    return `<span class="proc-due proc-due-late" title="${Math.abs(daysRounded)} days overdue">-${overWks}w</span>`;
  };
  const hiddenSet = new Set(_procState.hiddenPartCols || []);
  const visCols = PROC_PART_COLS.filter(c => !hiddenSet.has(c.key));
  const gridTpl = visCols.map(c => c.w).join(' ');

  // Header titles per key
  const colTitle = { ordered: 'PO purchase date', lead: 'Days between purchase and expected delivery', due: 'Days until / since expected delivery' };
  const hcols = visCols.map((c, i) => {
    const t = colTitle[c.key] ? ` title="${colTitle[c.key]}"` : '';
    const cls = c.key === 'qty' ? ' class="num"' : '';
    return `<span${cls}${t}>${c.label}${rh(i)}</span>`;
  }).join('');

  // Row cell renderer per column key
  const cellFor = (key, p, st) => {
    switch (key) {
      case 'qty':     return `<span class="num">${p.qty ?? ''}</span>`;
      case 'pn':      return `<span class="proc-plpn" data-copy="${escapeHtml(p.pn || '')}" title="Click to copy part number">${escapeHtml(p.pn || '—')}</span>`;
      case 'desc':    return `<span class="proc-pdesc" title="${escapeHtml(p.desc || '')}">${escapeHtml(p.desc || '')}</span>`;
      case 'parent':  return `<span class="proc-plsrc" title="${escapeHtml(p.parentDesc || '')}"><span class="proc-plsrc-pn">${escapeHtml(p.parentPN || 'LOOSE')}</span></span>`;
      case 'cat':     return `<span class="proc-plcat" title="${escapeHtml(p.category || '')}">${p.category ? escapeHtml(p.category) : '—'}</span>`;
      case 'mfr':     return `<span class="proc-pmfr" title="${escapeHtml(p.manufacturer || '')}">${escapeHtml(p.manufacturer || 'SDC')}</span>`;
      case 'sup':     return `<span class="proc-psup" title="${escapeHtml(p.supplier || '')}">${p.supplier ? escapeHtml(p.supplier) : '—'}</span>`;
      case 'po':      return `<span class="proc-plpo${p.poId ? ' clickable' : ''}" data-poid="${p.poId || ''}" title="${p.poId ? 'Click to view PO' : ''}">${p.poId ? escapeHtml(String(p.poId)) : '—'}</span>`;
      case 'ordered': return `<span>${fmt(p.orderDate)}</span>`;
      case 'exp':     return `<span>${fmt(p.expDate || p.requiredDate)}</span>`;
      case 'lead':    return leadChip(p.orderDate, p.expDate);
      case 'due':     return dueChip(p.expDate, st.key === 'received');
      case 'status':  return `<span class="proc-pill proc-pill-${st.cls}" title="${escapeHtml(st.sub)}">${st.label}${st.sub ? `<i>${escapeHtml(st.sub)}</i>` : ''}</span>`;
      default: return '<span></span>';
    }
  };

  return `<div class="proc-plist" style="--proc-grid-cols:${gridTpl}">
    <div class="proc-plist-head">${hcols}</div>
    ${rows.map(p => {
      const st = _procPartStatus(p);
      return `<div class="proc-plrow${st.key === 'overdue' ? ' proc-plrow-overdue' : ''}" data-pn="${escapeHtml(p.pn || '')}">
        ${visCols.map(c => cellFor(c.key, p, st)).join('')}
      </div>`;
    }).join('')}
  </div>`;
}

// PM-facing section (spec) label overrides. Total ETO is read-only and its
// section names don't always match how SDC refers to them, so we remap by
// SpecID for DISPLAY ONLY. Add an entry here to rename a section; any section
// not listed falls back to the ETO SDescription. Keyed by String(specId).
//   30 → "Controls Design" (ETO)        shown as "Control-Related Parts"
//   40 → "Machine Testing" (ETO)        shown as "Machine Testing-Related Parts"
const SECTION_LABEL_OVERRIDE = {
  '30': 'Control-Related Parts',
  '40': 'Machine Testing-Related Parts',
};
function _procSectionLabel(specId, specName) {
  return SECTION_LABEL_OVERRIDE[String(specId)] || specName || '';
}

// Column header for the assemblies grid — same column track as .proc-arow so
// labels sit over their columns. Explains the otherwise-cryptic cells
// (6/7 parts, 1 no PO, priced, cost, readiness bar).
function _procAssemblyHeader() {
  return `<div class="proc-arow proc-ahead">
    <span class="proc-caret"></span>
    <span class="proc-ah">Assembly</span>
    <span class="proc-ah">Description</span>
    <span class="proc-ah" title="Parts received / total parts in this assembly (e.g. 6/7 parts)">Rcvd / Total</span>
    <span class="proc-ah" title="Parts with no purchase order yet">No PO</span>
    <span class="proc-ah" title="Parts in this assembly that have a unit price">Priced</span>
    <span class="proc-aspacer"></span>
    <span class="proc-ah proc-acost" title="Purchased material cost — qty × latest PO unit price per part">Material&nbsp;$</span>
    <span class="proc-ah" title="Build readiness — % of parts received">Readiness</span>
    <span class="proc-ah proc-pct">%</span>
  </div>`;
}

function _drawerResizeStart(e, bodyClass) {
  e.preventDefault();
  e.stopPropagation();
  // The handle is usually inside the body, but for the Notes drawer it sits at
  // the panel's top edge (outside the flex body) — so fall back to finding the
  // body within the enclosing drawer.
  let body = e.target.closest('.' + bodyClass);
  if (!body) {
    const drawer = e.target.closest('#schedule-notes, .schedule-proc-drawer, .schedule-hours-drawer, #schedule-drawer-stack');
    if (drawer) body = drawer.querySelector('.' + bodyClass);
  }
  if (!body) return;
  const startY = e.clientY;
  const startH = body.getBoundingClientRect().height;
  const minH = 120, maxH = window.innerHeight * 0.85;
  document.body.style.cursor = 'ns-resize';
  document.body.style.userSelect = 'none';
  e.target.classList.add('resizing');
  function onMove(ev) {
    const h = Math.min(maxH, Math.max(minH, startH - (ev.clientY - startY)));
    body.style.maxHeight = h + 'px';
    try { localStorage.setItem('drawerH_' + bodyClass, h); } catch (_) {}
  }
  function onUp() {
    document.body.style.cursor = '';
    document.body.style.userSelect = '';
    e.target.classList.remove('resizing');
    document.removeEventListener('mousemove', onMove);
    document.removeEventListener('mouseup', onUp);
  }
  document.addEventListener('mousemove', onMove);
  document.addEventListener('mouseup', onUp);
}

function _drawerRestoreHeight(bodyClass) {
  try {
    const h = localStorage.getItem('drawerH_' + bodyClass);
    if (h) document.querySelectorAll('.' + bodyClass).forEach(el => el.style.maxHeight = h + 'px');
  } catch (_) {}
}

const DRAWER_HANDLE = cls => `<div class="drawer-resize-handle" onmousedown="_drawerResizeStart(event,'${cls}')"></div>`;

function _procPartsColResizeStart(e, colIdx) {
  e.preventDefault();
  e.stopPropagation();
  const container = e.target.closest('.proc-parts');
  if (!container) return;
  const cell = container.querySelector('.proc-phead').children[colIdx];
  const startW = cell.getBoundingClientRect().width;
  const startX = e.clientX;
  const minW = colIdx === 0 ? 30 : 48;
  e.target.classList.add('resizing');
  document.body.style.cursor = 'col-resize';
  document.body.style.userSelect = 'none';
  function onMove(ev) {
    container.style.setProperty('--ap' + colIdx, Math.max(minW, startW + (ev.clientX - startX)) + 'px');
  }
  function onUp() {
    e.target.classList.remove('resizing');
    document.body.style.cursor = '';
    document.body.style.userSelect = '';
    document.removeEventListener('mousemove', onMove);
    document.removeEventListener('mouseup', onUp);
  }
  document.addEventListener('mousemove', onMove);
  document.addEventListener('mouseup', onUp);
}

function _procAssemblyRow(node, depth) {
  const st = node.stats || { total: 0, received: 0, noPO: 0, ordered: 0, pct: 0 };
  const open = !!_procState.open[node.id];
  // Each meta fact is its own grid cell so they line up in columns down the page
  // (parts under parts, no-PO under no-PO, priced under priced).
  const partsCell = `${st.received}/${st.total} parts`;
  const noPoCell  = st.noPO ? `<span class="proc-nopo-badge">⚠ ${st.noPO} no&nbsp;PO</span>` : '';
  const pricedCount = node.parts.filter(p => (Number(p.unitPrice) || 0) > 0).length;
  const pricedCell  = pricedCount ? `${pricedCount}/${node.parts.length}` : '';
  // Depth no longer indents the row — the Description column starts at a fixed
  // position on every row (consistent alignment). Nesting is conveyed by the
  // depth-tinted row background (--d) and the expand caret, not by indentation.
  let html = `
    <div class="proc-arow${open ? ' proc-arow-open' : ''}" data-aid="${escapeHtml(String(node.id))}" style="--d:${depth}">
      <span class="proc-caret${node.children.length === 0 ? ' proc-caret-leaf' : ''}">${open ? '▾' : '▸'}</span>
      <button class="proc-pn" data-copy="${escapeHtml(node.pn)}" type="button" title="Click to copy part number">${escapeHtml(node.pn)}</button>
      <span class="proc-aname" title="${escapeHtml(node.desc || '')}">${escapeHtml(node.desc || '')}</span>
      <span class="proc-acol proc-acol-parts">${partsCell}</span>
      <span class="proc-acol proc-acol-nopo">${noPoCell}</span>
      <span class="proc-acol">${pricedCell}</span>
      <span class="proc-aspacer"></span>
      <span class="proc-acost" title="Purchased material cost for this assembly — qty × latest PO unit price per part. In-house parts with no PO price count as $0.">${_procUsd(st.cost)}</span>
      <span class="proc-bar"><span class="proc-bar-fill" style="width:${Math.min(100, st.pct)}%;background:${_procBarColor(st.pct)}"></span></span>
      <span class="proc-pct" style="color:${_procBarColor(st.pct)}">${st.pct}%</span>
    </div>`;
  if (open) {
    for (const child of node.children) html += _procAssemblyRow(child, depth + 1);
    if (node.parts.length) {
      const q = (_procState.search || '').toLowerCase();
      const parts = q
        ? node.parts.filter(p => [p.pn, p.desc, p.manufacturer].some(v => String(v || '').toLowerCase().includes(q)))
        : node.parts;
      const money = v => v > 0 ? '$' + Number(v).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '—';
      const _partAccent = ['#1574C4','#0ea5e9','#38bdf8','#7dd3fc'][Math.min(depth, 3)];
      html += `<div class="proc-parts" style="margin-left:10px;--proc-parts-accent:${_partAccent}">
        ${parts.map(p => `
          <div class="proc-prow proc-prow-${p.status}">
            <span class="num">${p.qty ?? ''}</span>
            <button class="proc-pn proc-pn-sm" data-copy="${escapeHtml(p.pn || '')}" type="button" title="Click to copy part number">${escapeHtml(p.pn || '—')}</button>
            <span class="proc-pdesc" title="${escapeHtml(p.desc || '')}">${escapeHtml(p.desc || '')}</span>
            <span class="proc-pmfr">${escapeHtml(p.manufacturer || '')}</span>
            <span class="proc-ppo${p.poId ? ' clickable' : ''}" data-poid="${p.poId || ''}" title="${p.poId ? 'Click to view PO' : ''}">${p.poId ? escapeHtml(String(p.poId)) : ''}</span>
            <span class="num">${money(p.unitPrice)}</span>
            <span class="num">${money((Number(p.qty) || 0) * (Number(p.unitPrice) || 0))}</span>
          </div>`).join('')}
      </div>`;
    }
  }
  return html;
}

async function loadVendorPOs() {
  try { state.vendorPOs = await api.vendorPOs.list(); } catch (_) { state.vendorPOs = []; }
  renderVendorPOsPage();
}

// Live ETO part lines for one PO — lazy-loaded when a synced row is expanded.
const _vpoLinesCache = {}; // "job|po" → lines[]
async function _vpoLoadLines(box) {
  const job = box.dataset.linesJob, po = box.dataset.linesPo;
  const key = `${job}|${po}`;
  if (!_vpoLinesCache[key]) {
    box.innerHTML = '<div class="vpo-lines-note">Loading parts from Total ETO…</div>';
    try { _vpoLinesCache[key] = await api.eto.poLines(job, po); }
    catch (e) { box.innerHTML = `<div class="vpo-lines-note">⚠ Could not load part lines: ${escapeHtml(e.message)}</div>`; delete _vpoLinesCache[key]; return; }
  }
  const lines = _vpoLinesCache[key];
  if (!lines.length) { box.innerHTML = '<div class="vpo-lines-note">No part lines on this PO in ETO.</div>'; return; }
  const fmt = d => d ? fmtDate(d) : '—';
  box.innerHTML = `
    <div class="vpo-lines-title">Parts on this PO <span class="vpo-lines-src">live from Total ETO</span></div>
    <div class="vpo-lines-head"><span></span><span>Part No</span><span>Description</span><span class="num">Qty</span><span class="num">Rcvd</span><span>Due</span><span class="num">Price</span></div>
    ${lines.map(l => {
      const due = l.dateRevised || l.dateRequired;
      const revised = !!(l.dateRevised && l.dateRequired && l.dateRevised !== l.dateRequired);
      return `<div class="vpo-line vpo-line-${l.status}">
        <span class="proc-dot proc-dot-${l.status === 'received' ? 'received' : 'ordered'}" title="${l.status === 'received' ? 'Received' : 'Open'}"></span>
        <span class="vpo-line-pn">${escapeHtml(l.partNumber || '—')}</span>
        <span class="vpo-line-desc" title="${escapeHtml(l.desc || '')}">${escapeHtml(l.desc || '')}</span>
        <span class="num">${l.qty ?? ''}</span>
        <span class="num">${l.received ?? 0}</span>
        <span class="${revised ? 'vpo-line-revised' : ''}" title="${revised ? `Buyer revised this date — originally ${fmt(l.dateRequired)}` : ''}">${fmt(due)}${revised ? ' ↻' : ''}</span>
        <span class="num">${l.price != null ? '$' + Number(l.price).toFixed(2) : '—'}</span>
      </div>`;
    }).join('')}`;
}
function _vpoTrackingLink(t) {
  if (!t) return '';
  const s = String(t).trim(); if (!s) return '';
  let url = '';
  if (/^1Z[0-9A-Z]{16}$/i.test(s)) url = `https://wwwapps.ups.com/tracking/tracking.cgi?tracknum=${encodeURIComponent(s)}`;
  else if (/^\d{12}$|^\d{15}$/.test(s)) url = `https://www.fedex.com/fedextrack/?trknbr=${encodeURIComponent(s)}`;
  else if (/^\d{20,22}$/.test(s)) url = `https://tools.usps.com/go/TrackConfirmAction?qtc_tLabels1=${encodeURIComponent(s)}`;
  return url ? `<a class="vpo-track-link" href="${escapeHtml(url)}" target="_blank" rel="noopener">${escapeHtml(s)}</a>` : escapeHtml(s);
}
function _vpoRows(all, st) {
  let rows = all.slice();
  if (st.filter === 'open') rows = rows.filter(r => !r.complete);
  else if (st.filter === 'complete') rows = rows.filter(r => r.complete);
  if (st.fVendor && st.fVendor !== 'all') rows = rows.filter(r => (r.vendor || '') === st.fVendor);
  if (st.fPm && st.fPm !== 'all') rows = rows.filter(r => (r.pm || '') === st.fPm);
  if (st.fStatus && st.fStatus !== 'all') rows = rows.filter(r => _vpoStatusOf(r) === st.fStatus);
  if (st.fJob && st.fJob !== 'all') rows = rows.filter(r => String(r.job || '') === st.fJob);
  if (st.etaRange && st.etaRange !== 'all') { const cut = Date.now() + Number(st.etaRange) * 86400000; rows = rows.filter(r => { const e = _vpoEtaMs(r); return e != null && e <= cut; }); }
  const q = (st.search || '').trim().toLowerCase();
  if (q) rows = rows.filter(r => [r.po, r.job, r.vendor, r.pm, r.tracking, r.comments, r.po_price].some(v => String(v || '').toLowerCase().includes(q)));
  const cmp = (a, b) => {
    const dir = st.sortDir === 'desc' ? -1 : 1;
    if (st.sortKey === 'job') return dir * String(a.job||'').localeCompare(String(b.job||'')) || (a.id - b.id);
    if (st.sortKey === 'vendor') return dir * String(a.vendor||'').localeCompare(String(b.vendor||'')) || (a.id - b.id);
    if (st.sortKey === 'pm') return dir * String(a.pm||'').localeCompare(String(b.pm||'')) || (a.id - b.id);
    if (st.sortKey === 'price') return dir * ((parseFloat(a.po_price)||0) - (parseFloat(b.po_price)||0)) || (a.id - b.id);
    const ea = _vpoEtaMs(a) ?? Infinity, eb = _vpoEtaMs(b) ?? Infinity; return dir * (ea - eb) || (a.id - b.id);
  };
  rows.sort((a, b) => (a.complete ? 1 : 0) - (b.complete ? 1 : 0) || cmp(a, b));
  return rows;
}
async function _vpoSetField(id, field, val, inputEl) {
  const r = (state.vendorPOs || []).find(x => x.id === id); if (!r) return;
  if (inputEl) { inputEl.classList.remove('sp-saved','sp-save-err'); inputEl.classList.add('sp-saving'); }
  try {
    const upd = await api.vendorPOs.update(id, { [field]: val });
    if (upd) Object.assign(r, upd); else r[field] = val;
    if (inputEl) { inputEl.classList.remove('sp-saving'); inputEl.classList.add('sp-saved'); setTimeout(() => { try { inputEl.classList.remove('sp-saved'); } catch(_){} }, 1500); }
  } catch (_) {
    if (inputEl) { inputEl.classList.remove('sp-saving'); inputEl.classList.add('sp-save-err'); setTimeout(() => { try { inputEl.classList.remove('sp-save-err'); } catch(_){} }, 2000); }
  }
}

function renderVendorPOsPage() {
  const root = document.getElementById('vendor-pos-page');
  if (!root) return;
  const st = _vpoStateGet();
  const all = Array.isArray(state.vendorPOs) ? state.vendorPOs : [];
  const rows = _vpoRows(all, st);
  const openCount = all.filter(r => !r.complete).length;
  const vendors = [...new Set(all.map(r => r.vendor).filter(Boolean))].sort();
  const pms = [...new Set(all.map(r => r.pm).filter(Boolean))].sort();
  const jobsList = [...new Set(all.map(r => r.job).filter(Boolean))].sort((a, b) => Number(b) - Number(a) || String(a).localeCompare(String(b)));
  const teamNames = (state.team || []).filter(m => !isPlaceholder(m.name) && m.active !== 0).map(m => m.name).sort();
  const pmList = `<datalist id="vpo-pm-list">${[...new Set([...teamNames, ...pms])].map(n => `<option value="${escapeHtml(n)}"></option>`).join('')}</datalist>`;
  const vendorList = `<datalist id="vpo-vendor-list">${vendors.map(v => `<option value="${escapeHtml(v)}"></option>`).join('')}</datalist>`;

  // Pagination
  const totalPages = Math.ceil(rows.length / VPO_PAGE_SIZE) || 1;
  const page = Math.max(0, Math.min(st.page || 0, totalPages - 1));
  const pageRows = rows.slice(page * VPO_PAGE_SIZE, (page + 1) * VPO_PAGE_SIZE);

  const detailInput = (r, c) => {
    const val = r[c.key];
    const a = `data-id="${r.id}" data-field="${c.key}"`;
    let inp;
    if (c.type === 'num') inp = `<input type="number" step="any" class="sp-dinput" ${a} value="${val ?? ''}"/>`;
    else if (c.type === 'date') inp = `<input type="date" class="sp-dinput" ${a} value="${/^\d{4}-\d{2}-\d{2}$/.test(String(val || '')) ? val : ''}"/>`;
    else if (c.type === 'pm') inp = `<input type="text" list="vpo-pm-list" class="sp-dinput" ${a} value="${escapeHtml(val || '')}"/>`;
    else inp = `<input type="text" class="sp-dinput" ${a} value="${escapeHtml(val || '')}"/>`;
    return `<label class="sp-field"><span>${escapeHtml(c.label)}</span>${inp}</label>`;
  };
  const detailFields = (r) => VPO_COLS.map(c => detailInput(r, c)).join('');

  const sk = st.sortKey || 'eta', sd = st.sortDir || 'asc', sa = sd === 'asc' ? '▲' : '▼';
  const sHdr = (k, lbl, h='') => `<span class="vpo-sort-hdr${sk === k ? ' vpo-sort-active' : ''}" data-vpo-sort="${k}">${lbl}${sk === k ? ' ' + sa : ''}${h}</span>`;

  const row = (r, mode) => {
    const isList = mode === 'list';
    const sName = _vpoStatusOf(r);
    const s = VPO_STATUS[sName];
    const e = _vpoEtaMs(r);
    const etaStr = e != null ? fmtDate(new Date(e).toISOString().slice(0, 10)) : '';
    const slipped = r.eto_synced && r.eta && r.eta_original && r.eta !== r.eta_original;
    const slipTip = slipped ? (r.eta > r.eta_original ? `Slipped from ${_vpoFmtDate(r.eta_original)} — buyer revised the date in ETO` : `Moved up from ${_vpoFmtDate(r.eta_original)} — buyer revised the date in ETO`) : '';
    const slipMark = slipped ? ` <span class="vpo-slip" title="${escapeHtml(slipTip)}">↻</span>` : '';
    const priBadge = r.priority ? `<span class="vpo-pri-badge" title="Priority ${r.priority}">${r.priority}</span> ` : '';
    const priceCell = r.complete ? (r.completed_on ? escapeHtml(_vpoFmtDate(r.completed_on)) : '') : (r.po_price ? escapeHtml(String(r.po_price)) : '');
    return `<div class="sp-prow vpo-row vpo-st-${sName}" data-id="${r.id}">
      <div class="sp-prow-line">
        ${isList ? `<input type="checkbox" class="vpo-bulk-chk" data-id="${r.id}"/>` : '<span></span>'}
        <span class="vpo-dot vpo-dot-${sName}" title="${s.label}" aria-label="${s.label}">${sName==='complete'?'✓':sName==='late'?'!':sName==='shipped'?'↑':sName==='partial'?'~':sName==='soon'?'▲':''}</span>
        <span class="vpo-po" data-toggle="${r.id}">${priBadge}${escapeHtml(r.po || '—')}${r.eto_synced ? ' <span class="vpo-eto-pill" title="Auto-synced from Total ETO">ETO</span>' : ''}</span>
        <span class="vpo-job${isList && r.job ? ' vpo-filter-click' : ''}"${isList && r.job ? ` data-fk="fJob" data-fv="${escapeHtml(String(r.job))}"` : ''}>${escapeHtml(r.job || '')}</span>
        ${isList ? `<span class="vpo-vendor${r.vendor ? ' vpo-filter-click' : ''}" ${r.vendor ? `data-fk="fVendor" data-fv="${escapeHtml(r.vendor)}"` : ''}>${escapeHtml(r.vendor || '')}</span>` : ''}
        <span class="vpo-eta">${etaStr}${slipMark}</span>
        ${isList ? `<span class="vpo-ship">${r.ship_date ? escapeHtml(_vpoFmtDate(r.ship_date)) : ''}</span>` : ''}
        ${isList ? `<span class="vpo-track">${_vpoTrackingLink(r.tracking)}</span>` : ''}
        ${isList ? `<span class="vpo-pm${r.pm ? ' vpo-filter-click' : ''}" ${r.pm ? `data-fk="fPm" data-fv="${escapeHtml(r.pm)}"` : ''}>${escapeHtml(r.pm || '')}</span>` : ''}
        ${isList ? `<span class="vpo-price">${priceCell}</span>` : ''}
        <label class="sp-done" title="Partial shipment"><input type="checkbox" data-id="${r.id}" data-field="partial" ${r.partial ? 'checked' : ''}/></label>
        <label class="sp-done" title="Complete"><input type="checkbox" data-id="${r.id}" data-field="complete" ${r.complete ? 'checked' : ''}/></label>
      </div>
      <div class="sp-card-details" data-details="${r.id}" hidden>${r.eto_synced && r.job && r.po ? `<div class="vpo-lines" data-lines-job="${escapeHtml(r.job)}" data-lines-po="${escapeHtml(r.po)}"></div>` : ''}<div class="sp-fields sp-fields-lazy" data-lazy-id="${r.id}"></div><button class="vpo-del" data-id="${r.id}" type="button">Delete PO</button></div>
    </div>`;
  };

  const rh = (i) => `<span class="vpo-rhandle" data-col="${i}" title="Drag to resize"></span>`;
  const listHead = `<div class="sp-list-head vpo-head"><span><input type="checkbox" class="vpo-bulk-all" title="Select all"/></span><span></span><span>PO #${rh(0)}</span>${sHdr('job','Job',rh(1))}${sHdr('vendor','Vendor',rh(2))}${sHdr('eta','ETA',rh(3))}<span>Ship${rh(4)}</span><span>Tracking${rh(5)}</span>${sHdr('pm','PM',rh(6))}${sHdr('price','Price',rh(7))}<span>Part</span><span>Done</span></div>`;
  const cardHead = `<div class="sp-prow-line vpo-cardhead"><span></span><span></span><span>PO #</span><span>Job</span><span>ETA</span><span>Part</span><span>Done</span></div>`;

  let mainHtml;
  if (pageRows.length === 0) mainHtml = '<p class="sp-empty">No POs to show.</p>';
  else if (st.view === 'cards') {
    const groups = {};
    pageRows.forEach(r => { const k = r.vendor && r.vendor.trim() ? r.vendor : 'No vendor'; (groups[k] = groups[k] || []).push(r); });
    mainHtml = `<div class="sp-proj-grid">${Object.keys(groups).sort((a, b) => a.localeCompare(b)).map(vn =>
      `<section class="sp-proj-card"><header class="sp-proj-head"><span class="sp-proj-name">${escapeHtml(vn)}</span><span class="sp-group-count">${groups[vn].length}</span></header><div class="sp-proj-body">${cardHead}${groups[vn].map(r => row(r, 'card')).join('')}</div></section>`).join('')}</div>`;
  } else {
    mainHtml = `<div class="sp-flat">${listHead}${pageRows.map(r => row(r, 'list')).join('')}</div>`;
  }

  const sel = (val, opts, attr) => `<select ${attr}>${opts.map(o => `<option value="${escapeHtml(o.v)}"${val === o.v ? ' selected' : ''}>${escapeHtml(o.t)}</option>`).join('')}</select>`;
  const legend = ['complete', 'shipped', 'partial', 'late', 'soon'].map(k => `<span class="vpo-leg"><i style="background:${VPO_STATUS[k].color}"></i>${VPO_STATUS[k].label}</span>`).join('')
    + (_etoAvailable ? '<span class="vpo-leg" title="The buyer entered a revised date in Total ETO — the ETA shown is the new promise; hover the ↻ on a row to see the original."><span class="vpo-slip">↻</span> date revised in ETO</span>' : '');

  const paginationHtml = totalPages > 1 ? `<div class="vpo-pagination"><button class="vpo-page-btn" data-vpo-pg="${page - 1}" ${page === 0 ? 'disabled' : ''}>‹ Prev</button><span class="vpo-page-info">Page ${page + 1} of ${totalPages} &nbsp;(${rows.length} POs)</span><button class="vpo-page-btn" data-vpo-pg="${page + 1}" ${page >= totalPages - 1 ? 'disabled' : ''}>Next ›</button></div>` : '';

  // ── Dashboards ──
  const nowMs = Date.now();
  const openPOs = all.filter(r => !r.complete);
  const donePOs = all.filter(r => r.complete);
  const dRange = [7, 14, 21, 28, 99999].includes(Number(st.dashRange)) ? Number(st.dashRange) : 7;
  const dCut = dRange >= 99999 ? -Infinity : nowMs - dRange * 86400000;
  const compDate = (r) => { for (const d of [r.completed_on, r.delivery_date, r.ship_date]) { const t = d ? Date.parse(d) : NaN; if (!isNaN(t)) return t; } return null; };
  // All-time = every completed PO (even ones with no date on file); a specific
  // range needs a date to place it, so undated completes only show in All time.
  const compInRange = dRange >= 99999 ? donePOs.slice() : donePOs.filter(r => { const t = compDate(r); return t != null && t >= dCut; });
  const lateList = openPOs.map(r => { const e = _vpoEtaMs(r); return { r, late: (e != null && e < nowMs) ? Math.floor((nowMs - e) / 86400000) : -1 }; }).filter(x => x.late >= 0);
  const inTransit = openPOs.filter(r => r.tracking && String(r.tracking).trim());
  const byVendor = {};
  openPOs.forEach(r => { const k = r.vendor && r.vendor.trim() ? r.vendor : 'No vendor'; const e = _vpoEtaMs(r); byVendor[k] = byVendor[k] || { n: 0, late: 0 }; byVendor[k].n++; if (e != null && e < nowMs) byVendor[k].late++; });
  const vendorRows = Object.keys(byVendor).sort((a, b) => byVendor[b].n - byVendor[a].n);
  const compEta = compInRange.filter(r => _vpoEtaMs(r) != null && compDate(r) != null);
  const onTimeN = compEta.filter(r => compDate(r) <= _vpoEtaMs(r) + 86400000).length;
  const onTimePct = compEta.length ? Math.round((onTimeN / compEta.length) * 100) : null;
  const oldestOpen = [...openPOs].sort((a, b) => (Date.parse(a.po_date) || 0) - (Date.parse(b.po_date) || 0)).slice(0, 5);
  const weeksOut = (r) => { const t = Date.parse(r.po_date); if (isNaN(t)) return 0; return Math.round((Math.max(0, (nowMs - t) / 86400000) / 7) * 2) / 2; };
  // Completed-in-range list with how close each landed to its ETA.
  const compRows = compInRange.map(r => { const e = _vpoEtaMs(r); const c = compDate(r); const v = (e != null && c != null) ? Math.round((c - e) / 86400000) : null; return { r, v, took: _vpoActualWeeks(r) }; })
    .sort((a, b) => (compDate(b.r) || 0) - (compDate(a.r) || 0)).slice(0, 8);
  // Average actual lead time per vendor (only completed POs where we know both dates).
  const leadByVendor = {};
  donePOs.forEach(r => { const a = _vpoActualWeeks(r); if (a != null && r.vendor) { (leadByVendor[r.vendor] = leadByVendor[r.vendor] || { sum: 0, n: 0 }); leadByVendor[r.vendor].sum += a; leadByVendor[r.vendor].n++; } });
  const leadRows = Object.keys(leadByVendor).map(k => ({ vendor: k, avg: Math.round((leadByVendor[k].sum / leadByVendor[k].n) * 2) / 2, n: leadByVendor[k].n })).sort((a, b) => b.n - a.n);
  const cvar = (vDays) => { if (vDays == null) return '<span class="sp-cvar">—</span>'; const w = Math.round((vDays / 7) * 2) / 2; if (w > 0) return `<span class="sp-cvar is-late">${w}w late</span>`; if (w < 0) return `<span class="sp-cvar is-early">${-w}w early</span>`; return '<span class="sp-cvar is-ontime">on time</span>'; };
  const lateWeeks = (days) => Math.round((days / 7) * 2) / 2;
  const etaStrOf = (r) => { const e = _vpoEtaMs(r); return e != null ? fmtDate(new Date(e).toISOString().slice(0, 10)) : '—'; };
  const vRangeOpts = [{ v: 7, t: '1 week' }, { v: 14, t: '2 weeks' }, { v: 21, t: '3 weeks' }, { v: 28, t: '4 weeks' }, { v: 99999, t: 'All time' }];
  const openVal = openPOs.reduce((s, r) => s + (r.po_price ? parseFloat(r.po_price)||0 : 0), 0);
  const openValStr = openVal > 0 ? '$' + openVal.toLocaleString('en-US', { maximumFractionDigits: 0 }) : '—';
  const dashHtml = `
    <div class="sp-dash vpo-dash-main">
      <div class="sp-dcard">
        <div class="sp-dcard-head">Open by vendor <span class="sp-dhint">${lateList.length} late</span></div>
        <div class="sp-dproj-head"><span>Vendor</span><span>POs</span><span>Late</span></div>
        <div class="sp-dproj-list">${vendorRows.length ? vendorRows.map(vn => `<div class="sp-dprow sp-drow-click" data-fk="fVendor" data-fv="${escapeHtml(vn)}"><span class="sp-dproj">${escapeHtml(vn)}</span><span class="sp-dcount">${byVendor[vn].n}</span><span class="sp-dbehind">${byVendor[vn].late ? `<span class="sp-dlate-pill">${byVendor[vn].late}</span>` : '—'}</span></div>`).join('') : '<div class="sp-dempty">No open POs</div>'}</div>
      </div>
      <div class="sp-dcard">
        <div class="sp-dcard-head">In transit <span class="sp-dhint">${inTransit.length}</span></div>
        <div class="sp-late-head"><span>PO #</span><span>Vendor</span><span>ETA</span><span>Ship</span></div>
        <div class="sp-dlist">${inTransit.length ? inTransit.slice(0, 8).map(r => `<div class="sp-laterow${r.partial ? ' is-partial' : ''}"><span class="sp-dpn vpo-dash-po-link" data-id="${r.id}" data-po="${escapeHtml(r.po||'')}">${escapeHtml(r.po || '—')}</span><span class="sp-dproj">${escapeHtml(r.vendor || '')}</span><span class="sp-deta">${etaStrOf(r)}</span><span class="sp-deta">${r.ship_date ? escapeHtml(_vpoFmtDate(r.ship_date)) : '—'}</span></div>`).join('') : '<div class="sp-dempty">Nothing in transit</div>'}</div>
      </div>
      <div class="sp-dcard">
        <div class="sp-dcard-head">Late POs <span class="sp-dhint">${lateList.length}</span></div>
        <div class="sp-late-head"><span>PO #</span><span>Vendor</span><span>ETA</span><span>Late</span></div>
        <div class="sp-dlist">${lateList.length ? [...lateList].sort((a, b) => b.late - a.late).slice(0, 8).map(x => `<div class="sp-laterow${x.r.partial ? ' is-partial' : ''}"><span class="sp-dpn vpo-dash-po-link" data-id="${x.r.id}" data-po="${escapeHtml(x.r.po||'')}">${escapeHtml(x.r.po || '—')}</span><span class="sp-dproj">${escapeHtml(x.r.vendor || '')}</span><span class="sp-deta">${etaStrOf(x.r)}</span><span class="sp-cvar is-late">${lateWeeks(x.late)}w</span></div>`).join('') : '<div class="sp-dempty">Nothing late 🎉</div>'}</div>
      </div>
      <div class="sp-dcard">
        <div class="sp-dcard-head">Completed <select class="vpo-dash-range">${vRangeOpts.map(o => `<option value="${o.v}"${dRange === o.v ? ' selected' : ''}>${o.t}</option>`).join('')}</select> <span class="sp-dhint">${compInRange.length}</span></div>
        <div class="sp-comp-head"><span>PO #</span><span>Job</span><span>Lead</span><span>Took</span></div>
        <div class="sp-dlist">${compRows.length ? compRows.map(x => `<div class="sp-comprow"><span class="sp-dpn vpo-dash-po-link" data-id="${x.r.id}" data-po="${escapeHtml(x.r.po||'')}">${escapeHtml(x.r.po || '—')}</span><span class="sp-dproj">${escapeHtml(x.r.job || '')}</span><span class="sp-deta">${x.r.lead_time != null && x.r.lead_time !== '' ? x.r.lead_time + 'w' : '—'}</span><span class="sp-cvar">${x.took != null ? x.took + 'w' : '—'}</span></div>`).join('') : '<div class="sp-dempty">None completed in range</div>'}</div>
      </div>
      <div class="sp-dcard">
        <div class="sp-dcard-head">Longest outstanding</div>
        <div class="sp-late-head"><span>PO #</span><span>Vendor</span><span>Due</span><span>Out</span></div>
        <div class="sp-dlist">${oldestOpen.length ? oldestOpen.map(r => `<div class="sp-laterow"><span class="sp-dpn vpo-dash-po-link" data-id="${r.id}" data-po="${escapeHtml(r.po||'')}">${escapeHtml(r.po || '—')}</span><span class="sp-dproj">${escapeHtml(r.vendor || '')}</span><span class="sp-deta">${etaStrOf(r)}</span><span class="sp-cvar">${weeksOut(r)}w</span></div>`).join('') : '<div class="sp-dempty">None open 🎉</div>'}</div>
      </div>
    </div>`;

  const headStat = `
    <div class="vpo-headstat">
      <div class="vpo-hs-ontime">
        <span class="vpo-hs-label">On-time delivery</span>
        ${_shopDonut(onTimePct)}
        <span class="vpo-hs-sub">${compEta.length ? `${onTimeN}/${compEta.length}` : '—'}</span>
      </div>
      <div class="vpo-hs-total">
        <span class="vpo-hs-label">Open PO value</span>
        <span class="vpo-hs-totalval">${openValStr}</span>
      </div>
      <div class="vpo-hs-lead">
        <span class="vpo-hs-label">Avg lead by vendor</span>
        <div class="vpo-hs-leadlist">${leadRows.length ? leadRows.slice(0, 12).map(x => `<div class="vpo-hs-leadrow"><span class="vpo-hs-vn">${escapeHtml(x.vendor)}</span><span class="vpo-hs-avg">${x.avg}w</span></div>`).join('') : '<div class="sp-dempty">No data yet</div>'}</div>
      </div>
    </div>`;

  root.innerHTML = `
    <div class="shop-parts-head">
      <div class="sp-head-top">
        <h1 class="projects-page-title">Vendor PO Track</h1>
        ${headStat}
        ${_etoAvailable ? `<button class="btn-secondary sp-add-toggle" data-action="vpo-eto-sync" data-scope="all" type="button" title="Pull the latest PO status from Total ETO — runs automatically every 30 min; this is the on-demand version.">⟳ Sync from ETO</button>` : ''}
        <button class="btn-primary sp-add-toggle" data-action="vpo-toggle-add" type="button">${_vpoAddOpen ? '✕ Close' : '＋ Add PO'}</button>
      </div>
      <form class="sp-add-bar${_vpoAddOpen ? '' : ' is-hidden'}" data-action="vpo-add-form">
        <label class="sp-add-f"><span>PO #</span><input name="po" autocomplete="off"/></label>
        <label class="sp-add-f"><span>Job #</span><input name="job" autocomplete="off"/></label>
        <label class="sp-add-f"><span>Vendor</span><input name="vendor" list="vpo-vendor-list" autocomplete="off"/></label>
        <label class="sp-add-f"><span>PO Date</span><input name="po_date" type="date"/></label>
        <label class="sp-add-f"><span>Lead (wks)</span><input name="lead_time" type="number" min="0" style="width:64px"/></label>
        <label class="sp-add-f"><span>ETA</span><input name="eta" type="date"/></label>
        <label class="sp-add-f"><span>PM</span><input name="pm" list="vpo-pm-list" autocomplete="off"/></label>
        <label class="sp-add-f"><span>Tracking</span><input name="tracking" autocomplete="off"/></label>
        <label class="sp-add-f"><span>PO Price</span><input name="po_price" autocomplete="off"/></label>
        <label class="sp-add-f sp-add-f-grow"><span>Comments</span><input name="comments" autocomplete="off"/></label>
        <button class="btn-primary sp-add-btn" type="submit">Add</button>
      </form>
      <div class="vpo-bulk-bar" id="vpo-bulk-bar" hidden>
        <span class="vpo-bulk-count">0 selected</span>
        <button class="btn-secondary vpo-bulk-complete" type="button">Mark Complete</button>
        <button class="btn-secondary vpo-bulk-delete" type="button">Delete</button>
        <button class="vpo-bulk-clear" type="button">Clear</button>
      </div>
      <div class="vpo-sticky-controls">
      <div class="shop-parts-toolbar">
        <div class="seg-control sp-view">
          <button class="seg-btn${st.view === 'list' ? ' is-active' : ''}" data-vview="list" type="button">List</button>
          <button class="seg-btn${st.view === 'cards' ? ' is-active' : ''}" data-vview="cards" type="button">Cards</button>
        </div>
        <div class="seg-control sp-filter">
          <button class="seg-btn${st.filter === 'open' ? ' is-active' : ''}" data-vfilter="open" type="button">Open ${openCount}</button>
          <button class="seg-btn${st.filter === 'complete' ? ' is-active' : ''}" data-vfilter="complete" type="button">Complete</button>
          <button class="seg-btn${st.filter === 'all' ? ' is-active' : ''}" data-vfilter="all" type="button">All</button>
          <button class="seg-btn${st.fStatus === 'soon' ? ' is-active' : ''}" data-vfilter-status="soon" type="button">Due soon</button>
        </div>
        ${sel(st.fStatus, [{ v: 'all', t: 'Status: all' }, { v: 'late', t: 'Late' }, { v: 'shipped', t: 'Shipped' }, { v: 'soon', t: 'Due ≤1 wk' }, { v: 'partial', t: 'Partial' }, { v: 'complete', t: 'Complete' }], 'class="vpo-fsel" data-fk="fStatus"')}
        ${sel(st.fVendor, [{ v: 'all', t: 'Vendor: all' }, ...vendors.map(v => ({ v, t: v }))], 'class="vpo-fsel" data-fk="fVendor"')}
        ${sel(st.fPm, [{ v: 'all', t: 'PM: all' }, ...pms.map(v => ({ v, t: v }))], 'class="vpo-fsel" data-fk="fPm"')}
        ${sel(st.fJob, [{ v: 'all', t: 'Job: all' }, ...jobsList.map(v => ({ v, t: `#${v}` }))], 'class="vpo-fsel" data-fk="fJob"')}
        ${sel(st.etaRange, [{ v: 'all', t: 'ETA: any' }, { v: '7', t: '≤ 1 week' }, { v: '14', t: '≤ 2 weeks' }, { v: '30', t: '≤ 30 days' }], 'class="vpo-fsel" data-fk="etaRange"')}
        <input type="search" class="vpo-search" placeholder="Search PO / job / vendor / tracking…" value="${escapeHtml(st.search || '')}"/>
        ${st.search ? `<button class="vpo-clear-search" data-action="vpo-clear-search" type="button" title="Clear search and show all">✕ Clear</button>` : ''}
        <button class="btn-secondary vpo-csv-btn" data-action="vpo-csv" type="button" title="Export to CSV">⬇ CSV</button>
      </div>
      <div class="vpo-legend">${legend}</div>
      </div>
    </div>
    ${dashHtml}
    ${mainHtml}
    ${paginationHtml}
    ${pmList}${vendorList}`;

  // ── Event listeners ──
  root.querySelector('[data-action="vpo-toggle-add"]').addEventListener('click', () => { _vpoAddOpen = !_vpoAddOpen; renderVendorPOsPage(); if (_vpoAddOpen) { const p = root.querySelector('input[name="po"]'); if (p) p.focus(); } });
  // Apply column widths
  _vpoApplyCols(_vpoColWidths());
  // Column resize drag
  root.querySelectorAll('.vpo-rhandle[data-col]').forEach(handle => {
    handle.addEventListener('mousedown', (e) => {
      e.preventDefault();
      const colIdx = Number(handle.dataset.col);
      const startX = e.clientX;
      const w = _vpoColWidths();
      const startW = w[colIdx];
      const onMove = (ev) => {
        const newW = Math.max(40, startW + ev.clientX - startX);
        w[colIdx] = newW;
        _vpoApplyCols(w);
      };
      const onUp = () => {
        _vpoSaveColWidths(w);
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
      };
      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
    });
    handle.addEventListener('dblclick', () => {
      const w = _vpoColWidths();
      w[Number(handle.dataset.col)] = VPO_COL_DEFAULTS[Number(handle.dataset.col)];
      _vpoSaveColWidths(w); _vpoApplyCols(w);
    });
  });
  _etoCheckOnce();
  root.querySelectorAll('[data-action="vpo-eto-sync"]').forEach(etoBtn => etoBtn.addEventListener('click', async () => {
    const scope = etoBtn.dataset.scope || 'linked';
    const label = etoBtn.textContent;
    etoBtn.disabled = true; etoBtn.textContent = '⟳ Syncing…';
    try {
      const r = await api.eto.syncVendorPOs(scope);
      if (r && r.ok) { showToast(`ETO sync done — ${r.pos} PO${r.pos === 1 ? '' : 's'} across ${r.jobs} job${r.jobs === 1 ? '' : 's'} (${r.created} new, ${r.updated} updated)`, { kind: 'success' }); await loadVendorPOs(); return; }
      showToast(`ETO sync failed: ${(r && r.error) || 'unknown error'}`, { kind: 'error' });
    } catch (e) { showToast(`ETO sync failed: ${e.message}`, { kind: 'error' }); }
    etoBtn.disabled = false; etoBtn.textContent = label;
  }));
  root.querySelector('[data-action="vpo-add-form"]').addEventListener('submit', async (e) => {
    e.preventDefault(); const f = e.target;
    const data = { po: f.po.value.trim()||null, job: f.job.value.trim()||null, vendor: f.vendor.value.trim()||null, po_date: f.po_date.value||null, lead_time: f.lead_time.value===''?null:Number(f.lead_time.value), eta: f.eta.value||null, pm: f.pm.value.trim()||null, tracking: f.tracking.value.trim()||null, po_price: f.po_price.value.trim()||null, comments: f.comments.value.trim()||null, complete: 0, partial: 0 };
    let created;
    try { created = await api.vendorPOs.create(data); } catch (err) { showToast(err.message || 'Failed to create PO', { kind: 'error' }); return; }
    if (created && created.id) { state.vendorPOs.push(created); f.reset(); _vpoAddOpen = true; renderVendorPOsPage(); }
  });
  root.querySelectorAll('.sp-view [data-vview]').forEach(b => b.addEventListener('click', () => { st.view = b.dataset.vview; st.page = 0; _vpoSave(); renderVendorPOsPage(); }));
  root.querySelectorAll('.sp-filter [data-vfilter]').forEach(b => b.addEventListener('click', () => { st.filter = b.dataset.vfilter; st.page = 0; _vpoSave(); renderVendorPOsPage(); }));
  root.querySelectorAll('[data-vfilter-status]').forEach(b => b.addEventListener('click', () => { st.fStatus = st.fStatus === b.dataset.vfilterStatus ? 'all' : b.dataset.vfilterStatus; st.page = 0; _vpoSave(); renderVendorPOsPage(); }));
  root.querySelectorAll('.vpo-fsel').forEach(s => s.addEventListener('change', () => { st[s.dataset.fk] = s.value; st.page = 0; _vpoSave(); renderVendorPOsPage(); }));
  const vdr = root.querySelector('.vpo-dash-range');
  if (vdr) vdr.addEventListener('change', () => { st.dashRange = Number(vdr.value); _vpoSave(); renderVendorPOsPage(); });
  const se = root.querySelector('.vpo-search');
  se.addEventListener('input', () => {
    st.search = se.value; st.page = 0;
    clearTimeout(_vpoSearchT);
    _vpoSearchT = setTimeout(() => { _vpoSave(); renderVendorPOsPage(); const s2 = document.querySelector('.vpo-search'); if (s2) { s2.focus(); s2.setSelectionRange(s2.value.length, s2.value.length); } }, 300);
  });
  // Column sort
  root.querySelectorAll('[data-vpo-sort]').forEach(h => h.addEventListener('click', () => {
    const k = h.dataset.vpoSort;
    if (st.sortKey === k) st.sortDir = st.sortDir === 'asc' ? 'desc' : 'asc'; else { st.sortKey = k; st.sortDir = 'asc'; }
    st.page = 0; _vpoSave(); renderVendorPOsPage();
  }));
  // Pagination
  root.querySelectorAll('[data-vpo-pg]').forEach(b => b.addEventListener('click', () => { st.page = Number(b.dataset.vpoPg); _vpoSave(); renderVendorPOsPage(); }));
  // Row expand toggle with lazy field fill
  root.querySelectorAll('[data-toggle]').forEach(b => b.addEventListener('click', () => {
    const d = root.querySelector(`[data-details="${b.dataset.toggle}"]`);
    if (!d) return;
    d.hidden = !d.hidden;
    if (!d.hidden) {
      const lazy = d.querySelector('.sp-fields-lazy');
      if (lazy && !lazy.dataset.filled) {
        lazy.dataset.filled = '1';
        const r2 = (state.vendorPOs || []).find(x => x.id === Number(lazy.dataset.lazyId));
        if (r2) lazy.innerHTML = detailFields(r2);
      }
      const box = d.querySelector('.vpo-lines');
      if (box && !box.dataset.loaded) { box.dataset.loaded = '1'; _vpoLoadLines(box); }
      setTimeout(() => { try { d.scrollIntoView({ behavior: 'smooth', block: 'nearest' }); } catch(_){} }, 50);
    }
  }));
  // Change handler — module-level guard survives root re-creation
  if (!_vpoChangeBound || _vpoChangeRoot !== root) {
    _vpoChangeBound = true; _vpoChangeRoot = root;
    root.addEventListener('change', async (e) => {
      const el = e.target.closest('[data-id][data-field]'); if (!el) return;
      const id = Number(el.dataset.id), field = el.dataset.field;
      let val; if (el.type === 'checkbox') val = el.checked ? 1 : 0; else if (el.type === 'number') val = el.value === '' ? null : Number(el.value); else val = el.value;
      await _vpoSetField(id, field, val, el.type !== 'checkbox' ? el : null);
      if (['complete', 'partial', 'tracking', 'vendor', 'eta', 'po_date', 'lead_time'].includes(field)) renderVendorPOsPage();
    });
  }
  root.querySelectorAll('.vpo-del').forEach(btn => btn.addEventListener('click', async () => {
    const id = Number(btn.dataset.id); const r = state.vendorPOs.find(x => x.id === id);
    const ok = await showConfirmDialog({ title: 'Delete PO?', message: `Delete PO "${escapeHtml(r?.po || 'this PO')}"?`, okLabel: 'Delete', cancelLabel: 'Cancel', danger: true });
    if (!ok) return;
    try { await api.vendorPOs.remove(id); } catch (err) { showToast(err.message || 'Delete failed', { kind: 'error' }); return; }
    state.vendorPOs = state.vendorPOs.filter(x => x.id !== id); renderVendorPOsPage();
  }));
  // Click-to-filter on job / vendor / pm cells
  root.querySelectorAll('.vpo-filter-click[data-fk]').forEach(span => span.addEventListener('click', (e) => {
    e.stopPropagation();
    const fk = span.dataset.fk, fv = span.dataset.fv || 'all';
    st[fk] = fv; st.page = 0; _vpoSave(); renderVendorPOsPage();
  }));
  // Dashboard vendor click → filter to that vendor, switch to open
  root.querySelectorAll('.sp-drow-click[data-fk]').forEach(row => row.addEventListener('click', () => {
    st[row.dataset.fk] = row.dataset.fv; st.filter = 'open'; st.page = 0; _vpoSave(); renderVendorPOsPage();
  }));
  // Dashboard PO# click → search for that PO, scroll + highlight in list
  root.querySelectorAll('.vpo-dash-po-link[data-id]').forEach(span => span.addEventListener('click', () => {
    const id = Number(span.dataset.id), po = span.dataset.po;
    st.search = po; st.filter = 'all'; st.fStatus = 'all'; st.page = 0; _vpoSave();
    renderVendorPOsPage();
    const target = root.querySelector(`.vpo-row[data-id="${id}"]`);
    if (target) {
      target.scrollIntoView({ behavior: 'smooth', block: 'center' });
      target.classList.add('vpo-row-highlight');
      setTimeout(() => target.classList.remove('vpo-row-highlight'), 1800);
    }
  }));
  // Bulk checkboxes
  const bulkBar = root.querySelector('#vpo-bulk-bar');
  const updateBulk = () => {
    const checked = [...root.querySelectorAll('.vpo-bulk-chk:checked')];
    if (bulkBar) { bulkBar.hidden = checked.length === 0; const cnt = bulkBar.querySelector('.vpo-bulk-count'); if (cnt) cnt.textContent = `${checked.length} selected`; }
  };
  root.querySelectorAll('.vpo-bulk-chk').forEach(c => c.addEventListener('change', updateBulk));
  const allChk = root.querySelector('.vpo-bulk-all');
  if (allChk) allChk.addEventListener('change', () => { root.querySelectorAll('.vpo-bulk-chk').forEach(c => c.checked = allChk.checked); updateBulk(); });
  if (bulkBar) {
    bulkBar.querySelector('.vpo-bulk-clear')?.addEventListener('click', () => { root.querySelectorAll('.vpo-bulk-chk').forEach(c => c.checked = false); if (allChk) allChk.checked = false; updateBulk(); });
    bulkBar.querySelector('.vpo-bulk-complete')?.addEventListener('click', async () => {
      const ids = [...root.querySelectorAll('.vpo-bulk-chk:checked')].map(c => Number(c.dataset.id));
      await Promise.all(ids.map(id => _vpoSetField(id, 'complete', 1)));
      renderVendorPOsPage();
    });
    bulkBar.querySelector('.vpo-bulk-delete')?.addEventListener('click', async () => {
      const ids = [...root.querySelectorAll('.vpo-bulk-chk:checked')].map(c => Number(c.dataset.id));
      if (!ids.length) return;
      const ok = await showConfirmDialog({ title: 'Delete POs?', message: `Delete ${ids.length} selected PO${ids.length === 1 ? '' : 's'}?`, okLabel: 'Delete', cancelLabel: 'Cancel', danger: true });
      if (!ok) return;
      await Promise.all(ids.map(id => api.vendorPOs.remove(id)));
      state.vendorPOs = state.vendorPOs.filter(r => !ids.includes(r.id));
      renderVendorPOsPage();
    });
  }
  // Clear search
  const clearBtn = root.querySelector('[data-action="vpo-clear-search"]');
  if (clearBtn) clearBtn.addEventListener('click', () => { st.search = ''; st.filter = 'all'; st.fStatus = 'all'; st.page = 0; _vpoSave(); renderVendorPOsPage(); });
  // CSV export
  root.querySelectorAll('[data-action="vpo-csv"]').forEach(btn => btn.addEventListener('click', () => {
    const headers = ['PO#','Job','Vendor','ETA','Ship Date','Tracking','PM','Price','Status','Partial','Complete'];
    const csvData = [headers, ...rows.map(r => [r.po||'', r.job||'', r.vendor||'', r.eta||'', r.ship_date||'', r.tracking||'', r.pm||'', r.po_price||'', _vpoStatusOf(r), r.partial?'yes':'no', r.complete?'yes':'no'])];
    const csv = csvData.map(row => row.map(c => `"${String(c).replace(/"/g,'""')}"`).join(',')).join('\n');
    const a = document.createElement('a'); a.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csv); a.download = 'vendor-pos.csv'; a.click();
  }));
}

// ─── Job Hours Page ───────────────────────────────────────────────────────────
const _jhPageState = { jobIds: [], search: '', pbiJobs: null, hoursType: 'quoted', dropdownOpen: false, fnFilter: null, fnDropOpen: false, _didAutoSelect: false };

function renderJobHoursPage() {
  const root = document.getElementById('job-hours-page');
  if (!root) return;

  // ── Build job list from local DB merged with PBI status ───────────────────
  const localJobs = Object.entries(state.projectsIndex || {})
    .map(([name, info]) => ({ id: String(info.hours_job_id || info.job_number || '').trim(), name, status: '' }))
    .filter(j => j.id);

  const pbiMap = new Map((_jhPageState.pbiJobs || []).map(j => [j.id, j]));
  const allJobs = localJobs.map(j => {
    const p = pbiMap.get(j.id);
    return p ? { ...j, name: p.name || j.name, status: p.status || '' } : j;
  });
  if (_jhPageState.pbiJobs) {
    const localIds = new Set(localJobs.map(j => j.id));
    for (const p of _jhPageState.pbiJobs) {
      if (!localIds.has(p.id)) allJobs.push(p);
    }
  }
  allJobs.sort((a, b) => a.name.localeCompare(b.name));

  // Auto-select first job only on true first load, not after a user clears/removes
  if (!_jhPageState._didAutoSelect && !_jhPageState.jobIds.length && allJobs.length) {
    _jhPageState.jobIds = [allJobs[0].id];
    _jhPageState._didAutoSelect = true;
  }

  const selIds = new Set(_jhPageState.jobIds);
  const q      = _jhPageState.search.toLowerCase();

  const selCount = selIds.size;
  const dropOpen = _jhPageState.dropdownOpen;

  // Build pill chips for selected jobs
  const pillsHtml = selCount === 0
    ? `<span class="jhp-dd-placeholder">Select job…</span>`
    : [...selIds].map(id => {
        const j = allJobs.find(x => x.id === id);
        const lbl = j ? `${id} — ${j.name}` : id;
        return `<span class="jhp-sel-pill"><span class="jhp-sel-pill-lbl">${escapeHtml(lbl)}</span><span class="jhp-sel-pill-x" data-jhp-pill-rm="${escapeHtml(id)}">×</span></span>`;
      }).join('');

  // Build grouped list with checkboxes
  const statuses = ['Active', 'Complete', ''];
  const grouped  = statuses.map(s => ({
    label: s || '(Blank)',
    jobs: allJobs.filter(j => j.status === s && (!q || j.name.toLowerCase().includes(q) || j.id.includes(q))),
  })).filter(g => g.jobs.length);

  const dropHtml = grouped.map(g => `
    <div class="jhp-dd-group">
      <div class="jhp-dd-group-label">${escapeHtml(g.label)}</div>
      ${g.jobs.map(j => {
        const checked = selIds.has(j.id);
        return `<label class="jhp-dd-item${checked ? ' is-active' : ''}" data-jhp-id="${escapeHtml(j.id)}">
          <span class="jhp-dd-cb${checked ? ' checked' : ''}"></span>
          <span class="jhp-dd-job-id">${escapeHtml(j.id)}</span>
          <span class="jhp-dd-job-name">${escapeHtml(j.name)}</span>
        </label>`;
      }).join('')}
    </div>`).join('');

  root.innerHTML = `
    <div class="jhp-page">
      <div class="jhp-top-filters">
        <div class="jhp-filter-block">
          <div class="jhp-filter-block-title">Job Status, Job</div>
          <div class="jhp-dd-wrap${dropOpen ? ' is-open' : ''}">
            <button class="jhp-dd-btn${selCount ? ' has-pills' : ''}" id="jhp-dd-toggle">
              <span class="jhp-dd-pills-wrap">${pillsHtml}</span>
              <span class="jhp-dd-caret">${dropOpen ? '▲' : '▼'}</span>
            </button>
            ${dropOpen ? `
            <div class="jhp-dd-panel">
              <div class="jhp-dd-search-wrap">
                <span class="jhp-dd-search-icon">🔍</span>
                <input class="jhp-dd-search" placeholder="Search" value="${escapeHtml(_jhPageState.search)}" autofocus>
              </div>
              ${selCount > 0 ? `<div class="jhp-dd-sel-bar"><span>${selCount} selected</span><button class="jhp-dd-clear">Clear all</button></div>` : ''}
              <div class="jhp-dd-list">${dropHtml || '<div class="jhp-dd-empty">No jobs found</div>'}</div>
            </div>` : ''}
          </div>
        </div>
        <div class="jhp-filter-block">
          <div class="jhp-filter-block-title">Hours Type</div>
          <div class="jhp-ht-radios">
            <label class="jhp-ht-radio"><input type="radio" name="jht" value="quoted"${_jhPageState.hoursType==='quoted'?' checked':''}> Quoted</label>
            <label class="jhp-ht-radio"><input type="radio" name="jht" value="etc"${_jhPageState.hoursType==='etc'?' checked':''}> ETC</label>
          </div>
        </div>
        <div id="jhp-fn-filter-slot"></div>
        ${selCount > 0 ? `<div class="jhp-filter-active-job">
          <span class="jhp-active-job-name">${escapeHtml(selCount === 1 ? (allJobs.find(j => j.id === [...selIds][0])?.name || '') : `${selCount} jobs`)}</span>
          <span class="jhp-active-job-id">${[...selIds].map(id => `#${escapeHtml(id)}`).join(', ')}</span>
        </div>` : ''}
      </div>
      <div id="jhp-hours-content" class="jhp-hours-content">
        ${selCount ? `<div class="proc-empty">Loading hours…</div>` : `<div class="proc-empty">Select a job to view hours.</div>`}
      </div>
    </div>`;

  // Toggle dropdown
  root.querySelector('#jhp-dd-toggle').addEventListener('click', e => {
    e.stopPropagation();
    _jhPageState.dropdownOpen = !_jhPageState.dropdownOpen;
    renderJobHoursPage();
  });

  // Close dropdown on outside click
  if (dropOpen) {
    const close = e => {
      if (!root.querySelector('.jhp-dd-panel')?.contains(e.target) &&
          !root.querySelector('#jhp-dd-toggle')?.contains(e.target)) {
        _jhPageState.dropdownOpen = false;
        renderJobHoursPage();
        document.removeEventListener('click', close);
      }
    };
    document.addEventListener('click', close);
  }

  // Checkbox toggle — keep dropdown open, reload hours
  root.querySelectorAll('[data-jhp-id]').forEach(el => {
    el.addEventListener('click', e => {
      e.stopPropagation();
      const id = el.dataset.jhpId;
      const cur = new Set(_jhPageState.jobIds);
      if (cur.has(id)) cur.delete(id); else cur.add(id);
      _jhPageState.jobIds = [...cur];
      _jhPageState.fnFilter = null; // reset fn filter when job selection changes
      renderJobHoursPage();
    });
  });

  // Clear all
  root.querySelector('.jhp-dd-clear')?.addEventListener('click', e => {
    e.stopPropagation();
    _jhPageState.jobIds = [];
    renderJobHoursPage();
  });

  // Pill × remove buttons — stop propagation so they don't toggle the dropdown
  root.querySelectorAll('[data-jhp-pill-rm]').forEach(x => {
    x.addEventListener('click', e => {
      e.stopPropagation();
      const id = x.dataset.jhpPillRm;
      _jhPageState.jobIds = _jhPageState.jobIds.filter(j => j !== id);
      _jhPageState.fnFilter = null;
      renderJobHoursPage();
    });
  });

  // Search — re-render but restore focus so typing is uninterrupted
  root.querySelector('.jhp-dd-search')?.addEventListener('input', e => {
    const pos = e.target.selectionStart;
    _jhPageState.search = e.target.value;
    renderJobHoursPage();
    const inp = root.querySelector('.jhp-dd-search');
    if (inp) { inp.focus(); inp.setSelectionRange(pos, pos); }
  });

  // Hours type radios
  root.querySelectorAll('input[name="jht"]').forEach(r => {
    r.addEventListener('change', () => { _jhPageState.hoursType = r.value; _loadJhpHours(); });
  });

  // Load hours for selected jobs
  if (selCount) _loadJhpHours();

  // Sequential pre-fetch — keeps at most 1 background query in-flight at a time
  (async () => {
    for (const j of allJobs) {
      if (_hoursCache[j.id] || _hoursFetching[j.id]) continue;
      _hoursFetching[j.id] = true;
      try {
        const r = await fetch(`/api/hours/${encodeURIComponent(j.id)}`);
        const d = await r.json();
        if (!d?.error) _hoursCache[j.id] = d;
      } catch (_) {}
      _hoursFetching[j.id] = false;
    }
  })();

  // Fetch PBI jobs list in background to enrich status
  if (!_jhPageState.pbiJobs) {
    fetch('/api/hours/jobs/list').then(r => r.json()).then(data => {
      if (!data.error) { _jhPageState.pbiJobs = data; renderJobHoursPage(); }
    }).catch(() => {});
  }
}

// Sequential prefetch — one job at a time so user-triggered requests
// queue behind at most 1 background query instead of all of them at once.
async function _prefetchJobHours() {
  const localJobs = Object.entries(state.projectsIndex || {})
    .map(([name, info]) => ({ id: String(info.hours_job_id || info.job_number || '').trim(), name }))
    .filter(j => j.id)
    .sort((a, b) => a.name.localeCompare(b.name));
  for (const j of localJobs) {
    if (_hoursCache[j.id] || _hoursFetching[j.id]) continue;
    _hoursFetching[j.id] = true;
    try {
      const r = await fetch(`/api/hours/${encodeURIComponent(j.id)}`);
      const d = await r.json();
      if (!d?.error) _hoursCache[j.id] = d;
    } catch (_) {}
    _hoursFetching[j.id] = false;
  }
}

function _jhBarChart(title, groups, seriesLabels, seriesColors, W, H) {
  const F = "Montserrat,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif";
  const hasSec   = groups.some(g => g.sectionLabel);
  const hasGrp   = groups.some(g => g.groupLabel);
  const fnRowH   = 32;
  const grpRowH  = hasSec || hasGrp ? 28 : 0;
  const secRowH  = hasSec ? 30 : 0;
  const legendH  = 32;
  const padL = 72, padR = 8, padT = 36;
  W = Math.max(W, padL + padR + groups.length * 90);
  const padB = fnRowH + grpRowH + secRowH + legendH + 6;
  const chartH = H - padT - padB;
  const axisY  = padT + chartH;
  const allVals = groups.flatMap(g => g.series.map(s => s.value));
  const rawMax  = Math.max(...allVals, 1);
  const mag     = Math.pow(10, Math.floor(Math.log10(rawMax)));
  const step    = rawMax / mag <= 2 ? mag * 0.5 : rawMax / mag <= 5 ? mag : mag * 2;
  const maxVal  = Math.ceil(rawMax / step) * step;
  const ticks = 5;
  const tickStep = maxVal / ticks;
  let grid = '';
  for (let i = 0; i <= ticks; i++) {
    const v   = tickStep * i;
    const y   = padT + chartH - (v / maxVal) * chartH;
    const lbl = Math.round(v).toLocaleString();
    grid += `<line x1="${padL}" x2="${W-padR}" y1="${y.toFixed(1)}" y2="${y.toFixed(1)}" stroke="#e2e8f0" stroke-width="1"/>`;
    grid += `<text x="${padL-6}" y="${(y+4).toFixed(1)}" text-anchor="end" font-size="13" style="fill:var(--text-muted,#64748b);font-family:${F}">${lbl}</text>`;
  }
  const groupCount = groups.length;
  const slotW = (W - padL - padR) / groupCount;
  const barPad = 1;
  const seriesCount = seriesLabels.length;
  const barW = Math.max(4, Math.floor((slotW * 0.85 - barPad * (seriesCount - 1)) / seriesCount));
  let bars = '';
  const sectionMeta = new Map();
  const groupMeta   = new Map();
  groups.forEach((g, gi) => {
    const slotX = padL + gi * slotW;
    const groupCenter = slotX + slotW / 2;
    const totalBarW = barW * seriesCount + barPad * (seriesCount - 1);
    const barsStartX = groupCenter - totalBarW / 2;
    const sk = g.sectionLabel || '';
    const gk = (g.sectionLabel||'') + '||' + (g.label||'');
    if (!sectionMeta.has(sk)) sectionMeta.set(sk, { start: gi, end: gi });
    else sectionMeta.get(sk).end = gi;
    if (!groupMeta.has(gk)) groupMeta.set(gk, { start: gi, end: gi, label: g.label, sec: g.sectionLabel });
    else groupMeta.get(gk).end = gi;
    const qVal = g.series[0]?.value || 0;
    const aVal = g.series[1]?.value || 0;
    const diff = qVal - aVal;
    let minBarTop = axisY;
    g.series.forEach((s, si) => {
      if (!s.value) return;
      const color = seriesColors[si] || s.color;
      const bh  = Math.max(1, (s.value / maxVal) * chartH);
      const bx  = barsStartX + si * (barW + barPad);
      const by  = axisY - bh;
      if (by < minBarTop) minBarTop = by;
      const q = Math.round(qVal).toLocaleString();
      const a = Math.round(aVal).toLocaleString();
      const diffStr = (diff>=0?'+':'')+Math.round(diff).toLocaleString();
      const tip = `${g.fn || g.label || ''}\nQuoted: ${q}\nActual: ${a}\nDiff: ${diffStr}`;
      bars += `<rect x="${bx.toFixed(1)}" y="${by.toFixed(1)}" width="${barW}" height="${bh.toFixed(1)}" fill="${color}"><title>${escapeHtml(tip)}</title></rect>`;
      const lv = Math.round(s.value).toLocaleString();
      const lblY = by + Math.min(bh - 4, 18);
      const lblColor = si === 1 ? 'white' : '#0f172a';
      bars += `<text x="${(bx+barW/2).toFixed(1)}" y="${lblY.toFixed(1)}" text-anchor="middle" font-size="15" font-weight="700" style="fill:${lblColor};font-family:${F}">${lv}</text>`;
    });
    if (qVal && aVal) {
      const diffLabel = (diff >= 0 ? '+' : '') + Math.round(diff).toLocaleString();
      const diffColor = diff >= 0 ? '#16a34a' : '#dc2626';
      const actualBh = Math.max(1, (aVal / maxVal) * chartH);
      const actualBx = barsStartX + 1 * (barW + barPad);
      const actualBy = axisY - actualBh;
      bars += `<text x="${(actualBx + barW/2).toFixed(1)}" y="${(actualBy - 5).toFixed(1)}" text-anchor="middle" font-size="12" font-weight="700" style="fill:${diffColor};font-family:${F}">${diffLabel}</text>`;
    }
    const fnLabel = g.fn || g.label || '';
    bars += `<text x="${groupCenter.toFixed(1)}" y="${(axisY + secRowH + grpRowH + fnRowH - 6).toFixed(1)}" text-anchor="middle" font-size="13" font-weight="700" style="fill:var(--text,#061d39);font-family:${F}">${escapeHtml(fnLabel)}</text>`;
  });
  let secBandRects = '', secBandLabels = '';
  if (secRowH) {
    const sy = axisY;
    sectionMeta.forEach((m, sk) => {
      if (!sk) return;
      const x1 = padL + m.start * slotW;
      const x2 = padL + (m.end + 1) * slotW;
      const secBandW = x2 - x1;
      secBandRects  += `<rect x="${x1.toFixed(1)}" y="${sy.toFixed(1)}" width="${secBandW.toFixed(1)}" height="${secRowH}" fill="${seriesColors[1]||'#1e3a5f'}"><title>${escapeHtml(sk)}</title></rect>`;
      secBandLabels += `<text x="${((x1+x2)/2).toFixed(1)}" y="${(sy+secRowH/2+5).toFixed(1)}" text-anchor="middle" font-size="14" font-weight="700" fill="white" style="font-family:${F}">${escapeHtml(sk)}</text>`;
      secBandRects += `<line x1="${x2.toFixed(1)}" y1="${sy.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${(sy+secRowH).toFixed(1)}" stroke="white" stroke-width="2"/>`;
    });
  }
  const secBands = secBandRects + secBandLabels;
  let grpBandRects = '', grpBandLabels = '';
  if (grpRowH) {
    const gy = axisY + secRowH;
    groupMeta.forEach((m) => {
      const x1 = padL + m.start * slotW;
      const x2 = padL + (m.end + 1) * slotW;
      const grpBandW = x2 - x1;
      const grpLabel = m.label || '';
      grpBandRects  += `<rect x="${x1.toFixed(1)}" y="${gy.toFixed(1)}" width="${grpBandW.toFixed(1)}" height="${grpRowH}" fill="${seriesColors[0]||'#AACEE8'}"><title>${escapeHtml(`${m.sec ? m.sec + ' › ' : ''}${grpLabel}`)}</title></rect>`;
      grpBandLabels += `<text x="${((x1+x2)/2).toFixed(1)}" y="${(gy+grpRowH/2+5).toFixed(1)}" text-anchor="middle" font-size="13" font-weight="700" fill="#0f172a" style="font-family:${F}">${escapeHtml(grpLabel)}</text>`;
      grpBandRects  += `<line x1="${x2.toFixed(1)}" y1="${gy.toFixed(1)}" x2="${x2.toFixed(1)}" y2="${(gy+grpRowH).toFixed(1)}" stroke="white" stroke-width="2"/>`;
    });
  }
  const grpBands = grpBandRects + grpBandLabels;
  const legendY = axisY + fnRowH + grpRowH + secRowH + 8;
  const legendTotalW = seriesLabels.reduce((a, sl) => a + 14 + sl.length * 6.5 + 16, 0);
  let legend = '', lx = (W - legendTotalW) / 2;
  seriesLabels.forEach((sl, i) => {
    legend += `<rect x="${lx.toFixed(1)}" y="${legendY}" width="10" height="10" fill="${seriesColors[i]}" rx="1"/>`;
    legend += `<text x="${(lx+16).toFixed(1)}" y="${legendY+10}" font-size="13" font-weight="600" style="fill:var(--text,#061d39);font-family:${F}">${escapeHtml(sl)}</text>`;
    lx += 14 + sl.length * 6.5 + 16;
  });
  const titleSvg = `<text x="${(W/2).toFixed(1)}" y="22" text-anchor="middle" font-size="16" font-weight="700" style="fill:var(--text,#061d39);font-family:${F}">${escapeHtml(title)}</text>`;
  return `<div class="jhp-chart-wrap">
    <svg viewBox="0 0 ${W} ${H}" width="100%" style="display:block;overflow:visible">
      ${titleSvg}${grid}${bars}${grpBands}${secBands}${legend}
      <line x1="${padL}" x2="${padL}" y1="${padT}" y2="${axisY}" stroke="#cbd5e1" stroke-width="1"/>
      <line x1="${padL}" x2="${W-padR}" y1="${axisY}" y2="${axisY}" stroke="#cbd5e1" stroke-width="1"/>
    </svg>
  </div>`;
}

async function _loadJhpHours() {
  const content = document.getElementById('jhp-hours-content');
  if (!content) return;
  const job = [..._jhPageState.jobIds].sort().join('&').trim();
  if (!job) { content.innerHTML = `<div class="proc-empty">Select a job to view hours.</div>`; return; }

  if (!_hoursCache[job]) {
    // Already being pre-fetched? Wait for it, otherwise fetch now
    const _loadingMsg = () => `<div class="proc-empty jhp-loading-msg"><span class="jhp-spinner"></span>Querying Power BI… this takes 10–30 s on first load</div>`;
    if (_hoursFetching[job]) {
      content.innerHTML = _loadingMsg();
      await _awaitHoursFetch(job);
      if (!_hoursCache[job]) {
        content.innerHTML = `<div class="proc-empty proc-error">⚠ Timed out waiting for Power BI.<br><button class="jhp-retry-btn">↺ Retry</button></div>`;
        content.querySelector('.jhp-retry-btn')?.addEventListener('click', () => _loadJhpHours());
        return;
      }
    } else {
      content.innerHTML = _loadingMsg();
      _hoursFetching[job] = true;
      let fetchedData;
      try {
        fetchedData = await _fetchJobHoursJson(job);
      } catch (e) {
        _hoursFetching[job] = false;
        content.innerHTML = `<div class="proc-empty proc-error">⚠ Failed to load hours: ${escapeHtml(ctrlAbortMsg(e))}<br><button class="jhp-retry-btn">↺ Retry</button></div>`;
        content.querySelector('.jhp-retry-btn')?.addEventListener('click', () => _loadJhpHours());
        return;
      }
      _hoursFetching[job] = false;
      if (fetchedData?.error) {
        content.innerHTML = `<div class="proc-empty proc-error">⚠ ${escapeHtml(fetchedData.error)}<br><button class="jhp-retry-btn">↺ Retry</button></div>`;
        content.querySelector('.jhp-retry-btn')?.addEventListener('click', () => _loadJhpHours());
        return;
      }
      _hoursCache[job] = fetchedData;
    }
  }

  const data = _hoursCache[job];
  if (!data) return;
  if (data.error) { content.innerHTML = `<div class="proc-empty proc-error">⚠ ${escapeHtml(data.error)}</div>`; return; }

  const { bgTotals, totals } = data;
  // Remap Manufacturing out of "Shop" group into its own standalone group
  const fns = data.fns.map(r => r.fn === 'Manufacturing' ? { ...r, group: 'Manufacturing' } : r);
  if (!fns || !fns.length) { content.innerHTML = `<div class="proc-empty">No hours data found for job ${escapeHtml(job)}.</div>`; return; }

  const fmt   = n => Math.round(n || 0).toLocaleString();
  const dCls  = d => d < -0.5 ? ' hours-over' : d > 0.5 ? ' hours-under' : '';
  const dFmt  = d => `${d > 0 ? '+' : ''}${fmt(d)}`;

  // ── Function Hierarchy filter ─────────────────────────────────────────────
  // Build section→groups hierarchy from ALL fns (unfiltered)
  const fnHier = [];
  const fnHierMap = new Map();
  for (const r of fns) {
    if (!fnHierMap.has(r.section)) { fnHierMap.set(r.section, new Set()); fnHier.push(r.section); }
    if (r.group) fnHierMap.get(r.section).add(r.group);
  }

  // Build the full set of "section\x00group" keys
  const allFnKeys = new Set();
  for (const sec of fnHier) {
    const grps = fnHierMap.get(sec);
    if (grps.size) grps.forEach(g => allFnKeys.add(sec + '\x00' + g));
    else allFnKeys.add(sec + '\x00');
  }

  // Active filter — null means all shown
  const activeFnKeys = _jhPageState.fnFilter || allFnKeys;

  // Apply filter to fns — exclude PM group and Warranty section from pivot/chart
  const allFns = fns.filter(r => {
    const key = r.section + '\x00' + (r.group || '');
    if (/^pm$/i.test(r.group || '')) return false;
    if (/warranty/i.test(r.section || '')) return false;
    return activeFnKeys.has(key);
  });
  const secGroups = [];
  const secSeen = new Map();
  for (const r of allFns) {
    if (!secSeen.has(r.section)) { secSeen.set(r.section, []); secGroups.push({ sec: r.section, fns: secSeen.get(r.section) }); }
    secSeen.get(r.section).push(r);
  }
  const pivotCols = secGroups.flatMap(g => g.fns);

  const secSpans = secGroups.map(g => `<th class="hpt-sec-hdr" colspan="${g.fns.length}" title="${escapeHtml(g.sec)}">${escapeHtml(g.sec)}</th>`).join('');
  const grpSpans = secGroups.flatMap(g => {
    const grpOrder = [], grpCount = new Map();
    for (const r of g.fns) { const k = r.group || ''; if (!grpCount.has(k)) { grpOrder.push(k); grpCount.set(k, 0); } grpCount.set(k, grpCount.get(k)+1); }
    const _gl = g => g === 'Manufacturing' ? 'MFG' : g;
    return grpOrder.map(grp => `<th class="hpt-grp-hdr" colspan="${grpCount.get(grp)}" title="${escapeHtml(grp)}">${escapeHtml(_gl(grp))}</th>`);
  }).join('');
  const _glFn = s => s === 'Manufacturing' ? 'MFG' : s;
  const fnHdrs = pivotCols.map(r => `<th class="hpt-fn-hdr" title="${escapeHtml(r.fn)}" style="color:#000!important;font-weight:700"><span style="color:#000!important">${escapeHtml(_glFn(r.fn))}</span></th>`).join('');

  // Pre-compute per-column full data for rich tooltips
  const colTip = pivotCols.map(r => {
    const q = r.quoted||0, a = r.actual||0, e = r.etc||0, d = q - a;
    return escapeHtml(JSON.stringify({ fn: r.fn, group: r.group||'', section: r.section||'', q, a, e, d }));
  });
  const makeRow = (label, valFn, cls, rowCls) => {
    const cells = pivotCols.map((r, i) => { const v = valFn(r); return `<td class="hpt-val${cls ? cls(r) : ''}" data-tip="${colTip[i]}" data-tip-row="${label}">${fmt(v)}</td>`; }).join('');
    const total = pivotCols.reduce((a, r) => a + valFn(r), 0);
    const tq = pivotCols.reduce((a,r)=>a+(r.quoted||0),0), ta = pivotCols.reduce((a,r)=>a+(r.actual||0),0);
    const totTip = escapeHtml(JSON.stringify({ fn:'Total', group:'', section:'All functions', q:tq, a:ta, e:pivotCols.reduce((a,r)=>a+(r.etc||0),0), d:tq-ta }));
    return `<tr class="${rowCls||''}"><td class="hpt-row-lbl">${label}</td>${cells}<td class="hpt-total" data-tip="${totTip}" data-tip-row="${label}">${fmt(total)}</td></tr>`;
  };
  const ht     = _jhPageState.hoursType;
  const isEtc  = ht === 'etc';
  const pivotBody = [
    makeRow('Quoted', r => r.quoted || 0, null, ht === 'quoted' ? ' hpt-row-active' : ''),
    makeRow('Actual', r => r.actual || 0),
    makeRow('ETC',    r => r.etc    || 0, null, ht === 'etc'    ? ' hpt-row-active' : ''),
    makeRow('Diff',   r => (isEtc ? (r.etc||0) : (r.quoted||0)) - (r.actual||0), r => dCls((isEtc ? (r.etc||0) : (r.quoted||0))-(r.actual||0))),
  ].join('');

  const totalQ = pivotCols.reduce((a,r) => a+(r.quoted||0), 0);
  const totalA = pivotCols.reduce((a,r) => a+(r.actual||0), 0);
  const totalE = pivotCols.reduce((a,r) => a+(r.etc||0), 0);



  // ── Chart 1: driven by hoursType filter ──────────────────────────────────
  const compVal    = r => isEtc ? (r.etc || 0) : (r.quoted || 0);
  const compLabel  = isEtc ? 'ETC' : 'Quoted';
  const chartTitle = isEtc ? 'Estimate to Complete vs Actual' : 'Quoted vs Actual by Function';

  const _gl = g => g === 'Manufacturing' ? 'MFG' : g;
  const fnGroups = secGroups.flatMap(sg => {
    return sg.fns.map(r => ({
      fn: _gl(r.fn),
      label: _gl(r.group || r.fn),
      sectionLabel: sg.sec,
      series: [{ value: compVal(r) }, { value: r.actual || 0 }],
    }));
  }).filter(g => g.series[0].value || g.series[1].value);
  const fnChart = _jhBarChart(chartTitle, fnGroups, [compLabel, 'Actual'], ['#AACEE8','#1e3a5f'], 1800, 900);

  // ── Chart 2: Billing Group — driven by hoursType filter ──────────────────
  const BG_ORDER = ['Engineering', 'Shop', 'Manufacturing'];
  const bgGroups = BG_ORDER.filter(bg => bgTotals[bg]).map(bg => ({
    fn: _gl(bg), label: _gl(bg), sectionLabel: null,
    series: [{ value: isEtc ? bgTotals[bg].etc : bgTotals[bg].quoted }, { value: bgTotals[bg].actual }],
  }));
  const bgChartTitle = isEtc ? 'ETC and Actual by Billing Group' : 'Quoted and Actual by Billing Group';
  const bgChart = _jhBarChart(bgChartTitle, bgGroups, [compLabel, 'Actual'], ['#AACEE8','#1e3a5f'], 600, 900);

  // billing group cards
  const BG_CARD_ORDER = ['Engineering', 'Shop', 'Manufacturing'];
  const bgCards = BG_CARD_ORDER.map(bg => {
    const t = bgTotals[bg] || { quoted: 0, actual: 0, etc: 0 };
    const diff = t.quoted - t.actual;
    return `<div class="hours-bg-card" data-tip="${escapeHtml(JSON.stringify({ fn: bg, group: 'Billing Group', section: '', q: t.quoted, a: t.actual, e: t.etc||0, d: diff }))}" data-tip-row="Billing">
      <div class="hours-bg-name">${bg.toUpperCase()}</div>
      <div class="hours-bg-nums">
        <span class="hours-col-q">${fmt(t.quoted)}</span>
        <span class="hours-col-a">${fmt(t.actual)}</span>
        <span class="hours-col-d${dCls(diff)}">${dFmt(diff)}</span>
      </div>
    </div>`;
  }).join('');

  // ── Function Hierarchy dropdown HTML ────────────────────────────────────
  const SEC_DISPLAY_LABEL = {
    'Complete Design and Build': 'Sec-10: Complete Design and Build',
    'Machine Testing':           'Sec-40: Machine Testing',
    'Teardown and Install':      'Sec-50: Teardown and Install',
  };
  const fnDropOpen = _jhPageState.fnDropOpen;
  const fnFilterActive = _jhPageState.fnFilter;
  const fnSelCount = fnFilterActive ? fnFilterActive.size : allFnKeys.size;
  const fnTotalCount = allFnKeys.size;
  const fnBtnLabel = !fnFilterActive || fnSelCount === fnTotalCount ? 'All' : 'Multiple selections';

  const fnDropHtml = fnHier.map(sec => {
    const grps = [...fnHierMap.get(sec)];
    const secKeys = grps.length
      ? grps.map(g => sec + '\x00' + g)
      : [sec + '\x00'];
    const selCount = secKeys.filter(k => activeFnKeys.has(k)).length;
    const allSel = selCount === secKeys.length;
    const noneSel = selCount === 0;
    const partSel = !allSel && !noneSel;
    return `<div class="jhp-fn-sec">
      <label class="jhp-fn-item jhp-fn-sec-row" data-fn-sec="${escapeHtml(sec)}">
        <span class="jhp-dd-cb${allSel ? ' checked' : partSel ? ' partial' : ''}"></span>
        <span class="jhp-fn-sec-name">${escapeHtml(SEC_DISPLAY_LABEL[sec] || sec)}</span>
      </label>
      ${grps.map(g => {
        const k = sec + '\x00' + g;
        const sel = activeFnKeys.has(k);
        return `<label class="jhp-fn-item jhp-fn-grp-row" data-fn-sec="${escapeHtml(sec)}" data-fn-grp="${escapeHtml(g)}">
          <span class="jhp-dd-cb${sel ? ' checked' : ''}"></span>
          <span class="jhp-fn-grp-name">${escapeHtml(g)}</span>
        </label>`;
      }).join('')}
    </div>`;
  }).join('');

  // Inject Function Hierarchy filter into the top-bar slot
  const fnSlot = document.getElementById('jhp-fn-filter-slot');
  if (fnSlot) {
    fnSlot.innerHTML = `
      <div class="jhp-filter-block">
        <div class="jhp-filter-block-title">Function Hierarchy</div>
        <div class="jhp-dd-wrap${fnDropOpen ? ' is-open' : ''}">
          <button class="jhp-dd-btn jhp-fn-dd-btn" id="jhp-fn-dd-toggle">
            <span class="jhp-dd-btn-label">${escapeHtml(fnBtnLabel)}</span>
            <span class="jhp-dd-caret">${fnDropOpen ? '▲' : '▼'}</span>
          </button>
          ${fnDropOpen ? `
          <div class="jhp-dd-panel jhp-fn-dd-panel">
            <div class="jhp-dd-search-wrap">
              <span class="jhp-dd-search-icon">🔍</span>
              <input class="jhp-fn-search" placeholder="Search" autofocus>
            </div>
            <div class="jhp-dd-sel-bar">
              <label class="jhp-fn-item" data-fn-all>
                <span class="jhp-dd-cb${!fnFilterActive || fnSelCount===fnTotalCount ? ' checked' : ''}"></span>
                <span>Select all</span>
              </label>
              ${fnFilterActive ? `<button class="jhp-dd-clear" data-fn-clear>Clear</button>` : ''}
            </div>
            <div class="jhp-fn-list">${fnDropHtml}</div>
          </div>` : ''}
        </div>
      </div>`;
  }

  content.innerHTML = `
    <div class="hours-bg-row" style="margin-bottom:12px">${bgCards}</div>
    <div class="jhp-summary-bar">
      <div class="jhp-totals">
        <span class="jhp-total-label">Total Quoted</span><span class="jhp-total-val">${fmt(totalQ)}</span>
        <span class="jhp-total-sep">·</span>
        <span class="jhp-total-label">Actual</span><span class="jhp-total-val">${fmt(totalA)}</span>
        <span class="jhp-total-sep">·</span>
        <span class="jhp-total-label">ETC</span><span class="jhp-total-val">${fmt(totalE)}</span>
        <span class="jhp-total-sep">·</span>
        <span class="jhp-total-label">Diff</span><span class="jhp-total-val${dCls(totalQ-totalA)}">${dFmt(totalQ-totalA)}</span>
      </div>
    </div>
    <div class="hpt-fn-wrap" style="margin-top:12px;overflow-x:auto">
      <table class="hpt" style="table-layout:auto;width:100%">
        <colgroup>
          <col style="width:80px">
          ${pivotCols.map(() => `<col>`).join('')}
          <col style="width:80px">
        </colgroup>
        <thead>
          <tr><th class="hpt-corner" rowspan="3"></th>${secSpans}<th class="hpt-total-hdr" rowspan="3">Total</th></tr>
          <tr>${grpSpans}</tr>
          <tr>${fnHdrs}</tr>
        </thead>
        <tbody>${pivotBody}</tbody>
      </table>
    </div>
    <div class="jhp-charts-row" style="align-items:flex-start">
      <div class="jhp-chart-main" style="overflow-x:auto">${fnChart}</div>
      <div class="jhp-chart-side" style="overflow-x:auto">${bgChart}</div>
    </div>`;

  // Wire fn filter events on the slot
  if (fnSlot) {
    fnSlot.querySelector('#jhp-fn-dd-toggle')?.addEventListener('click', e => {
      e.stopPropagation();
      _jhPageState.fnDropOpen = !_jhPageState.fnDropOpen;
      _loadJhpHours();
    });

    if (fnDropOpen) {
      const close = e => {
        if (!fnSlot.contains(e.target)) {
          _jhPageState.fnDropOpen = false;
          _loadJhpHours();
          document.removeEventListener('click', close);
        }
      };
      document.addEventListener('click', close);
    }

    fnSlot.querySelector('[data-fn-all]')?.addEventListener('click', e => {
      e.stopPropagation();
      _jhPageState.fnFilter = null;
      _loadJhpHours();
    });

    fnSlot.querySelector('[data-fn-clear]')?.addEventListener('click', e => {
      e.stopPropagation();
      _jhPageState.fnFilter = new Set();
      _loadJhpHours();
    });

    fnSlot.querySelector('.jhp-fn-search')?.addEventListener('input', e => {
      const q = e.target.value.toLowerCase();
      fnSlot.querySelectorAll('.jhp-fn-sec').forEach(secEl => {
        const secName = secEl.querySelector('.jhp-fn-sec-name')?.textContent.toLowerCase() || '';
        let anyVisible = secName.includes(q);
        secEl.querySelectorAll('.jhp-fn-grp-row').forEach(grpEl => {
          const grpName = grpEl.querySelector('.jhp-fn-grp-name')?.textContent.toLowerCase() || '';
          const vis = grpName.includes(q) || secName.includes(q);
          grpEl.style.display = vis ? '' : 'none';
          if (vis) anyVisible = true;
        });
        secEl.style.display = anyVisible ? '' : 'none';
      });
    });

    fnSlot.querySelectorAll('[data-fn-grp]').forEach(el => {
      el.addEventListener('click', e => {
        e.stopPropagation();
        const sec = el.dataset.fnSec, grp = el.dataset.fnGrp;
        const key = sec + '\x00' + grp;
        const cur = new Set(_jhPageState.fnFilter || allFnKeys);
        if (cur.has(key)) cur.delete(key); else cur.add(key);
        _jhPageState.fnFilter = cur.size === allFnKeys.size ? null : cur;
        _loadJhpHours();
      });
    });

    fnSlot.querySelectorAll('[data-fn-sec]:not([data-fn-grp])').forEach(el => {
      el.addEventListener('click', e => {
        e.stopPropagation();
        const sec = el.dataset.fnSec;
        const grps = [...fnHierMap.get(sec)];
        const secKeys = grps.length ? grps.map(g => sec + '\x00' + g) : [sec + '\x00'];
        const cur = new Set(_jhPageState.fnFilter || allFnKeys);
        const allSel = secKeys.every(k => cur.has(k));
        if (allSel) secKeys.forEach(k => cur.delete(k));
        else secKeys.forEach(k => cur.add(k));
        _jhPageState.fnFilter = cur.size === allFnKeys.size ? null : cur;
        _loadJhpHours();
      });
    });
  }

  // ── Rich floating tooltip for pivot cells + billing cards ──────────────────
  _jhpTipWire(content);
}

function _jhpTipWire(container) {
  // Ensure tooltip element exists
  let tip = document.getElementById('jhp-tip');
  if (!tip) {
    tip = document.createElement('div');
    tip.id = 'jhp-tip';
    document.body.appendChild(tip);
  }
  const fmt = n => Math.round(n || 0).toLocaleString();
  const show = (d, row, x, y) => {
    try {
      const p = JSON.parse(d);
      const diff = p.d;
      const diffCls = diff < -0.5 ? 'jt-over' : diff > 0.5 ? 'jt-under' : 'jt-val';
      const diffSign = diff > 0 ? '+' : '';
      const path = [p.section, p.group].filter(Boolean).join(' › ');
      tip.innerHTML = `
        <div class="jt-fn">${escapeHtml(p.fn)}</div>
        ${path ? `<div class="jt-path">${escapeHtml(path)}</div>` : ''}
        <div class="jt-div"></div>
        <div class="jt-row"><span class="jt-lbl">Quoted</span><span class="jt-val">${fmt(p.q)}</span></div>
        <div class="jt-row"><span class="jt-lbl">Actual</span><span class="jt-val">${fmt(p.a)}</span></div>
        <div class="jt-row"><span class="jt-lbl">ETC</span><span class="jt-val">${fmt(p.e)}</span></div>
        <div class="jt-div"></div>
        <div class="jt-row"><span class="jt-lbl">Diff (Q−A)</span><span class="${diffCls}">${diffSign}${fmt(diff)}</span></div>`;
      tip.style.display = 'block';
      _jhpTipMove(x, y);
    } catch (_) {}
  };
  container.addEventListener('mouseover', e => {
    const el = e.target.closest('[data-tip]');
    if (el) show(el.dataset.tip, el.dataset.tipRow, e.clientX, e.clientY);
  });
  container.addEventListener('mousemove', e => {
    if (tip.style.display === 'block') _jhpTipMove(e.clientX, e.clientY);
  });
  container.addEventListener('mouseout', e => {
    if (!e.target.closest('[data-tip]')) return;
    if (!e.relatedTarget || !e.relatedTarget.closest('[data-tip]')) tip.style.display = 'none';
  });
  // Hide when leaving content area entirely
  container.addEventListener('mouseleave', () => { tip.style.display = 'none'; });
}

function _jhpTipMove(x, y) {
  const tip = document.getElementById('jhp-tip');
  if (!tip) return;
  const W = tip.offsetWidth || 200, H = tip.offsetHeight || 120;
  const vw = window.innerWidth, vh = window.innerHeight;
  tip.style.left = (x + 14 + W > vw ? x - W - 10 : x + 14) + 'px';
  tip.style.top  = (y + 14 + H > vh ? y - H - 10 : y + 14) + 'px';
}

function renderProjectsPage() {
  const root = document.getElementById('projects-page');
  if (!root) return;
  // Merge projects from the DB index (loaded eagerly in init) with any in tasks
  const fromIndex = Object.keys(state.projectsIndex || {});
  const fromTasks = uniqueValues('project');
  const all = [...new Set([...fromIndex, ...fromTasks])].sort();
  const openSet = new Set(state.openProjects);
  const recentSet = new Map((state.recentProjects || []).map((p, i) => [p, i]));
  const byWs = Object.fromEntries(WORKSPACES.map(ws => [ws, []]));
  for (const p of all) byWs[projectWorkspace(p)].push(p);
  for (const ws of WORKSPACES) {
    byWs[ws].sort((a, b) => {
      const ta = isTemplateProject(a) ? 0 : 1;
      const tb = isTemplateProject(b) ? 0 : 1;
      if (ta !== tb) return ta - tb;
      return a.localeCompare(b);
    });
  }
  const expanded = state._projectsExpanded || (state._projectsExpanded = {});
  const searchQ = (state._projectsSearch || '').toLowerCase().trim();

  const favSet = new Set(state.favoriteProjects || []);

  // Workspace accent colors for visual differentiation
  const WS_ACCENT = { Active: '#1574c4', Sales: '#d97706', Closed: '#94a3b8' };
  const WS_COUNT_BG = { Active: '#dbeafe', Sales: '#fef9c3', Closed: '#f1f5f9' };
  const WS_COUNT_COLOR = { Active: '#1d4ed8', Sales: '#92400e', Closed: '#64748b' };

  // Last-opened label from recentProjects index
  const recentLabel = (p) => {
    const idx = recentSet.get(p);
    if (idx === undefined) return '';
    if (idx === 0) return 'opened just now';
    if (idx === 1) return 'opened recently';
    return 'opened recently';
  };

  const rowHtml = (p) => {
    const isOpen = openSet.has(p);
    const isFav = favSet.has(p);
    const isTmpl = isTemplateProject(p);
    const favBtn = `<button class="projects-row-favbtn${isFav ? ' is-fav' : ''}" data-action="toggle-fav" data-project="${escapeHtml(p)}" type="button" title="${isFav ? 'Unfavorite' : 'Add to favorites'}">${isFav ? '★' : '☆'}</button>`;
    const isSalesProject = !isTmpl && projectWorkspace(p) === 'Sales';
    const promoteBtn = isSalesProject
      ? `<button class="projects-row-promotebtn" data-action="promote" data-project="${escapeHtml(p)}" type="button" title="Promote this sales schedule to a detailed project.">→ Project</button>`
      : '';
    const openBtn = `<button class="projects-row-openbtn${isOpen ? ' is-open' : ''}" data-action="open-project" data-project="${escapeHtml(p)}" type="button">OPEN</button>`;
    return `<div class="projects-row${isOpen ? ' is-open' : ''}${isTmpl ? ' is-template' : ''}" data-project="${escapeHtml(p)}" role="button" tabindex="0">
      <span class="projects-row-name">${escapeHtml(p)}</span>
      ${promoteBtn}
      ${openBtn}
      ${favBtn}
    </div>`;
  };

  const workspaceSection = (ws) => {
    const projects = byWs[ws];
    const templates = projects.filter(isTemplateProject);
    let nonTemplates = projects.filter(p => !isTemplateProject(p));
    if (searchQ) nonTemplates = nonTemplates.filter(p => p.toLowerCase().includes(searchQ));
    const isExpanded = !!expanded[ws];
    const allowsNew = ws !== 'Closed';
    const wsTmpl = templates.length === 1 ? templates[0]
      : templates.find(t => !/duplicate/i.test(t)) || templates[0] || null;
    // Generic label — the dialog itself offers this workspace's templates,
    // so naming one specific template here was misleading when two exist.
    const newBtnLabel = wsTmpl ? '+ New from template' : '+ New schedule';
    const displayCount = searchQ ? nonTemplates.length : nonTemplates.length;
    return `
      <div class="projects-workspace projects-ws-${ws.toLowerCase()}${isExpanded ? ' is-expanded' : ''}" data-workspace="${escapeHtml(ws)}">
        <button class="projects-workspace-head" data-action="toggle" type="button">
          <span class="projects-workspace-caret">▶</span>
          <span class="projects-workspace-name">${escapeHtml(ws)}</span>
          <span class="projects-workspace-count">${displayCount}</span>
        </button>
        <div class="projects-workspace-body">
          ${allowsNew ? `<button class="projects-workspace-newbtn" data-action="new" data-workspace="${escapeHtml(ws)}"${wsTmpl ? ` data-template="${escapeHtml(wsTmpl)}"` : ''} type="button">${newBtnLabel}</button>` : ''}
          ${!searchQ && templates.length > 0 ? `
            <div class="projects-templates-row">
              <div class="projects-templates-label">Templates</div>
              ${templates.map(rowHtml).join('')}
            </div>
          ` : ''}
          ${nonTemplates.length === 0
            ? `<div class="projects-workspace-empty">${searchQ ? 'No matches.' : 'No schedules yet — use the "+ New" button to start one.'}</div>`
            : nonTemplates.map(rowHtml).join('')}
        </div>
      </div>
    `;
  };

  const nonTmplCount = all.filter(p => !isTemplateProject(p)).length;
  const wsWithProjects = WORKSPACES.filter(ws => byWs[ws].some(p => !isTemplateProject(p))).length;

  root.innerHTML = `
    <h1 class="projects-page-title">Projects</h1>
    <div class="projects-page-sub">${nonTmplCount} schedule${nonTmplCount !== 1 ? 's' : ''} across ${wsWithProjects} workspace${wsWithProjects !== 1 ? 's' : ''}</div>
    <div class="projects-search-wrap">
      <span class="projects-search-icon">🔍</span>
      <input class="projects-search-input" type="text" placeholder="Search projects…" value="${escapeHtml(searchQ)}" autocomplete="off" spellcheck="false" />
    </div>
    ${WORKSPACES.map(workspaceSection).join('')}
  `;

  // Search input — filter rows in real-time without a full re-render
  const searchInput = root.querySelector('.projects-search-input');
  if (searchInput) {
    searchInput.focus();
    searchInput.setSelectionRange(searchInput.value.length, searchInput.value.length);
    searchInput.addEventListener('input', () => {
      state._projectsSearch = searchInput.value;
      renderProjectsPage();
    });
  }

  // Toggle expand/collapse on the workspace header. The header is itself a
  // button; the inner "+ New schedule" button shouldn't trigger the toggle,
  // so we stop propagation on its click separately below.
  root.querySelectorAll('.projects-workspace-head').forEach(head => {
    head.addEventListener('click', (e) => {
      // Bail if the click was on the inner New-schedule button.
      if (e.target.closest('[data-action="new"]')) return;
      const wsDiv = head.closest('.projects-workspace');
      if (!wsDiv) return;
      const ws = wsDiv.dataset.workspace;
      expanded[ws] = !expanded[ws];
      wsDiv.classList.toggle('is-expanded', expanded[ws]);
      try { localStorage.setItem('sdcProjectsExpanded', JSON.stringify(expanded)); } catch {}
    });
  });
  root.querySelectorAll('.projects-row').forEach(row => {
    row.addEventListener('click', (e) => {
      // Star button intercept — toggles favorite, doesn't open the project.
      if (e.target.closest('[data-action="toggle-fav"]')) return;
      // Promote button intercept — opens the sales → detailed promote modal.
      if (e.target.closest('[data-action="promote"]')) {
        e.stopPropagation();
        const p = e.target.closest('[data-action="promote"]').dataset.project;
        if (p) openPromoteModal(p);
        return;
      }
      // OPEN button or anywhere on the row opens the project.
      if (e.target.closest('[data-action="open-project"]')) e.stopPropagation();
      const p = row.dataset.project;
      if (!p) return;
      if (!state.openProjects.includes(p)) state.openProjects.push(p);
      state.filters.project = p;
      state.activeWorkspace = projectWorkspace(p);
      recordRecentProject(p);
      saveProjectTabs();
      setView('schedule');
    });
    row.addEventListener('contextmenu', (e) => {
      e.preventDefault();
      const p = row.dataset.project;
      if (!p) return;
      showProjectTabMenu(e.clientX, e.clientY, p);
    });
  });
  root.querySelectorAll('[data-action="new"]').forEach(btn => {
    btn.addEventListener('click', async (e) => {
      e.stopPropagation();  // don't toggle the section
      const ws = btn.dataset.workspace;
      if (!ws || ws === 'Closed') return;
      state.activeWorkspace = ws;
      saveProjectTabs();
      // Sales gets its own slim dialog (name + copy-from, defaulting to the
      // sales template) — the click already declared the intent, so no
      // template/other/blank picker and no Smartsheet import. Other
      // workspaces keep the full create dialog.
      if (ws === 'Sales') showSalesCreateDialog(btn.dataset.template || '');
      else showCreateScheduleDialog(ws);
    });
  });
  // Star toggle on each row (favorite / unfavorite).
  root.querySelectorAll('[data-action="toggle-fav"]').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const p = btn.dataset.project;
      if (p) toggleFavoriteProject(p);
    });
  });
}

// Favorites page — list of starred projects. Click to open like the Projects page.
function renderFavoritesPage() {
  const root = document.getElementById('favorites-page');
  if (!root) return;
  const favs = (state.favoriteProjects || []).filter(p => state.tasks.some(t => t.project === p));
  root.innerHTML = `
    <h1 class="projects-page-title">Favorites</h1>
    <div class="projects-page-sub">${favs.length} starred schedule${favs.length === 1 ? '' : 's'}</div>
    ${favs.length === 0
      ? '<p class="projects-page-empty">No favorites yet. Click the ☆ next to any schedule on the Projects page to star it.</p>'
      : `<div class="projects-workspace is-expanded"><div class="projects-workspace-body">${favs.map(p => {
          const isOpen = state.openProjects.includes(p);
          const isTmpl = isTemplateProject(p);
          return `<div class="projects-row${isOpen ? ' is-open' : ''}${isTmpl ? ' is-template' : ''}" data-project="${escapeHtml(p)}" role="button" tabindex="0">
            <span class="projects-row-star">${isTmpl ? '★' : ''}</span>
            <span class="projects-row-name">${escapeHtml(p)}</span>
            ${isOpen ? '<span class="projects-row-badge">open</span>' : ''}
            <button class="projects-row-favbtn is-fav" data-action="toggle-fav" data-project="${escapeHtml(p)}" type="button" title="Unfavorite">★</button>
          </div>`;
        }).join('')}</div></div>`}
  `;
  root.querySelectorAll('.projects-row').forEach(row => {
    row.addEventListener('click', (e) => {
      if (e.target.closest('[data-action="toggle-fav"]')) return;
      const p = row.dataset.project;
      if (!p) return;
      if (!state.openProjects.includes(p)) state.openProjects.push(p);
      state.filters.project = p;
      state.activeWorkspace = projectWorkspace(p);
      recordRecentProject(p);
      saveProjectTabs();
      setView('schedule');
    });
  });
  root.querySelectorAll('[data-action="toggle-fav"]').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const p = btn.dataset.project;
      if (p) toggleFavoriteProject(p);
    });
  });
}

